class _KitchenDispatchFeedback {
  const _KitchenDispatchFeedback({
    this.error,
    this.notice,
    this.queuedOnly = false,
    this.progressed = false,
    this.physicallyDispatched = false,
    this.orderId,
    this.printJobIds = const <String>[],
    this.bridgeRequestMs = 0,
    this.dispatchPath = '',
    this.payloadBuildMs = 0,
    this.printerResolveMs = 0,
    this.totalToBridgeMs = 0,
    this.directPrintStartedMs = 0,
    this.directPrintDoneMs = 0,
    this.fastPathDecisionMs = 0,
    this.printerCacheResolveMs = 0,
    this.stationResolveMs = 0,
    this.fallbackReason = '',
    this.selectedPrinterId = '',
  });

  final String? error;
  final String? notice;
  final bool queuedOnly;
  final bool progressed;

  /// Local bridge already printed; skip polling / "sonuç kontrol ediliyor".
  final bool physicallyDispatched;
  final String? orderId;
  final List<String> printJobIds;
  final int bridgeRequestMs;
  final String dispatchPath;
  final int payloadBuildMs;
  final int printerResolveMs;
  final int totalToBridgeMs;
  final int directPrintStartedMs;
  final int directPrintDoneMs;
  final int fastPathDecisionMs;
  final int printerCacheResolveMs;
  final int stationResolveMs;
  final String fallbackReason;
  final String selectedPrinterId;

  bool get hasError => error != null && error!.trim().isNotEmpty;
  bool get hasNotice => notice != null && notice!.trim().isNotEmpty;
  bool get hasTrackedJobs => printJobIds.isNotEmpty;
  bool get shouldTrackPrintCompletion =>
      hasTrackedJobs && !physicallyDispatched;

  static const none = _KitchenDispatchFeedback();
}

enum _GarsonSubmitFeedbackTone { loading, success, warning }

String _normalizePrinterWorkflowMessageValue(
  Object error, {
  required String fallback,
}) {
  // Fast path: LocalPrintServiceException with a structured errorCode.
  if (error is LocalPrintServiceException &&
      error.details is Map<String, dynamic>) {
    final details = error.details! as Map<String, dynamic>;
    final errorCode = details['errorCode']?.toString().trim() ?? '';
    if (errorCode == 'cups_queue_busy' || errorCode == 'cups_queue_stuck') {
      final queue =
          details['printer_queue']?.toString().trim() ??
          details['queue']?.toString().trim() ??
          '';
      // Show a concise, actionable message — not the raw JSON blob.
      return queue.isNotEmpty
          ? 'Yazıcı kuyruğu meşgul ($queue). '
                "Sistem Ayarları > Yazıcılar'dan kuyruğu temizleyin veya USB'yi çıkarıp takın."
          : 'Yazıcı kuyruğu meşgul. '
                "Sistem Ayarları > Yazıcılar'dan kuyruğu temizleyin veya USB'yi çıkarıp takın.";
    }
  }
  final rawMessage = error.toString().replaceFirst('Exception: ', '').trim();
  if (rawMessage.isEmpty) {
    return fallback;
  }
  final normalized = rawMessage.toLowerCase();
  if (normalized.contains('macos yazıcıyı kilitledi')) {
    return 'macOS yazıcıyı kilitledi. Sistem Ayarları > Yazıcılar içinde '
        'POS58/CUPS kaydini kaldirin, sonra gelen izin penceresinden USB '
        'kilidini acin.';
  }
  // cups_queue_busy/stuck can also surface as a plain string (e.g. from
  // the job-failed row in the queue tracking table).
  if (normalized.contains('cups_queue_busy') ||
      normalized.contains('cups_queue_stuck') ||
      normalized.contains('kuyruğunda bekleyen işler var')) {
    return 'Yazıcı kuyruğu meşgul. '
        "Sistem Ayarları > Yazıcılar'dan kuyruğu temizleyin veya USB'yi çıkarıp takın.";
  }
  if (normalized.contains('aktif yazdirma yetkisi yok') ||
      normalized.contains('bu restoranda aktif') ||
      normalized.contains('bu restoran için işlem yetkiniz yok') ||
      normalized.contains('permission denied') ||
      normalized.contains('row-level security') ||
      normalized.contains('42501')) {
    return rawMessage;
  }
  return rawMessage;
}

class _SellerDashboardSnapshot {
  const _SellerDashboardSnapshot({
    required this.metrics,
    required this.statusCounts,
    required this.weeklyStats,
    required this.monthlyStats,
    required this.totalOrderCount,
    required this.completionRate,
    required this.averageOrderChange,
    required this.topProducts,
    required this.cargoSummary,
    required this.pendingTasks,
  });

  final SellerDashboardMetrics metrics;
  final Map<String, int> statusCounts;
  final (double, int, double) weeklyStats;
  final (double, int) monthlyStats;
  final int totalOrderCount;
  final double completionRate;
  final double averageOrderChange;
  final List<Map<String, dynamic>> topProducts;
  final List<Map<String, dynamic>> cargoSummary;
  final List<Map<String, dynamic>> pendingTasks;
}

SellerPanelEntryRole parseSellerPanelEntryRole(Object? arguments) {
  if (arguments is SellerPanelEntryRole) {
    return arguments;
  }
  final rawValue = arguments is Map<String, dynamic>
      ? arguments['entryRole']?.toString()
      : arguments?.toString();
  switch (rawValue?.trim().toLowerCase()) {
    case 'waiter':
    case 'garson':
      return SellerPanelEntryRole.waiter;
    default:
      return SellerPanelEntryRole.seller;
  }
}

/// Customer [table_orders] rows in `new` / `waiting` need garson "Siparişi Gönder"
/// before kitchen dispatch; waiter-placed rows do not.
bool _garsonTableOrderNeedsCustomerKitchenApproval(Map<String, dynamic> order) {
  final s = order['status']?.toString().toLowerCase().trim() ?? '';
  if (s != 'new' && s != 'waiting') return false;
  final src = order['placement_source']?.toString().toLowerCase().trim() ?? '';
  return src == 'customer';
}

