  void _onSellerOrderHighlightExpired(List<String> expiredOrderIds) {
    if (!mounted ||
        _sellerPanelControllersDisposed ||
        expiredOrderIds.isEmpty) {
      return;
    }
    setState(() {
      for (final orderId in expiredOrderIds) {
        _highlightedSellerOrderIds.remove(orderId);
      }
    });
