  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addObserver(this);
    _bindNavigationController(source: 'initState', viaSetState: false);
    _logSellerPanelLifecycle(
      'initState',
      newInitialModule: _selectedModule.name,
      includeStack: true,
    );
    _logSellerPanel(
      'Init',
      'phase=initState '
          'entryRole=${widget.entryRole.name} '
          'authUserId=${_authService.currentUser?.id ?? '-'} '
          'initialTab=${_selectedModule.name}',
    );
    _applySellerSeo();
    unawaited(_restoreLastSelectedModule());
    unawaited(_restoreGarsonAreaFilter());
    unawaited(_restoreSidebarCollapsed());
    _sellerOrderHighlightExpiryScheduler = SellerOrderHighlightExpiryScheduler(
      highlightDuration: const Duration(seconds: 30),
      onExpired: _onSellerOrderHighlightExpired,
    );
    _logSellerPanel(
      'Init',
      'branch=store_profile trigger=initState requestUrl=${_sellerPanelRestRequestUrl('stores', query: <String, String>{'select': '*', 'seller_id': 'eq.${_authService.currentUser?.id.trim().isNotEmpty == true ? _authService.currentUser!.id.trim() : '<missing>'}'})}',
    );
    _loadStoreProfile();
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted) return;
      _logSellerPanelLifecycle('build', newInitialModule: _selectedModule.name);
      _logSellerPanel(
        'Init',
        'phase=postFrame activeTab=${_selectedModule.name} '
            'action=ensureModuleDataLoaded',
      );
      unawaited(_ensureDesktopPrintHubStarted(reason: 'post_frame_init'));
      unawaited(_ensureModuleDataLoaded(_selectedModule));
      _scheduleLocalPrintStatusRefreshIfNeeded(
        module: _selectedModule,
        reason: 'seller_panel_init',
      );
    });
  }

  Future<void> _restoreLastSelectedModule() async {
    final prefs = await SharedPreferences.getInstance();
    final restored = _moduleFromStorageKey(
      prefs.getString(_sellerPanelLastModulePrefKey),
    );
    if (restored == null || restored == SellerModule.dashboard) {
      _logSellerPanel(
        'Tab',
        'action=restoreLastSelectedModule restored=${restored?.name ?? '-'} '
            'applied=false',
      );
      return;
    }
    _logSellerPanel(
      'Tab',
      'action=restoreLastSelectedModule restored=${restored.name} applied=false',
    );
    await prefs.remove(_sellerPanelLastModulePrefKey);
  }

  static const String _garsonLastAreaPrefKey = 'seller_panel.garson.last_area';

  Future<void> _restoreGarsonAreaFilter() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final restored = (prefs.getString(_garsonLastAreaPrefKey) ?? '').trim();
      if (!mounted) return;
      if (restored.isNotEmpty) {
        setState(() => _garsonAreaFilterKey = restored);
