  /// SINGLE source of truth for every write to [_selectedModule].
  ///
  /// After initState seeds the first value, every navigation mutation MUST
  /// flow through this helper.
  bool _setActiveSellerModule(
    SellerModule next, {
    required String source,
    required bool userInitiated,
    bool parentRestore = false,
  }) {
    if (!mounted) return false;
    final controller = _navigationController;
    if (controller == null) return false;
    final previous = controller.activeModule;
    final hasUserSelected = controller.hasUserSelected;
    final navigationSource = _navigationSourceCategory(
      userInitiated: userInitiated,
      parentRestore: parentRestore,
    );

    if (!userInitiated &&
        !parentRestore &&
        next == SellerModule.dashboard &&
        hasUserSelected) {
      debugPrint(
        '[NAV_BLOCKED] '
        'source=$source '
        'from=${previous.name} '
        'to=dashboard '
        'userInitiated=false '
        'parentRestore=false '
        'navSource=${navigationSource.name} '
        'reason=user_selected_lock',
      );
      debugPrint(StackTrace.current.toString());
      return false;
    }

    if (!userInitiated &&
        !parentRestore &&
        next == SellerModule.dashboard &&
        previous == SellerModule.garson) {
      debugPrint(
        '[NAV_BLOCKED] '
        'source=$source '
        'from=garson '
        'to=dashboard '
        'userInitiated=false '
        'parentRestore=false '
        'navSource=${navigationSource.name} '
        'reason=garson_active',
      );
      debugPrint(StackTrace.current.toString());
      return false;
    }

    if (!userInitiated &&
        !parentRestore &&
        next == SellerModule.dashboard &&
        _isGarsonTableRouteOpen) {
      debugPrint(
        '[NAV_BLOCKED] '
        'source=$source '
        'from=${previous.name} '
        'to=dashboard '
        'userInitiated=false '
        'parentRestore=false '
        'navSource=${navigationSource.name} '
        'reason=garson_table_route_open',
      );
      debugPrint(StackTrace.current.toString());
      return false;
    }

    final decision = evaluateSellerNavigationWrite(
      current: previous,
      next: next,
      hasUserSelectedModule: hasUserSelected,
      userInitiated: userInitiated,
      parentRestore: parentRestore,
    );
    if (decision.action == SellerNavigationWriteAction.blocked) {
      debugPrint(
        '[NAV_BLOCKED] '
        'source=$source '
        'from=${previous.name} '
        'to=${next.name} '
        'userInitiated=$userInitiated '
        'parentRestore=$parentRestore '
        'navSource=${navigationSource.name} '
        'reason=user_selected_lock',
      );
      return false;
    }

    final changed = userInitiated
        ? controller.selectByUser(next, source: source)
        : parentRestore
        ? controller.restoreParent(next, source: source)
        : controller.tryAsyncSet(next, source: source);
    _syncStateFromNavigationController(
      source: 'setActiveSellerModule:$source',
      viaSetState: true,
    );
    if (!changed && previous == next) {
      debugPrint(
        '[NAV_NOOP] '
        'source=$source '
        'module=${next.name} '
        'userInitiated=$userInitiated '
        'parentRestore=$parentRestore '
        'navSource=${navigationSource.name}',
      );
      return true;
    }
    if (changed) {
      debugPrint(
        '[NAV_WRITE] '
        'source=$source '
        'from=${previous.name} '
        'to=${next.name} '
        'userInitiated=$userInitiated '
        'parentRestore=$parentRestore '
        'navSource=${navigationSource.name} '
        'owner=$_navigationControllerOwnerKey',
      );
      _logSellerPanelStateUpdate(
        'selected_module',
        note:
            'source=$source from=${previous.name} to=${next.name} '
            'userInitiated=$userInitiated parentRestore=$parentRestore '
            'navSource=${navigationSource.name} owner=$_navigationControllerOwnerKey',
      );
    }
    return changed;
  }

  void _setSelectedModule(SellerModule module) {
    final previousModule = _selectedModule;
    sellerNavigationLog(
      'page_changed_by_user',
      extra: {'from': previousModule.name, 'to': module.name},
    );
    _logSellerPanel(
      'Tab',
      'action=select from=${previousModule.name} to=${module.name} '
          'changed=${previousModule != module}',
    );
    final source = _moduleTapSource(module);
    debugPrint(
      '[SellerNavigation][user_tap] '
      'source=$source from=${previousModule.name} to=${module.name} '
      'hasUserSelected=${_navigationController?.hasUserSelected ?? _hasUserSelectedSellerModule}',
    );
    final changed = _setActiveSellerModule(
      module,
      source: source,
      userInitiated: true,
    );
    if (!changed && previousModule == module) {
      _scheduleLocalPrintStatusRefreshIfNeeded(
        module: module,
        reason: 'module_selected_noop',
      );
      _applySellerSeo(module);
      unawaited(_persistSelectedModule(module));
      return;
    }
    if (module == SellerModule.system && _isFoodStoreCategory(_storeCategory)) {
      unawaited(_loadStoreTables());
    }
    unawaited(_ensureModuleDataLoaded(module));
    _scheduleLocalPrintStatusRefreshIfNeeded(
      module: module,
      reason: 'module_selected',
    );
    _applySellerSeo(module);
    unawaited(_persistSelectedModule(module));
  }

  /// Called when the user closes/backs out of a Garson table detail screen.
  ///
  /// Ensures [_selectedModule] is garson and logs the return. This is the
  /// single source-of-truth for "close table → go back to garson list".
  ///
  /// Safe to call even when already on garson (idempotent). Uses
  /// `parentRestore: true` so the user-selected lock cannot block the
  /// return-to-parent transition.
  void _returnFromGarsonTableToGarsonList({String source = 'unknown'}) {
    if (!mounted) return;
    final moduleBefore = _selectedModule;
    debugPrint(
      '[GarsonNavigation][close_table] '
      'source=$source '
      'moduleBefore=${moduleBefore.name} '
      'moduleAfter=garson',
    );
    sellerNavigationLog(
      'close_table',
      extra: {
        'source': source,
        'moduleBefore': moduleBefore.name,
        'moduleAfter': 'garson',
      },
    );
    _setActiveSellerModule(
      SellerModule.garson,
      source: source,
      userInitiated: false,
      parentRestore: true,
    );
  }

  Future<void> _refreshGarsonDataManually({
    String source = 'garson_manual_refresh_button',
    bool allowInitialAutoSeed = false,
  }) async {
    if (!shouldAllowGarsonManualRefresh(
      source: source,
      allowInitialAutoSeed: allowInitialAutoSeed,
    )) {
      debugPrint(
        '[GarsonManualRefresh][blocked] '
        'source=$source '
        'reason=not_user_manual',
      );
      return;
    }
    if (shouldSkipManualGarsonRefresh(
      refreshInProgress: _garsonManualRefreshInProgress,
    )) {
      debugPrint('[GarsonManualRefresh][skip] reason=already_running');
      return;
    }
    if (!mounted) return;
    debugPrint('[GarsonManualRefresh][start] source=$source');
    _safeSetState(() {
      _garsonManualRefreshInProgress = true;
    });
    try {
      _garsonManualRefreshGeneration += 1;
      await Future.wait<void>(<Future<void>>[
        _loadStoreTables(silent: false, source: source),
        _loadProductsSnapshot(source: source).then((_) {}),
        _loadGarsonTableOrdersSnapshot(
          source: source,
          showError: true,
        ).then((_) {}),
      ]);
      _ensureGarsonRealtimeMonitoring(_resolveGarsonSellerId());
      if (!mounted) return;
      _hasLoadedGarsonBootstrapData = true;
      _garsonHasPendingRemoteChanges.value = false;
      _publishGarsonVisibleSnapshotFromCurrentState(
        source: '${source}_publish',
      );
      debugPrint(
        '[GarsonManualRefresh][done] '
        'tables=${_storeTables.length} '
        'products=${_products.length} '
        'orders=${_garsonManualTableOrders.length}',
      );
    } finally {
      if (mounted) {
        _safeSetState(() {
          _garsonManualRefreshInProgress = false;
        });
      }
    }
  }

  Future<void> _ensureModuleDataLoaded(SellerModule module) async {
    void logDecision(String fetchName, bool scheduled) {
      _logSellerPanel(
        'Tab',
        'module=${module.name} fetch=$fetchName refetch=$scheduled',
      );
    }

    _logSellerPanel(
      'Init',
      'phase=ensureModuleDataLoaded module=${module.name} activeTab=${_selectedModule.name}',
    );
    switch (module) {
      case SellerModule.dashboard:
        final shouldLoadCampaigns = !_hasLoadedCampaignsData;
        logDecision('campaigns', shouldLoadCampaigns);
        if (shouldLoadCampaigns) {
          _hasLoadedCampaignsData = true;
          unawaited(_loadCampaigns());
        }
        final shouldLoadSellerOrders = !_hasLoadedSellerOrdersData;
        logDecision('seller_orders', shouldLoadSellerOrders);
        if (shouldLoadSellerOrders) {
          _hasLoadedSellerOrdersData = true;
          unawaited(_loadSellerOrders());
        }
        final shouldLoadSellerWallet = !_hasLoadedSellerWalletData;
        logDecision('seller_wallet', shouldLoadSellerWallet);
        if (shouldLoadSellerWallet) {
          _hasLoadedSellerWalletData = true;
          unawaited(_loadSellerWalletBalance(silent: true));
        }
        // Always (re-)fetch table orders for food businesses. If _storeCategory
        // is not known yet, the method guards itself and returns early; a
        // subsequent call from _loadStoreProfile will populate the data.
        unawaited(
          _loadDashboardTableOrdersGuarded(
            source: '_ensureModuleDataLoaded_dashboard',
          ),
        );
        break;
      case SellerModule.products:
        final shouldLoadProducts = !_hasLoadedProductsData;
        logDecision('products', shouldLoadProducts);
        if (shouldLoadProducts) {
          _hasLoadedProductsData = true;
          _loadProducts();
        }
        break;
      case SellerModule.collections:
        _logSellerPanel(
          'Tab',
          'module=${module.name} fetch=none refetch=false',
        );
        break;
      case SellerModule.orders:
        final shouldLoadSellerOrders = !_hasLoadedSellerOrdersData;
        logDecision('seller_orders', shouldLoadSellerOrders);
        if (shouldLoadSellerOrders) {
          _hasLoadedSellerOrdersData = true;
          unawaited(_loadSellerOrders());
        }
        break;
      case SellerModule.garson:
        unawaited(
          _warmGarsonPrintCaches(_authService.currentUser?.id.trim() ?? ''),
        );
        final shouldBootstrapGarson = !_hasLoadedGarsonBootstrapData;
        logDecision('garson_initial_visible_seed', shouldBootstrapGarson);
        unawaited(
          _ensureGarsonInitialVisibleData(
            source: shouldBootstrapGarson
                ? 'garson_initial_visible_seed'
                : 'garson_visible_reenter_seed',
          ),
        );
        _ensureGarsonRealtimeMonitoring(_resolveGarsonSellerId());
        break;
      case SellerModule.system:
        unawaited(
          _warmGarsonPrintCaches(_authService.currentUser?.id.trim() ?? ''),
        );
        final shouldLoadStoreTables = !_hasLoadedStoreTablesData;
        logDecision('store_tables', shouldLoadStoreTables);
        if (shouldLoadStoreTables) {
          _hasLoadedStoreTablesData = true;
          unawaited(_loadStoreTables());
        }
        final shouldLoadProducts = !_hasLoadedProductsData;
        logDecision('products', shouldLoadProducts);
        if (shouldLoadProducts) {
          _hasLoadedProductsData = true;
          _loadProducts();
        }
        break;
      case SellerModule.store:
        final shouldReloadStoreProfile = !_hasLoadedStoreProfile && !_isLoading;
        logDecision('store_profile', shouldReloadStoreProfile);
        if (shouldReloadStoreProfile) {
          unawaited(_loadStoreProfile());
        }
        final shouldLoadPendingLocation = !_hasLoadedPendingLocationRequestData;
        logDecision(
          'pending_location_change_request',
          shouldLoadPendingLocation,
        );
        if (shouldLoadPendingLocation) {
          _hasLoadedPendingLocationRequestData = true;
          unawaited(_loadPendingLocationChangeRequest());
        }
        break;
      case SellerModule.team:
        final shouldLoadSubAdmins = !_hasLoadedSubAdminsData;
        logDecision('sub_admins', shouldLoadSubAdmins);
        if (shouldLoadSubAdmins) {
          _hasLoadedSubAdminsData = true;
          _loadSubAdmins();
        }
        break;
      case SellerModule.campaigns:
        final shouldLoadCampaigns = !_hasLoadedCampaignsData;
        logDecision('campaigns', shouldLoadCampaigns);
        if (shouldLoadCampaigns) {
          _hasLoadedCampaignsData = true;
          unawaited(_loadCampaigns());
        }
        break;
      case SellerModule.finance:
        final shouldLoadSellerOrders = !_hasLoadedSellerOrdersData;
        logDecision('seller_orders', shouldLoadSellerOrders);
        if (shouldLoadSellerOrders) {
          _hasLoadedSellerOrdersData = true;
          unawaited(_loadSellerOrders());
        }
        final shouldLoadSellerWallet = !_hasLoadedSellerWalletData;
        logDecision('seller_wallet', shouldLoadSellerWallet);
        if (shouldLoadSellerWallet) {
          _hasLoadedSellerWalletData = true;
          unawaited(_loadSellerWalletBalance(silent: true));
        }
        break;
      case SellerModule.reviews:
      case SellerModule.support:
        final shouldLoadSellerQuestions = !_hasLoadedSellerQuestionsData;
        logDecision('seller_questions', shouldLoadSellerQuestions);
        if (shouldLoadSellerQuestions) {
          _hasLoadedSellerQuestionsData = true;
          unawaited(_loadSellerQuestions());
        }
        _logSellerPanel(
          'Tab',
          'module=${module.name} fetch=support_subscriptions refetch=true',
        );
        _subscribeSupportTickets();
        _subscribeCancelAppealNotifications();
        break;
    }
  }

  void _applySellerSeo([SellerModule? module]) {
    final activeModule = module ?? _selectedModule;
    final moduleLabel = _moduleLabel(activeModule);
    setSeoMeta(
      title: '$moduleLabel | İbul Satıcı Paneli',
      description:
          'İbul satıcı panelinde $moduleLabel ekranını kullanarak mağaza operasyonlarınızı yönetin.',
      canonicalPath: '/seller',
      keywords: const [
        'ibul',
        'satıcı paneli',
        'mağaza yönetimi',
        'e-ticaret satıcı',
      ],
    );
  }

  void _subscribeSupportTickets() {
    final sellerId = _authService.currentUser?.id;
    if (sellerId == null || sellerId.isEmpty) return;
    final requestUrl = _sellerPanelRestRequestUrl(
      'support_tickets',
      query: <String, String>{
        'select': '*',
        'user_id': 'eq.$sellerId',
        'order': 'created_at.desc',
      },
    );
    _logSellerPanel(
      'Fetch',
      'branch=support_tickets:stream_subscribe '
          'requestUrl=$requestUrl',
    );
    _supportTicketsSubscription?.cancel();
    _supportTicketsSubscription = _supportService
        .getUserTickets(sellerId)
        .listen(
          (tickets) {
            if (!mounted) return;
            setState(() {
              _supportTickets = tickets;
              _supportTicketsVersion += 1;
              _invalidateDashboardSnapshot();
              _hasShownSupportSchemaError = false;
            });
            _logSellerPanelStateUpdate(
              'support_tickets_stream',
              note: 'tickets=${tickets.length}',
            );
          },
          onError: (error) {
            if (!mounted) return;
            if (_isRealtimeTimeoutError(error)) {
              _showRealtimeFallbackWarning(
                'Canlı destek akışı bağlantısı zaman aşımına uğradı. Anlık yerine periyodik veri gösterilecek.',
              );
              unawaited(_loadSupportTicketsSnapshot());
              return;
            }
            if (_hasShownSupportSchemaError) return;
            _hasShownSupportSchemaError = true;
            _logSellerPanel(
              'Error',
              'branch=support_tickets:stream_error requestUrl=$requestUrl',
              error: error,
            );
            ScaffoldMessenger.of(context).showSnackBar(
              SnackBar(
                content: Text(error.toString().replaceFirst('Exception: ', '')),
              ),
            );
          },
        );
    unawaited(_loadSupportTicketsSnapshot());
  }

  void _subscribeCancelAppealNotifications() {
    final sellerId = _authService.currentUser?.id;
    if (sellerId == null || sellerId.isEmpty) return;
    _cancelAppealNotificationsSubscription?.cancel();
    _cancelAppealNotificationsSubscription = Supabase.instance.client
        .from('user_notifications')
        .stream(primaryKey: ['id'])
        .eq('user_id', sellerId)
        .order('created_at', ascending: false)
        .map(_extractCancelAppealNotifications)
        .listen(
          (rows) {
            if (!mounted) return;
            setState(() {
              _cancelAppealNotifications = rows;
              _invalidateFeedbackDerivedState();
            });
          },
          onError: (error) {
            debugPrint('SellerPanel cancel_appeal stream warn: $error');
            if (!mounted) return;
            if (_isRealtimeTimeoutError(error)) {
              _showRealtimeFallbackWarning(
                'Canlı bildirim akışı zaman aşımına uğradı. Güncel veriler sorgu ile yenilenecek.',
              );
            }
            unawaited(_loadCancelAppealNotificationsSnapshot());
          },
        );
    unawaited(_loadCancelAppealNotificationsSnapshot());
  }

  List<Map<String, dynamic>> _extractCancelAppealNotifications(
    Iterable<dynamic> rows,
  ) {
    final filtered = <Map<String, dynamic>>[];
    for (final raw in rows) {
      final row = Map<String, dynamic>.from(raw as Map);
      final dataRaw = row['data'];
      final data = dataRaw is Map
          ? dataRaw.map((k, v) => MapEntry(k.toString(), v))
          : <String, dynamic>{};
      final type = data['type']?.toString().trim().toLowerCase() ?? '';
      if (type != 'cancel_appeal_received') continue;
      filtered.add({...row, 'data': data});
    }
    return filtered;
  }

  Future<void> _loadSupportTicketsSnapshot() async {
    final sellerId = _authService.currentUser?.id;
    if (sellerId == null || sellerId.isEmpty) return;
    final requestUrl = _sellerPanelRestRequestUrl(
      'support_tickets',
      query: <String, String>{
        'select': '*',
        'user_id': 'eq.$sellerId',
        'order': 'created_at.desc',
      },
    );
    final watch = Stopwatch()..start();
    try {
      final tickets = await _supportService.getUserTicketsSnapshot(sellerId);
      if (!mounted) return;
      setState(() {
        _supportTickets = tickets;
        _supportTicketsVersion += 1;
        _invalidateDashboardSnapshot();
      });
      _logSellerPanel(
        'Fetch',
        'branch=support_tickets:snapshot_success '
            'requestUrl=$requestUrl '
            'durationMs=${watch.elapsedMilliseconds} '
            'rowCount=${tickets.length}',
      );
      _logSellerPanelStateUpdate(
        'support_tickets_snapshot',
        note: 'tickets=${tickets.length}',
      );
    } catch (error) {
      _logSellerPanel(
        'Error',
        'branch=support_tickets:snapshot_error requestUrl=$requestUrl '
            'durationMs=${watch.elapsedMilliseconds}',
        error: error,
      );
    }
  }

  Future<void> _loadCancelAppealNotificationsSnapshot() async {
    final sellerId = _authService.currentUser?.id;
    if (sellerId == null || sellerId.isEmpty) return;
    final requestUrl = _sellerPanelRestRequestUrl(
      'user_notifications',
      query: <String, String>{
        'select': '*',
        'user_id': 'eq.$sellerId',
        'order': 'created_at.desc',
      },
    );
    final watch = Stopwatch()..start();
    try {
      final rows = await Supabase.instance.client
          .from('user_notifications')
          .select()
          .eq('user_id', sellerId)
          .order('created_at', ascending: false);
      final filtered = _extractCancelAppealNotifications(rows as List<dynamic>);
      if (!mounted) return;
      setState(() {
        _cancelAppealNotifications = filtered;
        _invalidateFeedbackDerivedState();
      });
      _logSellerPanel(
        'Fetch',
        'branch=cancel_appeal_notifications:snapshot_success '
            'requestUrl=$requestUrl '
            'durationMs=${watch.elapsedMilliseconds} '
            'rowCount=${filtered.length}',
      );
      _logSellerPanelStateUpdate(
        'cancel_appeal_notifications_snapshot',
        note: 'rows=${filtered.length}',
      );
    } catch (error) {
      _logSellerPanel(
        'Error',
        'branch=cancel_appeal_notifications:snapshot_error '
            'requestUrl=$requestUrl '
            'durationMs=${watch.elapsedMilliseconds}',
        error: error,
      );
    }
  }

  bool _isRealtimeTimeoutError(Object error) {
    final normalized = error.toString().toLowerCase();
    return normalized.contains('realtimesubscribeexception') &&
        normalized.contains('timedout');
  }

  bool _isRealtimeConnectionError(Object error) {
    final normalized = error.toString().toLowerCase();
    return normalized.contains('realtimesubscribeexception') &&
        (normalized.contains('timedout') ||
            normalized.contains('channelerror') ||
            normalized.contains('websocket') ||
            normalized.contains('connection failed'));
  }

  void _showRealtimeFallbackWarning(String message) {
    if (!mounted || _hasShownRealtimeTimeoutWarning) return;
    _hasShownRealtimeTimeoutWarning = true;
    // Debug-only — do not show a SnackBar to the user for infrastructure
    // hiccups; the fallback snapshot query is transparent to the user.
    debugPrint('[RealtimeFallback] $message');
  }

  void _invalidateOrdersDerivedState() {
    _ordersVersion++;
    _sellerOrderById = {
      for (final order in _sellerOrders)
        if ((order['id']?.toString() ?? '').isNotEmpty)
          order['id'].toString(): order,
    };
    _sellerOrderStatusCountsCacheKey = null;
    _sellerOrderStatusCountsCache = null;
    _filteredSellerOrdersCacheKey = null;
    _filteredSellerOrdersCache = null;
    _financeSummaryCacheKey = null;
    _financeSummaryCache = null;
    _invalidateDashboardSnapshot();
  }

  void _invalidateFeedbackDerivedState() {
    _feedbackDataCacheKey = null;
    _feedbackDataCache = null;
  }

