  Stream<List<Map<String, dynamic>>> _getSellerTableOrdersStream(
    String sellerId,
  ) {
    final normalizedSellerId = sellerId.trim();
    final decision = resolveTableOrdersStreamLifecycle(
      requestedSellerId: sellerId,
      cachedSellerId: _tableOrdersStreamSellerId,
    );
    if (decision.action == TableOrdersStreamLifecycleAction.reuse &&
        _tableOrdersStream != null) {
      // Build-phase telemetry without re-creating the stream object.
      // Logging `stream_reuse` confirms the cached stream is preserved
      // across rebuilds — important during the products-timeout retry
      // window when setState fires on the parent. The lifecycle helper
      // is the single source-of-truth for this decision so it can be
      // unit-tested without mounting the panel.
      debugPrint(
        '[GarsonRealtime] mode=stream_reuse '
        'sellerId=$normalizedSellerId',
      );
      _garsonStreamState = 'stream_reuse:$normalizedSellerId';
      return _tableOrdersStream!;
    }
    debugPrint(
      '[GarsonRealtime] mode=stream_start '
      'supabaseUrl=${AppRuntimeConfig.rawSupabaseUrl.trim().isEmpty ? '(missing)' : AppRuntimeConfig.rawSupabaseUrl.trim()} '
      'storeId=$normalizedSellerId '
      'sellerId=$normalizedSellerId '
      'waiterId=${_authService.currentUser?.id ?? '-'} '
      'schema=public table=table_orders channel=auto:stream(table_orders) '
      'filter=seller_id=eq.$normalizedSellerId',
    );
    _garsonStreamState = 'stream_start:$normalizedSellerId';
    _tableOrdersStreamSellerId = sellerId;
    _tableOrdersStream = _storeService.getTableOrdersStream(sellerId);
    return _tableOrdersStream!;
  }

  Future<List<Map<String, dynamic>>> _getSellerTableOrdersFallbackFuture(
    String sellerId,
  ) {
    final normalizedSellerId = sellerId.trim();
    if (_tableOrdersFallbackFuture == null ||
        _tableOrdersFallbackSellerId != normalizedSellerId) {
      _tableOrdersFallbackSellerId = normalizedSellerId;
      _garsonStreamState = 'fallback_snapshot:$normalizedSellerId';
      _tableOrdersFallbackFuture = _storeService.getTableOrdersSnapshot(
        normalizedSellerId,
      );
    }
    return _tableOrdersFallbackFuture!;
  }

  void _invalidateSellerTableOrdersFallbackFuture() {
    _tableOrdersFallbackFuture = null;
  }

  List<Map<String, dynamic>> _resolveGarsonTableOrdersForUi(
    List<Map<String, dynamic>>? streamOrQuerySnapshot,
  ) {
    if (_garsonManualTableOrders.isNotEmpty) {
      return _garsonOrdersSnapshotForUi();
    }
    return streamOrQuerySnapshot ?? const <Map<String, dynamic>>[];
  }

  void _ensureGarsonRealtimeMonitoring(String sellerId) {
    final stream = _getSellerTableOrdersStream(sellerId);
    if (_garsonRealtimeSubscription != null &&
        _tableOrdersStreamSellerId == sellerId.trim()) {
      return;
    }
    _garsonRealtimeSubscription?.cancel();
    _garsonRealtimeSubscription = stream.listen(
      (orders) {
        final nextSignature = tableOrdersListSignature(orders);
        if (_garsonManualTableOrdersSignature == nextSignature) {
          _garsonStreamState = 'stream_event_same';
          return;
        }
        if (_shouldBlockGarsonBackgroundPublish(
          source: 'table_orders_stream',
          hasPublishedData: _garsonManualTableOrdersSignature != null,
        )) {
          _garsonStreamState = 'stream_event_blocked';
          debugPrint(
            '[GarsonAutoRefresh][blocked] '
            'source=table_orders_stream '
            'reason=table_orders_background_update',
          );
          _markGarsonHasPendingRemoteChanges(source: 'table_orders_stream');
          return;
        }
        if (!mounted) return;
        _safeSetState(() {
          _garsonManualTableOrders = orders;
          _garsonManualTableOrdersSellerId = sellerId.trim();
          _garsonManualTableOrdersSignature = nextSignature;
          _hasLoadedGarsonTableOrdersData = true;
        });
        _publishGarsonVisibleOrders(orders);
        _garsonStreamState = 'stream_event_applied';
      },
      onError: (error) {
        _handleGarsonRealtimeError(error, sellerId: sellerId);
        if (_shouldBlockGarsonBackgroundPublish(
          source: 'table_orders_stream_error',
          hasPublishedData: _garsonManualTableOrdersSignature != null,
        )) {
          debugPrint(
            '[GarsonAutoRefresh][blocked] '
            'source=table_orders_stream_error '
            'reason=table_orders_background_update',
          );
          _markGarsonHasPendingRemoteChanges(
            source: 'table_orders_stream_error',
          );
        }
      },
    );
  }

  Future<bool> _loadGarsonTableOrdersSnapshot({
    required String source,
    bool showError = false,
  }) async {
    final sellerId = _resolveGarsonSellerId().trim();
    if (sellerId.isEmpty) return false;
    _invalidateSellerTableOrdersFallbackFuture();
    try {
      final fresh = await _storeService.getTableOrdersSnapshot(sellerId);
      final nextSignature = tableOrdersListSignature(fresh);
      if (_garsonManualTableOrdersSignature == nextSignature) {
        _garsonStreamState = 'snapshot_same_data';
        return false;
      }
      if (_shouldBlockGarsonBackgroundPublish(
        source: source,
        hasPublishedData: _garsonManualTableOrdersSignature != null,
      )) {
        _garsonStreamState = 'snapshot_blocked';
        debugPrint(
          '[GarsonAutoRefresh][blocked] '
          'source=$source '
          'reason=table_orders_background_update',
        );
        _markGarsonHasPendingRemoteChanges(source: source);
        return false;
      }
      if (!mounted) return false;
      _safeSetState(() {
        _garsonManualTableOrders = fresh;
        _garsonManualTableOrdersSellerId = sellerId;
        _garsonManualTableOrdersSignature = nextSignature;
        _hasLoadedGarsonTableOrdersData = true;
      });
      _publishGarsonVisibleOrders(fresh);
      _garsonStreamState = 'snapshot_applied';
      return true;
    } catch (error) {
      _garsonStreamState = 'snapshot_error';
      if (showError && mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
            content: Text(
              'Siparişler yenilenemedi: '
              '${error.toString().replaceFirst('Exception: ', '')}',
            ),
          ),
        );
      }
      return false;
    }
  }

  Future<void> _pullRefreshGarsonTableOrders(String sellerId) async {
    if (sellerId.trim().isEmpty) return;
    await _loadGarsonTableOrdersSnapshot(
      source: 'garson_local_table_action',
      showError: true,
    );
  }

  void _handleGarsonRealtimeError(Object error, {required String sellerId}) {
    final normalizedSellerId = sellerId.trim();
    _garsonStreamState = 'stream_error:$normalizedSellerId';
    debugPrint(
      '[GarsonRealtime] mode=stream_error '
      'supabaseUrl=${AppRuntimeConfig.rawSupabaseUrl.trim().isEmpty ? '(missing)' : AppRuntimeConfig.rawSupabaseUrl.trim()} '
      'storeId=$normalizedSellerId '
      'sellerId=$normalizedSellerId '
      'waiterId=${_authService.currentUser?.id ?? '-'} '
      'schema=public table=table_orders channel=auto:stream(table_orders) '
      'filter=seller_id=eq.$normalizedSellerId '
      'error=$error',
    );
    if (_isRealtimeConnectionError(error)) {
      WidgetsBinding.instance.addPostFrameCallback((_) {
        _showRealtimeFallbackWarning(
          'Canlı sipariş akışı bağlanamadı. Garson ekranı sorgu verisi ile çalışıyor.',
        );
      });
    }
  }

  Map<String, int> _sellerOrderStatusCounts() {
    final cacheKey = '$_ordersVersion';
    if (_sellerOrderStatusCountsCacheKey == cacheKey &&
        _sellerOrderStatusCountsCache != null) {
      return _sellerOrderStatusCountsCache!;
    }

    final counts = <String, int>{
      'all': _sellerOrders.length,
      'new': 0,
      'confirmed': 0,
      'preparing': 0,
      'ready_to_ship': 0,
      'shipped': 0,
      'delivered': 0,
      'returns': 0,
      'external': 0,
    };
    for (final order in _sellerOrders) {
      final status = (order['status'] ?? '').toString();
      if (_isSellerExternalOrder(order)) {
        counts['external'] = (counts['external'] ?? 0) + 1;
      }
      if (status == 'new') counts['new'] = (counts['new'] ?? 0) + 1;
      if (status == 'confirmed') {
        counts['confirmed'] = (counts['confirmed'] ?? 0) + 1;
      }
      if (status == 'preparing') {
        counts['preparing'] = (counts['preparing'] ?? 0) + 1;
      }
      if (status == 'ready_to_ship') {
        counts['ready_to_ship'] = (counts['ready_to_ship'] ?? 0) + 1;
      }
      if (status == 'shipped') {
        counts['shipped'] = (counts['shipped'] ?? 0) + 1;
      }
      if (status == 'delivered') {
        counts['delivered'] = (counts['delivered'] ?? 0) + 1;
      }
      if (status.contains('return') || status.contains('cancel')) {
        counts['returns'] = (counts['returns'] ?? 0) + 1;
      }
    }

    _sellerOrderStatusCountsCacheKey = cacheKey;
    _sellerOrderStatusCountsCache = counts;
    return counts;
  }

  bool _isSellerExternalOrder(Map<String, dynamic> order) {
    final orderNumber = (order['order_number'] ?? '').toString().toUpperCase();
    if (orderNumber.startsWith('IBUL-EXT-')) return true;

    final productCode = (order['product_code'] ?? '').toString().toUpperCase();
    if (productCode.startsWith('EXT-')) return true;

    final deliverySlot = (order['delivery_slot'] ?? '')
        .toString()
        .toLowerCase();
    if (deliverySlot.contains('harici')) return true;

    final storeName = (order['store_name'] ?? '').toString().toLowerCase();
    return storeName.contains('harici siparis') ||
        storeName.contains('harici sipariş');
  }

  bool _isIhizCargoCompany(String? cargoCompany) {
    final normalized = (cargoCompany ?? '')
        .replaceAll('İ', 'I')
        .replaceAll('ı', 'i')
        .toLowerCase();
    return normalized.contains('ihiz') || normalized.contains('hiz');
  }

  List<Map<String, dynamic>> _getFilteredSellerOrders() {
    final cacheKey =
        '$_ordersVersion|$_selectedSellerOrderFilter|$_debouncedSellerOrderQuery';
    if (_filteredSellerOrdersCacheKey == cacheKey &&
        _filteredSellerOrdersCache != null) {
      return _filteredSellerOrdersCache!;
    }

    final query = _debouncedSellerOrderQuery;
    final filtered = _sellerOrders
        .where((order) {
          final status = (order['status'] ?? '').toString();
          final matchesFilter = switch (_selectedSellerOrderFilter) {
            'all' => true,
            'new' => status == 'new' || status == 'confirmed',
            'preparing' => status == 'preparing',
            'ready_to_ship' => status == 'ready_to_ship',
            'external' => _isSellerExternalOrder(order),
            'shipped' =>
              status == 'shipped' ||
                  status == 'transfer' ||
                  status == 'branch' ||
                  status == 'out_for_delivery',
            'delivered' => status == 'delivered',
            'returns' => status.contains('return') || status.contains('cancel'),
            _ => true,
          };
          if (!matchesFilter) return false;
          if (query.isEmpty) return true;
          final haystack = [
            order['order_number'],
            order['product_name'],
            order['product_code'],
            order['tracking_number'],
            _sellerOrderCustomerName(order),
            _sellerOrderCustomerPhone(order),
          ].map((e) => (e ?? '').toString().toLowerCase()).join(' ');
          return haystack.contains(query);
        })
        .toList(growable: false);

    _filteredSellerOrdersCacheKey = cacheKey;
    _filteredSellerOrdersCache = filtered;
    return filtered;
  }

  Future<void> _exitSellerPanel() async {
    debugPrint(
      '[SellerExit] _exitSellerPanel triggered — full sign-out (no consumer session restore)',
    );
    setState(() => _isLoading = true);
    try {
      await _authService.signOut();
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('Satıcı panelinden çıkıldı.')),
      );
      debugPrint(
        '[SellerExit] navigating to HomeScreen(profile tab) — routes cleared',
      );
      Navigator.of(context, rootNavigator: true).pushAndRemoveUntil(
        buildAppPageRoute<void>(
          builder: (_) => const HomeScreen(initialIndex: 4),
        ),
        (route) => false,
      );
    } catch (e) {
      if (!mounted) return;
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text('Çıkış yapılamadı: $e')));
    } finally {
      if (mounted) {
        setState(() => _isLoading = false);
      }
    }
  }

  Future<void> _loadSellerOrders() async {
    final sellerId = _authService.currentUser?.id;
    if (sellerId == null || sellerId.isEmpty) return;
    final requestId = ++_sellerOrdersLoadRequestId;
    final requestUrl = 'OrderService.getSellerOrders(sellerId=$sellerId)';
    final watch = Stopwatch()..start();
    if (!_canApplySellerOrdersRequest(requestId)) return;
    _safeSetStateForSellerOrders(
      requestId,
      () => _isLoadingSellerOrders = true,
    );
    _logSellerPanelStateUpdate(
      'seller_orders_loading_start',
      note: 'requestId=$requestId',
    );
    try {
      _debugLogSellerBootstrap(
        branch: 'seller_orders:start',
        requestUrl: requestUrl,
      );
      final orders = await OrderService.instance.getSellerOrders(sellerId);
      if (!_canApplySellerOrdersRequest(requestId)) return;
      final previousIds = _sellerOrders
          .map((order) => order['id']?.toString())
          .whereType<String>()
          .toSet();
      final hadPriorSnapshot = _sellerOrdersHadSuccessfulLoad;
      final newIds = sellerOrderIdsToHighlight(
        hadPriorSnapshot: hadPriorSnapshot,
        previousIds: previousIds,
        incomingIds: orders
            .map((order) => order['id']?.toString())
            .whereType<String>(),
      );
      if (!_canApplySellerOrdersRequest(requestId)) return;
      _safeSetStateForSellerOrders(requestId, () {
        _sellerOrders = orders;
        _invalidateOrdersDerivedState();
        _highlightedSellerOrderIds.addAll(newIds);
        final selectedId =
            _selectedSellerOrderItemId ??
            _selectedSellerOrderDetail?['id']?.toString();
        if (selectedId != null) {
          final refreshed =
              _sellerOrderById[selectedId] ?? _selectedSellerOrderDetail;
          if (refreshed != null) {
            _selectedSellerOrderDetail = refreshed;
            _selectedSellerOrderItemId = selectedId;
          }
        }
      });
      if (!_canApplySellerOrdersRequest(requestId)) return;
      _debugLogSellerBootstrap(
        branch: 'seller_orders:success',
        requestUrl: requestUrl,
        note:
            'requestId=$requestId durationMs=${watch.elapsedMilliseconds} '
            'orders=${orders.length} newIds=${newIds.length}',
      );
      _logSellerPanelStateUpdate(
        'seller_orders_loaded',
        note:
            'requestId=$requestId durationMs=${watch.elapsedMilliseconds} '
            'orders=${orders.length} newIds=${newIds.length}',
      );
      final selectedItemId =
          _selectedSellerOrderItemId ??
          _selectedSellerOrderDetail?['id']?.toString();
      if (selectedItemId != null && selectedItemId.isNotEmpty) {
        unawaited(_loadSelectedSellerOrderHistory(selectedItemId));
      }
      _sellerOrdersHadSuccessfulLoad = true;
      for (final id in newIds) {
        _scheduleSellerOrderHighlightClear(id);
      }
    } catch (error, stackTrace) {
      if (!_canApplySellerOrdersRequest(requestId)) return;
      _hasLoadedSellerOrdersData = false;
      _debugLogSellerBootstrap(
        branch: 'seller_orders:catch',
        requestUrl: requestUrl,
        note: 'requestId=$requestId durationMs=${watch.elapsedMilliseconds}',
        error: error,
        stackTrace: stackTrace,
      );
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text(_mapSellerOrdersLoadError(error))));
    } finally {
      if (_canApplySellerOrdersRequest(requestId)) {
        _safeSetStateForSellerOrders(
          requestId,
          () => _isLoadingSellerOrders = false,
        );
        _logSellerPanelStateUpdate(
          'seller_orders_loading_end',
          note: 'requestId=$requestId durationMs=${watch.elapsedMilliseconds}',
        );
      }
    }
  }

  String _mapSellerOrdersLoadError(Object error) {
    final raw = error.toString();
    final lowered = raw.toLowerCase();
    if (raw.contains('42P17') ||
        lowered.contains('infinite recursion detected in policy')) {
      return 'Sipariş listesi alınamadı: backend RLS policy hatası (42P17). '
          'Supabase tarafında orders/order_items recursion fix migration çalıştırılmalı.';
    }
    return raw.replaceFirst('Exception: ', '');
  }

  /// Thin wrapper around [_loadDashboardTableOrders] that adds structured
  /// `[DashboardRefresh]` logging and a fast-fail when a load is already in
  /// flight. The wrapper no longer attempts to "restore" the selected module
  /// after the await — that defensive code became impossible to trigger once
  /// [_setActiveSellerModule] became the only path that mutates
  /// [_selectedModule]; async work simply cannot reach the navigation state
  /// any more.
  Future<void> _loadDashboardTableOrdersGuarded({
    required String source,
  }) async {
    // ⛔ Same dashboard-visibility gate as [_refreshDashboardData]. We only
    // load table orders for dashboard summary cards when the dashboard is
    // actually the visible module. Loading them while on garson is wasted
    // work that bumps the version and invalidates the snapshot cache.
    if (!shouldRunDashboardRefresh(selectedModule: _selectedModule)) {
      debugPrint(
        '[DashboardRefresh][skip] '
        'source=$source reason=dashboard_not_visible '
        'current=${_selectedModule.name}',
      );
      return;
    }
    if (_isDashboardTableOrdersLoading) {
      debugPrint(
        '[DashboardRefresh][skip] '
        'source=$source reason=already_loading',
      );
      return;
    }
    debugPrint('[DashboardRefresh][start] source=$source');
    final watch = Stopwatch()..start();
    final changed = await _loadDashboardTableOrders(source: source);
    debugPrint(
      '[DashboardRefresh][done] '
      'source=$source changed=$changed '
      'count=${_dashboardTableOrders.length} '
      'durationMs=${watch.elapsedMilliseconds}',
    );
  }

  /// Fetches table/garson orders for dashboard stats.
  /// Only runs for food/restaurant businesses; silently no-ops otherwise.
  /// Errors are swallowed so the dashboard gracefully degrades.
  /// This method NEVER touches [_selectedModule].
  ///
  /// Returns `true` when the fetched snapshot actually differed from the
  /// previously cached one (signature mismatch). Identical snapshots are
  /// dropped without calling [setState] or bumping
  /// [_dashboardTableOrdersVersion] — this is what stops the "Genel Bakış
  /// sayıları sürekli gidip geliyor" rebuild loop.
  Future<bool> _loadDashboardTableOrders({String source = 'unknown'}) async {
    if (_isDashboardTableOrdersLoading) {
      debugPrint(
        '[DashboardRefresh][skip] '
        'source=$source reason=already_loading inner=true',
      );
      return false;
    }
    if (!_isFoodStoreCategory(_storeCategory)) {
      debugPrint(
        '[DashboardTableOrders][skip] storeCategory=$_storeCategory '
        'isFoodBusiness=false source=$source',
      );
      return false;
    }
    // Prefer the seller_id from currentUser — _resolveGarsonSellerId reads
    // _storeTables which may be empty at this point; auth user ID is always
    // the canonical seller identifier.
    final sellerId = (_authService.currentUser?.id ?? '').trim();
    if (sellerId.isEmpty) {
      debugPrint('[DashboardTableOrders][skip] sellerId empty source=$source');
      return false;
    }
    _isDashboardTableOrdersLoading = true;
    debugPrint(
      '[DashboardTableOrders][load_start] '
      'sellerId=$sellerId storeCategory=$_storeCategory source=$source',
    );
    try {
      final orders = await _storeService.getTableOrdersSnapshot(sellerId);
      if (!mounted) return false;

      // Debug: log a sample to verify data shape.
      if (orders.isNotEmpty) {
        final sample = orders.first;
        final sampleStatus = (sample['status'] ?? '-').toString();
        final sampleTotal = _garsonOrderTotal(sample);
        final sampleCreatedAt = sample['created_at']?.toString() ?? '-';
        debugPrint(
          '[DashboardTableOrders][raw_response] '
          'count=${orders.length} '
          'sample_id=${sample['id']} '
          'sample_seller_id=${sample['seller_id']} '
          'sample_status=$sampleStatus '
          'sample_total=$sampleTotal '
          'sample_created_at=$sampleCreatedAt',
        );
      } else {
        debugPrint(
          '[DashboardTableOrders][raw_response] count=0 '
          'sellerId=$sellerId — no rows returned',
        );
      }

      // Summary counters for debug.
      final today = DateTime.now();
      final todayStart = DateTime(today.year, today.month, today.day);
      final todayEnd = DateTime(today.year, today.month, today.day, 23, 59, 59);
      var todayCount = 0;
      var openCount = 0;
      var sentCount = 0;
      var closedTodayCount = 0;
      var cancelledCount = 0;
      var todayRevenue = 0.0;
      for (final order in orders) {
        final status = (order['status'] ?? '').toString().toLowerCase().trim();
        final createdAt = DateTime.tryParse(
          order['created_at']?.toString() ?? '',
        )?.toLocal();
        final isToday =
            createdAt != null &&
            !createdAt.isBefore(todayStart) &&
            !createdAt.isAfter(todayEnd);
        if (status == 'cancelled') {
          cancelledCount++;
        } else {
          if (status != 'closed') openCount++;
          if (status == 'done' ||
              status == 'sent' ||
              status == 'kitchen_sent' ||
              status == 'preparing') {
            sentCount++;
          }
          if (isToday) {
            todayCount++;
            todayRevenue += _garsonOrderTotal(order);
            if (status == 'closed') closedTodayCount++;
          }
        }
      }
      debugPrint(
        '[DashboardTableOrders][summary] '
        'total=${orders.length} '
        'openTables=$openCount '
        'todayOrders=$todayCount '
        'sentToKitchen=$sentCount '
        'closedToday=$closedTodayCount '
        'cancelled=$cancelledCount '
        'todayRevenue=$todayRevenue',
      );

      if (!mounted) return false;
      // Idempotency guard: only publish the new list when it actually differs
      // from the previously cached snapshot. Without this guard every
      // _refreshDashboardData/_loadStoreProfile tick would call setState +
      // bump _dashboardTableOrdersVersion + invalidate the dashboard
      // snapshot cache, producing the "Genel Bakış sayıları sürekli gidip
      // geliyor" rebuild storm even when nothing changed server-side.
      final nextSignature = tableOrdersDashboardSignature(orders);
      if (nextSignature == _dashboardTableOrdersSignature) {
        debugPrint(
          '[DashboardRefresh][loop_guard] '
          'source=$source reason=same_data_no_setstate '
          'count=${orders.length}',
        );
        return false;
      }
      setState(() {
        _dashboardTableOrders = orders;
        _dashboardTableOrdersSignature = nextSignature;
        _dashboardTableOrdersVersion++;
        // NOTE: _selectedModule is intentionally NOT touched here.
      });
      return true;
    } catch (e) {
      debugPrint('[DashboardTableOrders][error] graceful fail: $e');
      return false;
    } finally {
      _isDashboardTableOrdersLoading = false;
    }
  }

  /// Combined orders list for dashboard calculations.
  /// For food businesses: online orders + normalised table orders.
  /// For others: online orders only (unchanged behaviour).
  List<Map<String, dynamic>> get _combinedDashboardOrders {
    if (!_isFoodStoreCategory(_storeCategory) ||
        _dashboardTableOrders.isEmpty) {
      return _sellerOrders;
    }
    final normalized = _dashboardTableOrders
        .map(_normalizeTableOrderForDashboard)
        .toList(growable: false);
    return [..._sellerOrders, ...normalized];
  }

  /// Maps a raw table_orders status string to the dashboard-normalised status.
  /// Handles all known garson status variants including legacy ones.
  static String _mapTableOrderStatus(String rawStatus) {
    switch (rawStatus) {
      case 'cancelled':
      case 'canceled':
      case 'void':
      case 'refunded':
      case 'deleted':
        return 'cancelled';
      case 'closed':
      case 'paid':
      case 'completed':
        return 'delivered';
      case 'done':
      case 'sent':
      case 'kitchen_sent':
      case 'preparing':
      case 'ready':
        return 'preparing';
      case 'new':
      case 'open':
      case 'active':
      case 'pending':
      default:
        return 'new';
    }
  }

  /// Converts a raw table_orders row to a shape compatible with dashboard
  /// helpers (same field names as online orders).
  Map<String, dynamic> _normalizeTableOrderForDashboard(
    Map<String, dynamic> order,
  ) {
    final rawStatus = (order['status'] ?? 'new')
        .toString()
        .toLowerCase()
        .trim();
    final mappedStatus = _mapTableOrderStatus(rawStatus);
    final total = _garsonOrderTotal(order);
    return <String, dynamic>{
      'id': order['id'],
      'created_at': order['created_at'],
      'status': mappedStatus,
      'total_price': total,
      'source': 'table',
      'table_number': order['table_number'],
      'table_name': 'Masa ${order['table_number'] ?? '-'}',
    };
  }

  /// Restaurant-specific status counts derived from the raw table_orders list.
  /// These are merged into the main statusCounts map for food businesses.
  Map<String, int> _dashboardRestaurantStatusCounts() {
    final today = DateTime.now();
    final todayStart = DateTime(today.year, today.month, today.day);
    final todayEnd = DateTime(today.year, today.month, today.day, 23, 59, 59);
    var openTables = 0;
    var sentToKitchen = 0;
    var closedToday = 0;
    var restaurantCancelled = 0;
    var todayTableOrders = 0;
    for (final order in _dashboardTableOrders) {
      final rawStatus = (order['status'] ?? '').toString().toLowerCase().trim();
      final mappedStatus = _mapTableOrderStatus(rawStatus);
      if (mappedStatus == 'cancelled') {
        restaurantCancelled++;
        continue;
      }
      if (mappedStatus != 'delivered') {
        openTables++;
      }
      if (mappedStatus == 'preparing') {
        sentToKitchen++;
      }
      final createdAt = DateTime.tryParse(
        order['created_at']?.toString() ?? '',
      )?.toLocal();
      if (createdAt != null &&
          !createdAt.isBefore(todayStart) &&
          !createdAt.isAfter(todayEnd)) {
        todayTableOrders++;
        if (mappedStatus == 'delivered') {
          closedToday++;
        }
      }
    }
    return <String, int>{
      'open_tables': openTables,
      'sent_to_kitchen': sentToKitchen,
      'closed_today': closedToday,
      'restaurant_cancelled': restaurantCancelled,
      'today_table_orders': todayTableOrders,
    };
  }

  Future<void> _loadCampaigns() async {
    final userId = _authService.currentUser?.id;
    if (userId == null) return;
    final requestUrl =
        'CampaignService.getStoreCampaignsForPanel(userId=$userId)';
    final watch = Stopwatch()..start();
    try {
      _debugLogSellerBootstrap(
        branch: 'campaigns:start',
        requestUrl: requestUrl,
      );
      final list = await CampaignService().getStoreCampaignsForPanel(userId);
      if (mounted) {
        setState(() {
          _campaigns = list;
          _campaignsVersion += 1;
          _invalidateDashboardSnapshot();
        });
        _debugLogSellerBootstrap(
          branch: 'campaigns:success',
          requestUrl: requestUrl,
          note:
              'durationMs=${watch.elapsedMilliseconds} campaigns=${list.length}',
        );
        _logSellerPanelStateUpdate(
          'campaigns_loaded',
          note:
              'durationMs=${watch.elapsedMilliseconds} campaigns=${list.length}',
        );
      }
      _hasLoadedCampaignsData = true;
    } catch (error, stackTrace) {
      _hasLoadedCampaignsData = false;
      _debugLogSellerBootstrap(
        branch: 'campaigns:catch',
        requestUrl: requestUrl,
        note: 'durationMs=${watch.elapsedMilliseconds}',
        error: error,
        stackTrace: stackTrace,
      );
    }
  }

  Future<void> _loadSellerQuestions() async {
    final sellerId = _authService.currentUser?.id;
    if (sellerId == null || sellerId.isEmpty) return;
    final requestUrl =
        'ProductQuestionService.getSellerQuestions(sellerId=$sellerId,storeName=${_storeNameController.text.trim()})';
    final watch = Stopwatch()..start();
    setState(() => _isLoadingSellerQuestions = true);
    _logSellerPanelStateUpdate(
      'seller_questions_loading_start',
      note: 'storeName=${_storeNameController.text.trim()}',
    );
    try {
      _debugLogSellerBootstrap(
        branch: 'seller_questions:start',
        requestUrl: requestUrl,
      );
      final questions = await ProductQuestionService.instance
          .getSellerQuestions(
            sellerId: sellerId,
            storeName: _storeNameController.text.trim(),
          );
      if (!mounted) return;
      setState(() {
        _sellerQuestions = questions;
        _sellerQuestionsVersion++;
        _invalidateFeedbackDerivedState();
        _invalidateDashboardSnapshot();
      });
      _debugLogSellerBootstrap(
        branch: 'seller_questions:success',
        requestUrl: requestUrl,
        note:
            'durationMs=${watch.elapsedMilliseconds} questions=${questions.length}',
      );
      _logSellerPanelStateUpdate(
        'seller_questions_loaded',
        note:
            'durationMs=${watch.elapsedMilliseconds} questions=${questions.length}',
      );
      _hasLoadedSellerQuestionsData = true;
    } catch (error, stackTrace) {
      _hasLoadedSellerQuestionsData = false;
      _debugLogSellerBootstrap(
        branch: 'seller_questions:catch',
        requestUrl: requestUrl,
        note: 'durationMs=${watch.elapsedMilliseconds}',
        error: error,
        stackTrace: stackTrace,
      );
    } finally {
      if (mounted) {
        setState(() => _isLoadingSellerQuestions = false);
        _logSellerPanelStateUpdate(
          'seller_questions_loading_end',
          note: 'durationMs=${watch.elapsedMilliseconds}',
        );
      }
    }
  }

  Future<void> _loadSellerWalletBalance({bool silent = false}) async {
    final sellerId = _authService.currentUser?.id ?? '';
    if (sellerId.isEmpty) return;
    final requestId = ++_sellerWalletLoadRequestId;
    final requestUrl =
        'SellerWalletService.getWalletBalance(sellerId=$sellerId)';
    final watch = Stopwatch()..start();
    if (!silent) {
      if (!_canApplySellerWalletRequest(requestId)) return;
      _safeSetStateForSellerWallet(requestId, () {
        _isLoadingSellerWallet = true;
      });
      _logSellerPanelStateUpdate(
        'seller_wallet_loading_start',
        note: 'silent=$silent requestId=$requestId',
      );
    }
    try {
      _debugLogSellerBootstrap(
        branch: 'seller_wallet:start',
        requestUrl: requestUrl,
      );
      final response = await _sellerWalletService.getWalletBalance(
        sellerId: sellerId,
      );
      if (!_canApplySellerWalletRequest(requestId)) return;
      final available = _toWalletDouble(response['available_balance']);
      final reserved = _toWalletDouble(response['reserved_balance']);
      if (!_canApplySellerWalletRequest(requestId)) return;
      _safeSetStateForSellerWallet(requestId, () {
        _sellerWalletAvailableBalance = available;
        _sellerWalletReservedBalance = reserved;
        _sellerWalletReady = true;
        _sellerWalletError = null;
      });
      _debugLogSellerBootstrap(
        branch: 'seller_wallet:success',
        requestUrl: requestUrl,
        note:
            'durationMs=${watch.elapsedMilliseconds} '
            'available=$available reserved=$reserved silent=$silent',
      );
      _logSellerPanelStateUpdate(
        'seller_wallet_loaded',
        note:
            'durationMs=${watch.elapsedMilliseconds} '
            'available=$available reserved=$reserved silent=$silent',
      );
      _hasLoadedSellerWalletData = true;
    } catch (error, stackTrace) {
      _hasLoadedSellerWalletData = false;
      _debugLogSellerBootstrap(
        branch: 'seller_wallet:catch',
        requestUrl: requestUrl,
        note: 'durationMs=${watch.elapsedMilliseconds} silent=$silent',
        error: error,
        stackTrace: stackTrace,
      );
      if (!_canApplySellerWalletRequest(requestId)) return;
      _safeSetStateForSellerWallet(requestId, () {
        _sellerWalletReady = false;
        _sellerWalletError = _mapSellerWalletError(error);
      });
    } finally {
      if (!silent && _canApplySellerWalletRequest(requestId)) {
        _safeSetStateForSellerWallet(requestId, () {
          _isLoadingSellerWallet = false;
        });
        _logSellerPanelStateUpdate(
          'seller_wallet_loading_end',
          note:
              'durationMs=${watch.elapsedMilliseconds} silent=$silent '
              'requestId=$requestId',
        );
      }
    }
  }

  double _toWalletDouble(dynamic value) {
    if (value is num) return value.toDouble();
    return double.tryParse(value?.toString() ?? '') ?? 0;
  }

  String _mapSellerWalletError(Object error) {
    final raw = error.toString().toLowerCase();
    if (raw.contains('wallet_get_seller_balance') &&
        raw.contains('does not exist')) {
      return 'Cuzdan altyapisi hazir degil. SUPABASE_SELLER_WALLET_DELIVERY.sql scriptini calistirin.';
    }
    return 'Cuzdan bilgisi alinamadi: $error';
  }

  String _buildSellerWalletIdempotencyKey({
    required String sellerId,
    required String prefix,
  }) {
    final safeSeller = sellerId
        .replaceAll(RegExp(r'[^a-zA-Z0-9_-]'), '')
        .toLowerCase();
    return '$prefix-$safeSeller-${DateTime.now().microsecondsSinceEpoch}';
  }

  Future<bool> _showSellerWalletTopupDialog() async {
    final sellerId = _authService.currentUser?.id ?? '';
    if (sellerId.isEmpty) {
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(content: Text('Satıcı oturumu bulunamadı.')),
        );
      }
      return false;
    }

    final amountController = TextEditingController();
    final noteController = TextEditingController();
    bool isSuccess = false;
    try {
      final result = await showDialog<bool>(
        context: context,
        builder: (dialogContext) {
          bool isSubmitting = false;
          return StatefulBuilder(
            builder: (context, setModalState) {
              Future<void> submit() async {
                final amount = _parseSellerCurrencyInput(amountController.text);
                if (amount <= 0) {
                  ScaffoldMessenger.of(dialogContext).showSnackBar(
                    const SnackBar(
                      content: Text('Gecerli bir bakiye tutari girin.'),
                    ),
                  );
                  return;
                }
                setModalState(() => isSubmitting = true);
                try {
                  final response = await _sellerWalletService.topUp(
                    sellerId: sellerId,
                    amount: amount,
                    idempotencyKey: _buildSellerWalletIdempotencyKey(
                      sellerId: sellerId,
                      prefix: 'topup',
                    ),
                    note: noteController.text.trim().isEmpty
                        ? null
                        : noteController.text.trim(),
                  );
                  final ok = response['ok'] == true;
                  if (!ok) {
                    throw Exception(
                      response['error']?.toString() ??
                          'Cuzdan yukleme basarisiz',
                    );
                  }
                  if (!dialogContext.mounted) return;
                  Navigator.of(dialogContext).pop(true);
                } catch (error) {
                  if (!dialogContext.mounted) return;
                  ScaffoldMessenger.of(dialogContext).showSnackBar(
                    SnackBar(content: Text('Bakiye yuklenemedi: $error')),
                  );
                } finally {
                  if (dialogContext.mounted) {
                    setModalState(() => isSubmitting = false);
                  }
                }
              }

              return AlertDialog(
                title: const Text('Cuzdana Bakiye Yukle'),
                content: SizedBox(
                  width: 420,
                  child: Column(
                    mainAxisSize: MainAxisSize.min,
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      Text(
                        'Kargo cikisi icin satıcı cüzdan bakiyesi zorunludur.',
                        style: TextStyle(
                          color: Colors.grey.shade700,
                          fontSize: 13,
                          height: 1.4,
                        ),
                      ),
                      const SizedBox(height: 12),
                      TextFormField(
                        controller: amountController,
                        keyboardType: TextInputType.number,
                        inputFormatters: [
                          FilteringTextInputFormatter.digitsOnly,
                          _ThousandsSeparatorInputFormatter(),
                        ],
                        decoration: InputDecoration(
                          labelText: 'Yukleme Tutari (TL)',
                          hintText: '1.000',
                          border: OutlineInputBorder(
                            borderRadius: BorderRadius.circular(10),
                          ),
                        ),
                      ),
                      const SizedBox(height: 10),
                      TextFormField(
                        controller: noteController,
                        decoration: InputDecoration(
                          labelText: 'Not (Opsiyonel)',
                          border: OutlineInputBorder(
                            borderRadius: BorderRadius.circular(10),
                          ),
                        ),
                      ),
                    ],
                  ),
                ),
                actions: [
                  TextButton(
                    onPressed: isSubmitting
                        ? null
                        : () => Navigator.of(dialogContext).pop(false),
                    child: const Text('Iptal'),
                  ),
                  FilledButton(
                    onPressed: isSubmitting ? null : submit,
                    child: Text(
                      isSubmitting ? 'Yukleniyor...' : 'Bakiye Yukle',
                    ),
                  ),
                ],
              );
            },
          );
        },
      );

      if (result == true) {
        isSuccess = true;
        await _loadSellerWalletBalance();
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            SnackBar(
              content: Text(
                'Bakiye yuklendi. Yeni kullanilabilir bakiye: ${_formatDashboardCurrency(_sellerWalletAvailableBalance)}',
              ),
            ),
          );
        }
      }
    } finally {
      amountController.dispose();
      noteController.dispose();
    }

    return isSuccess;
  }

  @override
  void dispose() {
    _logSellerPanelLifecycle(
      'dispose',
      newInitialModule: _selectedModule.name,
      includeStack: true,
    );
    _sellerOrdersLoadRequestId++;
    _sellerWalletLoadRequestId++;
    _storeProfileLoadRequestId++;
    _sellerPanelControllersDisposed = true;
    _cancelAllSellerOrderHighlightClearTimers();
    _highlightedSellerOrderIds.clear();
    _productsStreamState = 'disposed';
    _garsonStreamState = 'disposed';
    _logSellerPanel(
      'Dispose',
      'productsSubscription=${_productsSubscription != null} '
          'subAdminsSubscription=${_subAdminsSubscription != null} '
          'supportTicketsSubscription=${_supportTicketsSubscription != null} '
          'cancelAppealSubscription=${_cancelAppealNotificationsSubscription != null} '
          'sellerOrderSearchDebounce=${_sellerOrderSearchDebounce != null} '
          'feedbackSearchDebounce=${_feedbackSearchDebounce != null} '
          'supportSearchDebounce=${_supportSearchDebounce != null} '
          'packagingUploadTimer=${_packagingVideoUploadProgressTimer != null} '
          'sellerOrderHighlightExpiries=${_sellerOrderHighlightExpiryScheduler.scheduledExpiryCount} '
          'sellerOrderHighlightTimer=${_sellerOrderHighlightExpiryScheduler.activeTimerCount}',
    );
    _productsSubscription?.cancel();
    _productsRealtimeRetryTimer?.cancel();
    _garsonRealtimeSubscription?.cancel();
    _subAdminsSubscription?.cancel();
    _supportTicketsSubscription?.cancel();
    _cancelAppealNotificationsSubscription?.cancel();
    _sellerOrderSearchDebounce?.cancel();
    _feedbackSearchDebounce?.cancel();
    _supportSearchDebounce?.cancel();
    _storeNameController.dispose();
    _storeUrlController.dispose();
    _storeDescController.dispose();
    _sloganController.dispose();
    _phoneController.dispose();
    _emailController.dispose();
    _whatsappController.dispose();
    _supportPhoneController.dispose();
    _addressController.dispose();
    _postalCodeController.dispose();
    _taxNumberController.dispose();
    _taxOfficeController.dispose();
    _companyNameController.dispose();
    _instagramController.dispose();
    _facebookController.dispose();
    _twitterController.dispose();
    _websiteController.dispose();
    _customerServiceController.dispose();
    _companyTitleController.dispose();
    _productSearchController.dispose();
    _sellerOrderSearchController.dispose();
    _supportSearchController.dispose();
    _feedbackSearchController.dispose();
    _sellerDetailTrackingController.dispose();
    _packagingVideoUploadProgressTimer?.cancel();
    _localPrintPollTimer?.cancel();
    _localPrintPollTimer = null;
    unawaited(_garsonVisibleOrdersController.close());
    _garsonHasPendingRemoteChanges.dispose();
    _localPrintUiRevision.dispose();
    final printHub = _cachedDesktopPrintHub;
    if (printHub != null) {
      unawaited(printHub.stop());
    }
    _cachedDesktopPrintHub = null;
    if (_navigationControllerListener != null &&
        _navigationController != null) {
      _navigationController!.removeListener(_navigationControllerListener!);
    }
    _navigationControllerListener = null;
    WidgetsBinding.instance.removeObserver(this);
    super.dispose();
  }

  @override
  void didChangeAppLifecycleState(AppLifecycleState state) {
    super.didChangeAppLifecycleState(state);
    if (state == AppLifecycleState.resumed &&
        _shouldMonitorLocalPrintForModule(_selectedModule)) {
      debugPrint(
        '[LocalPrint][Lifecycle] appResumed — re-checking print service status',
      );
      unawaited(_refreshLocalPrintStatus(reason: 'app_lifecycle_resumed'));
    }
  }

  bool _syncStoreProfileControllersFromData(
    Map<String, dynamic> data,
    int requestId,
  ) {
    if (!_canApplyStoreProfileRequest(requestId)) return false;
    _storeNameController.text = data['storeName']?.toString() ?? '';
    _storeUrlController.text = data['storeUrl']?.toString() ?? '';
    _storeDescController.text = data['description']?.toString() ?? '';
    _sloganController.text = data['slogan']?.toString() ?? '';
    _phoneController.text = data['phone']?.toString() ?? '';
    _emailController.text = data['email']?.toString() ?? '';
    _whatsappController.text = data['whatsapp']?.toString() ?? '';
    _supportPhoneController.text = data['supportPhone']?.toString() ?? '';
    _addressController.text = data['address']?.toString() ?? '';
    _postalCodeController.text = data['postalCode']?.toString() ?? '';
    _taxNumberController.text = data['taxNumber']?.toString() ?? '';
    _taxOfficeController.text = data['taxOffice']?.toString() ?? '';
    _companyNameController.text = data['companyName']?.toString() ?? '';
    _instagramController.text = data['instagram']?.toString() ?? '';
    _facebookController.text = data['facebook']?.toString() ?? '';
    _twitterController.text = data['twitter']?.toString() ?? '';
    _websiteController.text = data['website']?.toString() ?? '';
    _customerServiceController.text = data['customerService']?.toString() ?? '';
    _companyTitleController.text = data['companyTitle']?.toString() ?? '';
    return true;
  }

  void _applyStoreProfileStateFieldsFromData(
    Map<String, dynamic> data, {
    required int requestId,
  }) {
    // Apply ALL non-navigation profile fields first. Navigation writes are
    // routed through [_setActiveSellerModule] AFTER the setState completes so
    // the user-selected lock can reject any background overrides.
    _safeSetStateForStoreProfile(requestId, () {
      _selectedCity = (data['city'] ?? '').toString().trim();
      _selectedDistrict = (data['district'] ?? '').toString().trim();
      _companyType = data['companyType']?.toString() ?? 'Limited Şirket';
      _storeCategory = (data['category'] ?? '').toString();
      _storeRating = (data['rating'] as num?)?.toDouble() ?? 0.0;
      _workingHours = data['workingHours']?.toString() ?? '09:00 - 18:00';
      _storeLat = (data['storeLat'] as num?)?.toDouble();
      _storeLng = (data['storeLng'] as num?)?.toDouble();

      _isStoreOpen = data['isStoreOpen'] as bool? ?? true;
      _acceptNewOrders = data['acceptNewOrders'] as bool? ?? true;
      _allowMessaging = data['allowMessaging'] as bool? ?? true;
      _isHolidayMode = data['isHolidayMode'] as bool? ?? false;

      _storeLogoUrl = data['logoUrl']?.toString();
      _storeCoverUrl = data['coverUrl']?.toString();
      for (var i = 0; i < _storeImages.length; i++) {
        _storeImages[i] = null;
      }
      for (var i = 0; i < _announcementBanners.length; i++) {
        _announcementBanners[i] = null;
      }
      _sellerVideos = <String>[];

      final gallery = data['galleryImages'];
      if (gallery is List) {
        for (var i = 0; i < gallery.length && i < 6; i++) {
          _storeImages[i] = gallery[i]?.toString();
        }
      }

      final banners = data['banners'];
      if (banners is List) {
        for (var i = 0; i < banners.length && i < 3; i++) {
          _announcementBanners[i] = banners[i]?.toString();
        }
      }

      final videos = data['sellerVideos'];
      if (videos is List) {
        _sellerVideos = videos.map((e) => e.toString()).toList();
      }
    });

    if (!_canApplyStoreProfileRequest(requestId)) return;

    if (_isWaiterEntry) {
      debugPrint(
        '[NAV_ASYNC_IGNORED] '
        'source=profile_reload_waiter_entry '
        'current=${_selectedModule.name} '
        'reason=controller_seed_owns_waiter_default',
      );
    } else if (_selectedModule == SellerModule.garson ||
        _selectedModule == SellerModule.system) {
      debugPrint(
        '[NAV_ASYNC_IGNORED] '
        'source=profile_reload_non_navigation '
        'current=${_selectedModule.name} '
        'category=${data['category']} '
        'reason=module_preserved',
      );
      sellerNavigationLog(
        'store_reload_no_navigation',
        extra: {
          'module': _selectedModule.name,
          'reason': 'module_preserved',
          'category': (data['category'] ?? '').toString(),
        },
      );
    }
  }

  Future<void> _loadStoreProfile() async {
    final requestId = ++_storeProfileLoadRequestId;
    final sellerId = _authService.currentUser?.id.trim() ?? '';
    final requestUrl = _sellerPanelRestRequestUrl(
      'stores',
      query: <String, String>{
        'select': '*',
        'seller_id': 'eq.${sellerId.isEmpty ? '<missing>' : sellerId}',
      },
    );
    final watch = Stopwatch()..start();
    if (!_canApplyStoreProfileRequest(requestId)) return;
    _safeSetStateForStoreProfile(requestId, () {
      _isLoading = true;
      _storeProfileLoadError = null;
    });
    _logSellerPanelStateUpdate(
      'store_profile_loading_start',
      note: 'requestId=$requestId',
    );
    try {
      _debugLogSellerBootstrap(
        branch: 'store_profile:start',
        requestUrl: requestUrl,
      );
      final data = await _storeService.getStoreProfile();
      if (!_canApplyStoreProfileRequest(requestId)) return;
      if (data != null) {
        if (data['isDeleted'] == true) {
          if (_canApplyStoreProfileRequest(requestId)) {
            ScaffoldMessenger.of(context).showSnackBar(
              const SnackBar(
                content: Text('Satıcı hesabınız kalıcı olarak kapatılmıştır.'),
              ),
            );
            await _authService.signOut();
            await Future.delayed(const Duration(milliseconds: 200));
            if (_canApplyStoreProfileRequest(requestId)) {
              debugPrint(
                '[SellerExit] store deleted — navigating to / via rootNavigator',
              );
              Navigator.of(context, rootNavigator: true).pushAndRemoveUntil(
                buildAppPageRoute<void>(
                  builder: (_) => const HomeScreen(initialIndex: 4),
                ),
                (route) => false,
              );
            }
          }
          return;
        }
        final isFoodStore = _isFoodStoreCategory(
          (data['category'] ?? '').toString(),
        );
        if (!_syncStoreProfileControllersFromData(data, requestId)) return;
        _applyStoreProfileStateFieldsFromData(data, requestId: requestId);
        if (!_canApplyStoreProfileRequest(requestId)) return;
        _applySellerSeo();
        if ((_isWaiterEntry || isFoodStore) &&
            (_selectedModule == SellerModule.garson ||
                _selectedModule == SellerModule.system)) {
          unawaited(_loadStoreTables(silent: true));
        } else if (_storeTables.isNotEmpty) {
          _safeSetStateForStoreProfile(requestId, () {
            _storeTables = <Map<String, dynamic>>[];
          });
        }
        // After profile load we know _storeCategory; kick off table orders
        // fetch for the dashboard ONLY when the user is actually viewing the
        // dashboard. Triggering it for users currently on garson/system was
        // pointless work that bumped versions and contributed to the
        // "sayılar gidip geliyor" refresh storm.
        if (isFoodStore && _selectedModule == SellerModule.dashboard) {
          unawaited(
            _loadDashboardTableOrdersGuarded(source: '_loadStoreProfile'),
          );
        }
        // Note: the previous `unawaited(_persistSelectedModule(dashboard))`
        // call that paired with the now-disabled non-food fallback has been
        // removed — there is no longer any async path that can move the
        // user from garson to dashboard.
        _hasLoadedStoreProfile = true;
        _debugLogSellerBootstrap(
          branch: 'store_profile:success',
          requestUrl: requestUrl,
          note:
              'durationMs=${watch.elapsedMilliseconds} '
              'storeCategory=${_storeCategory.isEmpty ? '-' : _storeCategory} '
              'hasLogo=${_storeLogoUrl?.isNotEmpty == true} '
              'galleryCount=${_storeImages.whereType<String>().length} '
              'bannerCount=${_announcementBanners.whereType<String>().length}',
        );
        _logSellerPanelStateUpdate(
          'store_profile_loaded',
          note:
              'durationMs=${watch.elapsedMilliseconds} '
              'storeCategory=${_storeCategory.isEmpty ? '-' : _storeCategory}',
        );
      } else if (_canApplyStoreProfileRequest(requestId)) {
        _debugLogSellerBootstrap(
          branch: 'store_profile:null_result',
          requestUrl: requestUrl,
          note:
              'durationMs=${watch.elapsedMilliseconds} '
              'StoreService.getStoreProfile returned null',
        );
        _safeSetStateForStoreProfile(requestId, () {
          _storeProfileLoadError =
              'Magaza profili bulunamadi. stores kaydi eksik veya seller_id eslesmiyor.';
          _hasLoadedStoreProfile = false;
        });
        _logSellerPanelStateUpdate(
          'store_profile_null_result',
          note: 'durationMs=${watch.elapsedMilliseconds}',
        );
      }
    } catch (e, stackTrace) {
      _debugLogSellerBootstrap(
        branch: 'store_profile:catch',
        requestUrl: requestUrl,
        note: 'durationMs=${watch.elapsedMilliseconds}',
        error: e,
        stackTrace: stackTrace,
      );
      if (_canApplyStoreProfileRequest(requestId)) {
        _safeSetStateForStoreProfile(requestId, () {
          _storeProfileLoadError = _mapStoreProfileLoadError(e);
          _hasLoadedStoreProfile = false;
        });
      }
    } finally {
      if (_canApplyStoreProfileRequest(requestId)) {
        _safeSetStateForStoreProfile(requestId, () => _isLoading = false);
        _logSellerPanelStateUpdate(
          'store_profile_loading_end',
          note: 'durationMs=${watch.elapsedMilliseconds} requestId=$requestId',
        );
      }
    }
  }

  String _mapStoreProfileLoadError(Object error) {
    final raw = error.toString().replaceFirst('Exception: ', '');
    if (raw.toLowerCase().contains('permission') ||
        raw.toLowerCase().contains('rls')) {
      return 'Magaza profili alinamadi. Yetki veya RLS ayarlarinizi kontrol edin.';
    }
    if (raw.toLowerCase().contains('404') ||
        raw.toLowerCase().contains('not found')) {
      return 'Magaza profili alinamadi. Gerekli kayit veya bagli kaynak bulunamadi (404).';
    }
    return 'Magaza profili yuklenemedi: $raw';
  }

  Future<void> _loadPendingLocationChangeRequest() async {
    try {
      final request = await _storeService.getPendingLocationChangeRequest();
      if (!mounted) return;
      setState(() {
        _pendingLocationChangeRequest = request;
      });
      _hasLoadedPendingLocationRequestData = true;
    } catch (_) {
      _hasLoadedPendingLocationRequestData = false;
    }
  }

  Future<void> _saveStoreProfile() async {
    final city = _selectedCity.trim();
    final district = _selectedDistrict.trim();
    if (city.isEmpty || district.isEmpty) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('Magaza profili icin il ve ilce secimi zorunludur.'),
        ),
      );
      return;
    }

    setState(() => _isLoading = true);
    try {
      // Remove nulls from lists
      final galleryImages = _storeImages.where((e) => e != null).toList();
      final banners = _announcementBanners.where((e) => e != null).toList();

      final data = {
        'storeName': _storeNameController.text,
        'storeUrl': _storeUrlController.text,
        'description': _storeDescController.text,
        'slogan': _sloganController.text,
        'phone': _phoneController.text,
        'email': _emailController.text,
        'whatsapp': _whatsappController.text,
        'supportPhone': _supportPhoneController.text,
        'address': _addressController.text,
        'postalCode': _postalCodeController.text,
        'taxNumber': _taxNumberController.text,
        'taxOffice': _taxOfficeController.text,
        'companyName': _companyNameController.text,
        'instagram': _instagramController.text,
        'facebook': _facebookController.text,
        'twitter': _twitterController.text,
        'website': _websiteController.text,
        'city': city,
        'district': district,
        'companyType': _companyType,
        'workingHours': _workingHours,
        'isStoreOpen': _isStoreOpen,
        'acceptNewOrders': _acceptNewOrders,
        'allowMessaging': _allowMessaging,
        'isHolidayMode': _isHolidayMode,
        'logoUrl': _storeLogoUrl,
        'coverUrl': _storeCoverUrl,
        'galleryImages': galleryImages,
        'banners': banners,
        'sellerVideos': _sellerVideos,
      };

      await _storeService.updateStoreProfile(data);

      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(
            content: Text('Mağaza bilgileri başarıyla kaydedildi!'),
          ),
        );
      }
    } catch (e) {
      if (mounted) {
        ScaffoldMessenger.of(
          context,
        ).showSnackBar(SnackBar(content: Text('Hata: $e')));
      }
    } finally {
      if (mounted) {
        setState(() => _isLoading = false);
      }
    }
  }

  int _tableNumberFromRow(Map<String, dynamic> row) {
    final raw = row['table_number'];
    if (raw is int) return raw;
    return int.tryParse(raw?.toString() ?? '') ?? 0;
  }

  String _tableDisplayLabelFromRow(Map<String, dynamic> row) {
    return resolveTableCardTitle(
      tableRow: row,
      tableNumber: _tableNumberFromRow(row),
    );
  }

  String _areaNameFromRow(Map<String, dynamic> row) {
    return row['area_name']?.toString().trim() ?? '';
  }

  Future<void> _loadStoreTables({
    bool silent = false,
    String source = 'store_tables_load',
  }) async {
    final sellerId = _authService.currentUser?.id.trim() ?? '';
    if (sellerId.isNotEmpty &&
        _storeTablesLoadedForSellerId != null &&
        _storeTablesLoadedForSellerId != sellerId) {
      if (mounted) {
        setState(() {
          _storeTables = <Map<String, dynamic>>[];
          _storeTableAreas = <Map<String, dynamic>>[];
          _storeTablesSignature = null;
          _storeTableAreasSignature = null;
          _hasLoadedStoreTablesData = false;
        });
      }
    }
    if (!_isFoodStoreCategory(_storeCategory)) {
      if (mounted && _storeTables.isNotEmpty) {
        setState(() {
          _storeTables = <Map<String, dynamic>>[];
          _storeTableAreas = <Map<String, dynamic>>[];
          _storeTablesSignature = null;
          _storeTableAreasSignature = null;
        });
        _logSellerPanelStateUpdate(
          'store_tables_cleared_non_food_store',
          note: 'silent=$silent',
        );
      }
      return;
    }
    if (sellerId.isEmpty) return;

    if (mounted && !silent && !_isLoadingStoreTables) {
      setState(() => _isLoadingStoreTables = true);
    }

    final inFlightLoad = _storeTablesLoadFuture;
    if (inFlightLoad != null) {
      return inFlightLoad;
    }

    final loadFuture = () async {
      final requestUrl = _sellerPanelRestRequestUrl(
        'store_tables',
        query: <String, String>{
          'select': '*',
          'seller_id': 'eq.$sellerId',
          'is_active': 'eq.true',
        },
      );
      final watch = Stopwatch()..start();
      try {
        _debugLogSellerBootstrap(
          branch: 'store_tables:start',
          requestUrl: requestUrl,
          note: 'silent=$silent',
        );
        final tables = await _storeService.getStoreTables(sellerId: sellerId);
        // Best-effort preload of dining areas (Salon/Bahçe/Teras...). This must
        // not break older deployments where the areas table doesn't exist.
        List<Map<String, dynamic>> areas = const <Map<String, dynamic>>[];
        try {
          areas = await _storeService.getTableAreas(sellerId: sellerId);
        } catch (_) {
          areas = const <Map<String, dynamic>>[];
        }
        if (!mounted) return;
        tables.sort(
          (a, b) => _tableNumberFromRow(a).compareTo(_tableNumberFromRow(b)),
        );
        final nextTablesSignature = garsonStoreTablesSignature(tables);
        final nextAreasSignature = garsonStoreTablesSignature(areas);
        final tablesChanged = _storeTablesSignature != nextTablesSignature;
        final areasChanged = _storeTableAreasSignature != nextAreasSignature;
        if (!tablesChanged && !areasChanged) {
          _hasLoadedStoreTablesData = true;
          _storeTablesLoadedForSellerId = sellerId;
          return;
        }
        if (_shouldBlockGarsonBackgroundPublish(
          source: source,
          hasPublishedData:
              _storeTablesSignature != null ||
              _storeTableAreasSignature != null,
        )) {
          debugPrint(
            '[GarsonAutoRefresh][blocked] '
            'source=$source '
            'reason=store_tables_background_update',
          );
          _markGarsonHasPendingRemoteChanges(source: source);
          _hasLoadedStoreTablesData = true;
          _storeTablesLoadedForSellerId = sellerId;
          return;
        }
        setState(() {
          _storeTables = tables;
          _storeTableAreas = areas;
          _storeTablesLoadedForSellerId = sellerId;
          _storeTablesSignature = nextTablesSignature;
          _storeTableAreasSignature = nextAreasSignature;
        });
        debugPrint(
          '[GarsonTables] count=${tables.length} '
          'areas=${areas.length} '
          'sample=${tables.take(5).map((t) => '{table=${t['table_number']} label=${t['display_label'] ?? ''} area=${t['area_name'] ?? ''} areaId=${t['area_id'] ?? ''} areaNo=${t['area_table_number'] ?? ''}}').join(' ')}',
        );
        unawaited(_ensureDesktopPrintHubStarted(reason: 'store_tables_loaded'));
        _debugLogSellerBootstrap(
          branch: 'store_tables:success',
          requestUrl: requestUrl,
          note:
              'silent=$silent durationMs=${watch.elapsedMilliseconds} '
              'tables=${tables.length}',
        );
        _logSellerPanelStateUpdate(
          'store_tables_loaded',
          note:
              'silent=$silent durationMs=${watch.elapsedMilliseconds} '
              'tables=${tables.length}',
        );
        _hasLoadedStoreTablesData = true;
      } catch (error, stackTrace) {
        _hasLoadedStoreTablesData = false;
        _debugLogSellerBootstrap(
          branch: 'store_tables:catch',
          requestUrl: requestUrl,
          note: 'silent=$silent durationMs=${watch.elapsedMilliseconds}',
          error: error,
          stackTrace: stackTrace,
        );
        if (!mounted || silent) return;
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
            content: Text(error.toString().replaceFirst('Exception: ', '')),
          ),
        );
      } finally {
        _storeTablesLoadFuture = null;
        if (mounted && _isLoadingStoreTables) {
          setState(() => _isLoadingStoreTables = false);
          _logSellerPanelStateUpdate(
            'store_tables_loading_end',
            note: 'silent=$silent',
          );
        }
      }
    }();

    _storeTablesLoadFuture = loadFuture;
    return loadFuture;
  }

  List<int> _sortedStoreTableNumbers() {
    final sellerId = _authService.currentUser?.id.trim() ?? '';
    if (sellerId.isNotEmpty &&
        _storeTablesLoadedForSellerId != null &&
        _storeTablesLoadedForSellerId != sellerId) {
      return const <int>[];
    }
    final numbers =
        _storeTables
            .map(_tableNumberFromRow)
            .where((n) => n > 0)
            .toSet()
            .toList(growable: false)
          ..sort();
    return numbers;
  }

  bool get _garsonStoreTablesReady {
    if (_isLoadingStoreTables) return false;
    if (!_hasLoadedStoreTablesData) return false;
    final sellerId = _authService.currentUser?.id.trim() ?? '';
    if (sellerId.isEmpty) return false;
    if (_storeTablesLoadedForSellerId != sellerId) return false;
    return true;
  }

