              letterSpacing: 0.4,
            ),
          ),
          const SizedBox(height: 4),
          Text(
            '$totalCount masa · $occupiedCount dolu · $emptyCount boş',
            style: TextStyle(
              fontSize: 12,
              fontWeight: FontWeight.w500,
