  Widget _buildGarsonGroupedTableGrids({
    required List<GarsonTableAreaGroup> groups,
    required Set<int> occupiedTableNumbers,
    required Widget Function(int tableNumber) cardBuilder,
    required int Function(double maxWidth) columnsResolver,
    required double Function(double maxWidth, int columns) aspectRatioResolver,
    EdgeInsetsGeometry sectionPadding = const EdgeInsets.fromLTRB(12, 0, 12, 0),
    double sectionSpacing = 18,
  }) {
    if (groups.isEmpty) {
      return const SizedBox.shrink();
    }
    return Column(
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        for (var i = 0; i < groups.length; i++) ...[
          Padding(
            padding: sectionPadding,
            child: _buildGarsonAreaSectionHeader(
              areaName: groups[i].areaName,
              totalCount: groups[i].tableNumbers.length,
              occupiedCount: groups[i].tableNumbers
                  .where(occupiedTableNumbers.contains)
                  .length,
            ),
          ),
          const SizedBox(height: 10),
          Padding(
            padding: sectionPadding,
            child: LayoutBuilder(
              builder: (context, constraints) {
                final columns = columnsResolver(constraints.maxWidth);
                final aspectRatio = aspectRatioResolver(
                  constraints.maxWidth,
                  columns,
                );
                final numbers = groups[i].tableNumbers;
                return GridView.builder(
                  shrinkWrap: true,
                  physics: const NeverScrollableScrollPhysics(),
                  itemCount: numbers.length,
                  gridDelegate: SliverGridDelegateWithFixedCrossAxisCount(
                    crossAxisCount: columns,
                    crossAxisSpacing: 10,
                    mainAxisSpacing: 10,
                    childAspectRatio: aspectRatio,
                  ),
                  itemBuilder: (context, index) {
                    return cardBuilder(numbers[index]);
                  },
                );
              },
            ),
          ),
          if (i < groups.length - 1) SizedBox(height: sectionSpacing),
        ],
        SizedBox(height: sectionSpacing),
      ],
    );
  }

  int _firstMissingStoreTableNumber(List<int> sortedNumbers) {
    var expected = 1;
    for (final n in sortedNumbers) {
      if (n == expected) {
        expected++;
      } else if (n > expected) {
        break;
      }
    }
    return expected;
  }

  Future<int?> _pickTableNumberToAdd() async {
    final sortedNumbers = _sortedStoreTableNumbers();
    final nextNewTableNumber = sortedNumbers.isEmpty
        ? 1
        : (sortedNumbers.last + 1);
    final missingTableNumber = _firstMissingStoreTableNumber(sortedNumbers);
    final hasMissingNumber = missingTableNumber < nextNewTableNumber;

    if (!hasMissingNumber) {
      return nextNewTableNumber;
    }

    return showDialog<int>(
      context: context,
      builder: (ctx) => AlertDialog(
        title: const Text('Masa Ekle'),
        content: const Text(
          'Eksik masa numarası bulundu. Nasıl eklemek istersin?',
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(ctx),
            child: const Text('Vazgeç'),
          ),
          OutlinedButton(
            onPressed: () => Navigator.pop(ctx, nextNewTableNumber),
            child: Text('Yeni Masa $nextNewTableNumber'),
          ),
          FilledButton(
            onPressed: () => Navigator.pop(ctx, missingTableNumber),
            child: Text('Eksik Masa $missingTableNumber'),
          ),
        ],
      ),
    );
  }

  Future<void> _addStoreTable() async {
    if (_isMutatingStoreTables) return;
    final selectedTableNumber = await _pickTableNumberToAdd();
    if (selectedTableNumber == null || selectedTableNumber <= 0) return;

    setState(() => _isMutatingStoreTables = true);
    try {
      await _storeService.addStoreTable(
        tableNumber: selectedTableNumber,
        preferMissingNumber: false,
      );
      await _loadStoreTables(silent: true);
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Masa $selectedTableNumber eklendi.')),
      );
    } catch (error) {
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(error.toString().replaceFirst('Exception: ', '')),
        ),
      );
    } finally {
      if (mounted) {
        setState(() => _isMutatingStoreTables = false);
      }
    }
  }

