      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text('Masa eklendi: $normalized')));
    } catch (error) {
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(error.toString().replaceFirst('Exception: ', '')),
        ),
      );
    } finally {
      if (mounted) setState(() => _isMutatingStoreTables = false);
    }
  }

  Future<void> _removeStoreTable(Map<String, dynamic> table) async {
    if (_isMutatingStoreTables) return;
    final tableId = table['id']?.toString() ?? '';
    final tableNumber = _tableNumberFromRow(table);
    if (tableId.isEmpty) {
      if (!mounted) return;
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(const SnackBar(content: Text('Masa kaydı silinemedi.')));
      return;
    }

    final confirmed = await showDialog<bool>(
      context: context,
      builder: (ctx) => AlertDialog(
        title: const Text('Masayı Sil'),
        content: Text(
          'Masa $tableNumber kaydını silmek istediğinize emin misiniz?',
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(ctx, false),
            child: const Text('Vazgeç'),
          ),
          FilledButton(
            onPressed: () => Navigator.pop(ctx, true),
            child: const Text('Sil'),
          ),
        ],
      ),
    );
    if (confirmed != true) return;

    setState(() => _isMutatingStoreTables = true);
    try {
      await _storeService.removeStoreTableById(tableId);
      await _loadStoreTables(silent: true);
      if (!mounted) return;
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text('Masa $tableNumber silindi.')));
    } catch (error) {
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(error.toString().replaceFirst('Exception: ', '')),
        ),
      );
    } finally {
      if (mounted) {
        setState(() => _isMutatingStoreTables = false);
      }
    }
  }

  /// Shows a dialog letting the user pick an area to move [table] into.
  Future<void> _moveTableToArea(Map<String, dynamic> table) async {
    if (_isMutatingStoreTables) return;
    final tableId = table['id']?.toString() ?? '';
    final tableNumber = _tableNumberFromRow(table);
    if (tableId.isEmpty || _storeTableAreas.isEmpty) {
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('Önce en az bir alan oluşturun.')),
      );
      return;
    }

    String? pickedAreaId;
    final picked = await showDialog<Map<String, dynamic>>(
      context: context,
      builder: (ctx) => AlertDialog(
        title: Text('Masa $tableNumber — Alan Seç'),
        content: Column(
          mainAxisSize: MainAxisSize.min,
          children: _storeTableAreas
              .map(
                (area) => ListTile(
                  leading: const Icon(Icons.place_outlined),
                  title: Text(area['name']?.toString() ?? '-'),
                  onTap: () => Navigator.pop(ctx, area),
                ),
              )
              .toList(),
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(ctx),
            child: const Text('Vazgeç'),
          ),
        ],
      ),
    );
    if (picked == null) return;
    pickedAreaId = picked['id']?.toString() ?? '';
    final pickedAreaName = picked['name']?.toString() ?? '';

    setState(() => _isMutatingStoreTables = true);
    try {
      await _storeService.updateStoreTableArea(
        tableId: tableId,
        areaId: pickedAreaId,
        areaName: pickedAreaName,
      );
      await _loadStoreTables(silent: true);
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text('Masa $tableNumber → $pickedAreaName alanına taşındı.'),
        ),
      );
    } catch (error) {
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(error.toString().replaceFirst('Exception: ', '')),
        ),
      );
    } finally {
      if (mounted) setState(() => _isMutatingStoreTables = false);
    }
  }

  Future<void> _initializeDefaultStoreTables() async {
    if (_isMutatingStoreTables) return;
    setState(() => _isMutatingStoreTables = true);
    try {
      final existing = await _storeService.getStoreTables();
      final target = 20;
      final toCreate = target - existing.length;
      if (toCreate <= 0) {
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(content: Text('Masa listesi zaten hazır.')),
          );
        }
        return;
      }
      for (var i = 0; i < toCreate; i++) {
        await _storeService.addStoreTable();
      }
      await _loadStoreTables(silent: true);
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('20 masa için QR oluşturuldu.')),
      );
    } catch (error) {
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(error.toString().replaceFirst('Exception: ', '')),
        ),
      );
    } finally {
      if (mounted) {
        setState(() => _isMutatingStoreTables = false);
      }
    }
  }

  String _buildTableQrLink({
    required String sellerId,
    required int tableNumber,
    required String token,
  }) {
    final fallbackBase = 'https://ibul-ecommerce.web.app';
    final origin = kIsWeb && Uri.base.origin.isNotEmpty
        ? Uri.base.origin
        : fallbackBase;
    final normalizedOrigin = origin.endsWith('/')
        ? origin.substring(0, origin.length - 1)
        : origin;
    // Use a dedicated /qr path with clean query parameters.
    // Firebase Hosting rewrites /qr → index.html, so the Flutter app always
    // loads. QrInitialParams captures seller/table/token from uri.queryParameters
    // before any routing occurs, and QrEntryScreen opens the table flow directly.
    final query = Uri(
      queryParameters: <String, String>{
        'seller': sellerId,
        'table': '$tableNumber',
        'token': token,
      },
    ).query;
    return '$normalizedOrigin/qr?$query';
  }

  String _buildTableQrImageUrl(String qrData) {
    return Uri.https('api.qrserver.com', '/v1/create-qr-code/', {
      'size': '240x240',
      'margin': '12',
      'data': qrData,
    }).toString();
  }

  Future<void> _copyTableQrLink(String url) async {
    await Clipboard.setData(ClipboardData(text: url));
    if (!mounted) return;
    ScaffoldMessenger.of(
      context,
    ).showSnackBar(const SnackBar(content: Text('QR bağlantısı kopyalandı.')));
  }

  String _escapePdfText(String raw) {
    return raw
        .replaceAll('\\', r'\\')
        .replaceAll('(', r'\(')
        .replaceAll(')', r'\)')
        .replaceAll('\n', ' ');
  }

  String _pdfNumber(num value) {
    var fixed = value.toStringAsFixed(2);
    if (fixed.contains('.')) {
      fixed = fixed.replaceFirst(RegExp(r'0+$'), '');
      fixed = fixed.replaceFirst(RegExp(r'\.$'), '');
    }
    return fixed;
  }

  Future<Uint8List> _buildTableQrPdfBytes({
    required int tableNumber,
    required String qrImageUrl,
    required String qrLink,
  }) async {
    final imageResponse = await http.get(Uri.parse(qrImageUrl));
    if (imageResponse.statusCode < 200 || imageResponse.statusCode >= 300) {
      throw Exception('QR görseli alınamadı.');
    }
    final decoded = img.decodeImage(imageResponse.bodyBytes);
    if (decoded == null) {
      throw Exception('QR görseli çözümlenemedi.');
    }
    final jpegBytes = img.encodeJpg(decoded, quality: 96);

    const pageWidth = 595.0;
    const pageHeight = 842.0;
    const margin = 48.0;
    const imageTop = 700.0;
    final maxImageWidth = pageWidth - (margin * 2);
    final maxImageHeight = 520.0;
    final scale = math.min(
      maxImageWidth / decoded.width,
      maxImageHeight / decoded.height,
    );
    final drawWidth = decoded.width * scale;
    final drawHeight = decoded.height * scale;
    final drawX = (pageWidth - drawWidth) / 2;
    final drawY = imageTop - drawHeight;

    final title = _escapePdfText('Masa $tableNumber QR');
    final subtitle = _escapePdfText(
      'Bu QR kod okutuldugunda masa otomatik acilir.',
    );
    final escapedLink = _escapePdfText(qrLink);

    final contentStream =
        '''
BT /F1 22 Tf ${_pdfNumber(margin)} 790 Td ($title) Tj ET
BT /F1 11 Tf ${_pdfNumber(margin)} 768 Td ($subtitle) Tj ET
q
${_pdfNumber(drawWidth)} 0 0 ${_pdfNumber(drawHeight)} ${_pdfNumber(drawX)} ${_pdfNumber(drawY)} cm
/Im0 Do
Q
BT /F1 10 Tf ${_pdfNumber(margin)} 66 Td (QR Link:) Tj ET
BT /F1 9 Tf ${_pdfNumber(margin)} 50 Td ($escapedLink) Tj ET
''';
    final contentBytes = utf8.encode(contentStream);

    final objects = <Uint8List>[
      Uint8List.fromList(
        utf8.encode('1 0 obj\n<< /Type /Catalog /Pages 2 0 R >>\nendobj\n'),
      ),
      Uint8List.fromList(
        utf8.encode(
          '2 0 obj\n<< /Type /Pages /Count 1 /Kids [3 0 R] >>\nendobj\n',
        ),
      ),
      Uint8List.fromList(
        utf8.encode(
          '3 0 obj\n'
          '<< /Type /Page /Parent 2 0 R /MediaBox [0 0 ${_pdfNumber(pageWidth)} ${_pdfNumber(pageHeight)}] '
          '/Resources << /XObject << /Im0 4 0 R >> /Font << /F1 5 0 R >> >> /Contents 6 0 R >>\n'
          'endobj\n',
        ),
      ),
      () {
        final builder = BytesBuilder(copy: false);
        builder.add(
          utf8.encode(
            '4 0 obj\n'
            '<< /Type /XObject /Subtype /Image /Width ${decoded.width} /Height ${decoded.height} '
            '/ColorSpace /DeviceRGB /BitsPerComponent 8 /Filter /DCTDecode /Length ${jpegBytes.length} >>\n'
            'stream\n',
          ),
        );
        builder.add(jpegBytes);
        builder.add(utf8.encode('\nendstream\nendobj\n'));
        return Uint8List.fromList(builder.toBytes());
      }(),
      Uint8List.fromList(
        utf8.encode(
          '5 0 obj\n<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>\nendobj\n',
        ),
      ),
      () {
        final builder = BytesBuilder(copy: false);
        builder.add(
          utf8.encode(
            '6 0 obj\n<< /Length ${contentBytes.length} >>\nstream\n',
          ),
        );
        builder.add(contentBytes);
        builder.add(utf8.encode('\nendstream\nendobj\n'));
        return Uint8List.fromList(builder.toBytes());
      }(),
    ];

    final output = BytesBuilder(copy: false);
    var cursor = 0;
    void writeText(String text) {
      final data = utf8.encode(text);
      output.add(data);
      cursor += data.length;
    }

    writeText('%PDF-1.4\n');
    final objectOffsets = <int>[];
    for (final object in objects) {
      objectOffsets.add(cursor);
      output.add(object);
      cursor += object.length;
    }

    final xrefStart = cursor;
    writeText('xref\n0 ${objects.length + 1}\n');
    writeText('0000000000 65535 f \n');
    for (final offset in objectOffsets) {
      writeText('${offset.toString().padLeft(10, '0')} 00000 n \n');
    }
    writeText(
      'trailer\n<< /Size ${objects.length + 1} /Root 1 0 R >>\n'
      'startxref\n$xrefStart\n%%EOF',
    );

    return Uint8List.fromList(output.toBytes());
  }

  Future<void> _downloadTableQrPdf({
    required int tableNumber,
    required String qrImageUrl,
    required String qrLink,
  }) async {
    try {
      final pdfBytes = await _buildTableQrPdfBytes(
        tableNumber: tableNumber,
        qrImageUrl: qrImageUrl,
        qrLink: qrLink,
      );
      BrowserFileDownload.saveBytes(
        bytes: pdfBytes,
        fileName: 'masa-$tableNumber-qr.pdf',
        mimeType: 'application/pdf',
      );
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Masa $tableNumber QR PDF indirildi.')),
      );
    } catch (error) {
      if (!mounted) return;
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text('PDF indirilemedi: $error')));
    }
  }

  Future<void> _openLocationChangeDialog() async {
    final result = await showDialog<Map<String, double>>(
      context: context,
      builder: (_) => _StoreLocationChangeDialog(
        initialLat: _storeLat,
        initialLng: _storeLng,
      ),
    );

    if (result == null) return;

    setState(() => _isLoading = true);
    try {
      await _storeService.submitStoreLocationChangeRequest(
        requestedLat: result['lat']!,
        requestedLng: result['lng']!,
      );
      await _loadPendingLocationChangeRequest();
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('Konum değişim talebi admin onayına gönderildi.'),
        ),
      );
    } catch (e) {
      if (!mounted) return;
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text('Konum talebi gönderilemedi: $e')));
    } finally {
      if (mounted) setState(() => _isLoading = false);
    }
  }

  Future<void> _pickAndUploadImage(String type, {int? index}) async {
    // Web/diyalog içinde image_picker güvenilir değil; ortak seçici kullanılır.
    PickedImageFile? picked;
    try {
      picked = await pickImageFile();
    } catch (e) {
      if (mounted) {
        ScaffoldMessenger.of(
          context,
        ).showSnackBar(SnackBar(content: Text('Görsel seçilemedi: $e')));
      }
      return;
    }
    if (picked == null) return;

    // 2. Configure Crop Settings based on type
    double? aspectRatio;
    double? suggestedWidth;

    if (type == 'logo') {
      aspectRatio = 1.0;
      suggestedWidth = 500.0;
    } else if (type == 'cover') {
      aspectRatio = 4.0;
      suggestedWidth = 1200.0;
    } else if (type == 'banner') {
      aspectRatio = 1200 / 200;
      suggestedWidth = 1200.0;
    } else {
      // Gallery - Square default
      aspectRatio = 1.0;
      suggestedWidth = 800.0;
    }

    // 3. Web'te cropper akisi kararsiz olabildigi icin dogrudan secilen
    // dosyayi yukle. Native taraf cropper deneyimini korusun.
    Uint8List uploadBytes = picked.bytes;
    if (!kIsWeb) {
      final XFile pickedFile = XFile.fromData(
        picked.bytes,
        name: picked.name,
        mimeType: 'image/jpeg',
      );
      Uint8List? croppedBytes;
      final imageBytes = await pickedFile.readAsBytes();
      if (!mounted) return;
      await showDialog(
        context: context,
        builder: (_) => ImageCropperWidget(
          imageData: imageBytes,
          aspectRatio: aspectRatio,
          suggestedWidth: suggestedWidth,
          onCropped: (croppedData) {
            croppedBytes = croppedData;
          },
        ),
      );

      if (croppedBytes == null) {
        return;
      }
      uploadBytes = croppedBytes!;
    }

    // Show local preview immediately
    Uint8List? previewBytes;
    try {
      previewBytes = uploadBytes;
      if (mounted) {
        setState(() {
          if (type == 'logo') {
            _localLogoBytes = previewBytes;
          }
        });
      }
    } catch (e) {
      debugPrint('Preview error: $e');
    }

    setState(() => _isLoading = true);

    try {
      String folder = 'general';
      if (type == 'logo') {
        folder = 'logos';
      } else if (type == 'cover') {
        folder = 'covers';
      } else if (type == 'gallery') {
        folder = 'gallery';
      } else if (type == 'banner') {
        folder = 'banners';
      }

      final url = await _storeService.uploadStoreImageBytes(
        uploadBytes,
        folder,
        fileName: picked.name,
      );

      if (url.isEmpty) throw Exception('Yükleme sonucu boş URL döndü');

      if (mounted) {
        setState(() {
          if (type == 'logo') {
            _storeLogoUrl = url;
            _localLogoBytes = null; // Clear local preview once uploaded
          } else if (type == 'cover') {
            _storeCoverUrl = url;
          } else if (type == 'gallery' && index != null) {
            _storeImages[index] = url;
          } else if (type == 'banner' && index != null) {
            _announcementBanners[index] = url;
          }
        });
      }

      // Auto-save after upload
      await _saveStoreProfile();
    } catch (e) {
      if (mounted) {
        // Revert local preview on error
        setState(() {
          if (type == 'logo') {
            _localLogoBytes = null;
          }
        });

        ScaffoldMessenger.of(
          context,
        ).showSnackBar(SnackBar(content: Text('Görsel yüklenirken hata: $e')));
      }
    } finally {
      if (mounted) setState(() => _isLoading = false);
    }
  }

  void _loadProducts() {
    final sellerId = _authService.currentUser?.id ?? '';
    final requestUrl = _sellerPanelRestRequestUrl(
      'products',
      query: <String, String>{
        'select': '*',
        'seller_id': 'eq.${sellerId.isEmpty ? '<missing>' : sellerId}',
        'order': 'created_at.desc',
      },
    );
    _logSellerPanel(
      'Fetch',
      'branch=products:subscribe requestUrl=$requestUrl',
    );
    _productsSubscription?.cancel();
    _productsRealtimeRetryTimer?.cancel();
    _productsStreamState = 'stream_start';
    unawaited(_loadProductsSnapshot(source: 'products_initial_load'));
    _productsSubscription = _storeService.getSellerProducts().listen(
      (products) {
        if (mounted) {
          // Successful emit — reset the timeout-backoff counter so the
          // next failure starts from the shortest retry window again.
          _productsStreamTimeoutAttempts = 0;
          // _applySellerProducts now manages its own setState and only
          // fires it when the products data actually changed (signature
          // mismatch). Wrapping the call in setState here would defeat
          // that guard and rebuild the entire panel — including the
          // garson StreamBuilder — every time the realtime stream
          // re-emits the same payload after a timeout retry.
          final changed = _applySellerProducts(
            products,
            source: 'products_stream',
          );
          _productsStreamState = changed
              ? 'stream_event_changed'
              : 'stream_event_same';
          if (changed) {
            _logSellerPanelStateUpdate(
              'products_stream',
              note: 'products=${products.length}',
            );
          }
        }
      },
      onError: (error) {
        _logSellerPanel(
          'Error',
          'branch=products:stream_error requestUrl=$requestUrl',
          error: error,
        );
        final isTimeout = _isRealtimeTimeoutError(error);
        // ⛔ HARD INVARIANT: products stream errors NEVER touch
        // [_selectedModule]. The render decision must stay on whatever
        // the user picked (garson, etc.). The block below only refreshes
        // the products list via a snapshot fetch — a pure data update —
        // and reschedules the realtime subscription with backoff. Any
        // navigation/dashboard refresh from this branch is a regression.
        final preservedModuleAtError = _selectedModule;
        if (isTimeout) {
          _productsStreamState = 'timeout';
          debugPrint(
            '[ProductsRealtime][timeout] '
            'activeModule=${preservedModuleAtError.name} '
            'attempt=${_productsStreamTimeoutAttempts + 1}',
          );
          _showRealtimeFallbackWarning(
            'Ürün canlı akışı zaman aşımına uğradı. Veriler sorgu ile yenileniyor.',
          );
        }
        debugPrint(
          '[ProductsRealtime][fallback_snapshot_start] '
          'activeModule=${preservedModuleAtError.name}',
        );
        _productsStreamState = 'fallback_snapshot';
        unawaited(_loadProductsSnapshot(source: 'products_stream_timeout'));
        // ── Exponential backoff retry ───────────────────────────────────
        // The previous fixed 10-second retry created a guaranteed loop:
        // subscribe → 9s timeout → fallback snapshot → 10s retry →
        // subscribe → 9s timeout → … forever. That cycle was the actual
        // engine behind the "panel sürekli yenileniyor" symptom. Backoff
        // starts at 10s, doubles each consecutive timeout, and caps at
        // 5 minutes. After the cap we stop retrying — the snapshot
        // fetch above already keeps products fresh enough for the UI.
        _productsStreamTimeoutAttempts++;
        final attempt = _productsStreamTimeoutAttempts;
        const maxAttempts = 6;
        final backoffSeconds = (10 * (1 << (attempt - 1).clamp(0, 5))).clamp(
          10,
          300,
        );
        _productsRealtimeRetryTimer?.cancel();
        if (attempt > maxAttempts) {
          debugPrint(
            '[ProductsRealtime][retry_disabled] '
            'attempts=$attempt cap=$maxAttempts '
            'reason=permanent_failure_relying_on_snapshot_only',
          );
          return;
        }
        debugPrint(
          '[ProductsRealtime][retry_scheduled] '
          'attempt=$attempt nextInSeconds=$backoffSeconds '
          'activeModule=${_selectedModule.name}',
        );
        _productsStreamState = 'retry_waiting_$attempt';
        _productsRealtimeRetryTimer = Timer(
          Duration(seconds: backoffSeconds),
          () {
            if (!mounted) return;
            debugPrint(
              '[ProductsRealtime][retry] '
              'attempt=$attempt '
              'activeModule=${_selectedModule.name}',
            );
            _productsStreamState = 'retrying_$attempt';
            _loadProducts();
          },
        );
      },
    );
  }

