  String _templateCategoryLabel(SellerProduct product) {
    if (_isMixedServiceTemplateProduct(product)) {
      return _isMenuTemplateProduct(product)
          ? 'Yemek > Menü'
          : 'Yemek > Servis';
    }
    return product.subCategory.isNotEmpty
