  @override
  Widget build(BuildContext context) {
    final buildId = ++_sellerPanelBuildCount;
    final buildWatch = Stopwatch()..start();
    final screenWidth = MediaQuery.of(context).size.width;
    final isMobile = screenWidth < 800;
    final isTablet = screenWidth >= 800 && screenWidth < 1200;
    final storeLabel = _storeNameController.text.trim().isEmpty
        ? 'Mağazam'
        : _storeNameController.text.trim();
    final sellerId = _authService.currentUser?.id ?? '';
    final sellerIdLabel = sellerId.isEmpty
        ? 'Satıcı ID: -'
        : 'Satıcı ID: ${sellerId.substring(0, sellerId.length < 8 ? sellerId.length : 8)}';

    final String shellBranch;
    if (isMobile) {
      shellBranch = 'mobile_shell';
    } else if (isTablet) {
      shellBranch = 'tablet_shell';
    } else {
      shellBranch = 'desktop_shell';
    }

    _logSellerPanel(
      'Build',
      'phase=start buildId=$buildId '
          'branch=$shellBranch '
          'orders=${_sellerOrders.length} '
          'products=${_products.length} '
          'isLoading=$_isLoading '
          'storeProfileLoaded=$_hasLoadedStoreProfile',
    );
    _logSellerPanelLifecycle('build', newInitialModule: _selectedModule.name);

    final webPrintNoticeBanner = _buildWebPrintNoticeBanner();

    late final Widget result;
    if (isMobile) {
      result = SellerPanelMobileShell(
        title: _moduleLabel(_selectedModule),
        storeLabel: storeLabel,
        drawer: SellerPanelMobileDrawer(
          items: _buildPanelMenuEntries(
            beforeSelect: () => Navigator.of(context).pop(),
          ),
          onLogoutTap: () {
            Navigator.of(context).pop();
            _exitSellerPanel();
          },
        ),
        content: _buildMobileContentArea(),
        onRefresh: () => _refreshDashboardData(
          source: 'mobile_pull_to_refresh',
          userInitiated: true,
        ),
        contentBanner: webPrintNoticeBanner,
      );
    } else if (isTablet) {
      result = SellerPanelTabletShell(
        title: _moduleLabel(_selectedModule),
        storeLabel: storeLabel,
        sellerIdLabel: sellerIdLabel,
        drawerItems: _buildPanelMenuEntries(
          beforeSelect: () => Navigator.of(context).maybePop(),
        ),
        onLogoutTap: _exitSellerPanel,
        content: _buildContent(),
        onNotificationsTap: () {},
        contentBanner: webPrintNoticeBanner,
      );
    } else {
      result = SellerPanelShell(
        topBar: SellerPanelTopBar(
          title: _moduleLabel(_selectedModule),
          storeLabel: storeLabel,
          sellerIdLabel: sellerIdLabel,
          onNotificationsTap: () {},
          sidebarCollapsed: _sidebarCollapsed,
          onToggleSidebar: _toggleSidebar,
        ),
        sidebar: SellerPanelSidebar(
          items: _buildPanelMenuEntries(),
          onLogoutTap: _exitSellerPanel,
          collapsed: _sidebarCollapsed,
        ),
        content: _buildContent(),
        contentBanner: webPrintNoticeBanner,
      );
    }

    _logSellerPanel(
      'Build',
      'phase=end buildId=$buildId '
          'durationMs=${buildWatch.elapsedMilliseconds} '
          'branch=$shellBranch',
    );
    debugPrint(
      '[SellerShell][visible_module] '
      'selectedModule=${_selectedModule.name} '
      'title=${_moduleLabel(_selectedModule)} '
      'shellBranch=$shellBranch '
      'isGarsonTableRouteOpen=$_isGarsonTableRouteOpen '
      'hasUserSelected=$_hasUserSelectedSellerModule',
    );
    return result;
  }

  Widget _buildMobileContentArea() {
    if (_isLoading && !_hasLoadedStoreProfile) {
      return const Center(child: CircularProgressIndicator());
    }
    if (_storeProfileLoadError != null && !_hasLoadedStoreProfile) {
      return ListView(
        padding: const EdgeInsets.all(16),
        children: [
          _buildStoreStateCard(
            icon: Icons.error_outline_rounded,
            title: 'Magaza profili acilamadi',
            message: _storeProfileLoadError!,
            isError: true,
            onRetry: _loadStoreProfile,
          ),
        ],
      );
    }
    // Guard: wait until store category is known before rendering seller modules.
    // This keeps mobile seller accounts from rendering the wrong panel while
    // the async store/profile chain is still resolving.
    if (!_hasLoadedStoreProfile) {
      return const Center(child: CircularProgressIndicator());
    }
    return AnimatedSwitcher(
      duration: AppMotion.normalTransitionDuration,
      reverseDuration: AppMotion.normalTransitionReverseDuration,
      switchInCurve: AppMotion.revealCurve,
      switchOutCurve: AppMotion.revealReverseCurve,
      transitionBuilder: (child, animation) =>
          AppMotion.buildFadeSlideTransition(animation, child),
      child: KeyedSubtree(
        key: ValueKey<String>(_moduleStorageKey(_selectedModule)),
        child: _buildMobileContent(),
      ),
    );
  }

  Widget _buildMobileContent() {
    final target = resolveSellerPanelRenderTarget(
      selectedModule: _selectedModule,
      storeCategory: _storeCategory,
      isWaiterEntry: _isWaiterEntry,
    );
    debugPrint(
      '[RENDER_DECISION] '
      'selectedModule=${_selectedModule.name} '
      'rendered=$target '
      'source=_buildMobileContent',
    );
    _logVisibleState(rendered: target, source: '_buildMobileContent');
    if (_selectedModule == SellerModule.garson &&
        target == SellerPanelRenderTargets.dashboard) {
      debugPrint(
        '[FATAL_RENDER_BLOCK] garson selected but dashboard requested '
        'source=_buildMobileContent',
      );
      debugPrint(StackTrace.current.toString());
      return _buildMobileGarsonModule();
    }
    switch (_selectedModule) {
      case SellerModule.dashboard:
        return _buildMobileDashboardModule();
      case SellerModule.products:
        return _buildMobileProductsModule();
      case SellerModule.collections:
        return _buildMobileCollectionsModule();
      case SellerModule.orders:
        return _buildMobileOrdersModule();
      case SellerModule.garson:
        if (target == SellerPanelRenderTargets.garson) {
          return _buildMobileGarsonModule();
        }
        return _buildSellerModuleUnavailablePlaceholder(
          moduleLabel: _moduleLabel(SellerModule.garson),
        );
      case SellerModule.system:
        if (target == SellerPanelRenderTargets.system) {
          return _buildMobileSystemModule();
        }
        return _buildSellerModuleUnavailablePlaceholder(
          moduleLabel: _moduleLabel(SellerModule.system),
        );
      case SellerModule.store:
        return _buildMobileStoreModule();
      case SellerModule.team:
        return _buildMobileTeamModule();
      case SellerModule.campaigns:
        return _buildMobileCampaignsModule();
      case SellerModule.finance:
        return _buildMobileFinanceModule();
      case SellerModule.reviews:
        return _buildMobileReviewsModule();
      case SellerModule.support:
        return _buildMobileSupportModule();
    }
  }

