  Widget _buildMobileDashboardPerformanceCard({
    required SellerDashboardMetrics metrics,
    required Map<String, int> statusCounts,
    required int totalOrderCount,
    required double completionRate,
  }) {
    final shippingPerformance = _dashboardShippingPerformance(statusCounts);
    final returnRate = _dashboardReturnRate(statusCounts, totalOrderCount);
    return _mobileSurfaceCard(
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          const Text(
            'Performans Metrikleri',
            style: TextStyle(
              fontSize: 16,
              fontWeight: FontWeight.w700,
              color: Color(0xFF1E293B),
            ),
          ),
          const SizedBox(height: 10),
          _buildMobilePerformanceMetricTile(
            icon: Icons.alarm_on_rounded,
            title: 'Zamanında Gönderim',
            value: '${shippingPerformance.toStringAsFixed(0)}%',
            progress: shippingPerformance / 100,
            color: const Color(0xFF6366F1),
          ),
          _buildMobilePerformanceMetricTile(
            icon: Icons.shield_outlined,
            title: 'Sipariş Tamamlama',
            value: '${completionRate.toStringAsFixed(0)}%',
            progress: completionRate / 100,
            color: const Color(0xFF10B981),
          ),
          _buildMobilePerformanceMetricTile(
            icon: Icons.star_border_rounded,
            title: 'Müşteri Puanı',
            value: metrics.storeRating <= 0
                ? '0.0 / 5'
