            color: const Color(0xFFEAB308),
          ),
          _buildMobilePerformanceMetricTile(
            icon: Icons.replay_circle_filled_outlined,
            title: 'İade Oranı',
            value: '${returnRate.toStringAsFixed(1)}%',
            progress: returnRate / 100,
            color: const Color(0xFFEF4444),
          ),
        ],
      ),
    );
