  Widget _buildMobileProductCard(SellerProduct product) {
    final isLowStock = _isLowStockProduct(product);
    final isOutOfStock = product.stock == 0;
    final isTemplate = _isMixedServiceTemplateProduct(product);
    final String? image = _primaryProductImage(product);
    final bool isDeleting = _deletingProductIds.contains(product.id);
    return Padding(
      padding: const EdgeInsets.only(bottom: 10),
      child: _mobileSurfaceCard(
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Row(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                ClipRRect(
                  borderRadius: BorderRadius.circular(10),
                  child: Container(
                    width: 74,
                    height: 74,
                    color: Colors.grey.shade100,
                    child: (image != null && image.isNotEmpty)
                        ? OptimizedImage(
                            imageUrlOrPath: image,
                            fit: BoxFit.cover,
                            cacheWidth: 148,
                            cacheHeight: 148,
                            errorWidget: const Icon(
                              Icons.image_not_supported,
                              color: Colors.grey,
                            ),
                          )
                        : const Icon(Icons.image_outlined, color: Colors.grey),
                  ),
                ),
                const SizedBox(width: 10),
                Expanded(
                  child: Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      Text(
                        product.name.isEmpty ? 'İsimsiz Ürün' : product.name,
                        maxLines: 2,
                        overflow: TextOverflow.ellipsis,
                        style: const TextStyle(
                          fontSize: 14,
                          fontWeight: FontWeight.w700,
                        ),
                      ),
                      const SizedBox(height: 4),
                      if (isTemplate) ...[
                        _templateTypeBadge(
                          product,
                          fontSize: 10,
                          padding: const EdgeInsets.symmetric(
                            horizontal: 8,
                            vertical: 3,
                          ),
                        ),
                        const SizedBox(height: 6),
                      ],
                      Text(
                        isTemplate
                            ? _templateCategoryLabel(product)
                            : product.subCategory.isNotEmpty
                            ? '${product.mainCategory} • ${product.subCategory}'
                            : product.mainCategory,
                        style: TextStyle(
                          fontSize: 12,
                          color: Colors.grey.shade600,
                        ),
                      ),
                      const SizedBox(height: 6),
                      Row(
                        children: [
                          Text(
                            isTemplate
                                ? _templatePreviewPriceLabel(product)
                                : product.displayPrice,
                            style: const TextStyle(
                              fontSize: 15,
                              fontWeight: FontWeight.w800,
                            ),
                          ),
                          if (product.hasDiscount && !isTemplate) ...[
                            const SizedBox(width: 6),
                            Text(
                              product.originalPrice,
                              style: TextStyle(
                                color: Colors.grey.shade500,
                                fontSize: 12,
                                decoration: TextDecoration.lineThrough,
                              ),
                            ),
                          ],
                        ],
                      ),
                    ],
                  ),
                ),
              ],
            ),
            const SizedBox(height: 10),
            Wrap(
              spacing: 8,
              runSpacing: 8,
              children: [
                _mobileBadge('SKU', product.sku),
                _mobileBadge(
                  isTemplate ? 'Tip' : 'Stok',
                  isTemplate ? _templateTypeLabel(product) : '${product.stock}',
                ),
                _mobileBadge('Durum', _getStatusLabel(product.status)),
                if (isOutOfStock)
                  _mobileBadge('Uyarı', 'Stok bitti', color: Colors.red.shade50)
                else if (isLowStock)
                  _mobileBadge(
                    'Uyarı',
                    'Düşük stok',
                    color: Colors.orange.shade50,
                  ),
              ],
            ),
            const SizedBox(height: 10),
            Row(
              children: [
                Expanded(
                  child: OutlinedButton.icon(
                    onPressed: () async {
                      productEditLog(
                        'route_decision',
                        extra: {
                          'productId': product.id,
                          'isTemplate': isTemplate,
                          'resolvedKind':
                              MixedServiceOrder.productTypeFromProduct(product),
                        },
                      );
                      if (isTemplate) {
                        productEditLog(
                          'open_service_editor',
                          extra: {'productId': product.id},
                        );
                        await _openTemplateEditor(existingProduct: product);
                        return;
                      }
                      productEditLog(
                        'open_normal_product_editor',
                        extra: {'productId': product.id},
                      );
                      final result = await Navigator.push(
                        context,
                        MaterialPageRoute(
                          builder: (context) => AddProductPage(
                            isEdit: true,
                            productId: product.id,
                          ),
                        ),
                      );
                      if (result == true) {
                        _refreshProducts();
                      }
                    },
                    icon: const Icon(Icons.edit_outlined, size: 16),
                    label: const Text('Düzenle'),
                  ),
                ),
                const SizedBox(width: 8),
                Expanded(
                  child: OutlinedButton.icon(
                    onPressed: isDeleting
                        ? null
                        : () => _deleteProduct(product.id),
                    icon: isDeleting
                        ? const SizedBox(
                            width: 16,
                            height: 16,
                            child: CircularProgressIndicator(strokeWidth: 2),
                          )
                        : const Icon(
                            Icons.delete_outline,
                            size: 16,
                            color: Colors.red,
                          ),
                    label: Text(isDeleting ? 'Siliniyor' : 'Sil'),
                  ),
                ),
              ],
            ),
          ],
        ),
      ),
    );
  }

