  Widget _buildMobileOrderStageStepper(String? status) {
    final normalizedStatus = (status ?? '').toLowerCase();
    if (normalizedStatus.contains('cancel')) {
      return Container(
        width: double.infinity,
        padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 10),
        decoration: BoxDecoration(
          color: const Color(0xFFFFF1F3),
          borderRadius: BorderRadius.circular(12),
          border: Border.all(color: const Color(0xFFF5C2C7)),
        ),
        child: const Row(
          children: [
            Icon(Icons.cancel_outlined, color: Color(0xFFB42318), size: 18),
            SizedBox(width: 8),
            Text(
              'Sipariş iptal edildi',
              style: TextStyle(
                fontWeight: FontWeight.w700,
                color: Color(0xFFB42318),
              ),
            ),
          ],
        ),
      );
    }
    final stage = _sellerOrderStageIndex(status);
    return Row(
      children: [
        Expanded(
          child: _buildMobileOrderStageNode(
            icon: Icons.error_outline_rounded,
            label: 'Yeni Sipariş',
            active: stage >= 0,
            completed: stage > 0,
          ),
        ),
        _buildMobileOrderStageDivider(completed: stage > 0),
        Expanded(
          child: _buildMobileOrderStageNode(
            icon: Icons.schedule_rounded,
            label: 'Hazırlanıyor',
            active: stage >= 1,
            completed: stage > 1,
          ),
        ),
        _buildMobileOrderStageDivider(completed: stage > 1),
        Expanded(
          child: _buildMobileOrderStageNode(
            icon: Icons.inventory_2_outlined,
            label: 'Hazır',
            active: stage >= 2,
            completed: stage > 2,
          ),
        ),
        _buildMobileOrderStageDivider(completed: stage > 2),
        Expanded(
          child: _buildMobileOrderStageNode(
            icon: Icons.local_shipping_outlined,
            label: 'Kargoda',
            active: stage >= 3,
            completed: stage > 3,
          ),
        ),
      ],
    );
  }

