  bool _canAdvanceMobileOrderStage(String? status) {
    final normalized = (status ?? '').toLowerCase();
    return normalized == 'new' ||
        normalized == 'confirmed' ||
        normalized == 'preparing';
  }

  String _mobilePrepareActionLabel(String? status) {
    final normalized = (status ?? '').toLowerCase();
    if (normalized == 'new' || normalized == 'confirmed') {
      return 'Hazırla';
    }
    if (normalized == 'preparing') {
      return 'Hazırlandı';
    }
    if (normalized == 'ready_to_ship') {
      return 'Kargoya Hazır';
    }
    if (normalized == 'shipped' ||
        normalized == 'transfer' ||
        normalized == 'branch' ||
        normalized == 'out_for_delivery' ||
        normalized == 'delivered') {
      return 'Kargoda';
    }
    return 'İşlem Tamam';
  }

  Future<void> _handleMobilePrepareAction(Map<String, dynamic> order) async {
    final status = (order['status'] ?? '').toString().toLowerCase();
    if (status == 'new' || status == 'confirmed') {
      await _updateOrderStatus(
        order,
        status: 'preparing',
        title: 'Sipariş hazırlanıyor',
        description: 'Satıcı siparişi hazırlamaya başladı.',
      );
      return;
    }
    if (status == 'preparing') {
      await _updateOrderStatus(
        order,
        status: 'ready_to_ship',
        title: 'Sipariş hazırlandı',
        description: 'Sipariş gönderime hazırlandı.',
      );
    }
  }

  Future<void> _showMobilePackagingVideoSheet(
    Map<String, dynamic> order,
  ) async {
    final orderItemId = order['id']?.toString() ?? '';
    if (orderItemId.isNotEmpty) {
      await _loadSelectedSellerOrderHistory(orderItemId);
    }
    if (!mounted) return;
    await showModalBottomSheet<void>(
      context: context,
      isScrollControlled: true,
      backgroundColor: Colors.white,
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.vertical(top: Radius.circular(22)),
      ),
      builder: (sheetContext) {
        return StatefulBuilder(
          builder: (modalContext, setModalState) {
            final status = order['status']?.toString();
            final supportsPackaging = _shouldShowPackagingPanel(status);
            final hasPackagingVideo =
                (_selectedPackagingVideoUrl?.isNotEmpty ?? false) &&
                _selectedPackagingVideoOrderItemId == orderItemId;
            return SafeArea(
              child: SingleChildScrollView(
                padding: EdgeInsets.fromLTRB(
                  16,
                  16,
                  16,
                  MediaQuery.of(modalContext).viewInsets.bottom + 20,
                ),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text(
                      'Paketleme Videosu • ${order['order_number']?.toString() ?? '-'}',
                      style: const TextStyle(
                        fontSize: 16,
                        fontWeight: FontWeight.w800,
                      ),
                    ),
                    const SizedBox(height: 10),
                    if (hasPackagingVideo)
                      ClipRRect(
                        borderRadius: BorderRadius.circular(14),
                        child: SizedBox(
                          height: 220,
                          width: double.infinity,
                          child: VideoPlayerWidget(
                            videoUrl: _selectedPackagingVideoUrl,
                            autoPlay: false,
                            trimStart: _selectedPackagingVideoTrimStart,
                            trimEnd: _selectedPackagingVideoTrimEnd,
                          ),
                        ),
                      )
                    else
                      Container(
                        width: double.infinity,
                        height: 180,
                        decoration: BoxDecoration(
                          color: const Color(0xFFF8F6FF),
                          borderRadius: BorderRadius.circular(14),
                          border: Border.all(color: const Color(0xFFE7DEFF)),
                        ),
                        child: const Column(
                          mainAxisAlignment: MainAxisAlignment.center,
                          children: [
                            Icon(
                              Icons.video_call_outlined,
                              size: 38,
                              color: AppColors.primary,
                            ),
                            SizedBox(height: 8),
                            Text(
                              'Henüz paketleme videosu yok',
                              style: TextStyle(
                                fontWeight: FontWeight.w700,
                                color: Color(0xFF332B4D),
                              ),
                            ),
                          ],
                        ),
                      ),
                    const SizedBox(height: 12),
                    if (!supportsPackaging)
                      Container(
                        width: double.infinity,
                        padding: const EdgeInsets.all(12),
                        decoration: BoxDecoration(
                          color: const Color(0xFFFFF8E7),
                          borderRadius: BorderRadius.circular(12),
                          border: Border.all(color: const Color(0xFFFDE68A)),
                        ),
                        child: const Text(
                          'Paketleme videosu sadece "Hazırlanıyor" veya "Hazır" adımında yönetilebilir.',
                          style: TextStyle(
                            fontSize: 12,
                            fontWeight: FontWeight.w600,
                            color: Color(0xFF92400E),
                          ),
                        ),
                      )
                    else
                      Wrap(
                        spacing: 8,
                        runSpacing: 8,
                        children: [
                          if (!hasPackagingVideo)
                            FilledButton.icon(
                              onPressed: _isUploadingPackagingVideo
                                  ? null
                                  : () async {
                                      await _pickPackagingVideo(order);
                                      if (sheetContext.mounted) {
                                        setModalState(() {});
                                      }
                                    },
                              icon: _isUploadingPackagingVideo
                                  ? const SizedBox(
                                      width: 14,
                                      height: 14,
                                      child: CircularProgressIndicator(
                                        strokeWidth: 2,
                                        valueColor:
                                            AlwaysStoppedAnimation<Color>(
                                              Colors.white,
                                            ),
                                      ),
                                    )
                                  : const Icon(Icons.upload_file_outlined),
                              label: const Text('Video Yükle'),
                            ),
                          if (hasPackagingVideo)
                            OutlinedButton.icon(
                              onPressed:
                                  _isUploadingPackagingVideo ||
                                      _isRemovingPackagingVideo
                                  ? null
                                  : () async {
                                      await _pickPackagingVideo(order);
                                      if (sheetContext.mounted) {
                                        setModalState(() {});
                                      }
                                    },
                              icon: const Icon(Icons.sync_outlined),
                              label: const Text('Değiştir'),
                            ),
                          if (hasPackagingVideo)
                            OutlinedButton.icon(
                              onPressed:
                                  _isUploadingPackagingVideo ||
                                      _isRemovingPackagingVideo
                                  ? null
                                  : () async {
                                      await _showPackagingVideoEditActions(
                                        order,
                                      );
                                      if (sheetContext.mounted) {
                                        setModalState(() {});
                                      }
                                    },
                              icon: const Icon(Icons.edit_outlined),
                              label: const Text('Düzenle'),
                            ),
                          if (hasPackagingVideo)
                            OutlinedButton.icon(
                              onPressed:
                                  _isUploadingPackagingVideo ||
                                      _isRemovingPackagingVideo
                                  ? null
                                  : () async {
                                      await _removePackagingVideo(order);
                                      if (sheetContext.mounted) {
                                        setModalState(() {});
                                      }
                                    },
                              icon: const Icon(Icons.delete_outline),
                              label: const Text('Kaldır'),
                            ),
                        ],
                      ),
                    if (_isUploadingPackagingVideo) ...[
                      const SizedBox(height: 12),
                      LinearProgressIndicator(
                        value: _packagingVideoUploadProgress <= 0
                            ? null
                            : _packagingVideoUploadProgress.clamp(0.0, 1.0),
                        minHeight: 8,
                        borderRadius: BorderRadius.circular(999),
                        backgroundColor: const Color(0xFFEAE7F5),
                        valueColor: const AlwaysStoppedAnimation<Color>(
                          AppColors.primary,
                        ),
                      ),
                      const SizedBox(height: 8),
                      Text(
                        _packagingUploadStatusText(),
                        style: const TextStyle(
                          fontSize: 12,
                          fontWeight: FontWeight.w700,
                          color: Color(0xFF475467),
                        ),
                      ),
                      if (_packagingUploadMetaText() != null) ...[
                        const SizedBox(height: 4),
                        Text(
                          _packagingUploadMetaText()!,
                          style: const TextStyle(
                            fontSize: 11,
                            fontWeight: FontWeight.w600,
                            color: Color(0xFF667085),
                          ),
                        ),
                      ],
                    ],
                  ],
                ),
              ),
            );
          },
        );
      },
    );
  }

  Widget _buildMobileOrderCard(Map<String, dynamic> order) {
    final statusColor = _sellerOrderStatusColor(order['status']?.toString());
    final orderNo = order['order_number']?.toString() ?? '-';
    final dateText = _formatSellerOrderDate(
      order['order_created_at']?.toString(),
    );
    final total =
        ((order['total_price'] ??
                    order['totalPrice'] ??
                    order['total_amount'] ??
                    order['totalAmount'] ??
                    0)
                as num)
            .toDouble();
    final itemCount = _sellerOrderItemCount(order);
    return Padding(
      padding: const EdgeInsets.only(bottom: 10),
      child: _mobileSurfaceCard(
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Row(
              children: [
                Expanded(
                  child: Text(
                    orderNo,
                    style: const TextStyle(
                      fontSize: 15,
                      fontWeight: FontWeight.w800,
                    ),
                  ),
                ),
                Container(
                  padding: const EdgeInsets.symmetric(
                    horizontal: 8,
                    vertical: 4,
                  ),
                  decoration: BoxDecoration(
                    color: statusColor.withValues(alpha: 0.12),
                    borderRadius: BorderRadius.circular(999),
                  ),
                  child: Text(
                    _sellerOrderStatusLabel(order['status']?.toString()),
                    style: TextStyle(
                      color: statusColor,
                      fontSize: 11,
                      fontWeight: FontWeight.w700,
                    ),
                  ),
                ),
              ],
            ),
            const SizedBox(height: 6),
            Text(
              dateText,
              style: TextStyle(fontSize: 12, color: Colors.grey.shade600),
            ),
            const SizedBox(height: 10),
            Row(
              children: [
                Text(
                  _formatDashboardCurrency(total),
                  style: const TextStyle(
                    fontSize: 15,
                    fontWeight: FontWeight.w800,
                  ),
                ),
                const Spacer(),
                Text(
                  '$itemCount ürün',
                  style: const TextStyle(
                    fontSize: 12,
                    fontWeight: FontWeight.w700,
                    color: Color(0xFF64748B),
                  ),
                ),
              ],
            ),
            const SizedBox(height: 10),
            SizedBox(
              width: double.infinity,
              child: OutlinedButton.icon(
                onPressed: () => _showMobileOrderDetailSheet(order),
                icon: const Icon(Icons.visibility_outlined, size: 17),
                label: const Text('Detay'),
                style: OutlinedButton.styleFrom(
                  foregroundColor: AppColors.primary,
                  side: const BorderSide(color: Color(0xFFCBD5E1)),
                ),
              ),
            ),
          ],
        ),
      ),
    );
  }

  Future<void> _showMobileOrderDetailSheet(Map<String, dynamic> order) async {
    final orderItemId = order['id']?.toString() ?? '';
    if (orderItemId.isNotEmpty) {
      await _loadSelectedSellerOrderHistory(orderItemId);
    }
    if (!mounted) return;
    await Navigator.of(context).push(
      MaterialPageRoute<void>(
        builder: (pageContext) {
          bool isVideoBusy = false;
          bool isStatusBusy = false;
          return StatefulBuilder(
            builder: (detailContext, setDetailState) {
              final latestOrder =
                  (orderItemId.isNotEmpty
                      ? _sellerOrderById[orderItemId]
                      : null) ??
                  order;
              final status = latestOrder['status']?.toString();
              final canAdvance = _canAdvanceMobileOrderStage(status);
              final prepareLabel = _mobilePrepareActionLabel(status);
              final customerName = _sellerOrderCustomerName(latestOrder);
              final customerPhone = _sellerOrderCustomerPhone(latestOrder);
              final region = _sellerOrderRegion(latestOrder);
              final addressPreview = _sellerOrderAddressPreview(latestOrder);
              final tags = _sellerOrderPreviewTags(latestOrder);
              final trackingNo =
                  (latestOrder['tracking_number']
                          ?.toString()
                          .trim()
                          .isNotEmpty ??
                      false)
                  ? latestOrder['tracking_number'].toString().trim()
                  : '-';
              final total =
                  ((latestOrder['total_price'] ??
                              latestOrder['totalPrice'] ??
                              latestOrder['total_amount'] ??
                              latestOrder['totalAmount'] ??
                              0)
                          as num)
                      .toDouble();
              final itemCount = _sellerOrderItemCount(latestOrder);
              final hasPackagingVideo =
                  (_selectedPackagingVideoUrl?.isNotEmpty ?? false) &&
                  _selectedPackagingVideoOrderItemId == orderItemId;
              final showPackagingPanel = _shouldShowPackagingPanel(status);
              return Scaffold(
                backgroundColor: const Color(0xFFF5F7FB),
                appBar: AppBar(
                  backgroundColor: Colors.white,
                  elevation: 0.8,
                  titleSpacing: 0,
                  title: Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      const Text(
                        'Sipariş Detayı',
                        style: TextStyle(
                          fontSize: 16,
                          fontWeight: FontWeight.w800,
                          color: Color(0xFF0F172A),
                        ),
                      ),
                      Text(
                        latestOrder['order_number']?.toString() ?? '-',
                        style: const TextStyle(
                          fontSize: 12,
                          color: Color(0xFF64748B),
                          fontWeight: FontWeight.w600,
                        ),
                      ),
                    ],
                  ),
                  actions: [
                    IconButton(
                      tooltip: 'PDF',
                      onPressed: () =>
                          _downloadShipmentLabel(latestOrder, 'pdf'),
                      icon: const Icon(
                        Icons.picture_as_pdf_outlined,
                        color: AppColors.primary,
                      ),
                    ),
                    IconButton(
                      tooltip: 'Yenile',
                      onPressed: orderItemId.isEmpty
