  Widget _buildMobileSystemModule() {
    final sellerId = _authService.currentUser?.id ?? '';
    final tables = List<Map<String, dynamic>>.from(
      _storeTables,
    )..sort((a, b) => _tableNumberFromRow(a).compareTo(_tableNumberFromRow(b)));
    return ListView(
      padding: const EdgeInsets.only(bottom: 8),
      physics: const BouncingScrollPhysics(),
      children: [
        _buildMobileModuleHero(
          title: 'Sistem • Masa QR',
          subtitle: 'QR masalarını oluştur, indir ve yönet',
          icon: Icons.qr_code_rounded,
          primary: const Color(0xFF7C3AED),
          secondary: const Color(0xFF8B5CF6),
        ),
        const SizedBox(height: 10),
        _mobileSurfaceCard(
          child: Wrap(
            spacing: 8,
            runSpacing: 8,
            children: [
              _mobileBadge('Aktif Masa', '${tables.length}'),
              FilledButton.icon(
                onPressed: _isMutatingStoreTables ? null : _addStoreTable,
                icon: const Icon(Icons.add),
                label: const Text('Masa Ekle'),
              ),
              OutlinedButton.icon(
                onPressed: sellerId.isEmpty
                    ? null
                    : () {
                        Navigator.push(
                          context,
                          MaterialPageRoute(
                            builder: (_) => KitchenPrintManagementPage(
                              restaurantId: sellerId,
                            ),
                          ),
                        );
                      },
                icon: const Icon(Icons.print_outlined),
                label: const Text('Yazıcı Ayarları'),
              ),
              OutlinedButton.icon(
                onPressed: sellerId.isEmpty
                    ? null
                    : () {
                        Navigator.push(
                          context,
                          MaterialPageRoute(
                            builder: (_) =>
                                KitchenDisplayScreen(sellerId: sellerId),
                          ),
                        );
                      },
                icon: const Icon(Icons.restaurant_menu_outlined),
                label: const Text('Mutfak Ekranı'),
              ),
              OutlinedButton.icon(
                onPressed: sellerId.isEmpty
                    ? null
                    : () {
                        Navigator.push(
                          context,
                          MaterialPageRoute(
                            builder: (_) => TableHistoryScreen(
                              sellerId: sellerId,
                              onReprint: _printHistoryKitchenTicket,
                              onPrintAdisyon: _printHistoryAdisyon,
                            ),
                          ),
                        );
                      },
                icon: const Icon(Icons.history_outlined),
                label: const Text('Geçmiş Masalar'),
              ),
              OutlinedButton.icon(
                onPressed: sellerId.isEmpty
                    ? null
                    : () {
                        Navigator.push(
                          context,
                          MaterialPageRoute(
                            builder: (_) =>
                                WaiterPerformanceScreen(sellerId: sellerId),
                          ),
                        );
                      },
                icon: const Icon(Icons.people_alt_outlined),
                label: const Text('Garson Analitik'),
              ),
              if (tables.isEmpty)
                OutlinedButton.icon(
                  onPressed: _isMutatingStoreTables
                      ? null
                      : _initializeDefaultStoreTables,
                  icon: const Icon(Icons.auto_fix_high_outlined),
                  label: const Text('Varsayılan Oluştur'),
                ),
            ],
          ),
        ),
        const SizedBox(height: 10),
        if (_isLoadingStoreTables)
          const Center(child: CircularProgressIndicator())
        else if (sellerId.isEmpty)
          _mobileSurfaceCard(
            child: const Center(child: Text('Satıcı oturumu bulunamadı.')),
          )
        else if (tables.isEmpty)
          _mobileSurfaceCard(
            child: Text(
              'Henüz masa kaydı yok. Masa ekledikçe QR otomatik oluşturulur.',
              style: TextStyle(color: Colors.grey.shade700),
            ),
          )
        else
          GridView.builder(
            shrinkWrap: true,
            physics: const NeverScrollableScrollPhysics(),
            itemCount: tables.length,
            gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(
              crossAxisCount: 3,
              crossAxisSpacing: 8,
              mainAxisSpacing: 8,
              childAspectRatio: 0.58,
            ),
            itemBuilder: (context, index) {
              final table = tables[index];
              return _buildMobileSystemTableCard(
                table,
                sellerId: sellerId,
                compact: true,
              );
            },
          ),
      ],
    );
  }

  Widget _buildMobileSystemTableCard(
    Map<String, dynamic> table, {
    required String sellerId,
    bool compact = false,
  }) {
    final tableNumber = _tableNumberFromRow(table);
    final token = table['qr_token']?.toString() ?? '';
    final qrLink = _buildTableQrLink(
      sellerId: sellerId,
      tableNumber: tableNumber,
      token: token,
    );
    final qrImageUrl = _buildTableQrImageUrl(qrLink);
    if (compact) {
      return _mobileSurfaceCard(
        padding: const EdgeInsets.all(8),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Row(
              children: [
                const Icon(
                  Icons.table_restaurant_outlined,
                  color: AppColors.primary,
                  size: 14,
                ),
                const SizedBox(width: 4),
                Expanded(
                  child: Text(
                    'Masa $tableNumber',
                    maxLines: 1,
                    overflow: TextOverflow.ellipsis,
                    style: const TextStyle(
                      fontSize: 11,
                      fontWeight: FontWeight.w800,
                    ),
                  ),
                ),
                IconButton(
                  onPressed: _isMutatingStoreTables
                      ? null
                      : () => _removeStoreTable(table),
                  tooltip: 'Masayı Sil',
                  padding: EdgeInsets.zero,
                  constraints: const BoxConstraints(
                    minWidth: 24,
                    minHeight: 24,
                  ),
                  iconSize: 16,
                  visualDensity: VisualDensity.compact,
                  icon: const Icon(Icons.delete_outline, color: Colors.red),
                ),
              ],
            ),
            const SizedBox(height: 6),
            ClipRRect(
              borderRadius: BorderRadius.circular(8),
              child: OptimizedImage(
                imageUrlOrPath: qrImageUrl,
                width: double.infinity,
                height: 86,
                fit: BoxFit.cover,
                errorBuilder: (_, _, _) => Container(
                  height: 86,
                  color: Colors.grey.shade100,
                  alignment: Alignment.center,
                  child: const Icon(Icons.qr_code_2, size: 26),
                ),
              ),
            ),
            const SizedBox(height: 6),
            Row(
              children: [
                Expanded(
                  child: Tooltip(
                    message: 'PDF indir',
                    child: InkWell(
                      borderRadius: BorderRadius.circular(8),
                      onTap: () => _downloadTableQrPdf(
                        tableNumber: tableNumber,
                        qrImageUrl: qrImageUrl,
                        qrLink: qrLink,
                      ),
                      child: Container(
                        height: 30,
                        decoration: BoxDecoration(
                          color: const Color(0xFFF3F4F6),
                          borderRadius: BorderRadius.circular(8),
                        ),
                        child: const Icon(Icons.download_rounded, size: 15),
                      ),
                    ),
                  ),
                ),
                const SizedBox(width: 4),
                Expanded(
                  child: Tooltip(
                    message: 'Link kopyala',
                    child: InkWell(
                      borderRadius: BorderRadius.circular(8),
                      onTap: () => _copyTableQrLink(qrLink),
                      child: Container(
                        height: 30,
                        decoration: BoxDecoration(
                          color: const Color(0xFFF3F4F6),
                          borderRadius: BorderRadius.circular(8),
                        ),
                        child: const Icon(Icons.copy_rounded, size: 15),
                      ),
                    ),
                  ),
                ),
                const SizedBox(width: 4),
                Expanded(
                  child: Tooltip(
                    message: 'Büyüt',
                    child: InkWell(
                      borderRadius: BorderRadius.circular(8),
                      onTap: () => _showTableQrDialog(
                        tableNumber: tableNumber,
                        qrImageUrl: qrImageUrl,
                        qrLink: qrLink,
                      ),
                      child: Container(
                        height: 30,
                        decoration: BoxDecoration(
                          color: const Color(0xFFF3F4F6),
                          borderRadius: BorderRadius.circular(8),
                        ),
                        child: const Icon(Icons.open_in_new_rounded, size: 15),
                      ),
                    ),
                  ),
                ),
              ],
            ),
          ],
        ),
      );
    }
    return _mobileSurfaceCard(
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            children: [
              const Icon(
                Icons.table_restaurant_outlined,
                color: AppColors.primary,
              ),
              const SizedBox(width: 8),
              Text(
                'Masa $tableNumber',
                style: const TextStyle(fontWeight: FontWeight.w700),
              ),
              const Spacer(),
              IconButton(
                onPressed: _isMutatingStoreTables
                    ? null
                    : () => _removeStoreTable(table),
                tooltip: 'Masayı Sil',
                visualDensity: VisualDensity.compact,
                icon: const Icon(Icons.delete_outline, color: Colors.red),
              ),
            ],
          ),
          const SizedBox(height: 10),
          ClipRRect(
            borderRadius: BorderRadius.circular(12),
            child: OptimizedImage(
              imageUrlOrPath: qrImageUrl,
              width: double.infinity,
              height: 210,
              fit: BoxFit.cover,
              errorBuilder: (_, _, _) => Container(
                height: 210,
                color: Colors.grey.shade100,
                alignment: Alignment.center,
                child: const Icon(Icons.qr_code_2, size: 56),
              ),
            ),
          ),
          const SizedBox(height: 8),
          SelectableText(
            qrLink,
            style: TextStyle(fontSize: 11, color: Colors.grey.shade700),
          ),
          const SizedBox(height: 8),
          Wrap(
            spacing: 8,
            runSpacing: 8,
            children: [
              FilledButton.icon(
                onPressed: () => _downloadTableQrPdf(
                  tableNumber: tableNumber,
                  qrImageUrl: qrImageUrl,
                  qrLink: qrLink,
                ),
                icon: const Icon(Icons.download_rounded, size: 15),
                label: const Text('PDF'),
              ),
              OutlinedButton.icon(
                onPressed: () => _copyTableQrLink(qrLink),
                icon: const Icon(Icons.copy, size: 15),
                label: const Text('Linki Kopyala'),
              ),
              OutlinedButton.icon(
                onPressed: () => _showTableQrDialog(
                  tableNumber: tableNumber,
                  qrImageUrl: qrImageUrl,
                  qrLink: qrLink,
                ),
                icon: const Icon(Icons.open_in_new, size: 15),
                label: const Text('Büyüt'),
              ),
            ],
          ),
        ],
      ),
    );
  }

  List<Map<String, dynamic>> _cloneGarsonItems(
    List<Map<String, dynamic>> items,
  ) {
    return items
        .map((item) => Map<String, dynamic>.from(item))
        .toList(growable: false);
  }

  void _onMobileGarsonDraftChanged(
    int tableNumber,
    List<Map<String, dynamic>> draftItems,
  ) {
    if (!mounted) return;
    setState(() {
      if (draftItems.isEmpty) {
        _mobileGarsonDraftItemsByTable.remove(tableNumber);
        _mobileGarsonDraftUpdatedAtByTable.remove(tableNumber);
      } else {
        _mobileGarsonDraftItemsByTable[tableNumber] = _cloneGarsonItems(
          draftItems,
        );
        _mobileGarsonDraftUpdatedAtByTable[tableNumber] = DateTime.now();
      }
      if (draftItems.isNotEmpty) {
        _mobileGarsonOptimisticSentAtByTable.remove(tableNumber);
        _mobileGarsonOptimisticItemsByTable.remove(tableNumber);
      }
    });
  }

  void _onMobileGarsonOrderSubmitted(
    int tableNumber,
    List<Map<String, dynamic>> items,
    Map<String, dynamic> submittedOrder,
  ) {
    if (!mounted) return;
    final enrichedOrder = _enrichGarsonSubmittedOrderForGrid(
      tableNumber: tableNumber,
      submittedOrder: submittedOrder,
      items: items,
    );
    debugPrint(
      '[GARSON_ORDER_SUBMIT_RESULT] '
      'table_id=${enrichedOrder['table_id'] ?? enrichedOrder['store_table_id'] ?? '-'} '
      'table_number=${enrichedOrder['table_number'] ?? tableNumber} '
      'display_table_label=${enrichedOrder['display_table_label'] ?? enrichedOrder['table_display_name'] ?? enrichedOrder['table_name'] ?? '-'} '
      'area_name=${enrichedOrder['area_name'] ?? enrichedOrder['table_area_name'] ?? '-'} '
      'area_table_number=${enrichedOrder['area_table_number'] ?? '-'} '
      'order_id=${enrichedOrder['id'] ?? '-'} '
      'active_order_id=${enrichedOrder['id'] ?? '-'} '
      'items_count=${items.length} '
      'total=${_garsonOrdersTotal(<Map<String, dynamic>>[enrichedOrder])} '
      'submit_ok=true',
    );
    setState(() {
      _invalidateSellerTableOrdersFallbackFuture();
      _garsonManualTableOrders = _mergeGarsonSubmittedOrderIntoParentState(
        submittedOrder: enrichedOrder,
      );
      _garsonManualTableOrdersSellerId = _resolveGarsonSellerId().trim();
      _garsonManualTableOrdersSignature = tableOrdersListSignature(
        _garsonManualTableOrders,
      );
      _hasLoadedGarsonTableOrdersData = true;
      _mobileGarsonDraftItemsByTable.remove(tableNumber);
      _mobileGarsonDraftUpdatedAtByTable.remove(tableNumber);
      _mobileGarsonOptimisticSentAtByTable[tableNumber] = DateTime.now();
      _mobileGarsonOptimisticItemsByTable[tableNumber] = _cloneGarsonItems(
        items,
      );
    });
    _publishGarsonVisibleOrders(_garsonManualTableOrders);
    unawaited(_refreshGarsonGridAfterOrderSubmit(tableNumber: tableNumber));
  }

  Map<String, dynamic> _enrichGarsonSubmittedOrderForGrid({
    required int tableNumber,
    required Map<String, dynamic> submittedOrder,
    required List<Map<String, dynamic>> items,
  }) {
    final tableRow = _storeTableRowByNumber(tableNumber);
    final tableId = tableRow?['id'];
    final sellerId = tableRow?['seller_id'];
    final tableFields = resolvePrintableTablePayloadFields(
      tableRow: tableRow,
      tableNumber: tableNumber,
    );
    return <String, dynamic>{
      ...submittedOrder,
      ...tableFields,
      'items': _cloneGarsonItems(items),
      if (tableId != null) 'table_id': tableId,
      if (tableId != null) 'store_table_id': tableId,
      if (sellerId != null) 'seller_id': sellerId,
    };
  }

  List<Map<String, dynamic>> _mergeGarsonSubmittedOrderIntoParentState({
    required Map<String, dynamic> submittedOrder,
  }) {
    final current = _garsonManualTableOrders.isNotEmpty
        ? _garsonManualTableOrders
        : _garsonOrdersSnapshotForUi();
    final merged = mergeGarsonTableOrders(<Map<String, dynamic>>[
      ...current,
      Map<String, dynamic>.from(submittedOrder),
    ], fallbackTableNumber: _garsonTableNumberFromOrder(submittedOrder));
    return merged;
  }

  Future<void> _refreshGarsonGridAfterOrderSubmit({
    required int tableNumber,
  }) async {
    final refreshed = await _loadGarsonTableOrdersSnapshot(
      source: 'garson_order_submit',
      showError: false,
    );
    if (!mounted) return;
    final currentOrders = _resolveGarsonTableOrdersForUi(
      _garsonOrdersSnapshotForUi(),
    );
    final matchedOrder = currentOrders
        .where((order) => _garsonTableNumberFromOrder(order) == tableNumber)
        .cast<Map<String, dynamic>?>()
        .firstWhere(
          (order) =>
              order != null &&
              !_isGarsonCompletedStatus(order['status']?.toString()),
          orElse: () => currentOrders
              .where(
                (order) => _garsonTableNumberFromOrder(order) == tableNumber,
              )
              .cast<Map<String, dynamic>?>()
              .firstWhere((_) => true, orElse: () => null),
        );
    final tableRow = _storeTableRowByNumber(tableNumber);
    final cardStatus = _mobileGarsonStatusLabel(
      matchedOrder?['status']?.toString(),
      hasOrder: matchedOrder != null,
    );
    debugPrint(
      '[GARSON_TABLE_REFRESH_AFTER_SUBMIT] '
      'table_count=${_storeTables.length} '
      'active_orders_count=${currentOrders.where((order) => !_isGarsonCompletedStatus(order['status']?.toString())).length} '
      'matched_table_id=${tableRow?['id'] ?? matchedOrder?['table_id'] ?? matchedOrder?['store_table_id'] ?? '-'} '
      'matched_table_number=$tableNumber '
      'matched_display_label=${tableRow == null ? '-' : _tableDisplayLabelFromRow(tableRow)} '
      'matched_order_id=${matchedOrder?['id'] ?? '-'} '
      'card_status=$cardStatus '
      'refreshed=$refreshed',
    );
    if (!refreshed) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text(
            'Sipariş kaydedildi ama masa durumu yenilenemedi. Yenile butonuna basın.',
          ),
          duration: Duration(seconds: 5),
        ),
      );
    }
  }

  Widget _buildMobileGarsonModule() {
    final sellerId = _resolveGarsonSellerId();
    _garsonBuildRenderCount += 1;
    debugPrint(
      '[GarsonBuild][render] '
      'buildId=$_garsonBuildRenderCount '
      'pendingChanges=${_garsonHasPendingRemoteChanges.value} '
      'refreshGeneration=$_garsonManualRefreshGeneration',
    );
    return ListView(
      padding: const EdgeInsets.only(bottom: 8),
      physics: const BouncingScrollPhysics(),
      children: [
        _buildMobileModuleHero(
          title: 'Garson • Masa Siparişleri',
          subtitle: 'Masa bazlı siparişleri canlı takip et',
          icon: Icons.room_service_rounded,
          primary: const Color(0xFF9A3412),
          secondary: const Color(0xFFF97316),
        ),
        const SizedBox(height: 10),
        if (kIsWeb) ...[
          _buildPrinterServiceCompactBar(uiBranch: 'mobile_garson_panel'),
          const SizedBox(height: 8),
        ],
        if (sellerId.isEmpty)
          _mobileSurfaceCard(
            child: const Center(child: Text('Satıcı oturumu bulunamadı.')),
          )
        else
          StreamBuilder<List<Map<String, dynamic>>>(
            initialData: _garsonOrdersSnapshotForUi(),
            stream: _garsonVisibleOrdersController.stream,
            builder: (ctx, snapshot) {
              if (snapshot.hasError) {
                _handleGarsonRealtimeError(snapshot.error!, sellerId: sellerId);
                return FutureBuilder<List<Map<String, dynamic>>>(
                  future: _getSellerTableOrdersFallbackFuture(sellerId),
                  builder: (context, fallbackSnapshot) {
                    final allOrders = _resolveGarsonTableOrdersForUi(
                      fallbackSnapshot.data,
                    );
                    if (_shouldShowGarsonInitialLoadingUi(allOrders)) {
                      return const Center(child: CircularProgressIndicator());
                    }
                    if (fallbackSnapshot.hasError &&
                        allOrders.isEmpty &&
                        _storeTables.isEmpty) {
                      return _mobileSurfaceCard(
                        child: Text('Hata: ${fallbackSnapshot.error}'),
                      );
                    }
                    final orders = allOrders;
                    final now = DateTime.now();

                    if (_garsonInitialLoadError != null &&
                        orders.isEmpty &&
                        _storeTables.isEmpty &&
                        !_isGarsonInitialLoading) {
                      return _buildGarsonInitialLoadErrorState();
                    }

                    if (orders.isEmpty &&
                        _storeTables.isEmpty &&
                        !_isGarsonInitialLoading) {
                      return _buildGarsonEmptyState(
                        message:
                            'Henüz masa/sipariş verisi yok. Yenile’ye bas.',
                      );
                    }

                    final ordersByTable = <int, List<Map<String, dynamic>>>{};
                    for (final order in orders) {
                      final tableNo = _garsonTableNumberFromOrder(order);
                      if (tableNo <= 0) continue;
                      ordersByTable
                          .putIfAbsent(tableNo, () => <Map<String, dynamic>>[])
                          .add(order);
                    }
                    for (final entry in ordersByTable.entries) {
                      entry.value.sort(
                        (a, b) =>
                            _garsonOrderCreatedAt(
                              b['created_at']?.toString(),
                            ).compareTo(
                              _garsonOrderCreatedAt(
                                a['created_at']?.toString(),
                              ),
                            ),
                      );
                    }
                    final selectedOrderByTable = <int, Map<String, dynamic>>{};
                    for (final entry in ordersByTable.entries) {
                      final preferred = entry.value.firstWhere(
                        (order) => !_isGarsonCompletedStatus(
                          order['status']?.toString(),
                        ),
                        orElse: () => entry.value.first,
                      );
                      selectedOrderByTable[entry.key] = preferred;
                    }
                    
                    // Include optimistic/draft items in selected orders map
                    final currentTime = DateTime.now();
                    for (final tableNumber in _mobileGarsonOptimisticSentAtByTable.keys) {
                      final optimisticAt = _mobileGarsonOptimisticSentAtByTable[tableNumber];
                      if (optimisticAt != null &&
                          currentTime.difference(optimisticAt) <= const Duration(seconds: 45)) {
                        final optimisticItems = _mobileGarsonOptimisticItemsByTable[tableNumber];
                        if (optimisticItems != null && optimisticItems.isNotEmpty && !selectedOrderByTable.containsKey(tableNumber)) {
                          selectedOrderByTable[tableNumber] = <String, dynamic>{
                            'status': 'sent',
                            'created_at': optimisticAt.toIso8601String(),
                            'items': optimisticItems,
                            'table_number': tableNumber,
                            '_is_optimistic': true,
                          };
                        }
                      }
                    }

                    final draftTableNumbers = _mobileGarsonDraftItemsByTable
                        .entries
                        .where((entry) => entry.value.isNotEmpty)
                        .map((entry) => entry.key)
                        .toSet();
                    final optimisticTableNumbers =
                        _mobileGarsonOptimisticSentAtByTable.entries
                            .where((entry) {
                              final at = entry.value;
                              return now.difference(at) <=
                                  const Duration(seconds: 45);
                            })
                            .map((entry) => entry.key)
                            .toSet();

                    final tableNumbers = _garsonTableNumbersForGrid(
                      orderTableNumbers: ordersByTable.keys.toList(
                        growable: false,
                      ),
                    );
                    if (tableNumbers.isEmpty) {
                      return _mobileSurfaceCard(
                        child: Text(
                          'Henüz masa kaydı yok. Sistem bölümünden masa ekleyin.',
                          style: TextStyle(color: Colors.grey.shade600),
                        ),
                      );
                    }
                    final filteredTableNumbers = tableNumbers
                        .where(_matchesGarsonAreaFilter)
                        .toList(growable: false);
                    final activeTableNumbers = <int>{};
                    for (final entry in ordersByTable.entries) {
                      final hasActiveOrder = entry.value.any(
                        (order) => !_isGarsonCompletedStatus(
                          order['status']?.toString(),
                        ),
                      );
                      if (hasActiveOrder) activeTableNumbers.add(entry.key);
                    }
                    activeTableNumbers.addAll(draftTableNumbers);
                    activeTableNumbers.addAll(optimisticTableNumbers);
                    final activeTableCount = activeTableNumbers.length;
                    final waitingCount = orders
                        .where(
                          (o) =>
                              _isGarsonWaitingStatus(o['status']?.toString()),
                        )
                        .map(_garsonTableNumberFromOrder)
                        .where((tableNo) => tableNo > 0)
                        .toSet()
                        .length;
                    final preparingCount = orders
                        .where(
                          (o) => (o['status']?.toString() ?? '') == 'preparing',
                        )
                        .map(_garsonTableNumberFromOrder)
                        .where((tableNo) => tableNo > 0)
                        .toSet()
                        .length;
                    final mutfaktaCount = orders
                        .where((o) {
                          final s = (o['status']?.toString() ?? '')
                              .toLowerCase();
                          return s == 'sent' || s == 'done';
                        })
                        .map(_garsonTableNumberFromOrder)
                        .where((n) => n > 0)
                        .toSet()
                        .length;

                    return Column(
                      children: [
                        Padding(
                          padding: const EdgeInsets.fromLTRB(12, 0, 12, 8),
                          child: _mobileSurfaceCard(
                            child: Row(
                              children: [
                                const Icon(
                                  Icons.map_outlined,
                                  size: 18,
                                  color: Color(0xFF0F172A),
                                ),
                                const SizedBox(width: 8),
                                const Text(
                                  'Alan Seç',
                                  style: TextStyle(fontWeight: FontWeight.w800),
                                ),
                                const SizedBox(width: 10),
                                Expanded(
                                  child: DropdownButtonHideUnderline(
                                    child: DropdownButton<String>(
                                      isExpanded: true,
                                      value:
                                          _garsonAreaOptions().any(
                                            (o) =>
                                                o.key == _garsonAreaFilterKey,
                                          )
                                          ? _garsonAreaFilterKey
                                          : 'all',
                                      items: _garsonAreaOptions()
                                          .map(
                                            (o) => DropdownMenuItem<String>(
                                              value: o.key,
                                              child: Text(
                                                o.label,
                                                overflow: TextOverflow.ellipsis,
                                              ),
                                            ),
                                          )
                                          .toList(growable: false),
                                      onChanged: (value) {
                                        final next = (value ?? 'all').trim();
                                        if (next.isEmpty) return;
                                        setState(
                                          () => _garsonAreaFilterKey = next,
                                        );
                                        unawaited(
                                          _persistGarsonAreaFilter(next),
                                        );
                                      },
                                    ),
                                  ),
                                ),
                              ],
                            ),
                          ),
                        ),
                        Padding(
                          padding: const EdgeInsets.fromLTRB(12, 0, 12, 8),
                          child: Wrap(
                            spacing: 8,
                            runSpacing: 8,
                            children: [
                              _mobileBadge('Dolu Masa', '$activeTableCount'),
                              _mobileBadge('Yeni', '$waitingCount'),
                              _mobileBadge('Mutfakta', '$mutfaktaCount'),
                              _mobileBadge('Hazırlanıyor', '$preparingCount'),
                              _buildLocalPrintStatusBadge(
                                uiBranch: 'mobile_garson_fallback_summary',
                              ),
                            ],
                          ),
                        ),
                        _buildGarsonGroupedTableGrids(
                          groups: _garsonTableAreaGroupsForNumbers(
                            filteredTableNumbers,
                          ),
                          occupiedTableNumbers: activeTableNumbers,
                          columnsResolver: _mobileGarsonGridColumns,
                          aspectRatioResolver: _mobileGarsonGridAspectRatio,
                          sectionPadding: const EdgeInsets.fromLTRB(
                            12,
                            0,
                            12,
                            0,
                          ),
                          cardBuilder: (tableNumber) {
                            final tableOrders =
                                ordersByTable[tableNumber] ??
                                const <Map<String, dynamic>>[];
                            final order = selectedOrderByTable[tableNumber];
                            // Check for optimistic items (submitted but not yet DB-confirmed)
                            final optimisticItems = _mobileGarsonOptimisticItemsByTable[tableNumber];
                            final hasOptimistic = _mobileGarsonOptimisticSentAtByTable[tableNumber] != null &&
                                now.difference(_mobileGarsonOptimisticSentAtByTable[tableNumber]!) <=
                                    const Duration(seconds: 45);
                            return _buildMobileGarsonTableCard(
                              tableNumber: tableNumber,
                              order: order,
                              orderCount: tableOrders.length,
                              optimisticItems: hasOptimistic ? optimisticItems : null,
                            );
                          },
                        ),
                      ],
                    );
                  },
                );
              }
              final allOrders = _resolveGarsonTableOrdersForUi(snapshot.data);
              final orders = allOrders;
              final now = DateTime.now();

              if (_shouldShowGarsonInitialLoadingUi(orders)) {
                return _buildGarsonTablesLoadingPlaceholder();
              }

              if (_garsonInitialLoadError != null &&
                  orders.isEmpty &&
                  _storeTables.isEmpty &&
                  !_isGarsonInitialLoading) {
                return _buildGarsonInitialLoadErrorState();
              }

              if (orders.isEmpty &&
                  _storeTables.isEmpty &&
                  !_isGarsonInitialLoading) {
                return _buildGarsonEmptyState(
                  message: 'Henüz masa/sipariş verisi yok. Yenile’ye bas.',
                );
              }

              final ordersByTable = <int, List<Map<String, dynamic>>>{};
              for (final order in orders) {
                final tableNo = _garsonTableNumberFromOrder(order);
                if (tableNo <= 0) continue;
                ordersByTable
                    .putIfAbsent(tableNo, () => <Map<String, dynamic>>[])
                    .add(order);
              }
              for (final entry in ordersByTable.entries) {
                entry.value.sort((a, b) {
                  final left =
                      garsonOrderActivityAt(a) ??
                      _garsonOrderCreatedAt(a['created_at']?.toString());
                  final right =
                      garsonOrderActivityAt(b) ??
                      _garsonOrderCreatedAt(b['created_at']?.toString());
                  return right.compareTo(left);
                });
              }
              final selectedOrderByTable = <int, Map<String, dynamic>>{};
              for (final entry in ordersByTable.entries) {
                final preferred = entry.value.firstWhere(
                  (order) =>
                      !_isGarsonCompletedStatus(order['status']?.toString()),
                  orElse: () => entry.value.first,
                );
                selectedOrderByTable[entry.key] = preferred;
              }

              final draftTableNumbers = _mobileGarsonDraftItemsByTable.entries
                  .where((entry) => entry.value.isNotEmpty)
                  .map((entry) => entry.key)
                  .toSet();
              final optimisticTableNumbers =
                  _mobileGarsonOptimisticSentAtByTable.entries
                      .where((entry) {
                        final at = entry.value;
                        return now.difference(at) <=
                            const Duration(seconds: 45);
                      })
                      .map((entry) => entry.key)
                      .toSet();

              final activeTableNumbers = <int>{};
              for (final entry in ordersByTable.entries) {
                final hasActiveOrder = entry.value.any(
                  (order) =>
                      !_isGarsonCompletedStatus(order['status']?.toString()),
                );
                if (hasActiveOrder) activeTableNumbers.add(entry.key);
              }
              activeTableNumbers.addAll(draftTableNumbers);
              activeTableNumbers.addAll(optimisticTableNumbers);
              final activeTableCount = activeTableNumbers.length;
              final waitingTableNumbers = orders
                  .where((o) => _isGarsonWaitingStatus(o['status']?.toString()))
                  .map(_garsonTableNumberFromOrder)
                  .where((tableNo) => tableNo > 0)
                  .toSet();
              waitingTableNumbers.addAll(draftTableNumbers);
              final newCount = waitingTableNumbers.length;
              final preparingCount = orders
                  .where((o) => (o['status']?.toString() ?? '') == 'preparing')
                  .length;
              final mutfaktaCount = orders
                  .where((o) {
                    final s = (o['status']?.toString() ?? '').toLowerCase();
                    return s == 'sent' || s == 'done';
                  })
                  .map(_garsonTableNumberFromOrder)
                  .where((n) => n > 0)
                  .toSet()
                  .length;

              final tableNumbersForGrid = _garsonTableNumbersForGrid(
                orderTableNumbers: ordersByTable.keys.toList(growable: false),
              );
              if (tableNumbersForGrid.isEmpty) {
                return _mobileSurfaceCard(
                  child: Text(
                    'Henüz masa kaydı yok. Sistem bölümünden masa ekleyin.',
                    style: TextStyle(color: Colors.grey.shade600),
                  ),
                );
              }
              final filteredTableNumbersForGrid = tableNumbersForGrid
                  .where(_matchesGarsonAreaFilter)
                  .toList(growable: false);

              return Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Padding(
                    padding: const EdgeInsets.fromLTRB(12, 0, 12, 8),
                    child: _mobileSurfaceCard(
                      child: Row(
                        children: [
                          const Icon(
                            Icons.map_outlined,
                            size: 18,
                            color: Color(0xFF0F172A),
                          ),
                          const SizedBox(width: 8),
                          const Text(
                            'Alan Seç',
                            style: TextStyle(fontWeight: FontWeight.w800),
                          ),
                          const SizedBox(width: 10),
                          Expanded(
                            child: DropdownButtonHideUnderline(
                              child: DropdownButton<String>(
                                isExpanded: true,
                                value:
                                    _garsonAreaOptions().any(
                                      (o) => o.key == _garsonAreaFilterKey,
                                    )
                                    ? _garsonAreaFilterKey
                                    : 'all',
                                items: _garsonAreaOptions()
                                    .map(
                                      (o) => DropdownMenuItem<String>(
                                        value: o.key,
                                        child: Text(
                                          o.label,
                                          overflow: TextOverflow.ellipsis,
                                        ),
                                      ),
                                    )
                                    .toList(growable: false),
                                onChanged: (value) {
                                  final next = (value ?? 'all').trim();
                                  if (next.isEmpty) return;
                                  setState(() => _garsonAreaFilterKey = next);
                                  unawaited(_persistGarsonAreaFilter(next));
                                },
                              ),
                            ),
                          ),
                        ],
                      ),
                    ),
                  ),
                  _mobileSurfaceCard(
                    child: Wrap(
                      spacing: 8,
                      runSpacing: 8,
                      children: [
                        _mobileBadge(
                          'Toplam Masa',
                          '${tableNumbersForGrid.length}',
                        ),
                        _mobileBadge('Dolu Masa', '$activeTableCount'),
                        _mobileBadge('Yeni Sipariş', '$newCount'),
                        _mobileBadge('Mutfakta', '$mutfaktaCount'),
                        _mobileBadge('Hazırlanıyor', '$preparingCount'),
                        _buildLocalPrintStatusBadge(
                          uiBranch: 'mobile_garson_summary',
                        ),
                      ],
                    ),
                  ),
                  const SizedBox(height: 10),
                  _buildGarsonGroupedTableGrids(
                    groups: _garsonTableAreaGroupsForNumbers(
                      filteredTableNumbersForGrid,
                    ),
                    occupiedTableNumbers: activeTableNumbers,
                    columnsResolver: _mobileGarsonGridColumns,
                    aspectRatioResolver: _mobileGarsonGridAspectRatio,
                    sectionPadding: const EdgeInsets.fromLTRB(12, 0, 12, 0),
                    cardBuilder: (tableNumber) {
                      final order = selectedOrderByTable[tableNumber];
                      final orderCount =
                          ordersByTable[tableNumber]?.length ?? 0;
                      final draftItems =
                          _mobileGarsonDraftItemsByTable[tableNumber] ??
                          const <Map<String, dynamic>>[];
                      final draftUpdatedAt =
                          _mobileGarsonDraftUpdatedAtByTable[tableNumber];
                      final optimisticAt =
                          _mobileGarsonOptimisticSentAtByTable[tableNumber];
                      final optimisticItems =
                          _mobileGarsonOptimisticItemsByTable[tableNumber] ??
                          const <Map<String, dynamic>>[];
                      final hasDraft = draftItems.isNotEmpty;
                      final hasRecentOptimistic =
                          optimisticAt != null &&
                          now.difference(optimisticAt) <=
                              const Duration(seconds: 45) &&
                          !hasDraft &&
                          orderCount == 0;

                      final optimisticOrder = hasRecentOptimistic
                          ? <String, dynamic>{
                              'status': 'sent',
                              'created_at': optimisticAt.toIso8601String(),
                              'items': optimisticItems,
                            }
                          : null;
                      final displayOrder = hasDraft
                          ? <String, dynamic>{
                              'status': 'draft',
                              'created_at': (draftUpdatedAt ?? now)
                                  .toIso8601String(),
                              'items': draftItems,
                            }
                          : (order ?? optimisticOrder);
                      final displayOrderCount = hasDraft
                          ? 1
                          : (orderCount > 0
                                ? orderCount
                                : (hasRecentOptimistic ? 1 : 0));
                      return _buildMobileGarsonTableCard(
                        tableNumber: tableNumber,
                        order: displayOrder,
                        orderCount: displayOrderCount,
                      );
                    },
                  ),
                ],
              );
            },
          ),
      ],
    );
  }

  /// Returns the restaurant-owner seller_id used for DB lookups.
  ///
  /// Garson sub-accounts have their own auth UID which differs from the
  /// restaurant owner UID stored in `seller_id` on every store row.
  /// Preferring the value from [_storeTables] ensures that stream
  /// subscriptions, order fetches, and adisyon prints all use the same
  /// ID as the one used when submitting orders.
  String _resolveGarsonSellerId() {
    final fromTables = _storeTables
        .map((row) => row['seller_id']?.toString().trim() ?? '')
        .firstWhere((id) => id.isNotEmpty, orElse: () => '');
    return fromTables.isNotEmpty
        ? fromTables
        : (_authService.currentUser?.id ?? '');
  }

  int _garsonTableNumberFromOrder(Map<String, dynamic> order) {
    // 1. Try to match by table_id or store_table_id (most reliable in area system)
    final tableId = order['table_id']?.toString() ?? order['store_table_id']?.toString();
    if (tableId != null && tableId.isNotEmpty) {
      for (final row in _storeTables) {
        if (row['id']?.toString() == tableId) {
          final matched = _tableNumberFromRow(row);
          if (matched > 0) return matched;
        }
      }
    }
    
    // 2. Fallback to table_number on order
    final raw = order['table_number'];
    if (raw is int) return raw;
    if (raw is num) return raw.toInt();
    return int.tryParse(raw?.toString() ?? '') ?? 0;
  }

  DateTime _garsonOrderCreatedAt(String? raw) {
    final parsed = DateTime.tryParse(raw ?? '');
    return parsed?.toLocal() ?? DateTime.fromMillisecondsSinceEpoch(0);
  }

  String _garsonOrderTimeAgoLabel(Map<String, dynamic> order) =>
      garsonOrderTimeAgoLabel(order);

  bool _isGarsonWaitingStatus(String? status) {
    final normalized = (status ?? '').toLowerCase();
    return normalized == 'new' || normalized == 'waiting';
  }

  /// Masa tamamen kapatıldığında true döner.
  /// 'sent'/'done' siparişleri garson ekranında aktif kalmaya devam eder
  /// (servis bekliyor), masa yalnızca [closeTableOrders] ile silinince boşalır.
  bool _isGarsonCompletedStatus(String? status) {
    final normalized = (status ?? '').toLowerCase();
    return normalized == 'closed';
  }

  bool _isGarsonClosedStatus(String? status) {
    return (status ?? '').toLowerCase() == 'closed';
  }

  int _mobileGarsonGridColumns(double maxWidth) {
    if (maxWidth >= 1100) return 6;
    if (maxWidth >= 900) return 5;
    if (maxWidth >= 700) return 4;
    if (maxWidth >= 520) return 3;
    return 2;
  }

  double _mobileGarsonGridAspectRatio(double maxWidth, int columns) {
    const spacing = 8.0;
    final safeColumns = columns <= 0 ? 1 : columns;
    final cardWidth = (maxWidth - ((safeColumns - 1) * spacing)) / safeColumns;
    if (cardWidth >= 220) return 1.15;
    if (cardWidth >= 175) return 1.02;
    return 0.92;
  }

  List<Map<String, dynamic>> _garsonExtractItems(Map<String, dynamic> order) {
    dynamic raw = order['items'];
    // Supabase realtime may deliver JSONB columns as a JSON-encoded string.
    if (raw is String) {
      try {
        raw = jsonDecode(raw);
      } catch (_) {
        return const <Map<String, dynamic>>[];
      }
    }
    if (raw is! List) return const <Map<String, dynamic>>[];
    return raw
        .whereType<Map>()
        .map(
          (e) => MixedServiceOrder.normalizeOrderItem(
            Map<String, dynamic>.from(e),
          ),
        )
        .toList(growable: false);
  }

  String _garsonFormatMoney(double amount) {
    final safe = amount.isFinite ? amount : 0;
    final text = safe.toStringAsFixed(2);
    final parts = text.split('.');
    final whole = parts[0];
    final decimal = parts.length > 1 ? parts[1] : '00';
    final buffer = StringBuffer();
    for (var i = 0; i < whole.length; i++) {
      final idxFromRight = whole.length - i;
      buffer.write(whole[i]);
      if (idxFromRight > 1 && idxFromRight % 3 == 1) {
        buffer.write('.');
      }
    }
    return '₺${buffer.toString()},$decimal';
  }

  double _garsonOrderTotal(Map<String, dynamic> order) {
    final items = _garsonExtractItems(order);
    return items.fold<double>(0, (sum, item) {
      return sum + MixedServiceOrder.itemLineTotal(item);
    });
  }

  bool _garsonOrderHasKitchenPrintItems(Map<String, dynamic> order) {
    for (final item in _garsonExtractItems(order)) {
      final t = item['type']?.toString().toLowerCase().trim() ?? '';
      if (t == 'waiter_call') continue;
      return true;
    }
    return false;
  }

  Future<bool> _confirmGarsonPendingKitchenPrint({
    required int tableNumber,
    required List<Map<String, dynamic>> tableOrders,
  }) async {
    final tapAt = DateTime.now();
    final sellerId = _resolveGarsonSellerId();
    if (sellerId.isEmpty) {
      if (!mounted) return false;
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('Satıcı oturumu bulunamadı.')),
      );
      return false;
    }

    final pending = tableOrders
        .where(_garsonTableOrderNeedsCustomerKitchenApproval)
        .toList(growable: false);

    if (pending.isEmpty) return false;

    setState(() => _garsonKitchenConfirmBusyTables.add(tableNumber));
    final user = Supabase.instance.client.auth.currentUser;
    final waiterName = _sellerPrintJobService.safeUserDisplayName(user);
    final errors = <String>[];
    var printedAny = false;
    var processedAny = false;

    try {
      for (final order in pending) {
        final perf = Stopwatch()..start();
        final id = order['id']?.toString() ?? '';
        if (id.isEmpty) continue;
        if (!_garsonKitchenDispatchInFlightOrderIds.add(id)) {
          continue;
        }
        processedAny = true;
        var printDispatchMs = 0;
        try {
          if (_garsonOrderHasKitchenPrintItems(order)) {
            debugPrint('[GarsonPrint][send_order_start]');
            debugPrint('table=$tableNumber');
            debugPrint('orderId=$id');
            final dispatchWatch = Stopwatch()..start();
            await _sellerPrintJobService.dispatchNewOrderFromTableOrder(
              tableOrderId: id,
              waiterName: waiterName,
            );
            printDispatchMs = dispatchWatch.elapsedMilliseconds;
            printedAny = true;
          }
          final dbWatch = Stopwatch()..start();
          await _storeService.updateTableOrderStatus(id, 'sent');
          final dbUpdateMs = dbWatch.elapsedMilliseconds;
          logPrintPerf('kitchen_order', <String, Object?>{
            'tap_at': tapAt.toIso8601String(),
            'db_create_or_update_ms': dbUpdateMs,
            'kitchen_payload_build_ms': 0,
            'print_dispatch_ms': printDispatchMs,
            'bridge_request_ms': 0,
            'total_ms': perf.elapsedMilliseconds,
            'total_submit_to_print_ms': perf.elapsedMilliseconds,
            'table': tableNumber,
            'table_order_id': id,
            'layer': 'seller_panel',
            'ok': true,
          });
        } catch (e) {
          errors.add(e.toString());
          logPrintPerf('kitchen_order', <String, Object?>{
            'tap_at': tapAt.toIso8601String(),
            'db_create_or_update_ms': 0,
            'kitchen_payload_build_ms': 0,
            'print_dispatch_ms': printDispatchMs,
            'bridge_request_ms': 0,
            'total_ms': perf.elapsedMilliseconds,
            'total_submit_to_print_ms': perf.elapsedMilliseconds,
            'table': tableNumber,
            'table_order_id': id,
            'layer': 'seller_panel',
            'ok': false,
            'error': e.toString(),
          });
        } finally {
          _garsonKitchenDispatchInFlightOrderIds.remove(id);
        }
      }

      if (!mounted) return false;
      final messenger = ScaffoldMessenger.of(context);
      if (processedAny && errors.isEmpty) {
        messenger.showSnackBar(
          SnackBar(
            content: Text(
              printedAny
                  ? 'Sipariş mutfağa gönderildi; mutfak fişi yazıcıya gönderildi.'
                  : 'Sipariş mutfağa gönderildi (mutfak kalemi yok).',
            ),
            backgroundColor: Colors.green.shade700,
          ),
        );
      } else if (errors.isNotEmpty) {
        messenger.showSnackBar(
          SnackBar(
            content: Text(
              errors.first.replaceFirst(RegExp(r'^Exception:\s*'), ''),
            ),
            backgroundColor: Colors.red,
          ),
        );
      }
      unawaited(_pullRefreshGarsonTableOrders(sellerId));
      return processedAny && errors.isEmpty;
    } finally {
      if (mounted) {
        setState(() => _garsonKitchenConfirmBusyTables.remove(tableNumber));
      }
    }
  }

  List<MixedServiceDisplayEntry> _garsonItemDetailLines(
    Map<String, dynamic> item,
  ) {
    final lines = <MixedServiceDisplayEntry>[];
    final gramaj = item['gramaj']?.toString().trim() ?? '';
    final notes = item['notes']?.toString().trim() ?? '';
    final attrs =
        (item['attributes'] as List?)
            ?.whereType<String>()
            .where((s) => s.isNotEmpty)
            .toList() ??
        const <String>[];
    if (gramaj.isNotEmpty) {
      lines.add(MixedServiceDisplayEntry.item(gramaj));
    }
    final noteParts = <String>[if (notes.isNotEmpty) notes, ...attrs];
    if (noteParts.isNotEmpty) {
      lines.add(MixedServiceDisplayEntry.item('Not: ${noteParts.join(', ')}'));
    }
    lines.addAll(MixedServiceOrder.childItemDisplayEntries(item));
    return lines;
  }

  double _garsonOrdersTotal(List<Map<String, dynamic>> orders) {
    return orders.fold<double>(
      0,
      (sum, order) => sum + _garsonOrderTotal(order),
    );
  }

  bool get _hasGarsonStoreContextOnPanel =>
      _hasLoadedStoreProfile || _storeNameController.text.trim().isNotEmpty;

  Map<String, String> _buildGarsonReceiptStoreContextFromPanelState(
    String sellerId,
  ) {
    final branchSource = _selectedDistrict.trim().isNotEmpty
        ? _selectedDistrict.trim()
        : (_selectedCity.trim().isNotEmpty ? _selectedCity.trim() : 'Merkez');
    final upperBranchSource = branchSource.toUpperCase();
    final branch =
        (upperBranchSource.contains('ŞUBE') ||
            upperBranchSource.contains('SUBE'))
        ? upperBranchSource
        : '$upperBranchSource ŞUBE';
    return <String, String>{
      'store_id': sellerId,
      'store_name': _storeNameController.text.trim().isNotEmpty
          ? _storeNameController.text.trim()
          : 'Mağaza',
      'branch': branch,
      'phone': _phoneController.text.trim().isNotEmpty
          ? _phoneController.text.trim()
          : '-',
    };
  }

  Map<String, String> _garsonReceiptStoreContextForPrint(String sellerId) {
    final cacheFresh =
        _garsonReceiptStoreContextCache != null &&
        _garsonReceiptStoreContextCachedAt != null &&
        DateTime.now().difference(_garsonReceiptStoreContextCachedAt!) <=
            const Duration(minutes: 30);
    if (cacheFresh) {
      return Map<String, String>.from(_garsonReceiptStoreContextCache!);
    }
    if (_hasGarsonStoreContextOnPanel) {
      final built = _buildGarsonReceiptStoreContextFromPanelState(sellerId);
      _garsonReceiptStoreContextCache = built;
      _garsonReceiptStoreContextCachedAt = DateTime.now();
      return built;
    }
    return _buildGarsonReceiptStoreContextFromPanelState(sellerId);
  }

  Future<Map<String, String>> _loadGarsonReceiptStoreContext(
    String sellerId,
  ) async {
    if (_hasGarsonStoreContextOnPanel) {
      return _garsonReceiptStoreContextForPrint(sellerId);
    }
    const storeContextSelect =
        'seller_id, business_name, phone, district, city';
    final storeRow = await Supabase.instance.client
        .from('stores')
        .select(storeContextSelect)
        .eq('seller_id', sellerId)
        .maybeSingle();

    final storeName =
        (storeRow?['business_name']?.toString().trim().isNotEmpty ?? false)
        ? storeRow!['business_name'].toString().trim()
        : 'Mağaza';

    final phone = (storeRow?['phone']?.toString().trim().isNotEmpty ?? false)
        ? storeRow!['phone'].toString().trim()
        : '-';

    final branchSource =
        (storeRow?['district']?.toString().trim().isNotEmpty ?? false)
        ? storeRow!['district'].toString().trim()
        : ((storeRow?['city']?.toString().trim().isNotEmpty ?? false)
              ? storeRow!['city'].toString().trim()
              : 'Merkez');

    final upperBranchSource = branchSource.toUpperCase();
    final branch =
        (upperBranchSource.contains('ŞUBE') ||
            upperBranchSource.contains('SUBE'))
        ? upperBranchSource
        : '$upperBranchSource ŞUBE';

    final built = <String, String>{
      'store_id': storeRow?['seller_id']?.toString() ?? sellerId,
      'store_name': storeName,
      'branch': branch,
      'phone': phone,
    };
    _garsonReceiptStoreContextCache = built;
    _garsonReceiptStoreContextCachedAt = DateTime.now();
    return built;
  }

  Future<void> _warmGarsonPrintCaches(String sellerId) async {
    if (sellerId.isEmpty || !_supportsDirectLocalPrintBridge) return;
    _garsonReceiptStoreContextForPrint(sellerId);
    final bridgeReachable =
        _isLocalPrintAvailable ??
        await _printOrchestrator.isLocalBridgeReachable(useCache: true);
    if (bridgeReachable != true) return;
    unawaited(
      _printOrchestrator.loadSetupSnapshot(
        restaurantId: sellerId,
        minimal: true,
        flowName: 'garson_warm',
        source: 'seller_panel_garson',
      ),
    );
    if (_garsonCachedReceiptPrinter == null) {
      final receiptPrinter = await _printOrchestrator
          .resolveReceiptPrinterForGarsonFast(sellerId);
      if (receiptPrinter != null) {
        _garsonCachedReceiptPrinter = receiptPrinter;
        _garsonCachedReceiptPrinterAt = DateTime.now();
        _garsonCachedReceiptEncodingProfile ??= await _printOrchestrator
            .loadEncodingProfile(
              restaurantId: sellerId,
              printerId: receiptPrinter.id,
            );
      }
    }
    if (_garsonCachedKitchenPrinter == null) {
      final kitchenPrinter = await _printOrchestrator
          .resolveKitchenPrinterForGarsonFast(sellerId);
      if (kitchenPrinter != null) {
        _garsonCachedKitchenPrinter = kitchenPrinter;
        _garsonCachedKitchenPrinterAt = DateTime.now();
        _garsonCachedKitchenEncodingProfile ??= await _printOrchestrator
            .loadEncodingProfile(
              restaurantId: sellerId,
              printerId: kitchenPrinter.id,
            );
      }
    }
    unawaited(
      _sellerPrintJobService.prefetchKitchenStationContext(
        restaurantId: sellerId,
        products: _products,
      ),
    );
  }

  Future<UnifiedPrinterModel?> _garsonReceiptPrinterForDirectDispatch(
    String sellerId,
  ) async {
    final cacheFresh =
        _garsonCachedReceiptPrinter != null &&
        _garsonCachedReceiptPrinterAt != null &&
        DateTime.now().difference(_garsonCachedReceiptPrinterAt!) <=
            const Duration(minutes: 30);
    if (cacheFresh) {
      return _garsonCachedReceiptPrinter;
    }
    final resolved = await _printOrchestrator
        .resolveReceiptPrinterForGarsonFast(sellerId);
    if (resolved != null) {
      _garsonCachedReceiptPrinter = resolved;
      _garsonCachedReceiptPrinterAt = DateTime.now();
      _garsonCachedReceiptEncodingProfile ??= await _printOrchestrator
          .loadEncodingProfile(restaurantId: sellerId, printerId: resolved.id);
    }
    return resolved;
  }

  void _scheduleLocalPrintStatusRefreshIfNeeded({
    required SellerModule module,
    required String reason,
  }) {
    if (_shouldMonitorLocalPrintForModule(module)) {
      unawaited(_refreshLocalPrintStatus(reason: reason));
      _startLocalPrintPollIfNeeded();
    } else {
      _stopLocalPrintPoll();
    }
  }

  void _startLocalPrintPollIfNeeded() {
    if (_localPrintPollTimer?.isActive == true) return;
    _localPrintPollTimer?.cancel();
    _localPrintPollTimer = Timer.periodic(const Duration(seconds: 30), (_) {
      if (!mounted || !_shouldMonitorLocalPrintForModule(_selectedModule)) {
        _stopLocalPrintPoll();
        return;
      }
      debugPrint('[LocalPrint][Poll] periodicCheck interval=30s');
      unawaited(_refreshLocalPrintStatus(reason: 'poll_30s'));
    });
    debugPrint('[LocalPrint][Poll] timerStarted interval=30s');
  }

  void _stopLocalPrintPoll() {
    if (_localPrintPollTimer != null) {
      debugPrint('[LocalPrint][Poll] timerStopped');
      _localPrintPollTimer?.cancel();
      _localPrintPollTimer = null;
    }
  }

  Future<LocalPrintHealthStatus?> _refreshLocalPrintStatus({
    required String reason,
  }) async {
    if (!_supportsDirectLocalPrintBridge) return null;
    final printService = LocalPrintService();
    try {
      final status = await printService.checkAvailability();
      _applyLocalPrintStatus(status, reason: reason);
      if (status.isAvailable) {
        unawaited(
          _recoverPendingKitchenPrintJobs(reason: 'bridge_available_$reason'),
        );
      }
      return status;
    } finally {
      printService.dispose();
    }
  }

  Future<void> _recoverPendingKitchenPrintJobs({required String reason}) async {
    if (!_shouldMonitorLocalPrintForModule(_selectedModule)) return;
    if (_isRecoveringPendingPrintJobs) return;
    final restaurantId = _resolveGarsonSellerId().trim();
    if (restaurantId.isEmpty) return;

    _isRecoveringPendingPrintJobs = true;
    try {
      final result = await _sellerPrintJobService.recoverPendingJobs(
        restaurantId: restaurantId,
        limit: 20,
      );
      debugPrint(
        '[LocalPrint][Recovery] reason=$reason restaurantId=$restaurantId '
        'pending=${result.pendingJobCount} dispatched=${result.dispatchedJobCount} '
        'failed=${result.failedJobCount}',
      );
    } catch (error, stackTrace) {
      debugPrint(
        '[LocalPrint][Recovery] failed reason=$reason restaurantId=$restaurantId '
        'error=$error',
      );
      debugPrintStack(stackTrace: stackTrace);
    } finally {
      _isRecoveringPendingPrintJobs = false;
    }
  }

  void _applyLocalPrintStatus(
    LocalPrintHealthStatus status, {
    required String reason,
  }) {
    if (status.isAvailable) {
      _lastLocalPrintSuccessAt = DateTime.now();
    }
    final nextLabel = status.isAvailable
        ? 'Yazıcı bağlı'
        : switch (status.reason) {
            'timeout' => 'Yanıt yok',
            'connection_error' => 'Servise ulaşılamadı',
            'web_cors_blocked' => 'CORS/PNA engeli',
            'server_error' => 'Servis hatası',
            _ => 'Servis kapalı',
          };
    final nextMessage = _localPrintHealthMessage(status);
    final requiresUpdate =
        _isLocalPrintAvailable != status.isAvailable ||
        _localPrintStatusLabel != nextLabel ||
        _localPrintStatusMessage != nextMessage;
    _isLocalPrintAvailable = status.isAvailable;
    _localPrintStatusLabel = nextLabel;
    _localPrintStatusMessage = nextMessage;
    if (requiresUpdate) {
      _notifyLocalPrintUiChanged();
    }
    final lastSuccessStr = _lastLocalPrintSuccessAt != null
        ? _lastLocalPrintSuccessAt!.toLocal().toString()
        : 'never';
    debugPrint(
      '[LocalPrint][Status] uiUpdated reason=$reason '
      'available=${status.isAvailable} label=$nextLabel '
      'failReason=${status.reason} '
      'message=$nextMessage requestUrl=${status.url} '
      'durationMs=${status.durationMs} statusCode=${status.statusCode ?? '-'} '
      'stateUpdated=$requiresUpdate lastSuccess=$lastSuccessStr',
    );
  }

  String _localPrintHealthMessage(LocalPrintHealthStatus status) {
    final lastSuccessStr = _lastLocalPrintSuccessAt != null
        ? ' (Son başarılı bağlantı: ${_timeAgoShort(_lastLocalPrintSuccessAt!)})'
        : '';
    switch (status.reason) {
      case 'ok':
        return 'Yazıcı servisi bu bilgisayarda hazır.';
      case 'connection_error':
        // Detect likely CORS / Private Network Access block (browser-side)
        final details = status.details?.toString() ?? '';
        final isCorsLike =
            details.contains('XMLHttpRequest') ||
            details.contains('CORS') ||
            details.contains('NetworkError') ||
            details.contains('Failed to fetch');
        if (isCorsLike) {
          return 'Tarayıcı CORS kuralı nedeniyle bağlantıyı engelledi. '
              'Yazıcı servisi 127.0.0.1:3001 adresinde çalışıyor olsa bile '
              'tarayıcı Private Network Access hatası üretiyor. '
              'Servisi yeniden başlatın veya DevTools Console’u kontrol edin.$lastSuccessStr';
        }
        return 'Yazıcı servisine bağlanamadı. '
            'Servis çalışmıyor olabilir veya farklı bir port dinliyor olabilir. '
            'Bu bilgisayarda http://127.0.0.1:3001 adresini kontrol edin.$lastSuccessStr';
      case 'timeout':
        return 'Yazıcı servisi ${status.durationMs}ms içinde yanıt vermedi. '
            'Servis aşırı yüklendi veya takıldı olabilir.$lastSuccessStr';
      case 'server_error':
        final code = status.statusCode != null
            ? ' (HTTP ${status.statusCode})'
            : '';
        return 'Yazıcı servisi bağlantıyı kabul etti ancak hata yanıtı döndürdü$code. '
            '${status.details?.toString().isNotEmpty == true ? status.details : 'Servis log’una bakın.'}'
            '$lastSuccessStr';
      default:
        return 'Yazıcı servis denetim isteği başarısız oldu. '
            'Ağ erişimi veya servis ayarını kontrol edin.$lastSuccessStr';
    }
  }

  /// Human-readable relative time, max precision minutes
  String _timeAgoShort(DateTime past) {
    final diff = DateTime.now().difference(past);
    if (diff.inSeconds < 60) return 'şimdi';
    if (diff.inMinutes < 60) return '${diff.inMinutes} dk önce';
    if (diff.inHours < 24) return '${diff.inHours} sa önce';
    return '${diff.inDays} gün önce';
  }

  Color _localPrintStatusColor(bool? isAvailable) {
    return isAvailable == true
        ? const Color(0xFF16A34A)
        : isAvailable == false
        ? const Color(0xFFDC2626)
        : const Color(0xFF6B7280);
  }

  void _setLocalPrintPanelBusy({bool? refreshing, bool? testing}) {
    final nextRefreshing = refreshing ?? _isLocalPrintRefreshing;
    final nextTesting = testing ?? _isLocalPrintTesting;
    final requiresUpdate =
        _isLocalPrintRefreshing != nextRefreshing ||
        _isLocalPrintTesting != nextTesting;
    _isLocalPrintRefreshing = nextRefreshing;
    _isLocalPrintTesting = nextTesting;
    if (requiresUpdate) {
      _notifyLocalPrintUiChanged();
    }
  }

  Future<void> _handleLocalPrintPanelRefresh({required String uiBranch}) async {
    debugPrint('[LocalPrint][Panel] refreshPressed uiBranch=$uiBranch');
    if (!kIsWeb || _isLocalPrintRefreshing || _isLocalPrintTesting) return;
    _setLocalPrintPanelBusy(refreshing: true);
    try {
      await _refreshLocalPrintStatus(reason: 'panel_refresh_button');
    } finally {
      _setLocalPrintPanelBusy(refreshing: false);
    }
  }

  Future<void> _handleLocalPrintPanelTest({required String uiBranch}) async {
    debugPrint('[LocalPrint][Panel] testPressed uiBranch=$uiBranch');
    if (!kIsWeb || _isLocalPrintRefreshing || _isLocalPrintTesting) return;
    _setLocalPrintPanelBusy(testing: true);
    try {
      final healthStatus = await _refreshLocalPrintStatus(
        reason: 'panel_test_preflight',
      );
      if (healthStatus?.isAvailable != true) {
        final blockReason = healthStatus?.reason ?? 'unknown';
        debugPrint(
          '[LocalPrint][Panel] testBlockedServiceUnavailable '
          'uiBranch=$uiBranch reason=$blockReason',
        );
        final blockMessage = blockReason == 'web_cors_blocked'
            ? 'Tarayıcı bağlantıyı engelledi (CORS/PNA). '
                  "Servisi başlatın ve DevTools Console'u kontrol edin."
            : blockReason == 'timeout'
            ? 'Yazıcı servisi yanıt vermedi. Servis takılmış olabilir.'
            : 'Bu bilgisayarda yazıcı servisini başlatın.';
        await _showLocalPrintPanelMessage(message: blockMessage);
        return;
      }

      try {
        final result = await _printOrchestrator.printTestReceipt(
          restaurantId: _resolveGarsonSellerId(),
          role: PrinterSetupRole.adisyon,
        );
        if (!result.ok) {
          throw Exception(result.message);
        }
        debugPrint(
          '[LocalPrint][Panel] testSuccess '
          'uiBranch=$uiBranch route=/print/test',
        );
        await _showLocalPrintPanelMessage(message: 'Test fişi yazdırıldı');
      } catch (error, stackTrace) {
        debugPrint(
          '[LocalPrint][Panel] testFail uiBranch=$uiBranch exception=$error',
        );
        debugPrint('$stackTrace');
        await _showLocalPrintPanelMessage(message: 'Test fişi yazdırılamadı');
      }
    } finally {
      _setLocalPrintPanelBusy(testing: false);
    }
  }

  Future<void> _showLocalPrintPanelMessage({required String message}) async {
    if (!mounted) return;
    final messenger = ScaffoldMessenger.of(context);
    messenger
      ..hideCurrentSnackBar()
      ..showSnackBar(SnackBar(content: Text(message)));
  }

