  double _garsonRoundMoney(num amount) {
    final safe = amount.isFinite ? amount.toDouble() : 0.0;
    return double.parse(safe.toStringAsFixed(2));
  }

  Map<String, dynamic> _buildGarsonReceiptPayload({
    required int tableNumber,
    required List<Map<String, dynamic>> tableOrders,
    required Map<String, String> storeContext,
    DateTime? createdAt,
    String? headerNote,
    bool isHistoryReprint = false,
    String? historyRecordId,
  }) {
    final now = DateTime.now().toLocal();
    final selectedTableRaw = _storeTableRowByNumber(tableNumber);
    final inferredFromOrders = () {
      if (tableOrders.isEmpty) return null;
      final first = tableOrders.first;
      final display =
          first['display_table_label'] ??
          first['table_display_name'] ??
          first['table_name'] ??
          first['display_label'];
      final areaName =
          first['table_area_name'] ?? first['area_name'] ?? first['table_area'];
      final areaTableNumber =
          first['area_table_number'] ??
          first['table_area_number'] ??
          first['area_table_no'];
      if ((display?.toString().trim() ?? '').isEmpty &&
          (areaName?.toString().trim() ?? '').isEmpty &&
          (areaTableNumber?.toString().trim() ?? '').isEmpty) {
        return null;
      }
      return <String, dynamic>{
        'display_label': display,
        'table_name': display,
        'area_name': areaName,
        'area_table_number': areaTableNumber,
      };
    }();

    final selectedTable = selectedTableRaw ?? inferredFromOrders;

    final tableFields = resolvePrintableTablePayloadFields(
      tableRow: selectedTable,
      tableNumber: tableNumber,
    );
    final resolvedDisplayLabel =
        (tableFields['display_table_label']?.toString().trim() ?? '');

    final items = <Map<String, dynamic>>[];
    var subtotal = 0.0;

    for (final order in tableOrders) {
      for (final item in _garsonExtractItems(order)) {
        var qty = (item['quantity'] as num?)?.toInt() ?? 1;
        if (qty <= 0) qty = 1;
        final rawLineTotal = MixedServiceOrder.itemLineTotal(item);
        final lineTotal = _garsonRoundMoney(rawLineTotal);
        final unitPrice = _garsonRoundMoney(rawLineTotal / qty);
        subtotal += rawLineTotal;
        final printLabel = GarsonProductSelection.resolvePrintItemLabel(item);
        final amountLabel = GarsonProductSelection.resolvePrintItemAmountLabel(
          item,
        );
        items.add(<String, dynamic>{
          'name': printLabel.isNotEmpty ? printLabel : '-',
          'display_label': printLabel.isNotEmpty ? printLabel : '-',
          if (amountLabel.isNotEmpty) 'amount_label': amountLabel,
          'qty': qty,
          'price': unitPrice,
          'total': lineTotal,
        });
        GarsonProductSelection.logGarsonPrintItemLabel(
          path: 'receipt',
          item: item,
          finalPrintName: printLabel,
        );
      }
    }

    const discount = 0.0;
    final roundedSubtotal = _garsonRoundMoney(subtotal);
    final grandTotal = _garsonRoundMoney(roundedSubtotal - discount);

    final payload = <String, dynamic>{
      'store_name': storeContext['store_name'] ?? 'Mağaza',
      'branch': storeContext['branch'] ?? 'MERKEZ ŞUBE',
      'phone': storeContext['phone'] ?? '-',
      'table_no': tableNumber.toString(),
      ...tableFields,
      // The receipt renderer prefers these timestamps in order:
      // receipt_printed_at -> printed_at -> order_created_at -> created_at -> datetime/date_time.
      'receipt_printed_at': now.toIso8601String(),
      'printed_at': now.toIso8601String(),
      'order_created_at': (createdAt ?? now).toIso8601String(),
      'created_at': (createdAt ?? now).toIso8601String(),
      'datetime': (createdAt ?? now).toIso8601String(),
      'items': items,
      'subtotal': roundedSubtotal,
      'discount': _garsonRoundMoney(discount),
      'grand_total': grandTotal,
      if (headerNote != null && headerNote.trim().isNotEmpty)
        'header_note': headerNote.trim(),
      if (headerNote != null && headerNote.trim().isNotEmpty)
        'reprint_label': headerNote.trim(),
      if (isHistoryReprint) 'is_history_reprint': true,
      if (isHistoryReprint && historyRecordId != null)
        'history_record_id': historyRecordId,
    };

    debugPrint(
      '[GARSON_RECEIPT_TABLE_LABEL] '
      'selectedTableRaw=${selectedTableRaw ?? '<null>'} '
      'tableNumber=$tableNumber '
      'areaId=${selectedTable?['area_id'] ?? ''} '
      'areaName=${selectedTable?['area_name'] ?? ''} '
      'areaTableNumber=${selectedTable?['area_table_number'] ?? ''} '
      'tableName=${selectedTable?['table_name'] ?? ''} '
      'displayLabel=${selectedTable?['display_label'] ?? ''} '
      'resolvedDisplayLabel=$resolvedDisplayLabel '
      'payload.display_table_label=${payload['display_table_label']} '
      'payload.table_display_name=${payload['table_display_name']} '
      'payload.table_name=${payload['table_name']} '
      'payload.table_area_name=${payload['table_area_name']}',
    );

    logReceiptFinalBeforeBridge(path: 'garson_receipt_build', payload: payload);

    return payload;
  }

  bool _hasConfiguredAdisyonPrinter(Map<String, dynamic>? stationConfig) {
    if (stationConfig == null) return false;
    final roleMappings = stationConfig['role_mappings'];
    if (roleMappings is Map) {
      final adisyon = roleMappings['adisyon'];
      if (adisyon is Map) {
        final bridgeId =
            adisyon['id']?.toString().trim() ??
            adisyon['bridgePrinterId']?.toString().trim() ??
            '';
        if (bridgeId.isNotEmpty) return true;
      }
    }
    final printerId =
        stationConfig['adisyon_printer_id']?.toString().trim() ?? '';
    return printerId.isNotEmpty;
  }

  Map<String, dynamic> _enrichQueuedReceiptPayloadWithPrinterRouting(
    Map<String, dynamic> payload, {
    required Map<String, dynamic>? stationConfig,
  }) {
    final nextPayload = Map<String, dynamic>.from(payload)
      ..['printer_role'] = 'adisyon'
      ..['document_type'] = 'receipt'
      ..['job_type'] = 'receipt';

    final roleMappings = stationConfig?['role_mappings'];
    if (roleMappings is Map) {
      final receiptRole = roleMappings['adisyon'];
      if (receiptRole is Map) {
        final printer = Map<String, dynamic>.from(receiptRole);
        final bridgePrinterId =
            printer['id']?.toString().trim() ??
            printer['bridgePrinterId']?.toString().trim() ??
            '';
        final printerRecordId =
            printer['printerRecordId']?.toString().trim() ??
            printer['printer_record_id']?.toString().trim() ??
            '';
        final printerName =
            printer['displayName']?.toString().trim() ??
            printer['name']?.toString().trim() ??
            '';
        final printerQueue =
            printer['queueName']?.toString().trim() ??
            printer['queue']?.toString().trim() ??
            '';
        final printerBackend =
            printer['backend']?.toString().trim() ??
            printer['transportType']?.toString().trim() ??
            '';
        final deviceIdentifier =
            printer['deviceIdentifier']?.toString().trim() ??
            printer['device_identifier']?.toString().trim() ??
            '';
        nextPayload['printer'] = printer;
        if (bridgePrinterId.isNotEmpty) {
          nextPayload['printer_id'] = bridgePrinterId;
        }
        if (printerRecordId.isNotEmpty) {
          nextPayload['printer_record_id'] = printerRecordId;
        }
        if (printerName.isNotEmpty) {
          nextPayload['printer_name'] = printerName;
        }
        if (printerQueue.isNotEmpty) {
          nextPayload['printer_queue'] = printerQueue;
        }
        if (printerBackend.isNotEmpty) {
          nextPayload['printer_backend'] = printerBackend;
        }
        if (deviceIdentifier.isNotEmpty) {
          nextPayload['printer_device_identifier'] = deviceIdentifier;
        }
        return nextPayload;
      }
    }

    final printerId =
        stationConfig?['adisyon_printer_id']?.toString().trim() ?? '';
    final printerName =
        stationConfig?['adisyon_printer_name']?.toString().trim() ?? '';
    if (printerId.isNotEmpty) {
      nextPayload['printer_id'] = printerId;
      nextPayload['printer_record_id'] = printerId;
    }
    if (printerName.isNotEmpty) {
      nextPayload['printer_name'] = printerName;
    }

    return nextPayload;
  }

  String _localReceiptPayloadSummary(Map<String, dynamic> payload) {
    final items = payload['items'];
    final itemCount = items is List ? items.length : 0;
    final keys = payload.keys.toList(growable: false)..sort();
    return 'keys=${keys.join(",")} items=$itemCount '
        'grandTotal=${payload['grand_total'] ?? '-'}';
  }

  void _logLocalReceiptEvent(
    String event, {
    required String uiAction,
    String? sellerId,
    String? storeId,
    String? guard,
    String? guardResult,
    String? emptyBranch,
    String? mappingStatus,
    bool? localPrintCallReached,
    int? durationMs,
    int? tableNumber,
    List<Map<String, dynamic>>? orders,
    Map<String, dynamic>? payload,
    String? queryTable,
    String? query,
    Object? error,
    StackTrace? stackTrace,
  }) {
    final itemCount = payload?['items'] is List
        ? (payload!['items'] as List).length
        : (orders?.length ?? 0);
    final payloadSummary = payload == null
        ? '-'
        : _localReceiptPayloadSummary(payload);
    debugPrint(
      '[LocalPrint][Receipt] $event uiAction=$uiAction '
      'sellerId=${sellerId ?? '-'} storeId=${storeId ?? '-'} '
      'guard=${guard ?? '-'} guardResult=${guardResult ?? '-'} '
      'emptyBranch=${emptyBranch ?? '-'} mappingStatus=${mappingStatus ?? '-'} '
      'localPrintCallReached=${localPrintCallReached ?? false} '
      'durationMs=${durationMs ?? '-'} '
      'queryTable=${queryTable ?? '-'} query=${query ?? '-'} '
      'tableNo=${tableNumber ?? '-'} itemCount=$itemCount '
      'payloadSummary=$payloadSummary',
    );
    if (error != null) {
      debugPrint(
        '[LocalPrint][Error] event=$event uiAction=$uiAction '
        'sellerId=${sellerId ?? '-'} storeId=${storeId ?? '-'} '
        'guard=${guard ?? '-'} guardResult=${guardResult ?? '-'} '
        'emptyBranch=${emptyBranch ?? '-'} mappingStatus=${mappingStatus ?? '-'} '
        'localPrintCallReached=${localPrintCallReached ?? false} '
        'durationMs=${durationMs ?? '-'} '
        'queryTable=${queryTable ?? '-'} query=${query ?? '-'} '
        'tableNo=${tableNumber ?? '-'} exception=$error',
      );
    }
    if (stackTrace != null) {
      debugPrint('$stackTrace');
    }
  }

  String _localPrintUserMessage(
    Object error, {
    required bool localPrintCallReached,
  }) {
    if (!localPrintCallReached) {
      final normalized = error.toString().toLowerCase();
      if (normalized.contains('stores') ||
          normalized.contains('business_name')) {
        return 'Mağaza bilgisi alınamadı. Adisyon hazırlanamadı.';
      }
    }
    if (error is LocalPrintServiceException) {
      final normalized = error.message.toLowerCase();
      if (normalized.contains('baglanilamadi')) {
        return 'Yazıcı servisi kapalı. Lütfen bu bilgisayarda yazıcı servisini başlatın.';
      }
      if (normalized.contains('zaman asimina')) {
        return 'Yazıcı servisi yanıt vermiyor. Lütfen bu bilgisayarda yazıcı servisini kontrol edin.';
      }
      if (error.statusCode != null) {
        return 'Adisyon yazdırılamadı. Lütfen yazıcı servisini kontrol edin.';
      }
      return localPrintCallReached
          ? 'Adisyon yazdırılamadı. Lütfen yazıcı servisini kontrol edin.'
          : 'Yazıcı servisine erişilemedi. Lütfen bu bilgisayarda yazıcı servisini kontrol edin.';
    }
    final rawMessage = error.toString().replaceFirst('Exception: ', '').trim();
    if (rawMessage.isEmpty) {
      return localPrintCallReached
          ? 'Adisyon yazdırılamadı. Lütfen yazıcı servisini kontrol edin.'
          : 'Yazıcı servisine erişilemedi. Lütfen bu bilgisayarda yazıcı servisini kontrol edin.';
    }
    return localPrintCallReached
        ? 'Adisyon yazdırılamadı. $rawMessage'
        : 'Adisyon yazdırılamadı: $rawMessage';
  }

  String _normalizePrinterWorkflowMessage(
    Object error, {
    required String fallback,
  }) {
    return _normalizePrinterWorkflowMessageValue(error, fallback: fallback);
  }

  void _showPrinterWorkflowSnackBar(String message, {bool warning = false}) {
    if (!mounted) return;
    final messenger = ScaffoldMessenger.of(context);
    messenger
      ..hideCurrentSnackBar()
      ..showSnackBar(
        SnackBar(
          content: Text(message),
          backgroundColor: warning ? Colors.orange.shade700 : null,
        ),
      );
  }

  Future<void> _printGarsonAdisyon({
    required int tableNumber,
    List<Map<String, dynamic>>? orders,
    String uiAction = 'adisyon_button',
  }) async {
    final tapAt = DateTime.now();
    final watch = Stopwatch()..start();
    var orderFetchMs = 0;
    var storeProfileFetchMs = 0;
    var printerResolveMs = 0;
    var payloadBuildMs = 0;
    var bridgeRequestMs = 0;
    var totalToBridgeMs = 0;
    String? path;
    bool? ok;
    String? errorMessage;
    var storeId = '';
    try {
      final sellerId = _resolveGarsonSellerId();
      if (sellerId.isEmpty) {
        if (!mounted) return;
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(content: Text('Satıcı oturumu bulunamadı.')),
        );
        return;
      }
      final providedOrders = (orders ?? const <Map<String, dynamic>>[]);
      final shouldFetchOrders = providedOrders.isEmpty;
      final ordersFuture = shouldFetchOrders
          ? _storeService.getTableOrdersByTable(
              sellerId: sellerId,
              tableNumber: tableNumber,
            )
          : Future<List<Map<String, dynamic>>>.value(providedOrders);

      final storeContext = _garsonReceiptStoreContextForPrint(sellerId);
      storeProfileFetchMs = 0;

      final bridgeReachableFuture = _supportsDirectLocalPrintBridge
          ? (_isLocalPrintAvailable == true
                ? Future<bool>.value(true)
                : _printOrchestrator.isLocalBridgeReachable(useCache: true))
          : Future<bool>.value(false);

      final fetchWatch = Stopwatch()..start();
      final liveData = await Future.wait<dynamic>([
        ordersFuture,
        bridgeReachableFuture,
      ]);
      final fetchedOrders = List<Map<String, dynamic>>.from(
        liveData[0] as List,
      );
      final bridgeReachable = liveData[1] as bool;
      if (shouldFetchOrders) {
        orderFetchMs = fetchWatch.elapsedMilliseconds;
      }
      final tableOrders = fetchedOrders;
      if (tableOrders.isEmpty) {
        if (!mounted) return;
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(content: Text('Masa $tableNumber için adisyon yok.')),
        );
        return;
      }
      storeId = storeContext['store_id'] ?? '';
      final payloadWatch = Stopwatch()..start();
      final basePayload = _buildGarsonReceiptPayload(
        tableNumber: tableNumber,
        tableOrders: tableOrders,
        storeContext: storeContext,
      );
      payloadBuildMs = payloadWatch.elapsedMilliseconds;

      if (_supportsDirectLocalPrintBridge && bridgeReachable) {
        final toBridgeWatch = Stopwatch()..start();
        final resolveWatch = Stopwatch()..start();
        final receiptPrinter = await _garsonReceiptPrinterForDirectDispatch(
          sellerId,
        );
        printerResolveMs = resolveWatch.elapsedMilliseconds;
        if (receiptPrinter == null) {
          _showPrinterWorkflowSnackBar(
            'Adisyon yazıcısı seçilmemiş.',
            warning: true,
          );
          return;
        }
        debugPrint('[ReceiptPrintJob][create_start]');
        debugPrint('documentType=receipt');
        debugPrint('expectedPrinter=${receiptPrinter.displayName}');
        debugPrint('expectedBackend=${receiptPrinter.backend.value}');
        debugPrint('printerId=${receiptPrinter.id}');
        final payload =
            _enrichQueuedReceiptPayloadWithPrinterRouting(
                basePayload,
                stationConfig: const <String, dynamic>{},
              )
              ..['printer_id'] = receiptPrinter.id
              ..['printer_name'] = receiptPrinter.displayName;
        _printOrchestrator.stampDispatchProfileOnPayload(
          payload,
          printer: receiptPrinter,
          documentType: 'receipt',
          role: 'adisyon',
        );
        debugPrint('[ReceiptPrintJob][persisted_payload]');
        debugPrint('documentType=receipt');
        debugPrint('printerRole=adisyon');
        debugPrint('printer_id=${payload['printer_id'] ?? '-'}');
        debugPrint(
          'backend=${payload['backend'] ?? payload['printer_backend'] ?? receiptPrinter.backend.value}',
        );
        debugPrint('paperWidthMm=${payload['paper_width_mm'] ?? '-'}');
        debugPrint(
          'printerProfile=${payload['printer_profile'] ?? payload['printer_profile_id'] ?? '-'}',
        );
        debugPrint('renderMode=${payload['render_mode'] ?? '-'}');
        if (_garsonCachedReceiptEncodingProfile != null) {
          _printOrchestrator.stampEncodingProfileOnPayload(
            payload,
            _garsonCachedReceiptEncodingProfile!,
          );
        } else {
          _printOrchestrator.stampDefaultTurkishGuaranteeOnPayload(payload);
        }
        final printWatch = Stopwatch()..start();
        final directResult = await _printOrchestrator.printPhysicalToPrinter(
          receiptPrinter,
          PrintPayload(documentType: 'receipt', body: payload),
          restaurantId: sellerId,
          flowName: 'waiter_receipt',
          flowType: 'waiter_receipt',
          source: 'seller_panel_garson',
          tableId: tableNumber.toString(),
        );
        bridgeRequestMs = printWatch.elapsedMilliseconds;
        totalToBridgeMs = toBridgeWatch.elapsedMilliseconds;
        path = 'direct';
        ok = directResult.ok;
        if (!mounted) return;
        if (directResult.ok) {
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(
              content: Text('Adisyon fiziksel olarak yazdırıldı.'),
              backgroundColor: Color(0xFF10B981),
            ),
          );
          return;
        }
        final dispatch = directResult.raw?['dispatch'];
        final detail = dispatch is Map
            ? jsonEncode(dispatch)
            : directResult.message;
        _showPrinterWorkflowSnackBar(
          'Adisyon yazdırılamadı. $detail',
          warning: true,
        );
        return;
      }

      final stationConfig = await _printStationService.fetchStationConfig(
        sellerId,
      );
      final printSystemEnabled =
          stationConfig?['print_system_enabled'] != false;
      if (!printSystemEnabled) {
        _showPrinterWorkflowSnackBar(
          'Baskı sistemi kapalı. Yazdırmak için Yazıcı Merkezi’nden sistemi açın.',
          warning: true,
        );
        return;
      }
      final payload = _enrichQueuedReceiptPayloadWithPrinterRouting(
        basePayload,
        stationConfig: stationConfig ?? const <String, dynamic>{},
      );
      final queuedReceiptPrinter = await _garsonReceiptPrinterForDirectDispatch(
        sellerId,
      );
      if (queuedReceiptPrinter != null) {
        _printOrchestrator.stampDispatchProfileOnPayload(
          payload,
          printer: queuedReceiptPrinter,
          documentType: 'receipt',
          role: 'adisyon',
        );
      }
      debugPrint('[ReceiptPrintJob][create_start]');
      debugPrint('documentType=receipt');
      debugPrint(
        'expectedPrinter=${payload['printer_name'] ?? stationConfig?['adisyon_printer_name'] ?? '-'}',
      );
      debugPrint(
        'expectedBackend=${payload['backend'] ?? payload['printer_backend'] ?? '-'}',
      );
      debugPrint('printerId=${payload['printer_id'] ?? '-'}');
      debugPrint('[ReceiptPrintJob][persisted_payload]');
      debugPrint('documentType=receipt');
      debugPrint('printerRole=adisyon');
      debugPrint('printer_id=${payload['printer_id'] ?? '-'}');
      debugPrint(
        'backend=${payload['backend'] ?? payload['printer_backend'] ?? '-'}',
      );
      debugPrint('paperWidthMm=${payload['paper_width_mm'] ?? '-'}');
      debugPrint(
        'printerProfile=${payload['printer_profile'] ?? payload['printer_profile_id'] ?? '-'}',
      );
      debugPrint('renderMode=${payload['render_mode'] ?? '-'}');

      if (!_hasConfiguredAdisyonPrinter(stationConfig)) {
        _showPrinterWorkflowSnackBar(
          'Adisyon yazıcısı seçilmemiş.',
          warning: true,
        );
        return;
      }

      final currentUser = Supabase.instance.client.auth.currentUser;
      final queueResponse = await _printStationService.enqueueReceiptPrintJob(
        restaurantId: sellerId,
        tableNumber: tableNumber,
        payload: payload,
        waiterId: currentUser?.id,
        waiterName: _sellerPrintJobService.safeUserDisplayName(currentUser),
        sourceDevice: _printStationService.currentPlatformLabel(),
      );
      final jobId = queueResponse['print_job_id']?.toString() ?? '';
      debugPrint(
        '[AdisyonQueue] queued job_id=$jobId table=$tableNumber seller=$sellerId '
        'storeId=$storeId durationMs=${watch.elapsedMilliseconds}',
      );
      _printerEventLogService
          .append(
            restaurantId: sellerId,
            event: 'adisyon_job_created',
            message: 'Adisyon print job oluşturuldu.',
            jobId: jobId,
            role: 'adisyon',
            details: <String, dynamic>{
              'tableNumber': tableNumber,
              'durationMs': watch.elapsedMilliseconds,
            },
          )
          .ignore();
      _printerEventLogService
          .append(
            restaurantId: sellerId,
            event: 'job_created',
            message: 'Adisyon print job oluşturuldu.',
            jobId: jobId,
            role: 'adisyon',
            details: <String, dynamic>{
              'tableNumber': tableNumber,
              'durationMs': watch.elapsedMilliseconds,
            },
          )
          .ignore();
      _printerEventLogService
          .append(
            restaurantId: sellerId,
            event: 'adisyon_job_queued',
            message: 'Adisyon print job kuyruğa alındı.',
            jobId: jobId,
            role: 'adisyon',
            details: <String, dynamic>{
              'tableNumber': tableNumber,
              'durationMs': watch.elapsedMilliseconds,
            },
          )
          .ignore();

      if (!mounted) return;
      final stationOnline = await _printStationService.isEffectivelyOnline(
        sellerId,
      );
      if (!mounted) return;
      if (jobId.isNotEmpty) {
        unawaited(
          _trackGarsonAdisyonPrintJob(sellerId: sellerId, jobId: jobId),
        );
      }
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            stationOnline
                ? 'Kuyruğa alındı, henüz basılmadı'
                : _printStationService.offlineWarningMessage(),
          ),
        ),
      );
      path ??= 'fallback_queue';
    } catch (error, stackTrace) {
      debugPrint(
        'SellerPanel queued receipt print failed for table '
        '$tableNumber storeId=$storeId uiAction=$uiAction error=$error',
      );
      debugPrintStack(stackTrace: stackTrace);
      final message = _normalizePrinterWorkflowMessage(
        error,
        fallback: 'Adisyon yazdırma kuyruğuna alınamadı.',
      );
      _showPrinterWorkflowSnackBar(message, warning: true);
      errorMessage = message.replaceAll('\n', ' ');
    } finally {
      logPrintPerf('waiter_receipt', <String, Object?>{
        'tap_at': tapAt.toIso8601String(),
        'order_fetch_ms': orderFetchMs,
        'store_profile_fetch_ms': storeProfileFetchMs,
        'printer_resolve_ms': printerResolveMs,
        'station_resolve_ms': 0,
        'payload_build_ms': payloadBuildMs,
        'bridge_request_ms': bridgeRequestMs,
        'total_to_bridge_ms': totalToBridgeMs > 0
            ? totalToBridgeMs
            : bridgeRequestMs,
        'total_ui_done_ms': watch.elapsedMilliseconds,
        'table': tableNumber,
        if (path != null) 'path': path,
        if (ok != null) 'ok': ok,
        if (errorMessage != null) 'error': errorMessage,
        if (path == 'direct') 'fallback_reason': 'none',
      });
    }
  }

  /// Geçmiş (kapanmış) bir masa için adisyonu "(ESKİ MASA)" başlığıyla
  /// yeniden yazdırma kuyruğuna alır. Canlı `table_orders` satırı oluşturmaz.
  Future<void> _printHistoryAdisyon(TableOrderHistoryRecord record) async {
    final sellerId = _resolveGarsonSellerId();
    if (sellerId.isEmpty) {
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('Satıcı oturumu bulunamadı.')),
      );
      return;
    }

    try {
      final stationConfig = await _printStationService.fetchStationConfig(
        sellerId,
      );
      final printSystemEnabled =
          stationConfig?['print_system_enabled'] != false;
      if (!printSystemEnabled) {
        _showPrinterWorkflowSnackBar(
          'Baskı sistemi kapalı. Yazdırmak için Yazıcı Merkezi’nden sistemi açın.',
          warning: true,
        );
        return;
      }

      final storeContext = await _loadGarsonReceiptStoreContext(sellerId);

      // Geçmiş kayıt items'ını canlı table_orders satırına benzeyen şekle çevir
      final pseudoOrder = <String, dynamic>{
        'id': record.originalOrderId,
        'table_number': record.tableNumber,
        'items': record.items,
        'created_at': (record.openedAt ?? record.createdAt).toIso8601String(),
      };

      final basePayload = _buildGarsonReceiptPayload(
        tableNumber: record.tableNumber,
        tableOrders: [pseudoOrder],
        storeContext: storeContext,
        createdAt: record.openedAt ?? record.createdAt,
        headerNote: '(ESKİ MASA)',
        isHistoryReprint: true,
        historyRecordId: record.id,
      );

      final payload = _enrichQueuedReceiptPayloadWithPrinterRouting(
        basePayload,
        stationConfig: stationConfig ?? const <String, dynamic>{},
      );

      final currentUser = Supabase.instance.client.auth.currentUser;
      final response = await _printStationService.enqueueAdisyonReprintPrintJob(
        restaurantId: sellerId,
        tableNumber: record.tableNumber,
        payload: payload,
        waiterId: currentUser?.id,
        waiterName: _sellerPrintJobService.safeUserDisplayName(currentUser),
        sourceDevice: _printStationService.currentPlatformLabel(),
        historyRecordId: record.id,
      );

      final jobId = response['print_job_id']?.toString() ?? '';
      debugPrint(
        '[HistoryAdisyonReprint] queued job_id=$jobId table=${record.tableNumber} '
        'historyId=${record.id} seller=$sellerId',
      );

      if (!mounted) return;
      final stationOnline = await _printStationService.isEffectivelyOnline(
        sellerId,
      );
      if (!mounted) return;
      if (jobId.isNotEmpty) {
        unawaited(
          _trackGarsonAdisyonPrintJob(sellerId: sellerId, jobId: jobId),
        );
      }
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            stationOnline
                ? '(Eski Masa) adisyon kuyruğa alındı, henüz basılmadı'
                : _printStationService.offlineWarningMessage(),
          ),
        ),
      );
    } catch (error, stackTrace) {
      debugPrint(
        'SellerPanel history adisyon reprint failed for table '
        '${record.tableNumber} historyId=${record.id} error=$error',
      );
      debugPrintStack(stackTrace: stackTrace);
      final message = _normalizePrinterWorkflowMessage(
        error,
        fallback: '(Eski Masa) adisyon yazdırma kuyruğuna alınamadı.',
      );
      _showPrinterWorkflowSnackBar(message, warning: true);
    }
  }

  /// Geçmiş (kapanmış) bir masa için mutfak fişini "(ESKİ MASA)" başlığıyla
  /// yeniden yazdırma kuyruğuna alır. Canlı `table_orders` satırı oluşturmaz.
  Future<void> _printHistoryKitchenTicket(
    TableOrderHistoryRecord record,
  ) async {
    final sellerId = _resolveGarsonSellerId();
    if (sellerId.isEmpty) {
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('Satıcı oturumu bulunamadı.')),
      );
      return;
    }

    if (record.items.isEmpty) {
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('Bu geçmiş masada yazdırılacak ürün bulunamadı.'),
        ),
      );
      return;
    }

    try {
      final stationConfig = await _printStationService.fetchStationConfig(
        sellerId,
      );
      final printSystemEnabled =
          stationConfig?['print_system_enabled'] != false;
      if (!printSystemEnabled) {
        _showPrinterWorkflowSnackBar(
          'Baskı sistemi kapalı. Yazdırmak için Yazıcı Merkezi’nden sistemi açın.',
          warning: true,
        );
        return;
      }

      final storeContext = await _loadGarsonReceiptStoreContext(sellerId);
      final tableRow = _storeTableRowByNumber(record.tableNumber);
      final tableFields = resolvePrintableTablePayloadFields(
        tableRow: tableRow,
        tableNumber: record.tableNumber,
      );

      final now = DateTime.now().toLocal();
      final kitchenItems = record.items
          .map((item) {
            final qty = (item['quantity'] as num?)?.toInt() ?? 1;
            final price = (item['price'] as num?)?.toDouble() ?? 0.0;
            final name = item['name']?.toString().trim().isNotEmpty == true
                ? item['name'].toString().trim()
                : '-';
            return <String, dynamic>{
              'id': item['id']?.toString() ?? '',
              'product_id': item['product_id']?.toString(),
              'name': name,
              'quantity': qty,
              'price': price,
              'note':
                  item['notes']?.toString() ?? item['note']?.toString() ?? '',
              if (item['amountLabel'] != null)
                'amount_label': item['amountLabel'],
              if (item['selectedAttrs'] is List)
                'selected_attrs': item['selectedAttrs'],
              if (item['selectedSizeName'] != null)
                'selected_size_name': item['selectedSizeName'],
            };
          })
          .toList(growable: false);

      final basePayload = <String, dynamic>{
        'title': 'MUTFAK FİŞİ (ESKİ MASA)',
        'store_name': storeContext['store_name'] ?? 'Restoran',
        'branch': storeContext['branch'] ?? 'MERKEZ ŞUBE',
        'table_no': record.tableNumber.toString(),
        'table_number': record.tableNumber,
        ...tableFields,
        'order_no': record.originalOrderId.length > 8
            ? record.originalOrderId.substring(0, 8).toUpperCase()
            : record.originalOrderId.toUpperCase(),
        'order_id': record.originalOrderId,
        'history_record_id': record.id,
        'is_history_reprint': true,
        'header_note': '(ESKİ MASA)',
        'reprint_label': '(ESKİ MASA)',
        'job_type': 'reprint',
        'waiter_name': record.waiterName ?? 'Garson',
        'order_created_at': (record.openedAt ?? record.createdAt)
            .toIso8601String(),
        'closed_at': record.closedAt.toIso8601String(),
        'datetime': now.toIso8601String(),
        'printed_at': now.toIso8601String(),
        'items': kitchenItems,
      };

      // Add printer routing for kitchen (mutfak) role from station config
      final routedPayload = _enrichKitchenReprintPayloadWithRouting(
        basePayload,
        stationConfig: stationConfig ?? const <String, dynamic>{},
      );

      final currentUser = Supabase.instance.client.auth.currentUser;
      final response = await _printStationService.enqueueKitchenReprintPrintJob(
        restaurantId: sellerId,
        tableNumber: record.tableNumber,
        payload: routedPayload,
        waiterId: currentUser?.id,
        waiterName: _sellerPrintJobService.safeUserDisplayName(currentUser),
        sourceDevice: _printStationService.currentPlatformLabel(),
        historyRecordId: record.id,
      );

      final jobId = response['print_job_id']?.toString() ?? '';
      debugPrint(
        '[HistoryKitchenReprint] queued job_id=$jobId table=${record.tableNumber} '
        'historyId=${record.id} seller=$sellerId',
      );

      if (!mounted) return;
      final stationOnline = await _printStationService.isEffectivelyOnline(
        sellerId,
      );
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            stationOnline
                ? '(Eski Masa) mutfak fişi kuyruğa alındı, henüz basılmadı'
                : _printStationService.offlineWarningMessage(),
          ),
        ),
      );
    } catch (error, stackTrace) {
      debugPrint(
        'SellerPanel history kitchen reprint failed for table '
        '${record.tableNumber} historyId=${record.id} error=$error',
      );
      debugPrintStack(stackTrace: stackTrace);
      final message = _normalizePrinterWorkflowMessage(
        error,
        fallback: '(Eski Masa) mutfak fişi yazdırma kuyruğuna alınamadı.',
      );
      _showPrinterWorkflowSnackBar(message, warning: true);
    }
  }

  /// Mutfak yazıcı rotalama bilgisini (`station_config` üzerinden)
  /// history kitchen reprint payload'una ekler.
  Map<String, dynamic> _enrichKitchenReprintPayloadWithRouting(
    Map<String, dynamic> payload, {
    required Map<String, dynamic>? stationConfig,
  }) {
    final nextPayload = Map<String, dynamic>.from(payload)
      ..['printer_role'] = 'mutfak'
      ..['document_type'] = 'kitchen';

    final roleMappings = stationConfig?['role_mappings'];
    if (roleMappings is Map) {
      final kitchenRole = roleMappings['mutfak'];
      if (kitchenRole is Map) {
        final printer = Map<String, dynamic>.from(kitchenRole);
        final bridgePrinterId =
            printer['id']?.toString().trim() ??
            printer['bridgePrinterId']?.toString().trim() ??
            '';
        final printerRecordId =
            printer['printerRecordId']?.toString().trim() ??
            printer['printer_record_id']?.toString().trim() ??
            '';
        final printerName =
            printer['displayName']?.toString().trim() ??
            printer['name']?.toString().trim() ??
            '';
        nextPayload['printer'] = printer;
        if (bridgePrinterId.isNotEmpty) {
          nextPayload['printer_id'] = bridgePrinterId;
        }
        if (printerRecordId.isNotEmpty) {
          nextPayload['printer_record_id'] = printerRecordId;
        }
        if (printerName.isNotEmpty) {
          nextPayload['printer_name'] = printerName;
        }
      }
    }
    return nextPayload;
  }

  Future<void> _trackGarsonAdisyonPrintJob({
    required String sellerId,
    required String jobId,
  }) async {
    const attempts = 20;
    for (var i = 0; i < attempts; i++) {
      await Future<void>.delayed(const Duration(milliseconds: 750));
      if (!mounted) return;
      try {
        final row = await Supabase.instance.client
            .from('print_jobs')
            .select('status, last_error')
            .eq('id', jobId)
            .maybeSingle();
        if (row == null) {
          return;
        }
        final status = row['status']?.toString().trim().toLowerCase() ?? '';
        if (status == 'completed') {
          if (!mounted) return;
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(
              content: Text('Adisyon fiziksel olarak yazdırıldı.'),
              backgroundColor: Color(0xFF10B981),
            ),
          );
          return;
        }
        if (status == 'failed') {
          final error = row['last_error']?.toString().trim().isNotEmpty == true
              ? _normalizePrinterWorkflowMessage(
                  row['last_error'].toString().trim(),
                  fallback: 'Adisyon yazdırılamadı.',
                )
              : 'Adisyon yazdırılamadı.';
          if (!mounted) return;
          ScaffoldMessenger.of(
            context,
          ).showSnackBar(SnackBar(content: Text(error)));
          return;
        }
      } catch (_) {
        return;
      }
    }
  }

  Future<void> _closeGarsonTable({
    required int tableNumber,
    List<Map<String, dynamic>>? existingOrders,
  }) async {
    final sellerId = _resolveGarsonSellerId();
    if (sellerId.isEmpty) {
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('Satıcı oturumu bulunamadı.')),
      );
      return;
    }
    try {
      var tableOrders =
          existingOrders ??
          await _storeService.getTableOrdersByTable(
            sellerId: sellerId,
            tableNumber: tableNumber,
          );
      if (tableOrders.isEmpty) {
        if (!mounted) return;
        ScaffoldMessenger.of(
          context,
        ).showSnackBar(SnackBar(content: Text('Masa $tableNumber zaten boş.')));
        return;
      }

      if (mounted) {
        setState(() {
          _invalidateSellerTableOrdersFallbackFuture();
          _webGarsonClosedTableAt[tableNumber] = DateTime.now();
        });
      }

      try {
        await _storeService.closeTableOrders(
          sellerId: sellerId,
          tableNumber: tableNumber,
        );
      } catch (_) {}

      tableOrders = await _storeService.getTableOrdersByTable(
        sellerId: sellerId,
        tableNumber: tableNumber,
      );
      if (tableOrders.isNotEmpty) {
        for (final order in tableOrders) {
          final orderId = order['id']?.toString() ?? '';
          if (orderId.isEmpty) continue;
          try {
            await _storeService.deleteTableOrder(orderId);
          } catch (_) {
            await _storeService.updateTableOrder(orderId, status: 'closed');
          }
        }
      }

      final remaining = await _storeService.getTableOrdersByTable(
        sellerId: sellerId,
        tableNumber: tableNumber,
      );
      if (remaining.isNotEmpty) {
        throw Exception(
          'Masa kayıtları kapatılamadı (kalan sipariş: ${remaining.length}).',
        );
      }

      if (!mounted) return;
      setState(() {
        _invalidateSellerTableOrdersFallbackFuture();
        _webGarsonClosedTableAt[tableNumber] = DateTime.now();
        _mobileGarsonDraftItemsByTable.remove(tableNumber);
        _mobileGarsonDraftUpdatedAtByTable.remove(tableNumber);
        _mobileGarsonOptimisticSentAtByTable.remove(tableNumber);
        _mobileGarsonOptimisticItemsByTable.remove(tableNumber);
      });
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text('Masa $tableNumber kapatıldı.')));
    } catch (error) {
      if (!mounted) return;
      setState(() {
        _webGarsonClosedTableAt.remove(tableNumber);
      });
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text('Masa kapatılamadı: $error')));
    }
  }

  Future<void> _confirmCloseGarsonTable({
    required int tableNumber,
    List<Map<String, dynamic>>? existingOrders,
  }) async {
    if (!mounted) return;
    final shouldClose = await showDialog<bool>(
      context: context,
      builder: (ctx) {
        return AlertDialog(
          title: Text('Masa $tableNumber kapatılsın mı?'),
          content: const Text(
            'Bu işlem masadaki aktif sipariş kayıtlarını kapatır.',
          ),
          actions: [
            TextButton(
              onPressed: () => Navigator.pop(ctx, false),
              child: const Text('Vazgeç'),
            ),
            FilledButton(
              onPressed: () => Navigator.pop(ctx, true),
              style: FilledButton.styleFrom(
                backgroundColor: Colors.red.shade600,
              ),
              child: const Text('Evet, Kapat'),
            ),
          ],
        );
      },
    );
    if (shouldClose == true) {
      await _closeGarsonTable(
        tableNumber: tableNumber,
        existingOrders: existingOrders,
      );
    }
  }

  Color _mobileGarsonStatusColor(String? status, {required bool hasOrder}) {
    if (!hasOrder) return const Color(0xFF94A3B8);
    switch ((status ?? '').toLowerCase()) {
      case 'call_waiter':
        return const Color(0xFFEA580C); // turuncu-kırmızı – garson çağrısı
      case 'draft':
        return const Color(0xFFD97706); // amber – taslak
      case 'waiting':
      case 'new':
        return const Color(0xFFEF4444); // kırmızı – yeni sipariş
      case 'sent':
      case 'done':
        return const Color(0xFF16A34A); // yeşil – mutfağa iletildi / gönderildi
      case 'preparing':
        return const Color(0xFF0891B2); // teal – hazırlanıyor
      case 'served':
        return const Color(0xFF16A34A); // yeşil – servis edildi
      default:
        return AppColors.primary;
    }
  }

  String _mobileGarsonStatusLabel(String? status, {required bool hasOrder, bool isOptimistic = false}) {
    if (!hasOrder) return 'Boş Masa';
    if (isOptimistic) return 'Gönderiliyor...';
    switch ((status ?? '').toLowerCase()) {
      case 'call_waiter':
        return '🔔 Garson Çağrıldı!';
      case 'draft':
        return 'Taslak Sipariş';
      case 'waiting':
      case 'new':
        return 'Yeni Sipariş';
      case 'sent':
      case 'done':
        return 'Mutfağa İletildi';
      case 'preparing':
        return 'Hazırlanıyor';
      case 'served':
        return 'Servis Edildi';
      default:
        return 'Sipariş Var';
    }
  }

  Widget _buildMobileGarsonTableCard({
    required int tableNumber,
    required Map<String, dynamic>? order,
    required int orderCount,
    List<Map<String, dynamic>>? optimisticItems,
  }) {
    // Prefer order from DB, but fall back to optimistic items if order is null
    final effectiveOrder = order;
    final hasOrderInDb = effectiveOrder != null;
    final hasOptimisticItems = optimisticItems != null && optimisticItems.isNotEmpty;
    final hasOrder = hasOrderInDb || hasOptimisticItems;
    
    final status = effectiveOrder?['status']?.toString();
    final isOptimistic = hasOptimisticItems && !hasOrderInDb;
    final color = _mobileGarsonStatusColor(status, hasOrder: hasOrder);
    final statusLabel = _mobileGarsonStatusLabel(status, hasOrder: hasOrder, isOptimistic: isOptimistic);
    
    // Use DB order items first, then fall back to optimistic items
    final previewItems = hasOrderInDb
        ? _garsonExtractItems(effectiveOrder!)
        : (optimisticItems ?? const <Map<String, dynamic>>[]);
    
    final sortedPreviewItems = List<Map<String, dynamic>>.from(previewItems)
      ..sort((a, b) {
        final left = (a['name']?.toString() ?? '').toLowerCase();
        final right = (b['name']?.toString() ?? '').toLowerCase();
        return left.compareTo(right);
      });
    final visiblePreviewItems = sortedPreviewItems
        .take(3)
        .toList(growable: false);
    final timeLabel = effectiveOrder != null
        ? _garsonOrderTimeAgoLabel(effectiveOrder)
        : 'Sipariş gir';
    final timeText = hasOrder
        ? (timeLabel == 'Az önce'
              ? 'Az önce${orderCount > 1 ? ' • $orderCount sipariş' : ''}'
              : '$timeLabel önce${orderCount > 1 ? ' • $orderCount sipariş' : ''}')
        : 'Dokun ve sipariş gir';
    final tableRow = _storeTableRowByNumber(tableNumber);
    final tableTitle = tableRow == null
        ? 'Masa $tableNumber'
        : _tableDisplayLabelFromRow(tableRow);
    
    final orderIdForDebug = effectiveOrder?['id'] ?? 'optimistic-${DateTime.now().millisecondsSinceEpoch}';
    final totalForDebug = hasOrderInDb
        ? _garsonOrdersTotal(<Map<String, dynamic>>[effectiveOrder!])
        : (optimisticItems?.isEmpty ?? true ? 0 : optimisticItems!.fold<num>(0, (sum, item) => sum + ((item['line_total'] as num?) ?? 0)));
    
    debugPrint(
      '[GARSON_TABLE_CARD_BIND] '
      'table_id=${tableRow?['id'] ?? order?['table_id'] ?? order?['store_table_id'] ?? '-'} '
      'table_number=$tableNumber '
      'display_label=$tableTitle '
      'active_order_found=$hasOrder '
      'from_db=$hasOrderInDb '
      'from_optimistic=$hasOptimisticItems '
      'order_id=$orderIdForDebug '
      'items_count=${previewItems.length} '
      'total=$totalForDebug',
    );

    return Material(
      color: Colors.transparent,
      child: InkWell(
        borderRadius: BorderRadius.circular(14),
        onTap: () {
          _openGarsonTableFlowPage(
            tableNumber: tableNumber,
            initialOrder: order,
          );
        },
        child: Container(
          padding: const EdgeInsets.all(10),
          decoration: BoxDecoration(
            color: hasOrder ? color.withValues(alpha: 0.12) : Colors.white,
            borderRadius: BorderRadius.circular(14),
            border: Border.all(
              color: hasOrder
                  ? color.withValues(alpha: 0.4)
                  : const Color(0xFFE2E8F0),
            ),
          ),
          child: Stack(
            children: [
              Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Row(
                    children: [
                      Expanded(
                        child: Text(
                          tableTitle,
                          maxLines: 1,
                          overflow: TextOverflow.ellipsis,
                          style: const TextStyle(
                            fontSize: 13,
                            fontWeight: FontWeight.w800,
                            color: Color(0xFF111827),
                          ),
                        ),
                      ),
                      if (orderCount > 1)
                        Container(
                          padding: const EdgeInsets.symmetric(
                            horizontal: 6,
                            vertical: 2,
                          ),
                          decoration: BoxDecoration(
                            color: color,
                            borderRadius: BorderRadius.circular(999),
                          ),
                          child: Text(
                            '$orderCount',
                            style: const TextStyle(
                              color: Colors.white,
                              fontSize: 10,
                              fontWeight: FontWeight.w800,
                            ),
                          ),
                        ),
                    ],
                  ),
                  const SizedBox(height: 6),
                  Text(
                    statusLabel,
                    maxLines: 1,
                    overflow: TextOverflow.ellipsis,
                    style: TextStyle(
                      fontSize: 11,
                      fontWeight: FontWeight.w700,
                      color: color,
                    ),
                  ),
                  const SizedBox(height: 2),
                  Text(
                    timeText,
                    maxLines: 1,
                    overflow: TextOverflow.ellipsis,
                    style: TextStyle(
                      fontSize: 10,
                      color: Colors.grey.shade600,
                      height: 1.2,
                    ),
                  ),
                  const SizedBox(height: 6),
                  if (visiblePreviewItems.isEmpty)
                    Expanded(
                      child: Center(
                        child: Icon(
                          hasOrder
                              ? Icons.notifications_active_rounded
                              : Icons.add_circle_outline_rounded,
                          color: color,
                          size: 22,
                        ),
                      ),
                    )
                  else
                    Expanded(
                      child: Column(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: [
                          ...visiblePreviewItems.map((item) {
                            final lineLabel =
                                GarsonProductSelection.orderItemDisplayLabel(
                                  item,
                                );
                            return Padding(
                              padding: const EdgeInsets.only(bottom: 2),
                              child: Text(
                                lineLabel.isNotEmpty ? lineLabel : '-',
                                maxLines: 1,
                                overflow: TextOverflow.ellipsis,
                                style: const TextStyle(
                                  fontSize: 10,
                                  fontWeight: FontWeight.w600,
                                  color: Color(0xFF111827),
                                ),
                              ),
                            );
                          }),
                          if (sortedPreviewItems.length >
                              visiblePreviewItems.length)
                            Text(
                              '+${sortedPreviewItems.length - visiblePreviewItems.length} ürün',
                              style: TextStyle(
                                fontSize: 10,
                                color: Colors.grey.shade600,
                                fontWeight: FontWeight.w600,
                              ),
                            ),
                        ],
                      ),
                    ),
                ],
              ),
            ],
          ),
        ),
      ),
    );
  }

  void _openGarsonTableFlowPage({
    required int tableNumber,
    Map<String, dynamic>? initialOrder,
  }) {
    unawaited(
      _pushGarsonTableFlowPage(
        tableNumber: tableNumber,
        initialOrder: initialOrder,
      ),
    );
  }

  Future<void> _pushGarsonTableFlowPage({
    required int tableNumber,
    Map<String, dynamic>? initialOrder,
  }) async {
    final sellerId =
        initialOrder?['seller_id']?.toString().trim().isNotEmpty == true
        ? initialOrder!['seller_id'].toString().trim()
        : (_storeTables
                  .firstWhere(
                    (row) =>
                        (row['seller_id']?.toString().trim() ?? '').isNotEmpty,
                    orElse: () => const <String, dynamic>{},
                  )['seller_id']
                  ?.toString()
                  .trim() ??
              _authService.currentUser?.id ??
              '');
    if (sellerId.isEmpty) {
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('Satıcı oturumu bulunamadı.')),
      );
      return;
    }

    await _warmGarsonPrintCaches(sellerId);
    if (!mounted) return;

    final tableRow = _storeTableRowByNumber(tableNumber);
    final tableTitle = resolveTableCardTitle(
      tableRow: tableRow,
      tableNumber: tableNumber,
    );
    final kitchenPrinter = _garsonCachedKitchenPrinter;
    final bridgeReady =
        _isLocalPrintAvailable ??
        await _printOrchestrator.isLocalBridgeReachable(useCache: true);
    final canFastKitchen =
        _supportsDirectLocalPrintBridge &&
        bridgeReady &&
        kitchenPrinter != null;

    final flowPage = _MobileGarsonTableFlowPage(
      sellerId: sellerId,
      tableNumber: tableNumber,
      tableTitleOverride: tableTitle,
      products: List<SellerProduct>.from(_products),
      initialTabIndex: initialOrder == null ? 0 : 2,
      initialOrderId: initialOrder?['id']?.toString(),
      tableOrdersStream: _tableOrdersStream,
      initialDraftItems:
          _mobileGarsonDraftItemsByTable[tableNumber] ??
          const <Map<String, dynamic>>[],
      // Pass the already-loaded store table numbers so the transfer modal
      // does not need a separate API call (which can fail with RLS errors).
      storeTableNumbers: _sortedStoreTableNumbers(),
      configureProductItem: _configureGarsonProductItem,
      editItemSettings: _editGarsonItemSettings,
      onDraftChanged: _onMobileGarsonDraftChanged,
      onOrderSubmitted: _onMobileGarsonOrderSubmitted,
      onPrintAdisyon: (selectedTableNumber, orders) => _printGarsonAdisyon(
        tableNumber: selectedTableNumber,
        orders: orders,
        uiAction: 'table_flow_adisyon_button',
      ),
      onTableCloseOptimistic: (closedTableNumber) {
        if (!mounted) return;
        setState(() {
          _invalidateSellerTableOrdersFallbackFuture();
          _webGarsonClosedTableAt[closedTableNumber] = DateTime.now();
        });
      },
      onTableCloseFailed: (closedTableNumber) {
        if (!mounted) return;
        setState(() => _webGarsonClosedTableAt.remove(closedTableNumber));
      },
      onTableClosed: (closedTableNumber) {
        if (!mounted) return;
        setState(() {
          _invalidateSellerTableOrdersFallbackFuture();
          _webGarsonClosedTableAt[closedTableNumber] = DateTime.now();
          _mobileGarsonDraftItemsByTable.remove(closedTableNumber);
          _mobileGarsonDraftUpdatedAtByTable.remove(closedTableNumber);
          _mobileGarsonOptimisticSentAtByTable.remove(closedTableNumber);
          _mobileGarsonOptimisticItemsByTable.remove(closedTableNumber);
        });
      },
      onConfirmCustomerKitchenPrint:
          ({
            required int tableNumber,
            required List<Map<String, dynamic>> tableOrders,
          }) => _confirmGarsonPendingKitchenPrint(
            tableNumber: tableNumber,
            tableOrders: tableOrders,
          ),
      supportsDirectLocalPrintBridge: _supportsDirectLocalPrintBridge,
      isLocalPrintAvailable: _isLocalPrintAvailable,
      canUseLocalPrintFastPath: canFastKitchen,
      cachedKitchenPrinterId: kitchenPrinter?.id,
      cachedKitchenPrinterName: kitchenPrinter?.displayName,
      cachedKitchenPrinterBackend: kitchenPrinter?.backend.value,
      cachedKitchenPrinterQueue: kitchenPrinter?.queueName,
    );

    // Always open as a full-screen route — consistent on mobile and web.
    final moduleBeforeOpen = _selectedModule;
    debugPrint(
      '[GarsonNavigation][open_table] '
      'table=$tableNumber '
      'moduleBefore=${moduleBeforeOpen.name}',
    );
    sellerNavigationLog(
      'open_table',
      extra: {
        'table': tableNumber.toString(),
        'moduleBefore': moduleBeforeOpen.name,
        'moduleAfter': 'garson',
      },
    );
    _setActiveSellerModule(
      SellerModule.garson,
      source: 'garson_table_open_parent_restore',
      userInitiated: false,
      parentRestore: true,
    );
    await Future<void>.delayed(Duration.zero);
    if (!mounted) return;
    _isGarsonTableRouteOpen = true;
    debugPrint(
      '[SellerNavigation][garson_table_route_lock] '
      'state=open table=$tableNumber '
      'hasUserSelected=$_hasUserSelectedSellerModule '
      'parent=${_selectedModule.name}',
    );
    try {
      await Navigator.of(
        context,
      ).push(MaterialPageRoute<void>(builder: (_) => flowPage));
    } finally {
      _isGarsonTableRouteOpen = false;
      debugPrint(
        '[SellerNavigation][garson_table_route_lock] '
        'state=closed table=$tableNumber '
        'parentAtPop=${_selectedModule.name}',
      );
      _returnFromGarsonTableToGarsonList(source: 'garson_table_route_popped');
      debugPrint(
        '[GarsonNavigation][route_popped_parent_restore] '
        'from=${moduleBeforeOpen.name} to=${_selectedModule.name}',
      );
    }
  }

