  (double, int, double) _dashboardRollingPeriodStats(int days) {
    final now = DateTime.now();
    final start = DateTime(
      now.year,
      now.month,
      now.day,
    ).subtract(Duration(days: days - 1));
    final end = DateTime(now.year, now.month, now.day, 23, 59, 59);
    final previousEnd = start.subtract(const Duration(seconds: 1));
    final previousStart = start.subtract(Duration(days: days));
    final currentOrders = _dashboardOrdersBetween(start, end);
    final previousOrders = _dashboardOrdersBetween(previousStart, previousEnd);
    final currentRevenue = _dashboardSumRevenue(currentOrders);
    final previousRevenue = _dashboardSumRevenue(previousOrders);
    return (
      currentRevenue,
      currentOrders.length,
      SellerDashboardService.calculateChangePercent(
        current: currentRevenue,
        previous: previousRevenue,
      ),
    );
  }

  (double, int) _dashboardMonthStats() {
    final now = DateTime.now();
    final start = DateTime(now.year, now.month, 1);
    final currentOrders = _dashboardOrdersBetween(
      start,
      DateTime(now.year, now.month, now.day, 23, 59, 59),
    );
    return (_dashboardSumRevenue(currentOrders), currentOrders.length);
  }

  int _dashboardTodayOrderCount() {
    final now = DateTime.now();
    return _dashboardOrdersBetween(
      DateTime(now.year, now.month, now.day),
      DateTime(now.year, now.month, now.day, 23, 59, 59),
    ).length;
  }

  int _dashboardTodayStatusCount(List<String> statuses) {
    final todayOrders = _dashboardOrdersBetween(
      DateTime.now(),
      DateTime.now(),
      normalizeDay: true,
    );
    return todayOrders.where((order) {
      final status = _normalizeDashboardOrderStatus(order['status']);
      return statuses.contains(status);
    }).length;
  }

  Map<String, int> _dashboardStatusCounts() {
    final counts = <String, int>{
      'new': 0,
      'preparing': 0,
      'ready_to_ship': 0,
      'shipped': 0,
      'delivered': 0,
      'returns': 0,
    };
    // Use combined orders so table orders (normalised to ecommerce-like
    // statuses) are counted in the shared buckets (new/preparing/delivered/returns).
    for (final order in _combinedDashboardOrders) {
      final status = _normalizeDashboardOrderStatus(order['status']);
      if (status == 'new' || status == 'confirmed') {
        counts['new'] = (counts['new'] ?? 0) + 1;
      } else if (status == 'preparing') {
        counts['preparing'] = (counts['preparing'] ?? 0) + 1;
      } else if (status == 'ready_to_ship') {
        counts['ready_to_ship'] = (counts['ready_to_ship'] ?? 0) + 1;
      } else if ([
        'shipped',
        'transfer',
        'branch',
        'out_for_delivery',
      ].contains(status)) {
        counts['shipped'] = (counts['shipped'] ?? 0) + 1;
      } else if (status == 'delivered') {
        counts['delivered'] = (counts['delivered'] ?? 0) + 1;
      } else if (status.contains('return') || status.contains('cancel')) {
        counts['returns'] = (counts['returns'] ?? 0) + 1;
      }
    }
    // For food businesses also attach restaurant-specific counters.
    if (_isFoodStoreCategory(_storeCategory)) {
      counts.addAll(_dashboardRestaurantStatusCounts());
    }
    return counts;
  }

  List<Map<String, dynamic>> _dashboardPendingTasks(
    SellerDashboardMetrics metrics,
    Map<String, int> statusCounts,
  ) {
    final lowStockProduct = _products.cast<SellerProduct?>().firstWhere(
      (product) => (product?.stock ?? 999) <= 5,
      orElse: () => null,
    );
    final items = <Map<String, dynamic>>[];

    if (_isFoodStoreCategory(_storeCategory)) {
      // ── Restaurant pending tasks ──────────────────────────────────────────
      final openTables = statusCounts['open_tables'] ?? 0;
      final sentToKitchen = statusCounts['sent_to_kitchen'] ?? 0;
      final restaurantCancelled = statusCounts['restaurant_cancelled'] ?? 0;
      final todayTableOrders = statusCounts['today_table_orders'] ?? 0;

      if (openTables > 0) {
        items.add({
          'icon': Icons.table_restaurant_outlined,
          'title': '$openTables açık masa var - takipte',
          'actionLabel': 'Garson',
          'accent': const Color(0xFF2563EB),
          'background': const Color(0xFFE8F0FF),
          'onTap': () => _setSelectedModule(SellerModule.garson),
        });
      }
      if (sentToKitchen > 0) {
        items.add({
          'icon': Icons.soup_kitchen_outlined,
          'title': '$sentToKitchen sipariş mutfağa iletildi',
          'actionLabel': 'Garson',
          'accent': const Color(0xFFF59E0B),
          'background': const Color(0xFFFFF4DB),
          'onTap': () => _setSelectedModule(SellerModule.garson),
        });
      }
      if (todayTableOrders > 0) {
        items.add({
          'icon': Icons.receipt_long_outlined,
          'title': 'Bugün $todayTableOrders garson siparişi alındı',
          'actionLabel': 'Görüntüle',
          'accent': const Color(0xFF16A34A),
          'background': const Color(0xFFECFDF5),
          'onTap': () => _setSelectedModule(SellerModule.garson),
        });
      }
      if (restaurantCancelled > 0) {
        items.add({
          'icon': Icons.cancel_outlined,
          'title': '$restaurantCancelled iptal edilmiş sipariş var',
          'actionLabel': 'İncele',
          'accent': const Color(0xFFEF4444),
          'background': const Color(0xFFFEF2F2),
          'onTap': () => _setSelectedModule(SellerModule.garson),
        });
      }
    } else {
      // ── E-commerce pending tasks (original behaviour) ────────────────────
      final newOrders = statusCounts['new'] ?? 0;
      final readyToShip = statusCounts['ready_to_ship'] ?? 0;
      final returns = statusCounts['returns'] ?? 0;
      if (newOrders > 0) {
        items.add({
          'icon': Icons.error_outline_rounded,
          'title': '$newOrders sipariş öncelikli - hemen hazırla',
          'actionLabel': 'Görüntüle',
          'accent': const Color(0xFFEF4444),
          'background': const Color(0xFFFEF2F2),
          'onTap': () {
            _setSelectedModule(SellerModule.orders);
          },
        });
      }
      if (readyToShip > 0) {
        items.add({
          'icon': Icons.timelapse_rounded,
          'title': '$readyToShip sipariş bugün gönderilmeli',
          'actionLabel': 'Görüntüle',
          'accent': const Color(0xFFF59E0B),
          'background': const Color(0xFFFEFCE8),
          'onTap': () {
            _setSelectedModule(SellerModule.orders);
          },
        });
      }
      if (returns > 0) {
        items.add({
          'icon': Icons.undo_rounded,
          'title': '$returns iade talebi inceleme bekliyor',
          'actionLabel': 'İncele',
          'accent': const Color(0xFF64748B),
          'background': const Color(0xFFF8FAFC),
          'onTap': () {
            _setSelectedModule(SellerModule.orders);
          },
        });
      }
    }

    // Low stock always shown regardless of business type.
    if (lowStockProduct != null) {
      items.add({
        'icon': Icons.warning_amber_rounded,
        'title':
            '${lowStockProduct.name} stoğu kritik seviyede (${lowStockProduct.stock} adet)',
        'actionLabel': 'Stok Ekle',
        'accent': const Color(0xFFF59E0B),
        'background': const Color(0xFFFFFBEB),
        'onTap': () {
          _setSelectedModule(SellerModule.products);
        },
      });
    }
    if (metrics.openSupportTickets > 0) {
      items.add({
        'icon': Icons.support_agent_outlined,
        'title': '${metrics.openSupportTickets} destek talebi cevap bekliyor',
        'actionLabel': 'Detay',
        'accent': const Color(0xFF64748B),
        'background': const Color(0xFFF8FAFC),
        'onTap': () {
          _setSelectedModule(SellerModule.support);
        },
      });
    }

    if (items.isEmpty) {
      items.add({
        'icon': Icons.check_circle_outline_rounded,
        'title': 'Şu anda bekleyen kritik işlem görünmüyor',
        'actionLabel': 'Yenile',
        'accent': const Color(0xFF10B981),
        'background': const Color(0xFFECFDF5),
        'onTap': () => _refreshDashboardData(
          source: 'pending_tasks_yenile',
          userInitiated: true,
        ),
      });
    }
    return items.take(5).toList(growable: false);
  }

  List<Map<String, dynamic>> _dashboardTopProducts() {
    final now = DateTime.now();
    final monthOrders = _dashboardOrdersBetween(
      DateTime(now.year, now.month, 1),
      DateTime(now.year, now.month, now.day, 23, 59, 59),
    );
    final stockBySku = <String, int>{};
    final stockByName = <String, int>{};
    for (final product in _products) {
      if (product.sku.trim().isNotEmpty) {
        stockBySku[product.sku] = product.stock;
      }
      stockByName[product.name] = product.stock;
    }
    final aggregated = <String, Map<String, dynamic>>{};
    for (final order in monthOrders) {
      final name = (order['product_name'] ?? order['productName'] ?? 'Ürün')
          .toString();
      final code = (order['product_code'] ?? order['productCode'] ?? name)
          .toString();
      final key = code.isEmpty ? name : code;
      final quantity = int.tryParse((order['quantity'] ?? 1).toString()) ?? 1;
      final revenue =
          ((order['total_price'] ??
                      order['totalPrice'] ??
                      order['total_amount'] ??
                      order['totalAmount'] ??
                      0)
                  as num)
              .toDouble();
      final entry = aggregated.putIfAbsent(key, () {
        return {
          'name': name,
          'code': code,
          'quantity': 0,
          'revenue': 0.0,
          'stock': stockBySku[code] ?? stockByName[name] ?? 0,
        };
      });
      entry['quantity'] = (entry['quantity'] as int) + quantity;
      entry['revenue'] = (entry['revenue'] as double) + revenue;
    }

    final list = aggregated.values.toList(growable: false)
      ..sort((a, b) {
        final countCompare = (b['quantity'] as int).compareTo(
          a['quantity'] as int,
        );
        if (countCompare != 0) return countCompare;
        return (b['revenue'] as double).compareTo(a['revenue'] as double);
      });
    return list.take(5).toList(growable: false);
  }

  List<Map<String, dynamic>> _dashboardCargoSummary() {
    const palette = [
      Color(0xFFA855F7),
      Color(0xFF3B82F6),
      Color(0xFFF97316),
      Color(0xFFEF4444),
      Color(0xFF10B981),
    ];
    final grouped = <String, Map<String, dynamic>>{};
    for (final order in _sellerOrders) {
      final rawCargo = (order['cargo_company'] ?? 'İHız').toString().trim();
      final cargo = rawCargo.isEmpty ? 'İHız' : rawCargo;
      final entry = grouped.putIfAbsent(cargo, () {
        return {'name': cargo, 'count': 0, 'delivered': 0};
      });
      entry['count'] = (entry['count'] as int) + 1;
      if (_normalizeDashboardOrderStatus(order['status']) == 'delivered') {
        entry['delivered'] = (entry['delivered'] as int) + 1;
      }
    }
    final items = grouped.values.toList(growable: false)
      ..sort((a, b) => (b['count'] as int).compareTo(a['count'] as int));
    return items
        .asMap()
        .entries
        .map((entry) {
          final count = entry.value['count'] as int;
          final delivered = entry.value['delivered'] as int;
          final success = count == 0 ? 0.0 : (delivered / count) * 100;
          return {
            'name': entry.value['name'] as String,
            'count': count,
            'success': success,
            'color': palette[entry.key % palette.length],
          };
        })
        .take(4)
        .toList(growable: false);
  }

  double _dashboardShippingPerformance(Map<String, int> statusCounts) {
    final shippedLike =
        (statusCounts['shipped'] ?? 0) + (statusCounts['delivered'] ?? 0);
    final operationalBase =
        (statusCounts['new'] ?? 0) +
        (statusCounts['preparing'] ?? 0) +
        (statusCounts['ready_to_ship'] ?? 0) +
        shippedLike;
    if (operationalBase == 0) return 0;
    return (shippedLike / operationalBase) * 100;
  }

  double _dashboardReturnRate(
    Map<String, int> statusCounts,
    int totalOrderCount,
  ) {
    if (totalOrderCount == 0) return 0;
    return ((statusCounts['returns'] ?? 0) / totalOrderCount) * 100;
  }

  List<Map<String, dynamic>> _dashboardOrdersBetween(
    DateTime start,
    DateTime end, {
    bool normalizeDay = false,
  }) {
    final normalizedStart = normalizeDay
        ? DateTime(start.year, start.month, start.day)
        : start;
    final normalizedEnd = normalizeDay
        ? DateTime(end.year, end.month, end.day, 23, 59, 59)
        : end;
    return _combinedDashboardOrders
        .where((order) {
          final createdAt = _dashboardOrderDate(order);
          if (createdAt == null) return false;
          return !createdAt.isBefore(normalizedStart) &&
              !createdAt.isAfter(normalizedEnd);
        })
        .toList(growable: false);
  }

  DateTime? _dashboardOrderDate(Map<String, dynamic> order) {
    final raw = order['created_at'] ?? order['createdAt'];
    if (raw == null) return null;
    return DateTime.tryParse(raw.toString())?.toLocal();
  }

  double _dashboardSumRevenue(List<Map<String, dynamic>> orders) {
    return orders.fold<double>(0, (sum, order) {
      final amount =
          order['total_price'] ??
          order['totalPrice'] ??
          order['total_amount'] ??
          order['totalAmount'] ??
          0;
      return sum + (amount as num).toDouble();
    });
  }

  String _normalizeDashboardOrderStatus(dynamic status) {
    return (status ?? '').toString().trim().toLowerCase();
  }

  Future<void> _setDashboardRollingRange(int days) async {
    final now = DateTime.now();
    setState(() {
      _dashboardRangePreset = SellerDashboardRangePreset.custom;
      _dashboardCustomRange = DateTimeRange(
        start: DateTime(
          now.year,
          now.month,
          now.day,
        ).subtract(Duration(days: days - 1)),
        end: now,
      );
    });
  }

  bool _isDashboardRollingRangeSelected(int days) {
    final range = _dashboardDateRange;
    final difference = range.end.difference(range.start).inDays + 1;
    return _dashboardRangePreset == SellerDashboardRangePreset.custom &&
        difference == days;
  }

  String _formatDashboardLongDate(DateTime date) {
    const days = [
      'Pazartesi',
      'Salı',
      'Çarşamba',
      'Perşembe',
      'Cuma',
      'Cumartesi',
      'Pazar',
    ];
    const months = [
      'Ocak',
      'Şubat',
      'Mart',
      'Nisan',
      'Mayıs',
      'Haziran',
      'Temmuz',
      'Ağustos',
      'Eylül',
      'Ekim',
      'Kasım',
      'Aralık',
    ];
    return '${days[date.weekday - 1]}, ${date.day} ${months[date.month - 1]} ${date.year}';
  }

  String _formatDashboardRangeCaption(DateTime start, DateTime end) {
    const months = [
      'Oca',
      'Şub',
      'Mar',
      'Nis',
      'May',
      'Haz',
      'Tem',
      'Ağu',
      'Eyl',
      'Eki',
      'Kas',
      'Ara',
    ];
    final startLabel = '${start.day} ${months[start.month - 1]}';
    final endLabel = '${end.day} ${months[end.month - 1]} ${end.year}';
    return '$startLabel - $endLabel';
  }

  String _formatDashboardNumber(num value) {
    final fixed = value.toStringAsFixed(0);
    final buffer = StringBuffer();
    for (var i = 0; i < fixed.length; i++) {
      buffer.write(fixed[i]);
      final remaining = fixed.length - i - 1;
      if (remaining > 0 && remaining % 3 == 0) {
        buffer.write('.');
      }
    }
    return buffer.toString();
  }

  String _formatDashboardCurrency(double value) {
    return '₺${_formatDashboardNumber(value.round())}';
  }

  Widget _buildEnhancedSalesChart(SellerDashboardMetrics metrics) {
    final points = _dashboardChartPoints(metrics);
    final hasData = points.any((point) => point.revenue > 0);
    final maxRevenue = points.fold<double>(
      1,
      (maxValue, point) => point.revenue > maxValue ? point.revenue : maxValue,
    );
    final lineColor = const Color(0xFF7C3AED);

    return Column(
      children: [
        SizedBox(
          height: 250,
          child: Row(
            crossAxisAlignment: CrossAxisAlignment.stretch,
            children: [
              SizedBox(
                width: 62,
                child: Column(
                  mainAxisAlignment: MainAxisAlignment.spaceBetween,
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: _buildChartYAxisLabels(maxRevenue),
                ),
              ),
              const SizedBox(width: 8),
              Expanded(
                child: Stack(
                  children: [
                    Positioned.fill(
                      child: CustomPaint(
                        painter: SellerDashboardLineChartPainter(
                          points: points,
                          lineColor: lineColor,
                          maxValue: maxRevenue,
                          showFullYearMarkers:
                              _dashboardRangePreset ==
                              SellerDashboardRangePreset.yearToDate,
                        ),
                      ),
                    ),
                    if (!hasData)
                      Center(
                        child: Text(
                          'Secili tarih araliginda satis verisi bulunmuyor',
                          style: TextStyle(
                            color: Colors.grey.shade400,
                            fontSize: 14,
                          ),
                        ),
                      ),
                  ],
                ),
              ),
            ],
          ),
        ),
        const SizedBox(height: 14),
        Row(
          mainAxisAlignment: MainAxisAlignment.spaceBetween,
          children: _buildChartXAxisLabels(points),
        ),
      ],
    );
  }

  List<Widget> _buildChartYAxisLabels(double maxRevenue) {
    final steps = 4;
    return List.generate(steps + 1, (index) {
      final ratio = (steps - index) / steps;
      final value = maxRevenue * ratio;
      return Text(
        _formatChartAxisValue(value),
        style: TextStyle(
          fontSize: 11,
          color: Colors.grey.shade500,
          fontWeight: FontWeight.w500,
        ),
      );
    });
  }

  List<Widget> _buildChartXAxisLabels(List<SellerDashboardSeriesPoint> points) {
    if (points.isEmpty) {
      return const [SizedBox.shrink()];
    }
    final labelIndices = <int>{};
    final desired = math.min(7, points.length);
    if (desired == 1) {
      labelIndices.add(0);
    } else {
      for (var i = 0; i < desired; i++) {
        final ratio = i / (desired - 1);
        labelIndices.add((ratio * (points.length - 1)).round());
      }
    }

    final sorted = labelIndices.toList()..sort();
    return sorted
        .map((index) {
          final point = points[index];
          return Text(
            point.label,
            textAlign: TextAlign.center,
            style: TextStyle(
              fontSize: 11,
              color: Colors.grey.shade600,
              fontWeight: FontWeight.w500,
            ),
          );
        })
        .toList(growable: false);
  }

  String _formatChartAxisValue(double value) {
    if (value <= 0) {
      return '₺0';
    }
    if (value >= 1000) {
      return '₺${(value / 1000).toStringAsFixed(0)}B';
    }
    return '₺${value.toStringAsFixed(0)}';
  }

