                  runSpacing: 6,
                  crossAxisAlignment: WrapCrossAlignment.center,
                  children: [
                    Text(
                      'SKU: ${product.sku}',
                      style: TextStyle(
                        fontSize: 10.5,
                        color: Colors.grey.shade600,
                      ),
                    ),
                    if (isTemplate) _templateTypeBadge(product),
                  ],
                ),
              ],
            ),
          ),
          const SizedBox(width: 16),

          // Kategori
          Expanded(
            child: Text(
              _templateCategoryLabel(product),
              style: TextStyle(fontSize: 11.5, color: Colors.grey.shade700),
              maxLines: 1,
              overflow: TextOverflow.ellipsis,
            ),
          ),
          const SizedBox(width: 16),

          // Fiyat
          SizedBox(
            width: priceColumnWidth,
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Text(
                  _templatePreviewPriceLabel(product),
                  style: const TextStyle(
                    fontSize: 12.5,
                    fontWeight: FontWeight.bold,
                  ),
                ),
                if (product.hasDiscount && !isTemplate)
                  Text(
                    product.originalPrice,
                    style: TextStyle(
                      fontSize: 10.5,
                      color: Colors.grey.shade500,
                      decoration: TextDecoration.lineThrough,
                    ),
                  ),
              ],
            ),
          ),
          const SizedBox(width: 16),

          // Stok
          SizedBox(
            width: stockColumnWidth,
            child: Row(
              children: [
                Container(
                  width: 8,
                  height: 8,
                  decoration: BoxDecoration(
                    color: isOutOfStock
                        ? Colors.red
                        : isLowStock
                        ? Colors.orange
                        : Colors.green,
                    shape: BoxShape.circle,
                  ),
                ),
                const SizedBox(width: 6),
                Text(
                  isTemplate ? _templateTypeLabel(product) : '${product.stock}',
                  style: TextStyle(
                    fontSize: 11.5,
                    fontWeight: FontWeight.w600,
                    color: isOutOfStock
                        ? Colors.red
                        : isLowStock
                        ? Colors.orange
                        : Colors.grey.shade800,
                  ),
                ),
              ],
            ),
          ),
          const SizedBox(width: 16),

          // Durum
          SizedBox(
            width: statusColumnWidth,
            child: Container(
              padding: const EdgeInsets.symmetric(horizontal: 7, vertical: 3),
              decoration: BoxDecoration(
                color: _getStatusColor(product.status, isBackground: true),
                borderRadius: BorderRadius.circular(5),
              ),
              child: Text(
                _getStatusLabel(product.status),
                style: TextStyle(
                  fontSize: 10.5,
                  fontWeight: FontWeight.w600,
                  color: _getStatusColor(product.status, isBackground: false),
                ),
                textAlign: TextAlign.center,
              ),
            ),
          ),
          const SizedBox(width: 16),

          // İşlemler
          SizedBox(
            width: actionColumnWidth,
            child: Row(
              children: [
                IconButton(
                  onPressed: () async {
                    productEditLog(
                      'route_decision',
                      extra: {
                        'productId': product.id,
                        'isTemplate': isTemplate,
                        'resolvedKind':
                            MixedServiceOrder.productTypeFromProduct(product),
                      },
                    );
                    if (isTemplate) {
                      productEditLog(
                        'open_service_editor',
                        extra: {'productId': product.id},
                      );
                      await _openTemplateEditor(existingProduct: product);
                      return;
                    }
                    productEditLog(
                      'open_normal_product_editor',
                      extra: {'productId': product.id},
                    );
                    final result = await Navigator.push(
                      context,
                      MaterialPageRoute(
                        builder: (context) =>
                            AddProductPage(isEdit: true, productId: product.id),
                      ),
                    );
                    if (result == true) _refreshProducts();
                  },
                  icon: const Icon(Icons.edit_outlined, size: 18),
                  tooltip: 'Düzenle',
                  padding: const EdgeInsets.all(4),
                  constraints: const BoxConstraints.tightFor(
                    width: 30,
                    height: 30,
                  ),
                ),
                const SizedBox(width: 6),
                IconButton(
                  onPressed: isDeleting
                      ? null
                      : () => _deleteProduct(product.id),
                  icon: isDeleting
                      ? const SizedBox(
                          width: 18,
                          height: 18,
                          child: CircularProgressIndicator(strokeWidth: 2),
                        )
                      : const Icon(
                          Icons.delete_outline,
                          size: 18,
                          color: Colors.red,
                        ),
                  tooltip: 'Sil',
                  padding: const EdgeInsets.all(4),
                  constraints: const BoxConstraints.tightFor(
                    width: 30,
                    height: 30,
                  ),
                ),
              ],
            ),
          ),
        ],
      ),
    );
  }

  void _deleteProduct(String productId) {
    if (_deletingProductIds.contains(productId)) return;
    showDialog(
      context: context,
      builder: (dialogContext) => AlertDialog(
        title: const Text('Ürünü Sil'),
        content: const Text('Bu ürünü silmek istediğinize emin misiniz?'),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(dialogContext),
            child: const Text('İptal'),
          ),
          ElevatedButton(
            onPressed: () async {
              final messenger = ScaffoldMessenger.of(context);
              final int originalIndex = _indexOfSellerProduct(productId);
              final SellerProduct? deletedProduct = _findSellerProductById(
                productId,
              );
              final ProductQuickEditDraft? deletedDraft =
                  _productQuickEditDrafts[productId];
              if (deletedProduct == null) {
                Navigator.pop(dialogContext);
                return;
              }

              setState(() {
                _deletingProductIds.add(productId);
                _removeProductFromLocalState(productId);
              });
              Navigator.pop(dialogContext);
              messenger
                ..hideCurrentSnackBar()
                ..showSnackBar(
                  SnackBar(
                    content: Text('${deletedProduct.name} listeden kaldırıldı'),
                  ),
                );

              try {
                await _storeService.deleteProduct(productId);
                if (!mounted) return;
                setState(() {
                  _deletingProductIds.remove(productId);
                });
              } catch (error) {
                if (!mounted) return;
                setState(() {
                  _deletingProductIds.remove(productId);
                  _restoreProductInLocalState(originalIndex, deletedProduct);
                  if (deletedDraft != null) {
                    _productQuickEditDrafts[productId] = deletedDraft;
                  }
                });
                messenger
                  ..hideCurrentSnackBar()
                  ..showSnackBar(
                    SnackBar(
                      content: Text(
                        '${deletedProduct.name} geri yüklendi: ${error.toString().replaceFirst('Exception: ', '').trim()}',
                      ),
                      backgroundColor: Colors.red.shade600,
                    ),
                  );
              }
            },
            style: ElevatedButton.styleFrom(backgroundColor: Colors.red),
            child: const Text('Sil'),
          ),
        ],
      ),
    );
  }

  Widget _buildOrdersModule() => _buildOrdersModuleImpl();

