  Widget _buildSellerOrdersEmptyState({required String query}) {
    final title = query.isNotEmpty || _selectedSellerOrderFilter != 'all'
        ? 'Bu filtrede sipariş bulunamadı'
        : 'Henüz sipariş yok';
    final subtitle = query.isNotEmpty || _selectedSellerOrderFilter != 'all'
        ? 'Arama veya durum filtresini temizleyip tüm sipariş akışını tekrar kontrol edin.'
        : 'Yeni siparişler düştüğünde burada SLA, kargo ve iade akışlarıyla birlikte listelenecek.';
    return SellerOrdersEmptyState(title: title, subtitle: subtitle);
  }

  Map<String, dynamic> _sellerOrderAddressData(Map<String, dynamic> order) {
    final raw = order['delivery_address'];
    if (raw is Map) {
      return raw.map((key, value) => MapEntry(key.toString(), value));
    }
    if (raw is String && raw.trim().isNotEmpty) {
      try {
        final decoded = jsonDecode(raw);
        if (decoded is Map) {
          return decoded.map((key, value) => MapEntry(key.toString(), value));
        }
      } catch (_) {}
    }
    return <String, dynamic>{};
  }

  String _firstFilledValue(List<String?> values, {String fallback = '-'}) {
    for (final value in values) {
      final trimmed = value?.trim();
      if (trimmed != null && trimmed.isNotEmpty) {
        return trimmed;
      }
    }
    return fallback;
  }

  String _sellerOrderCustomerName(Map<String, dynamic> order) {
    final address = _sellerOrderAddressData(order);
    final customerName = order['customer_name']?.toString();
    final fullName = address['fullName']?.toString();
    final combined = [
      address['name']?.toString(),
      address['surname']?.toString(),
    ].where((e) => (e ?? '').trim().isNotEmpty).join(' ').trim();
    return _firstFilledValue([
      customerName,
      fullName,
      combined,
      address['title']?.toString(),
      address['label']?.toString(),
      order['customer_id']?.toString(),
    ]);
  }

  String _sellerOrderCustomerPhone(Map<String, dynamic> order) {
    final address = _sellerOrderAddressData(order);
    return _firstFilledValue([
      order['customer_phone']?.toString(),
      address['phone']?.toString(),
      address['phoneNumber']?.toString(),
      address['gsm']?.toString(),
    ]);
  }

  String _sellerOrderRegion(Map<String, dynamic> order) {
    final address = _sellerOrderAddressData(order);
    final city = address['city']?.toString().trim() ?? '';
    final district = address['district']?.toString().trim() ?? '';
    if (city.isEmpty && district.isEmpty) return 'Konum girilmemiş';
    if (city.isEmpty) return district;
    if (district.isEmpty) return city;
    return '$city / $district';
  }

  String _sellerOrderAddressPreview(Map<String, dynamic> order) {
    final address = _sellerOrderAddressData(order);
    return _firstFilledValue([
      address['detail']?.toString(),
      address['address']?.toString(),
      address['building']?.toString(),
      address['description']?.toString(),
    ], fallback: 'Adres detayı girilmemiş');
  }

  String _sellerDeliveryTypeLabel(Map<String, dynamic> order) {
    final raw = order['delivery_type']?.toString().toLowerCase() ?? '';
    if (raw.contains('ihiz_kurye_bekleniyor')) {
      return 'Ihiz Kurye (Bekleniyor)';
    }
    if (raw.contains('ihiz_kurye')) {
      return 'Ihiz Kurye';
    }
    if (raw.contains('kargo_sube_ihiz')) {
      return 'Kargo Subeleri (Ihiz Teslim)';
    }
    if (raw.contains('kargo_sube_kendim')) {
      return 'Kargo Subeleri (Kendim Goturecegim)';
    }
    if (raw.contains('kargo_sube_firma')) {
      return 'Kargo Subeleri (Firma Adresten Alir)';
    }
    if (raw.contains('near') || raw.contains('yakin')) {
      return 'Yakın Lokasyon';
    }
    if (raw.contains('courier') || raw.contains('kurye')) {
      return 'Kurye Teslim';
    }
    if (raw.contains('pickup') || raw.contains('sube')) {
      return 'Şubeye Teslim';
    }
    if (raw.contains('standard') ||
        raw.contains('cargo') ||
        raw.contains('kargo')) {
      return 'Standart Kargo';
    }
    return 'Teslimat Planlanacak';
  }

  String _sellerDeliverySlotLabel(Map<String, dynamic> order) {
    final slot = order['delivery_slot']?.toString().trim();
    return (slot != null && slot.isNotEmpty) ? slot : 'Saat seçilmedi';
  }

  bool _isBranchDeliveryMode(String mode) {
    final normalized = mode.toLowerCase();
    return normalized == 'branch' || normalized.startsWith('branch_');
  }

  Map<String, List<String>> _sellerBranchOptionsByCargo() {
    return const <String, List<String>>{
      'Yurtici Kargo': <String>[
        'Kadikoy Subesi',
        'Besiktas Subesi',
        'Sisli Subesi',
      ],
      'Aras Kargo': <String>[
        'Uskudar Subesi',
        'Mecidiyekoy Subesi',
        'Levent Subesi',
      ],
      'MNG Kargo': <String>[
        'Atasehir Subesi',
        'Bakirkoy Subesi',
        'Beylikduzu Subesi',
      ],
    };
  }

  List<String> _sellerBranchesForSelectedCargo() {
    final cargo = _sellerDetailCargoCompany ?? 'Yurtici Kargo';
    return _sellerBranchOptionsByCargo()[cargo] ??
        const <String>['Merkez Sube'];
  }

  String _resolveSellerDeliveryTypeByMode(String mode) {
    switch (mode) {
      case 'courier_waiting_pickup':
        return 'ihiz_kurye_bekleniyor';
      case 'courier':
        return 'ihiz_kurye_teslim';
      case 'branch_ihiz_pool':
        return 'kargo_sube_ihiz_teslim';
      case 'branch_self_dropoff':
        return 'kargo_sube_kendim_goturecegim';
      case 'branch_company_pickup':
        return 'kargo_sube_firma_adresten_alim';
      case 'branch':
        return 'sube_teslim';
      default:
        return mode.contains('branch') ? 'sube_teslim' : 'kurye_teslim';
    }
  }

  String _sellerDeliveryBadgeLabel() {
    switch (_sellerDetailDeliveryMode) {
      case 'courier':
        return 'Ihiz';
      case 'branch_ihiz_pool':
        return 'Kargo Sube / Ihiz Teslim';
      case 'branch_self_dropoff':
        return 'Kargo Sube / Kendim';
      case 'branch_company_pickup':
        return 'Kargo Sube / Firma Pickup';
      default:
        return _isBranchDeliveryMode(_sellerDetailDeliveryMode)
            ? 'Kargo Sube'
            : 'Kurye';
    }
  }

  String _sellerSenderLabel() {
    return _firstFilledValue([
      _storeNameController.text,
      _companyNameController.text,
      _companyTitleController.text,
      'Mağazam',
    ], fallback: 'Mağazam');
  }

  String _sellerSenderPhone() {
    return _firstFilledValue([
      _phoneController.text,
      _supportPhoneController.text,
      _whatsappController.text,
    ]);
  }

  String _sellerSenderAddress() {
    final city = _selectedCity.trim();
    final district = _selectedDistrict.trim();
    final address = _addressController.text.trim();
    final combined = [district, city].where((e) => e.isNotEmpty).join(' / ');
    return _firstFilledValue([
      if (combined.isNotEmpty) combined,
      address,
      '$combined • $address',
    ], fallback: 'Mağaza çıkış adresi girilmemiş');
  }

  bool _isIhizCourierAwaitingPickup(
    Map<String, dynamic> order, {
    String? status,
  }) {
    final currentStatus = (status ?? order['status']?.toString() ?? '')
        .toLowerCase();
    if (currentStatus != 'ready_to_ship') return false;
    final deliveryType = order['delivery_type']?.toString().toLowerCase() ?? '';
    return deliveryType.contains('ihiz_kurye_bekleniyor');
  }

  String _shipmentLabelFileSafeOrderNo(Map<String, dynamic> order) {
    return (order['order_number']?.toString() ?? 'siparis').replaceAll(
      '/',
      '-',
    );
  }

  String _shipmentLabelBodyText(Map<String, dynamic> order) {
    return [
      'IBUL KARGO BILGI',
      'Siparis No: ${order['order_number'] ?? '-'}',
      'Urun: ${order['product_name'] ?? '-'}',
      'SKU: ${order['product_code'] ?? '-'}',
      'Adet: ${order['quantity'] ?? '1'}',
      'Satici: ${_sellerSenderLabel()}',
      'Satici Tel: ${_sellerSenderPhone()}',
      'Cikis Adresi: ${_sellerSenderAddress()}',
      'Alici: ${_sellerOrderCustomerName(order)}',
      'Alici Tel: ${_sellerOrderCustomerPhone(order)}',
      'Bolge: ${_sellerOrderRegion(order)}',
      'Teslimat Adresi: ${_sellerOrderAddressPreview(order)}',
      'Teslimat Tipi: ${_sellerDeliveryTypeLabel(order)}',
      'Teslimat Slotu: ${_sellerDeliverySlotLabel(order)}',
      'Kargo / Operasyon: ${order['cargo_company']?.toString().isNotEmpty == true ? order['cargo_company'] : 'ihız'}',
      'Takip No: ${order['tracking_number']?.toString().isNotEmpty == true ? order['tracking_number'] : 'Takip no yok'}',
      'Urun Tutari: ₺${((order['total_price'] as num?) ?? 0).toStringAsFixed(2)}',
      'Siparis Toplami: ₺${((order['order_total_amount'] as num?) ?? (order['total_price'] as num? ?? 0)).toStringAsFixed(2)}',
    ].join('\n');
  }

