  Uint8List _buildShipmentLabelImageBytes(
    Map<String, dynamic> order, {
    required bool asJpeg,
  }) {
    final canvas = img.Image(width: 1200, height: 900);
    img.fill(canvas, color: img.ColorRgb8(250, 247, 255));
    img.fillRect(
      canvas,
      x1: 34,
      y1: 34,
      x2: 1166,
      y2: 866,
      color: img.ColorRgb8(255, 255, 255),
    );
    img.fillRect(
      canvas,
      x1: 34,
      y1: 34,
      x2: 1166,
      y2: 120,
      color: img.ColorRgb8(107, 44, 255),
    );
    img.drawString(
      canvas,
      'IBUL KARGO BILGI',
      font: img.arial24,
      x: 58,
      y: 62,
      color: img.ColorRgb8(255, 255, 255),
    );
    final lines = _shipmentLabelBodyText(order).split('\n');
    var y = 160;
    for (final line in lines) {
      img.drawString(
        canvas,
        line,
        font: img.arial24,
        x: 58,
        y: y,
        color: img.ColorRgb8(36, 28, 60),
      );
      y += 44;
    }
    img.fillRect(
      canvas,
      x1: 58,
      y1: 720,
      x2: 1142,
      y2: 820,
      color: img.ColorRgb8(244, 238, 255),
    );
    img.drawString(
      canvas,
      'Cikti alip paketin ustune yapistirin. Kurye veya sube tesliminden once takip no, alici ve adresi dogrulayin.',
      font: img.arial14,
      x: 74,
      y: 758,
      color: img.ColorRgb8(95, 32, 255),
    );
    final bytes = asJpeg
        ? img.encodeJpg(canvas, quality: 92)
        : img.encodePng(canvas);
    return Uint8List.fromList(bytes);
  }

  void _downloadShipmentLabel(Map<String, dynamic> order, String format) {
    final fileBase = _shipmentLabelFileSafeOrderNo(order);
    if (format == 'pdf') {
      BrowserFileDownload.openPrintHtml(
        title: 'Kargo Bilgi $fileBase',
        htmlBody: _shipmentLabelHtml(order),
      );
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text(
            'Yazdır penceresi açıldı. Buradan PDF olarak kaydedebilirsiniz.',
          ),
        ),
      );
      return;
    }
    final bytes = _buildShipmentLabelImageBytes(order, asJpeg: format == 'jpg');
    BrowserFileDownload.saveBytes(
      bytes: bytes,
      fileName: '$fileBase.$format',
      mimeType: format == 'jpg' ? 'image/jpeg' : 'image/png',
    );
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(content: Text('Kargo bilgi etiketi $format olarak indirildi.')),
    );
  }

