  Future<void> _openSellerOrderDetail(Map<String, dynamic> order) async {
    final normalized = Map<String, dynamic>.from(order);
    final isExternalOrder = _isSellerExternalOrder(normalized);
    final rawDeliveryType =
        normalized['delivery_type']?.toString().toLowerCase() ?? '';
    if (isExternalOrder) {
      _sellerDetailDeliveryMode = 'courier';
      _sellerDetailBranchOperation = 'ihiz_to_branch';
    } else if (rawDeliveryType.contains('kargo_sube_ihiz')) {
      _sellerDetailDeliveryMode = 'branch_ihiz_pool';
      _sellerDetailBranchOperation = 'ihiz_to_branch';
    } else if (rawDeliveryType.contains('kargo_sube_kendim')) {
      _sellerDetailDeliveryMode = 'branch_self_dropoff';
      _sellerDetailBranchOperation = 'self_dropoff';
    } else if (rawDeliveryType.contains('kargo_sube_firma')) {
      _sellerDetailDeliveryMode = 'branch_company_pickup';
      _sellerDetailBranchOperation = 'cargo_pickup';
    } else if (rawDeliveryType.contains('pickup') ||
        rawDeliveryType.contains('sube')) {
      _sellerDetailDeliveryMode = 'branch';
      _sellerDetailBranchOperation = 'ihiz_to_branch';
    } else {
      _sellerDetailDeliveryMode = 'courier';
      _sellerDetailBranchOperation = 'ihiz_to_branch';
    }
    final cargo = normalized['cargo_company']?.toString().trim();
    final normalizedCargo = cargo?.toLowerCase() ?? '';
    _sellerDetailCargoCompany = isExternalOrder
        ? 'İHIZ'
        : (cargo == null ||
              cargo.isEmpty ||
              normalizedCargo.contains('ihiz') ||
              normalizedCargo.contains('hiz'))
        ? 'Yurtici Kargo'
        : cargo;
    final branches = _sellerBranchesForSelectedCargo();
    if (!branches.contains(_sellerDetailBranchName)) {
      _sellerDetailBranchName = branches.first;
    }
    final tracking = normalized['tracking_number']?.toString().trim();
    _sellerDetailTrackingController.text =
        (tracking == null || tracking == '-' || tracking.isEmpty)
        ? ''
        : tracking;
    setState(() {
      _selectedSellerOrderItemId = normalized['id']?.toString();
      _selectedSellerOrderDetail = normalized;
    });
    final itemId = normalized['id']?.toString();
    if (itemId != null && itemId.isNotEmpty) {
      await _loadSelectedSellerOrderHistory(itemId);
      unawaited(_loadSelectedSellerReturnRequest(itemId));
    }
  }

  Future<void> _loadSelectedSellerOrderHistory(String orderItemId) async {
    try {
      final rows = await OrderService.instance.getOrderItemTracking(
        orderItemId,
      );
      if (!mounted) return;
      final packagingVideo = _extractPackagingVideoMeta(rows);
      final hasVideoRemovalRecord = rows.any((row) {
        final description = row['description']?.toString() ?? '';
        return description.startsWith('VIDEO_REMOVED::');
      });
      setState(() {
        _selectedSellerOrderHistory = rows;
        if (packagingVideo != null) {
          _selectedPackagingVideoUrl = packagingVideo.url;
          _selectedPackagingVideoOrderItemId = orderItemId;
          _selectedPackagingVideoTrimStart = packagingVideo.trimStart;
          _selectedPackagingVideoTrimEnd = packagingVideo.trimEnd;
        } else if (hasVideoRemovalRecord) {
          _selectedPackagingVideoUrl = null;
          _selectedPackagingVideoOrderItemId = orderItemId;
          _selectedPackagingVideoTrimStart = null;
          _selectedPackagingVideoTrimEnd = null;
        } else if (_selectedPackagingVideoOrderItemId != orderItemId) {
          // Yeni siparişe geçildiğinde eski sipariş videosu taşınmasın.
          _selectedPackagingVideoUrl = null;
          _selectedPackagingVideoOrderItemId = orderItemId;
          _selectedPackagingVideoTrimStart = null;
          _selectedPackagingVideoTrimEnd = null;
        }
      });
    } catch (e) {
      debugPrint('SellerPanel._loadSelectedSellerOrderHistory warn: $e');
    }
  }

  Future<void> _loadSelectedSellerReturnRequest(
    String orderItemId, {
    bool force = false,
  }) async {
    final normalizedItemId = orderItemId.trim();
    if (normalizedItemId.isEmpty) return;
    if (!force && _sellerReturnRequestByItemId.containsKey(normalizedItemId)) {
      return;
    }
    if (_loadingSellerReturnRequestItemIds.contains(normalizedItemId)) return;
    _loadingSellerReturnRequestItemIds.add(normalizedItemId);
    try {
      final request = await OrderService.instance.getLatestReturnRequestForItem(
        orderItemId: normalizedItemId,
      );
      if (!mounted) return;
      setState(() {
        _sellerReturnRequestByItemId[normalizedItemId] = request;
      });
    } catch (e) {
      debugPrint('SellerPanel._loadSelectedSellerReturnRequest warn: $e');
    } finally {
      _loadingSellerReturnRequestItemIds.remove(normalizedItemId);
    }
  }

  _PackagingVideoMeta? _extractPackagingVideoMeta(
    List<Map<String, dynamic>> rows,
  ) {
    for (final row in rows.reversed) {
      final description = row['description']?.toString() ?? '';
      if (description.startsWith('VIDEO_REMOVED::')) return null;
      final meta = _parsePackagingVideoMeta(description);
      if (meta != null) return meta;
    }
    return null;
  }

  _PackagingVideoMeta? _parsePackagingVideoMeta(String description) {
    if (!description.startsWith('VIDEO::')) return null;
    final payload = description.replaceFirst('VIDEO::', '').trim();
    if (payload.isEmpty) return null;

    final trimSplit = payload.split('|TRIM:');
    final url = trimSplit.first.trim();
    if (url.isEmpty) return null;

    Duration? trimStart;
    Duration? trimEnd;
    if (trimSplit.length > 1) {
      final range = trimSplit[1].trim().split('-');
      if (range.length == 2) {
        final startMs = int.tryParse(range[0].trim());
        final endMs = int.tryParse(range[1].trim());
        if (startMs != null && startMs >= 0) {
          trimStart = Duration(milliseconds: startMs);
        }
        if (endMs != null && endMs > 0) {
          trimEnd = Duration(milliseconds: endMs);
        }
      }
    }

    return _PackagingVideoMeta(
      url: url,
      trimStart: trimStart,
      trimEnd: trimEnd,
    );
  }

  String _buildPackagingVideoDescription(
    String videoUrl,
    _VideoTrimSelection trim,
  ) {
    final hasTrim =
        trim.start.inMilliseconds > 0 ||
        trim.end.inMilliseconds < trim.total.inMilliseconds;
    if (!hasTrim) return 'VIDEO::$videoUrl';
    return 'VIDEO::$videoUrl|TRIM:${trim.start.inMilliseconds}-${trim.end.inMilliseconds}';
  }

  Future<_VideoTrimSelection?> _showPackagingVideoTrimDialog(
    XFile video,
  ) async {
    final sourceUri = kIsWeb ? Uri.parse(video.path) : Uri.file(video.path);
    final controller = VideoPlayerController.networkUrl(sourceUri);
    try {
      await controller.initialize();
      if (!mounted) return null;

      final total = controller.value.duration;
      if (total <= Duration.zero) {
        return null;
      }
      const maxPackagingDuration = Duration(seconds: 30);
      if (total > maxPackagingDuration) {
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(
              content: Text(
                'Paketleme videosu en fazla 30 saniye olabilir. Daha kısa video seçin.',
              ),
            ),
          );
        }
        return null;
      }

      var startMs = 0.0;
      var endMs = total.inMilliseconds.toDouble();
      final minClipMs = math.min(750.0, endMs);
      var isPreviewPlaying = false;

      void listener() {
        if (!controller.value.isInitialized) return;
        final positionMs = controller.value.position.inMilliseconds;
        if (positionMs >= endMs.round()) {
          controller.pause();
          controller.seekTo(Duration(milliseconds: startMs.round()));
          isPreviewPlaying = false;
        }
      }

      controller.addListener(listener);

      final result = await showDialog<_VideoTrimSelection>(
        context: context,
        barrierDismissible: false,
        builder: (dialogContext) {
          void syncPreviewRange() {
            if (!controller.value.isInitialized) return;
            final positionMs = controller.value.position.inMilliseconds
                .toDouble();
            if (positionMs < startMs || positionMs > endMs) {
              controller.seekTo(Duration(milliseconds: startMs.round()));
            }
          }

          return StatefulBuilder(
            builder: (context, setModalState) {
              final maxMs = math.max(1.0, total.inMilliseconds.toDouble());
              final maxStart = math.max(0.0, maxMs - minClipMs);
              final safeStart = startMs.clamp(0.0, maxStart);
              final safeEnd = endMs.clamp(safeStart + minClipMs, maxMs);

              final screen = MediaQuery.of(dialogContext).size;
              final dialogWidth = math.min(420.0, screen.width - 24);
              final dialogHeight = math.min(620.0, screen.height * 0.88);
              final previewHeight = math.min(240.0, screen.height * 0.34);
              final aspectRatio = controller.value.aspectRatio <= 0
                  ? 16 / 9
                  : controller.value.aspectRatio;
              final selectedDuration = Duration(
                milliseconds: math.max(1, (safeEnd - safeStart).round()),
              );

              return Dialog(
                insetPadding: const EdgeInsets.symmetric(
                  horizontal: 12,
                  vertical: 16,
                ),
                shape: RoundedRectangleBorder(
                  borderRadius: BorderRadius.circular(20),
                ),
                child: ConstrainedBox(
                  constraints: BoxConstraints(
                    maxWidth: dialogWidth,
                    maxHeight: dialogHeight,
                  ),
                  child: Padding(
                    padding: const EdgeInsets.fromLTRB(14, 14, 14, 12),
                    child: SingleChildScrollView(
                      child: Column(
                        mainAxisSize: MainAxisSize.min,
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: [
                          const Text(
                            'Video Kırpma',
                            style: TextStyle(
                              fontSize: 22,
                              fontWeight: FontWeight.w800,
                              color: Color(0xFF1D2939),
                            ),
                          ),
                          const SizedBox(height: 10),
                          ClipRRect(
                            borderRadius: BorderRadius.circular(12),
                            child: Container(
                              width: double.infinity,
                              height: previewHeight,
                              color: Colors.black,
                              child: Center(
                                child: AspectRatio(
                                  aspectRatio: aspectRatio,
                                  child: VideoPlayer(controller),
                                ),
                              ),
                            ),
                          ),
                          const SizedBox(height: 12),
                          Text(
                            'Başlangıç: ${_formatTrimTime(Duration(milliseconds: safeStart.round()))}  •  Bitiş: ${_formatTrimTime(Duration(milliseconds: safeEnd.round()))}',
                            style: const TextStyle(
                              fontSize: 12,
                              fontWeight: FontWeight.w700,
                              color: Color(0xFF475467),
                            ),
                          ),
                          const SizedBox(height: 4),
                          Text(
                            'Seçili süre: ${_formatTrimTime(selectedDuration)}',
                            style: const TextStyle(
                              fontSize: 12,
                              fontWeight: FontWeight.w600,
                              color: Color(0xFF667085),
                            ),
                          ),
                          RangeSlider(
                            min: 0,
                            max: maxMs,
                            values: RangeValues(safeStart, safeEnd),
                            onChanged: (values) {
                              var nextStart = values.start;
                              var nextEnd = values.end;
                              if (nextEnd - nextStart < minClipMs) {
                                if (nextStart != safeStart) {
                                  nextEnd = (nextStart + minClipMs).clamp(
                                    minClipMs,
                                    maxMs,
                                  );
                                } else {
                                  nextStart = (nextEnd - minClipMs).clamp(
                                    0,
                                    maxMs - minClipMs,
                                  );
                                }
                              }
                              setModalState(() {
                                startMs = nextStart;
                                endMs = nextEnd;
                              });
                              syncPreviewRange();
                            },
                          ),
                          const SizedBox(height: 2),
                          Wrap(
                            spacing: 8,
                            runSpacing: 8,
                            children: [
                              OutlinedButton.icon(
                                onPressed: () async {
                                  if (isPreviewPlaying) {
                                    await controller.pause();
                                    setModalState(() {
                                      isPreviewPlaying = false;
                                    });
                                    return;
                                  }
                                  await controller.seekTo(
                                    Duration(milliseconds: safeStart.round()),
                                  );
                                  await controller.play();
                                  setModalState(() {
                                    isPreviewPlaying = true;
                                  });
                                },
                                icon: Icon(
                                  isPreviewPlaying
                                      ? Icons.pause
                                      : Icons.play_arrow,
                                ),
                                label: Text(
                                  isPreviewPlaying ? 'Durdur' : 'Önizle',
                                ),
                              ),
                              TextButton(
                                onPressed: () {
                                  Navigator.of(dialogContext).pop(
                                    _VideoTrimSelection(
                                      start: Duration.zero,
                                      end: total,
                                      total: total,
                                    ),
                                  );
                                },
                                child: const Text('Tamamını Kullan'),
                              ),
                            ],
                          ),
                          const SizedBox(height: 10),
                          Row(
                            children: [
                              TextButton(
                                onPressed: () =>
                                    Navigator.of(dialogContext).pop(),
                                child: const Text('Vazgeç'),
                              ),
                              const Spacer(),
                              FilledButton(
                                onPressed: () =>
                                    Navigator.of(dialogContext).pop(
                                      _VideoTrimSelection(
                                        start: Duration(
                                          milliseconds: safeStart.round(),
                                        ),
                                        end: Duration(
                                          milliseconds: safeEnd.round(),
                                        ),
                                        total: total,
                                      ),
                                    ),
                                child: const Text('Kırp ve Devam Et'),
                              ),
                            ],
                          ),
                        ],
                      ),
                    ),
                  ),
                ),
              );
            },
          );
        },
      );
      controller.removeListener(listener);

      return result;
    } finally {
      await controller.pause();
      controller.dispose();
    }
  }

  String _formatTrimTime(Duration value) {
    final minutes = value.inMinutes.remainder(60).toString().padLeft(2, '0');
    final seconds = value.inSeconds.remainder(60).toString().padLeft(2, '0');
    final hours = value.inHours;
    if (hours > 0) {
      return '${hours.toString().padLeft(2, '0')}:$minutes:$seconds';
    }
    return '$minutes:$seconds';
  }

  String _packagingUploadStatusText() {
    final progress = _packagingVideoUploadProgress.clamp(0.0, 1.0).toDouble();
    if (progress <= 0) return 'Video yükleniyor...';
    final percent = progress >= 1
        ? 100
        : math.min(99, (progress * 100).floor());
    if (progress >= 0.98 && progress < 1) {
      return 'Sunucuya kaydediliyor: %$percent';
    }
    return 'Yükleniyor: %$percent';
  }

  String _formatUploadSpeed(double bytesPerSecond) {
    if (bytesPerSecond <= 0) return '-';
    final kb = bytesPerSecond / 1024;
    if (kb < 1024) {
      return '${kb.toStringAsFixed(0)} KB/sn';
    }
    return '${(kb / 1024).toStringAsFixed(2)} MB/sn';
  }

  String _formatUploadEta(Duration eta) {
    if (eta.inSeconds <= 0) return '<1 sn';
    if (eta.inMinutes >= 1) {
      final minutes = eta.inMinutes;
      final seconds = eta.inSeconds.remainder(60);
      return '${minutes}dk ${seconds}s';
    }
    return '${eta.inSeconds}s';
  }

  String? _packagingUploadMetaText() {
    if (_packagingVideoServerProcessing) {
      return 'Sunucu işlemi sürüyor...';
    }
    if (_packagingVideoUploadSpeedBytesPerSec <= 0) {
      return null;
    }
    final speedText = _formatUploadSpeed(_packagingVideoUploadSpeedBytesPerSec);
    final eta = _packagingVideoUploadEta;
    if (eta == null) return speedText;
    return '$speedText • Kalan: ${_formatUploadEta(eta)}';
  }

  void _setPackagingUploadProgressTarget(double target) {
    final normalized = target.clamp(0.0, 1.0).toDouble();
    _packagingVideoUploadProgressTarget = normalized;

    _packagingVideoUploadProgressTimer ??= Timer.periodic(
      const Duration(milliseconds: 80),
      (timer) {
        if (!mounted) {
          timer.cancel();
          _packagingVideoUploadProgressTimer = null;
          return;
        }
        final current = _packagingVideoUploadProgress;
        final targetProgress = _packagingVideoUploadProgressTarget;
        final delta = targetProgress - current;

        if (delta.abs() < 0.002) {
          if (current != targetProgress) {
            setState(() {
              _packagingVideoUploadProgress = targetProgress;
            });
          }
          if (!_isUploadingPackagingVideo && targetProgress >= 1) {
            timer.cancel();
            _packagingVideoUploadProgressTimer = null;
          }
          return;
        }

        final step = delta > 0 ? math.min(0.018, delta) : delta;
        setState(() {
          _packagingVideoUploadProgress = (current + step).clamp(0.0, 1.0);
        });
      },
    );
  }

  Future<void> _reloadAndKeepSellerOrderDetail(String? orderItemId) async {
    if (orderItemId == null || orderItemId.isEmpty) return;
    await _loadSellerOrders();
    await _loadSelectedSellerReturnRequest(orderItemId, force: true);
    if (!mounted) return;
    final refreshed =
        _sellerOrderById[orderItemId] ?? _selectedSellerOrderDetail;
    if (refreshed == null) {
      await _loadSelectedSellerOrderHistory(orderItemId);
      return;
    }
    await _openSellerOrderDetail(refreshed);
  }

  Future<void> _pickPackagingVideo(Map<String, dynamic> order) async {
    try {
      final XFile? video = await _picker.pickVideo(
        source: ImageSource.gallery,
        maxDuration: const Duration(seconds: 30),
      );
      if (video == null) return;
      final trimSelection = await _showPackagingVideoTrimDialog(video);
      if (trimSelection == null) return;
      setState(() {
        _packagingVideoUploadProgressTimer?.cancel();
        _packagingVideoUploadProgressTimer = null;
        _isUploadingPackagingVideo = true;
        _isRemovingPackagingVideo = false;
        _packagingVideoUploadProgressTarget = 0;
        _packagingVideoUploadProgress = 0;
        _packagingVideoUploadSpeedBytesPerSec = 0;
        _packagingVideoUploadEta = null;
        _packagingVideoServerProcessing = false;
      });
      final url = await _storeService.uploadStoreVideoWithProgress(
        video,
        onProgress: (progress) {
          if (!mounted) return;
          _setPackagingUploadProgressTarget(progress);
        },
        onProgressDetails: (details) {
          if (!mounted) return;
          setState(() {
            _packagingVideoUploadSpeedBytesPerSec = details.bytesPerSecond;
            _packagingVideoUploadEta = details.eta;
            _packagingVideoServerProcessing = details.isServerProcessing;
          });
        },
      );
      if (mounted) {
        _setPackagingUploadProgressTarget(1);
        setState(() {
          _packagingVideoUploadProgressTarget = 1;
          _packagingVideoUploadProgress = 1;
          _selectedPackagingVideoUrl = url;
          _selectedPackagingVideoOrderItemId = order['id']?.toString();
          _selectedPackagingVideoTrimStart = trimSelection.start;
          _selectedPackagingVideoTrimEnd =
              trimSelection.end < trimSelection.total
              ? trimSelection.end
              : null;
          _isUploadingPackagingVideo = false;
          _packagingVideoServerProcessing = false;
        });
      }
      final itemId = order['id']?.toString() ?? '';
      if (itemId.isNotEmpty) {
        await _persistPackagingVideoHistory(
          orderItemId: itemId,
          videoUrl: url,
          trimSelection: trimSelection,
        );
        if (mounted) {
          await _loadSelectedSellerOrderHistory(itemId);
        }
      }
      unawaited(_loadSellerOrders());
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('Paketleme videosu yüklendi.')),
      );
    } catch (e) {
      if (!mounted) return;
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text('Video yüklenemedi: $e')));
    } finally {
      if (mounted) {
        _packagingVideoUploadProgressTimer?.cancel();
        _packagingVideoUploadProgressTimer = null;
        setState(() {
          _isUploadingPackagingVideo = false;
          _packagingVideoUploadProgressTarget = 0;
          _packagingVideoUploadProgress = 0;
          _packagingVideoUploadSpeedBytesPerSec = 0;
          _packagingVideoUploadEta = null;
          _packagingVideoServerProcessing = false;
        });
      }
    }
  }

  Future<void> _persistPackagingVideoHistory({
    required String orderItemId,
    required String videoUrl,
    required _VideoTrimSelection trimSelection,
  }) async {
    try {
      await OrderService.instance.addOrderItemHistoryEntry(
        orderItemId: orderItemId,
        status: 'preparing',
        title: 'Paketleme videosu yüklendi',
        description: _buildPackagingVideoDescription(videoUrl, trimSelection),
      );
    } catch (historyError) {
      debugPrint('SellerPanel packaging video history warn: $historyError');
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('Video yüklendi ancak geçmiş kaydı oluşturulamadı.'),
        ),
      );
    }
  }

  Future<void> _showPackagingVideoEditActions(
    Map<String, dynamic> order,
  ) async {
    if (_isUploadingPackagingVideo || _isRemovingPackagingVideo) return;
    final action = await showModalBottomSheet<String>(
      context: context,
      backgroundColor: Colors.white,
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.vertical(top: Radius.circular(20)),
      ),
      builder: (sheetContext) {
        return SafeArea(
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              ListTile(
                leading: const Icon(Icons.video_settings_outlined),
                title: const Text('Videoyu Kırp / Değiştir'),
                subtitle: const Text('Yeni video seçip kırparak tekrar yükle'),
                onTap: () => Navigator.of(sheetContext).pop('replace'),
              ),
              ListTile(
                leading: const Icon(Icons.delete_outline),
                title: const Text('Videoyu Sil'),
                subtitle: const Text('Paketleme videosunu siparişten kaldır'),
                onTap: () => Navigator.of(sheetContext).pop('remove'),
              ),
              const SizedBox(height: 8),
            ],
          ),
        );
      },
    );
    if (!mounted) return;
    if (action == 'replace') {
      await _pickPackagingVideo(order);
    } else if (action == 'remove') {
      await _removePackagingVideo(order);
    }
  }

  Future<void> _removePackagingVideo(Map<String, dynamic> order) async {
    final hasVideo = _selectedPackagingVideoUrl?.isNotEmpty == true;
    if (!hasVideo) return;
    final orderItemId = order['id']?.toString() ?? '';
    if (orderItemId.isEmpty) return;
    try {
      setState(() {
        _isRemovingPackagingVideo = true;
      });
      await OrderService.instance.addOrderItemHistoryEntry(
        orderItemId: orderItemId,
        status: 'preparing',
        title: 'Paketleme videosu kaldırıldı',
        description: 'VIDEO_REMOVED::manual',
      );
      if (!mounted) return;
      await _loadSelectedSellerOrderHistory(orderItemId);
      unawaited(_loadSellerOrders());
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('Paketleme videosu kaldırıldı.')),
      );
    } catch (e) {
      if (!mounted) return;
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text('Video kaldırılamadı: $e')));
    } finally {
      if (mounted) {
        setState(() {
          _isRemovingPackagingVideo = false;
        });
      }
    }
  }

