  bool _isSellerOrderPriority(Map<String, dynamic> order) {
    if (order['is_priority'] == true) return true;
    final deliveryType = order['delivery_type']?.toString().toLowerCase() ?? '';
    return deliveryType.contains('near') || deliveryType.contains('yakin');
  }

  int _sellerOrderItemCount(Map<String, dynamic> order) {
    final raw = order['item_count'];
    if (raw is int) return raw;
    if (raw is num) return raw.toInt();
    return int.tryParse(raw?.toString() ?? '') ?? 1;
  }

  List<String> _sellerOrderPreviewTags(Map<String, dynamic> order) {
    final tags = <String>[];
    final productName = order['product_name']?.toString().trim();
    if (productName != null && productName.isNotEmpty) {
      tags.add(productName);
    }
    final secondary = order['secondary_product_name']?.toString().trim();
    if (secondary != null && secondary.isNotEmpty && secondary != productName) {
      tags.add(secondary);
    }
    final tertiary = order['third_product_name']?.toString().trim();
    if (tertiary != null &&
        tertiary.isNotEmpty &&
        tertiary != productName &&
        tertiary != secondary) {
      tags.add(tertiary);
    }
    final itemCount = _sellerOrderItemCount(order);
    if (itemCount > tags.length) {
      tags.add('+${itemCount - tags.length} daha');
    }
    if (tags.isEmpty) tags.add('Ürün yok');
    return tags.take(3).toList();
  }

  bool _isSellerReturnFlowStatus(String? status) {
    switch ((status ?? '').toLowerCase()) {
      case 'return_requested':
      case 'return_approved':
      case 'return_shipped_back':
      case 'return_received':
      case 'refunded':
      case 'returned':
        return true;
      default:
        return false;
    }
  }

  Widget _buildSellerReturnHeaderStage(String? status) {
    final normalized = (status ?? '').toLowerCase();
    String title = 'İade Süreci';
    String subtitle = 'Müşteri iade akışı devam ediyor.';
    Color color = const Color(0xFFB45309);
    IconData icon = Icons.assignment_return_rounded;

    if (normalized == 'return_approved') {
      title = 'İade Kabul Edildi';
      subtitle = 'Kullanıcının kurye tarih/saat seçimi bekleniyor.';
      color = const Color(0xFF16A34A);
      icon = Icons.check_circle_outline_rounded;
    } else if (normalized == 'return_shipped_back') {
      title = 'İade Kargosu Yolda';
      subtitle = 'Kurye ürünü mağazaya getiriyor.';
      color = const Color(0xFF0E7490);
      icon = Icons.local_shipping_outlined;
    } else if (normalized == 'return_received') {
      title = 'İade Ürünü Teslim Alındı';
      subtitle = 'İade tamamlama adımı bekleniyor.';
      color = const Color(0xFF334155);
      icon = Icons.inventory_2_rounded;
    } else if (normalized == 'refunded' || normalized == 'returned') {
      title = 'İade Tamamlandı';
      subtitle = 'İade dosyası kapandı.';
      color = const Color(0xFF6D28D9);
      icon = Icons.verified_rounded;
    }

    return Container(
      width: double.infinity,
      padding: const EdgeInsets.all(16),
      decoration: BoxDecoration(
        color: color.withValues(alpha: 0.08),
        borderRadius: BorderRadius.circular(14),
        border: Border.all(color: color.withValues(alpha: 0.26)),
      ),
      child: Row(
        children: [
          Icon(icon, color: color, size: 22),
          const SizedBox(width: 12),
          Expanded(
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Text(
                  title,
                  style: TextStyle(
                    fontSize: 14,
                    fontWeight: FontWeight.w800,
                    color: color,
                  ),
                ),
                const SizedBox(height: 4),
                Text(
                  subtitle,
                  style: const TextStyle(
                    fontSize: 12,
                    color: Color(0xFF475467),
                    fontWeight: FontWeight.w600,
                  ),
                ),
              ],
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildSellerReturnOperationContent(
    Map<String, dynamic> order,
    String currentStatus,
  ) {
    final orderItemId = order['id']?.toString().trim() ?? '';
    final request = orderItemId.isEmpty
        ? null
        : _sellerReturnRequestByItemId[orderItemId];
    final isLoading =
        orderItemId.isNotEmpty &&
        _loadingSellerReturnRequestItemIds.contains(orderItemId);
    if (request == null && !isLoading && orderItemId.isNotEmpty) {
      unawaited(_loadSelectedSellerReturnRequest(orderItemId));
    }

    final requestStatus = (request?['status']?.toString() ?? '')
        .trim()
        .toLowerCase();
    final reason = request?['reason']?.toString().trim() ?? '-';
    final damageLevel = request?['damage_level']?.toString().trim() ?? '-';
    final damageDescription =
        request?['damage_description']?.toString().trim() ?? '';
    final buyerDetail = request?['detail']?.toString().trim() ?? '';
    final sellerNote =
        request?['seller_decision_note']?.toString().trim() ?? '';
    final issueTags = ((request?['issue_tags'] as List?) ?? const [])
        .map((e) => e.toString())
        .where((e) => e.trim().isNotEmpty)
        .toList();
    final evidenceImages =
        ((request?['evidence_image_urls'] as List?) ?? const [])
            .map((e) => e.toString())
            .where((e) => e.trim().isNotEmpty)
            .toList();

    String statusLabel = 'İade inceleme bekliyor';
    Color statusColor = const Color(0xFFB45309);
    if (requestStatus == 'awaiting_ibul_review') {
      statusLabel = 'İBUL desteği incelemede';
      statusColor = const Color(0xFF7C3AED);
    } else if (currentStatus == 'return_approved') {
      statusLabel = 'Kullanıcıdan iade tarih seçimi bekleniyor';
      statusColor = const Color(0xFF166534);
    } else if (currentStatus == 'return_shipped_back') {
      statusLabel = 'İade kargosu mağazaya geliyor';
      statusColor = const Color(0xFF0E7490);
    } else if (currentStatus == 'return_received') {
      statusLabel = 'İade ürünü teslim alındı, son onay bekleniyor';
      statusColor = const Color(0xFF334155);
    } else if (currentStatus == 'refunded' || currentStatus == 'returned') {
      statusLabel = 'İade tamamlandı';
      statusColor = const Color(0xFF6D28D9);
    }

    final canReviewNow =
        currentStatus == 'return_requested' &&
        requestStatus != 'awaiting_ibul_review';

    return Padding(
      padding: const EdgeInsets.all(24),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Container(
            width: double.infinity,
            padding: const EdgeInsets.all(14),
            decoration: BoxDecoration(
              color: statusColor.withValues(alpha: 0.10),
              borderRadius: BorderRadius.circular(12),
              border: Border.all(color: statusColor.withValues(alpha: 0.25)),
            ),
            child: Text(
              statusLabel,
              style: TextStyle(color: statusColor, fontWeight: FontWeight.w800),
            ),
          ),
          const SizedBox(height: 14),
          if (isLoading && request == null)
            const Padding(
              padding: EdgeInsets.symmetric(vertical: 10),
              child: LinearProgressIndicator(minHeight: 3),
            ),
          _buildSellerReturnInfoRow('İade nedeni', reason),
          _buildSellerReturnInfoRow('Hasar sınıfı', damageLevel),
          if (damageDescription.isNotEmpty)
            _buildSellerReturnInfoRow(
              'Hasar tespit açıklaması',
              damageDescription,
            ),
          if (buyerDetail.isNotEmpty)
            _buildSellerReturnInfoRow('Müşteri açıklaması', buyerDetail),
          if (sellerNote.isNotEmpty)
            _buildSellerReturnInfoRow('Satıcı notu', sellerNote),
          if (issueTags.isNotEmpty) ...[
            const SizedBox(height: 10),
            Wrap(
              spacing: 8,
              runSpacing: 8,
              children: issueTags
                  .map(
                    (tag) => Container(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 10,
                        vertical: 5,
                      ),
                      decoration: BoxDecoration(
                        color: const Color(0xFFF3F4F6),
                        borderRadius: BorderRadius.circular(999),
                        border: Border.all(color: const Color(0xFFE5E7EB)),
                      ),
                      child: Text(
                        tag,
                        style: const TextStyle(
                          fontSize: 11,
                          color: Color(0xFF475467),
                          fontWeight: FontWeight.w600,
                        ),
                      ),
                    ),
                  )
                  .toList(),
            ),
          ],
          const SizedBox(height: 14),
          const Text(
            'Müşterinin Yüklediği Görseller',
            style: TextStyle(fontWeight: FontWeight.w800),
          ),
          const SizedBox(height: 8),
          if (evidenceImages.isEmpty)
            const Text(
              'Görsel yüklenmemiş.',
              style: TextStyle(fontSize: 12, color: Color(0xFF6B7280)),
            )
          else
            SizedBox(
              height: 96,
              child: ListView.separated(
                scrollDirection: Axis.horizontal,
                itemCount: evidenceImages.length,
                separatorBuilder: (_, _) => const SizedBox(width: 8),
                itemBuilder: (context, index) {
                  return ClipRRect(
                    borderRadius: BorderRadius.circular(10),
                    child: SizedBox(
                      width: 96,
                      child: _sellerReturnEvidenceImage(evidenceImages[index]),
                    ),
                  );
                },
              ),
            ),
          const SizedBox(height: 16),
          if (canReviewNow)
            Row(
              children: [
                Expanded(
                  child: FilledButton.icon(
                    onPressed: request == null
                        ? null
                        : () => _submitSellerReturnDecision(
                            order: order,
                            decision: 'approve',
                          ),
                    icon: const Icon(Icons.check_circle_outline_rounded),
                    label: const Text('İade Kabul Et'),
                    style: FilledButton.styleFrom(
                      backgroundColor: const Color(0xFF16A34A),
                      foregroundColor: Colors.white,
                      minimumSize: const Size(double.infinity, 50),
                    ),
                  ),
                ),
                const SizedBox(width: 10),
                Expanded(
                  child: OutlinedButton.icon(
                    onPressed: request == null
                        ? null
                        : () =>
                              _showSellerReturnRejectToIbulDialog(order: order),
                    icon: const Icon(Icons.gpp_bad_outlined),
                    label: const Text('İade Reddet'),
                    style: OutlinedButton.styleFrom(
                      foregroundColor: const Color(0xFFB91C1C),
                      side: const BorderSide(color: Color(0xFFB91C1C)),
                      minimumSize: const Size(double.infinity, 50),
                    ),
                  ),
                ),
              ],
            ),
          if (currentStatus == 'return_shipped_back') ...[
            SizedBox(
              width: double.infinity,
              child: FilledButton.icon(
                onPressed: () => _updateOrderStatus(
                  order,
                  status: 'return_received',
                  title: 'İade ürünü mağazaya ulaştı',
                  description: 'İade ürünü mağaza tarafından teslim alındı.',
                ),
                icon: const Icon(Icons.inventory_2_rounded),
                label: const Text('İade Ürününü Teslim Aldım'),
              ),
            ),
          ] else if (currentStatus == 'return_received') ...[
            SizedBox(
              width: double.infinity,
              child: FilledButton.icon(
                onPressed: () => _updateOrderStatus(
                  order,
                  status: 'refunded',
                  title: 'İade tamamlandı',
                  description:
                      'İade süreci tamamlandı ve geri ödeme akışına aktarıldı.',
                ),
                icon: const Icon(Icons.verified_rounded),
                label: const Text('İade Tamamlandı'),
              ),
            ),
          ],
        ],
      ),
    );
  }

  Future<void> _submitSellerReturnDecision({
    required Map<String, dynamic> order,
    required String decision,
    String note = '',
  }) async {
    final sellerId = _authService.currentUser?.id ?? '';
    final orderItemId = order['id']?.toString() ?? '';
    final request = _sellerReturnRequestByItemId[orderItemId];
    final requestId = request?['id']?.toString() ?? '';
    if (sellerId.isEmpty || orderItemId.isEmpty || requestId.isEmpty) {
      if (!mounted) return;
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(const SnackBar(content: Text('İade kaydı yüklenemedi.')));
      return;
    }
    try {
      await OrderService.instance.sellerReviewReturnRequest(
        sellerId: sellerId,
        returnRequestId: requestId,
        decision: decision,
        note: note,
      );
      await _reloadAndKeepSellerOrderDetail(orderItemId);
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            decision == 'approve'
                ? 'İade kabul edildi. Kullanıcıya tarih seçme bildirimi gönderildi.'
                : 'İade red talebi İBUL desteğe gönderildi.',
          ),
        ),
      );
    } catch (e) {
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text(e.toString().replaceFirst('Exception: ', ''))),
      );
    }
  }

  Future<void> _showSellerReturnRejectToIbulDialog({
    required Map<String, dynamic> order,
  }) async {
    var selectedReason = _sellerReturnRejectReasonOptions.first;
    final descriptionController = TextEditingController();

    await showDialog<void>(
      context: context,
      builder: (dialogContext) {
        var isSubmitting = false;
        return StatefulBuilder(
          builder: (dialogContext, setDialogState) {
            Future<void> submit() async {
              final description = descriptionController.text.trim();
              if (description.isEmpty) {
                ScaffoldMessenger.of(dialogContext).showSnackBar(
                  const SnackBar(
                    content: Text('Lütfen red gerekçesi açıklaması girin.'),
                  ),
                );
                return;
              }
              setDialogState(() => isSubmitting = true);
              final note =
                  'Satıcı red gerekçesi: $selectedReason\nAçıklama: $description';
              await _submitSellerReturnDecision(
                order: order,
                decision: 'reject',
                note: note,
              );
              if (!dialogContext.mounted) return;
              Navigator.of(dialogContext).pop();
            }

            return AlertDialog(
              title: const Text('İade Red Talebi'),
              content: SizedBox(
                width: 520,
                child: Column(
                  mainAxisSize: MainAxisSize.min,
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    const Text(
                      'Red talebin doğrudan kapanmaz; İBUL desteğe inceleme için gider.',
                      style: TextStyle(fontSize: 12, color: Color(0xFF6B7280)),
                    ),
                    const SizedBox(height: 12),
                    DropdownButtonFormField<String>(
                      initialValue: selectedReason,
                      decoration: const InputDecoration(
                        labelText: 'Red gerekçesi',
                        border: OutlineInputBorder(),
                      ),
                      items: _sellerReturnRejectReasonOptions
                          .map(
                            (reason) => DropdownMenuItem<String>(
                              value: reason,
                              child: Text(reason),
                            ),
                          )
                          .toList(),
                      onChanged: (value) {
                        if (value == null) return;
                        setDialogState(() {
                          selectedReason = value;
                        });
                      },
                    ),
                    const SizedBox(height: 10),
                    TextField(
                      controller: descriptionController,
                      maxLines: 4,
                      decoration: const InputDecoration(
                        labelText: 'Açıklama',
                        hintText:
                            'Hasar, yırtık, kullanım izi vb. durumu detaylı yazın.',
                        border: OutlineInputBorder(),
                      ),
                    ),
                  ],
                ),
              ),
              actions: [
                TextButton(
                  onPressed: isSubmitting
                      ? null
                      : () => Navigator.of(dialogContext).pop(),
                  child: const Text('Vazgeç'),
                ),
                FilledButton(
                  onPressed: isSubmitting ? null : submit,
                  child: Text(
                    isSubmitting ? 'Gönderiliyor...' : 'İBUL Desteğe Gönder',
                  ),
                ),
              ],
            );
          },
        );
      },
    );
    descriptionController.dispose();
  }

  Widget _buildSellerOrderStageStepper(String? status) {
    final normalizedStatus = (status ?? '').toLowerCase();
    if (normalizedStatus.contains('cancel')) {
      return Container(
        width: double.infinity,
        padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 12),
        decoration: BoxDecoration(
          color: const Color(0xFFFFF1F3),
          borderRadius: BorderRadius.circular(14),
          border: Border.all(color: const Color(0xFFF5C2C7)),
        ),
        child: const Row(
          children: [
            Icon(Icons.cancel_outlined, color: Color(0xFFB42318), size: 20),
            SizedBox(width: 10),
            Text(
              'Sipariş İptal Edildi',
              style: TextStyle(
                fontSize: 14,
                fontWeight: FontWeight.w800,
                color: Color(0xFFB42318),
              ),
            ),
          ],
        ),
      );
    }

    final stage = _sellerOrderStageIndex(status);
    return Row(
      children: [
        Expanded(
          child: _buildSellerOrderStageStep(
            icon: Icons.error_outline_rounded,
            label: 'Yeni Sipariş',
            active: stage >= 0,
            completed: stage > 0,
            isLast: false,
          ),
        ),
        Expanded(
          child: _buildSellerOrderStageStep(
            icon: Icons.schedule_rounded,
            label: 'Hazırlanıyor',
            active: stage >= 1,
            completed: stage > 1,
            isLast: false,
          ),
        ),
        Expanded(
          child: _buildSellerOrderStageStep(
            icon: Icons.inventory_2_outlined,
            label: 'Hazır',
            active: stage >= 2,
            completed: stage > 2,
            isLast: false,
          ),
        ),
        Expanded(
          child: _buildSellerOrderStageStep(
            icon: Icons.local_shipping_outlined,
            label: 'Kargoda',
            active: stage >= 3,
            completed: false,
            isLast: true,
          ),
        ),
      ],
    );
  }

  int _sellerOrderStageIndex(String? status) {
    switch ((status ?? '').toLowerCase()) {
      case 'new':
      case 'confirmed':
        return 0;
      case 'preparing':
        return 1;
      case 'ready_to_ship':
        return 2;
      case 'shipped':
      case 'transfer':
      case 'branch':
      case 'out_for_delivery':
      case 'delivered':
        return 3;
      default:
        return 0;
    }
  }

  Widget _buildSellerOrderStageStep({
    required IconData icon,
    required String label,
    required bool active,
    required bool completed,
    required bool isLast,
  }) {
    final color = active ? AppColors.primary : const Color(0xFFD0D5DD);
    return Row(
      children: [
        Column(
          children: [
            Container(
              width: 48,
              height: 48,
              decoration: BoxDecoration(
                shape: BoxShape.circle,
                color: completed ? AppColors.primary : Colors.white,
                border: Border.all(color: color, width: 3),
              ),
              child: Icon(
                icon,
                color: active
                    ? (completed ? Colors.white : AppColors.primary)
                    : const Color(0xFF98A2B3),
                size: 24,
              ),
            ),
            const SizedBox(height: 10),
            Text(
              label,
              style: TextStyle(
                fontSize: 14,
                fontWeight: active ? FontWeight.w700 : FontWeight.w600,
                color: active
                    ? const Color(0xFF344054)
                    : const Color(0xFF98A2B3),
              ),
            ),
          ],
        ),
        if (!isLast)
          Expanded(
            child: Container(
              margin: const EdgeInsets.only(bottom: 32),
              height: 3,
              color: completed ? AppColors.primary : const Color(0xFFD0D5DD),
            ),
          ),
      ],
    );
  }

