  Widget _buildSellerSummaryOperationContent(
    Map<String, dynamic> order,
    String? status,
    String tracking,
    String cargoCompany,
  ) {
    final currentStatus = (status ?? '').toLowerCase();
    if (_isSellerReturnFlowStatus(currentStatus)) {
      return _buildSellerReturnOperationContent(order, currentStatus);
    }
    final cancellationReason = _sellerOrderCancellationReason(order);
    final isExternalOrder = _isSellerExternalOrder(order);
    final isIhizShipment = _isIhizCargoCompany(cargoCompany);
    final isAwaitingIhizCourierPickup = _isIhizCourierAwaitingPickup(
      order,
      status: currentStatus,
    );

    if (currentStatus.contains('cancel')) {
      return Padding(
        padding: const EdgeInsets.all(24),
        child: Container(
          width: double.infinity,
          padding: const EdgeInsets.all(20),
          decoration: BoxDecoration(
            color: const Color(0xFFFFF1F3),
            borderRadius: BorderRadius.circular(16),
            border: Border.all(color: const Color(0xFFF5C2C7)),
          ),
          child: Row(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              const Icon(
                Icons.cancel_outlined,
                color: Color(0xFFB42318),
                size: 26,
              ),
              const SizedBox(width: 12),
              Expanded(
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    const Text(
                      'Sipariş İptal Edildi',
                      style: TextStyle(
                        fontSize: 18,
                        fontWeight: FontWeight.w800,
                        color: Color(0xFFB42318),
                      ),
                    ),
                    const SizedBox(height: 6),
                    Text(
                      cancellationReason == null
                          ? 'Sebep bilgisi bulunamadı.'
                          : 'Sebep: $cancellationReason',
                      style: const TextStyle(
                        fontSize: 14,
                        fontWeight: FontWeight.w600,
                        color: Color(0xFF7A271A),
                      ),
                    ),
                  ],
                ),
              ),
            ],
          ),
        ),
      );
    }

    if (isAwaitingIhizCourierPickup) {
      final trackingLabel = tracking.trim().isEmpty || tracking.trim() == '-'
          ? 'Takip no kurye paketi teslim aldığında oluşturulacak.'
          : 'Takip No: $tracking';
      return Padding(
        padding: const EdgeInsets.all(24),
        child: Container(
          width: double.infinity,
          padding: const EdgeInsets.all(22),
          decoration: BoxDecoration(
            color: const Color(0xFFF4F7FF),
            borderRadius: BorderRadius.circular(18),
            border: Border.all(color: const Color(0xFFDDE6F4)),
          ),
          child: Row(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              const Icon(
                Icons.delivery_dining_outlined,
                color: Color(0xFF155EEF),
                size: 28,
              ),
              const SizedBox(width: 14),
              Expanded(
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    const Text(
                      'İHIZ Kuryesi Bekleniliyor',
                      style: TextStyle(
                        fontSize: 18,
                        fontWeight: FontWeight.w800,
                        color: Color(0xFF1D4ED8),
                      ),
                    ),
                    const SizedBox(height: 6),
                    Text(
                      '$trackingLabel\nKurye siparişi teslim alınca durum "Kurye Dağıtımda" olarak güncellenecek.',
                      style: const TextStyle(
                        fontSize: 14,
                        color: Color(0xFF344054),
                      ),
                    ),
                    const SizedBox(height: 12),
                    OutlinedButton.icon(
                      onPressed: () => _updateOrderStatus(
                        order,
                        status: 'ready_to_ship',
                        trackingNumber:
                            tracking.trim().isEmpty || tracking.trim() == '-'
                            ? null
                            : tracking.trim(),
                        cargoCompany: 'İHIZ',
                        title: isExternalOrder
                            ? 'İHIZ kurye çağrısı güncellendi'
                            : 'İHIZ kurye çağrısı yenilendi',
                        description:
                            'İHIZ kurye çağrısı yenilendi. Kurye paketi teslim aldığında sipariş Kargoda adımına geçecek.',
                        deliveryTypeOverride: 'ihiz_kurye_bekleniyor',
                        forceUpdate: true,
                      ),
                      icon: const Icon(Icons.refresh_rounded),
                      label: const Text('Kurye çağrısını yenile'),
                    ),
                  ],
                ),
              ),
            ],
          ),
        ),
      );
    }

    if (currentStatus == 'shipped' ||
        currentStatus == 'transfer' ||
        currentStatus == 'branch' ||
        currentStatus == 'out_for_delivery' ||
        currentStatus == 'delivered') {
      final trackingLabel = tracking.trim().isEmpty || tracking.trim() == '-'
          ? 'Takip no henuz olusturulmadi'
          : 'Takip No: $tracking';
      return Padding(
        padding: const EdgeInsets.all(24),
        child: Container(
          width: double.infinity,
          padding: const EdgeInsets.all(24),
          decoration: BoxDecoration(
            color: const Color(0xFFEAFBF3),
            borderRadius: BorderRadius.circular(18),
            border: Border.all(color: const Color(0xFFB7E4C7)),
          ),
          child: Row(
            children: [
              Container(
                width: 42,
                height: 42,
                decoration: const BoxDecoration(
                  color: Colors.white,
                  shape: BoxShape.circle,
                ),
                child: const Icon(
                  Icons.check_rounded,
                  color: Color(0xFF067647),
                ),
              ),
              const SizedBox(width: 16),
              Expanded(
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text(
                      currentStatus == 'delivered'
                          ? 'Sipariş Teslim Edildi'
                          : isIhizShipment
                          ? 'Kurye Dağıtımda'
                          : 'Sipariş kargoya verildi',
                      style: const TextStyle(
                        fontSize: 18,
                        fontWeight: FontWeight.w800,
                        color: Color(0xFF05603A),
                      ),
                    ),
                    const SizedBox(height: 6),
                    Text(
                      (isExternalOrder && isIhizShipment)
                          ? 'İHIZ havuzunda kurye paketi teslim aldı. $trackingLabel'
                          : '${cargoCompany.trim().isEmpty ? 'İHIZ' : cargoCompany} • $trackingLabel',
                      style: const TextStyle(
                        fontSize: 15,
                        color: Color(0xFF067647),
                      ),
                    ),
                  ],
                ),
              ),
            ],
          ),
        ),
      );
    }

    if (currentStatus == 'ready_to_ship') {
      final cargoByCompany = _sellerBranchOptionsByCargo();
      final cargoCompanies = cargoByCompany.keys.toList();
      final selectedCargoCompany =
          cargoCompanies.contains(_sellerDetailCargoCompany)
          ? _sellerDetailCargoCompany!
          : cargoCompanies.first;
      final branchList =
          cargoByCompany[selectedCargoCompany] ?? const <String>['Merkez Sube'];
      final selectedBranchName = branchList.contains(_sellerDetailBranchName)
          ? _sellerDetailBranchName
          : branchList.first;
      final isIhizCourierSelected = isExternalOrder
          ? true
          : _sellerDetailDeliveryMode == 'courier';
      final isBranchSelected = isExternalOrder ? false : !isIhizCourierSelected;
      final isIhizToBranch = _sellerDetailBranchOperation == 'ihiz_to_branch';
      final isSelfDropoff = _sellerDetailBranchOperation == 'self_dropoff';
      final isCargoPickup = _sellerDetailBranchOperation == 'cargo_pickup';

      return Padding(
        padding: const EdgeInsets.all(24),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            const Text(
              'TESLİMAT TÜRÜ',
              style: TextStyle(
                fontSize: 13,
                fontWeight: FontWeight.w800,
                letterSpacing: 0.6,
                color: Color(0xFF667085),
              ),
            ),
            const SizedBox(height: 14),
            Row(
              children: [
