  String? _sellerOrderCancellationReason(Map<String, dynamic> order) {
    final status = order['status']?.toString().toLowerCase() ?? '';
    if (!status.contains('cancel')) return null;

    final directCandidates = <dynamic>[
      order['cancel_reason'],
      order['cancellation_reason'],
      order['reason'],
      order['description'],
    ];
    for (final candidate in directCandidates) {
      final parsed = _normalizeSellerCancellationReason(candidate?.toString());
      if (parsed != null) return parsed;
    }

    final orderItemId = order['id']?.toString().trim() ?? '';
    final selectedOrderItemId =
        _selectedSellerOrderItemId ??
        _selectedSellerOrderDetail?['id']?.toString().trim() ??
        '';
    if (orderItemId.isEmpty || selectedOrderItemId != orderItemId) {
      return null;
    }

    for (final row in _selectedSellerOrderHistory.reversed) {
      final rowStatus = (row['status'] ?? '').toString().toLowerCase();
      if (!rowStatus.contains('cancel')) continue;
      final parsed = _normalizeSellerCancellationReason(
        row['description']?.toString(),
      );
      if (parsed != null) return parsed;
    }
    return null;
  }

  String? _normalizeSellerCancellationReason(String? raw) {
    if (raw == null) return null;
    var text = raw.trim();
    if (text.isEmpty) return null;
    if (text.startsWith('VIDEO::') || text.startsWith('VIDEO_REMOVED::')) {
      return null;
    }

    final lower = text.toLowerCase();
    const markers = <String>[
      'iptal nedeni:',
      'iptal sebebi:',
      'sebep:',
      'neden:',
      'reason:',
    ];
    for (final marker in markers) {
      final index = lower.indexOf(marker);
      if (index < 0) continue;
      final start = index + marker.length;
      if (start <= text.length) {
        text = text.substring(start).trim();
      }
      break;
    }

    text = text.replaceFirst(RegExp(r'^[-:\s]+'), '').trim();
    if (text.isEmpty) return null;
    return text;
  }

