    return SellerReturnInfoRow(label: label, value: value);
  }

  Widget _sellerReturnEvidenceImage(String url) {
    if (url.startsWith('data:image/')) {
      try {
        final bytes = UriData.parse(url).contentAsBytes();
        return Image.memory(bytes, fit: BoxFit.cover);
      } catch (_) {
        return Container(
          color: Colors.grey.shade100,
          child: const Icon(Icons.broken_image_outlined),
        );
      }
    }
    return OptimizedImage(
      imageUrlOrPath: url,
      fit: BoxFit.cover,
      errorBuilder: (_, _, _) => Container(
        color: Colors.grey.shade100,
        child: const Icon(Icons.broken_image_outlined),
      ),
    );
  }

  Future<void> _updateOrderStatus(
    Map<String, dynamic> order, {
    required String status,
    String? trackingNumber,
    String cargoCompany = 'İHız',
    String? title,
    String? description,
    String? deliveryTypeOverride,
    bool forceUpdate = false,
  }) async {
    try {
      final orderId = order['id']?.toString();
      final normalizedDeliveryTypeOverride = (deliveryTypeOverride ?? '')
          .trim();
      final resolvedDeliveryType = normalizedDeliveryTypeOverride.isNotEmpty
          ? normalizedDeliveryTypeOverride
          : _resolveSellerDeliveryTypeByMode(_sellerDetailDeliveryMode);
      if (mounted) {
        setState(() {
          if (orderId != null && orderId.isNotEmpty) {
            _sellerOrders = _sellerOrders
                .map(
                  (row) => row['id']?.toString() == orderId
                      ? {
                          ...row,
                          'status': status,
                          if (trackingNumber != null &&
                              trackingNumber.trim().isNotEmpty)
                            'tracking_number': trackingNumber.trim(),
                          'cargo_company': cargoCompany,
                          'delivery_type': resolvedDeliveryType,
                        }
                      : row,
                )
                .toList();
            _invalidateOrdersDerivedState();
          }
          if (_selectedSellerOrderDetail != null &&
              (_selectedSellerOrderDetail!['id']?.toString() ==
                  order['id']?.toString())) {
            _selectedSellerOrderDetail = {
              ..._selectedSellerOrderDetail!,
              'status': status,
              if (trackingNumber != null && trackingNumber.trim().isNotEmpty)
                'tracking_number': trackingNumber.trim(),
              'cargo_company': cargoCompany,
              'delivery_type': resolvedDeliveryType,
            };
          }
        });
      }
      await OrderService.instance.updateSellerOrderStatus(
        itemId: order['id']?.toString() ?? '',
        orderId: order['order_id']?.toString() ?? '',
        sellerId:
            order['seller_id']?.toString() ??
            _selectedSellerOrderDetail?['seller_id']?.toString() ??
            _authService.currentUser?.id ??
            '',
        customerId: order['customer_id']?.toString() ?? '',
        status: status,
        trackingNumber: trackingNumber,
        cargoCompany: cargoCompany,
        title: title,
        description: description,
        storeName: order['store_name']?.toString(),
        storeLogoUrl:
            order['store_logo_url']?.toString() ??
            order['store_logo']?.toString(),
        productName: order['product_name']?.toString(),
        productCode: order['product_code']?.toString(),
        productImageUrl:
            order['product_image_url']?.toString() ??
            order['image_url']?.toString(),
        deliveryMode: _sellerDetailDeliveryMode,
        deliveryType: resolvedDeliveryType,
        forceUpdate: forceUpdate,
      );
      final itemId = order['id']?.toString();
      if (itemId != null && itemId.isNotEmpty) {
        await _reloadAndKeepSellerOrderDetail(itemId);
      } else {
        await _loadSellerOrders();
      }
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('${order['order_number']} durumu güncellendi.')),
      );
    } catch (e) {
      if (!mounted) return;
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text('Sipariş güncellenemedi: $e')));
    }
  }

  bool _shouldShowPackagingPanel(String? status) {
    final normalized = (status ?? '').toLowerCase();
    return normalized == 'preparing' || normalized == 'ready_to_ship';
  }

  Future<void> _showSellerQuestionsDialog() async {
    await _loadSellerQuestions();
    if (!mounted) return;
    showDialog(
      context: context,
      builder: (context) => Dialog(
        backgroundColor: Colors.white,
        child: Container(
          width: 760,
          constraints: const BoxConstraints(maxHeight: 720),
          padding: const EdgeInsets.all(20),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Row(
                children: [
                  const Expanded(
                    child: Text(
                      'Gelen Ürün Soruları',
                      style: TextStyle(
                        fontSize: 20,
                        fontWeight: FontWeight.w800,
                      ),
                    ),
                  ),
                  IconButton(
                    onPressed: () => Navigator.pop(context),
                    icon: const Icon(Icons.close),
                  ),
                ],
              ),
              const SizedBox(height: 12),
              Expanded(
                child: _isLoadingSellerQuestions
                    ? const Center(child: CircularProgressIndicator())
                    : _sellerQuestions.isEmpty
                    ? Center(
                        child: Text(
                          'Henüz size yöneltilmiş soru yok.',
                          style: TextStyle(color: Colors.grey.shade600),
                        ),
                      )
                    : ListView.builder(
                        itemCount: _sellerQuestions.length,
                        itemBuilder: (context, index) {
                          final question = _sellerQuestions[index];
                          final answered =
                              question['answer']
                                  ?.toString()
                                  .trim()
                                  .isNotEmpty ??
                              false;
                          return Container(
                            margin: const EdgeInsets.only(bottom: 12),
                            padding: const EdgeInsets.all(16),
                            decoration: BoxDecoration(
                              borderRadius: BorderRadius.circular(16),
                              border: Border.all(color: Colors.grey.shade200),
                              color: const Color(0xFFF9FAFB),
                            ),
                            child: Column(
                              crossAxisAlignment: CrossAxisAlignment.start,
                              children: [
                                Row(
                                  children: [
                                    Expanded(
                                      child: Text(
                                        question['productName']?.toString() ??
                                            'Ürün',
                                        style: const TextStyle(
                                          fontSize: 15,
                                          fontWeight: FontWeight.w700,
                                        ),
                                      ),
                                    ),
                                    Text(
                                      answered ? 'Yanıtlandı' : 'Yeni Soru',
                                      style: TextStyle(
                                        fontSize: 12,
                                        fontWeight: FontWeight.w700,
                                        color: answered
                                            ? Colors.green
                                            : AppColors.primary,
                                      ),
                                    ),
                                  ],
                                ),
                                const SizedBox(height: 8),
                                Text(
                                  question['question']?.toString() ?? '',
                                  style: const TextStyle(
                                    fontSize: 14,
                                    height: 1.45,
                                  ),
                                ),
                                const SizedBox(height: 10),
                                Container(
                                  width: double.infinity,
                                  padding: const EdgeInsets.all(12),
                                  decoration: BoxDecoration(
                                    color: Colors.white,
                                    borderRadius: BorderRadius.circular(12),
                                  ),
                                  child: Text(
                                    answered
                                        ? question['answer']?.toString() ?? ''
                                        : 'Henüz yanıt verilmedi.',
                                    style: TextStyle(
                                      fontSize: 13,
                                      color: answered
                                          ? Colors.black87
                                          : Colors.black45,
                                    ),
                                  ),
                                ),
                                const SizedBox(height: 10),
                                Align(
                                  alignment: Alignment.centerRight,
                                  child: OutlinedButton.icon(
                                    onPressed: () =>
                                        _answerSellerQuestion(question),
                                    icon: Icon(
                                      answered
                                          ? Icons.edit_outlined
                                          : Icons.reply_outlined,
                                      size: 16,
                                    ),
                                    label: Text(
                                      answered ? 'Yanıtı Düzenle' : 'Yanıtla',
                                    ),
                                  ),
                                ),
                              ],
                            ),
                          );
                        },
                      ),
              ),
            ],
          ),
        ),
      ),
    );
  }

  Future<void> _answerSellerQuestion(Map<String, dynamic> question) async {
    Navigator.pop(context);
    final controller = TextEditingController(
      text: question['answer']?.toString() ?? '',
    );
    final result = await showDialog<String>(
      context: context,
      builder: (context) => AlertDialog(
        title: const Text('Soruyu Yanıtla'),
        content: TextField(
          controller: controller,
          maxLines: 5,
          decoration: const InputDecoration(
            hintText: 'Yanıtınızı yazın',
            border: OutlineInputBorder(),
          ),
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(context),
            child: const Text('İptal'),
          ),
          ElevatedButton(
            onPressed: () => Navigator.pop(context, controller.text.trim()),
            child: const Text('Kaydet'),
          ),
        ],
      ),
    );
    if (result == null || result.isEmpty) return;
    try {
      await ProductQuestionService.instance.answerQuestion(
        questionId: question['id']?.toString() ?? '',
        answer: result,
      );
    } catch (_) {
      await AppState().answerProductQuestion(
        questionId: question['id']?.toString() ?? '',
        answer: result,
      );
    }
    await _loadSellerQuestions();
    if (!mounted) return;
    _showSellerQuestionsDialog();
  }

