  // ─── GARSON MODÜLÜ ────────────────────────────────────────────────────────

  Widget _buildGarsonModule() {
    final sellerId = _authService.currentUser?.id ?? '';
    _garsonBuildRenderCount += 1;
    debugPrint(
      '[GarsonBuild][render] '
      'buildId=$_garsonBuildRenderCount '
      'pendingChanges=${_garsonHasPendingRemoteChanges.value} '
      'refreshGeneration=$_garsonManualRefreshGeneration',
    );

    return Column(
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        // ── Garson Üst Bar ────────────────────────────────────────────────
        _buildGarsonTopBar(sellerId: sellerId),
        const SizedBox(height: 12),
        if (sellerId.isNotEmpty)
          Padding(
            padding: const EdgeInsets.symmetric(horizontal: 8),
            child: WaiterOrderRequestsBanner(sellerId: sellerId),
          ),
        if (kIsWeb) ...[
          Padding(
            padding: const EdgeInsets.symmetric(horizontal: 4),
            child: Align(
              alignment: Alignment.centerLeft,
              child: ConstrainedBox(
                constraints: const BoxConstraints(maxWidth: 440),
                child: _buildLocalPrintServicePanel(
                  uiBranch: 'web_garson_panel',
                ),
              ),
            ),
          ),
          const SizedBox(height: 12),
        ],

        Expanded(
          child: sellerId.isEmpty
              ? const Center(
                  child: Text(
                    'Oturum bulunamadı.',
                    style: TextStyle(color: Colors.grey),
                  ),
                )
              : StreamBuilder<List<Map<String, dynamic>>>(
                  initialData: _garsonOrdersSnapshotForUi(),
                  stream: _garsonVisibleOrdersController.stream,
                  builder: (ctx, snapshot) {
                    if (snapshot.hasError) {
                      _handleGarsonRealtimeError(
                        snapshot.error!,
                        sellerId: sellerId,
                      );
                      return FutureBuilder<List<Map<String, dynamic>>>(
                        future: _getSellerTableOrdersFallbackFuture(sellerId),
                        builder: (context, fallbackSnapshot) {
                          final allOrders = _resolveGarsonTableOrdersForUi(
                            fallbackSnapshot.data,
                          );
                          if (_shouldShowGarsonInitialLoadingUi(allOrders)) {
                            return const Center(
                              child: CircularProgressIndicator(),
                            );
                          }
                          if (fallbackSnapshot.hasError &&
                              allOrders.isEmpty &&
                              _storeTables.isEmpty) {
                            return Center(
                              child: Text('Hata: ${fallbackSnapshot.error}'),
                            );
                          }
                          if (_garsonInitialLoadError != null &&
                              allOrders.isEmpty &&
                              _storeTables.isEmpty &&
                              !_isGarsonInitialLoading) {
                            return _buildGarsonInitialLoadErrorState();
                          }
                          if (allOrders.isEmpty &&
                              _storeTables.isEmpty &&
                              !_isGarsonInitialLoading) {
                            return _buildGarsonEmptyState(
                              message:
                                  'Henüz masa/sipariş verisi yok. Yenile’ye bas.',
                            );
                          }
                          if (allOrders.isEmpty && _storeTables.isEmpty) {
                            return _buildGarsonEmptyState(
                              message:
                                  'Henüz masa/sipariş verisi yok. Yenile’ye bas.',
                            );
                          }

                          var orders = allOrders
                              .where(
                                (order) => !_isGarsonClosedStatus(
                                  order['status']?.toString(),
                                ),
                              )
                              .toList(growable: false);
                          orders = orders
                              .where((order) {
                                final tableNo = _garsonTableNumberFromOrder(
                                  order,
                                );
                                final closedAt =
                                    _webGarsonClosedTableAt[tableNo];
                                if (closedAt == null) return true;
                                final createdAt = _garsonOrderCreatedAt(
                                  order['created_at']?.toString(),
                                );
                                return createdAt.isAfter(closedAt);
                              })
                              .toList(growable: false);

                          if (_shouldShowGarsonInitialLoadingUi(allOrders)) {
                            return _buildGarsonTablesLoadingPlaceholder();
                          }

                          final ordersByTable =
                              <int, List<Map<String, dynamic>>>{};
                          for (final order in orders) {
                            final tableNo = _garsonTableNumberFromOrder(order);
                            if (tableNo <= 0) continue;
                            ordersByTable
                                .putIfAbsent(
                                  tableNo,
                                  () => <Map<String, dynamic>>[],
                                )
                                .add(order);
                          }
                          for (final entry in ordersByTable.entries) {
                            entry.value.sort(
                              (a, b) =>
                                  _garsonOrderCreatedAt(
                                    b['created_at']?.toString(),
                                  ).compareTo(
                                    _garsonOrderCreatedAt(
                                      a['created_at']?.toString(),
                                    ),
                                  ),
                            );
                          }

                          final displayTableNumbers =
                              _garsonTableNumbersForGrid(
                                orderTableNumbers: ordersByTable.keys.toList(
                                  growable: false,
                                ),
                              );
                          if (displayTableNumbers.isEmpty) {
                            return Center(
                              child: Text(
                                'Henüz masa kaydı yok. Sistem bölümünden masa ekleyin.',
                                style: TextStyle(color: Colors.grey.shade600),
                              ),
                            );
                          }

                          final occupiedTableNumbers = displayTableNumbers
                              .where(
                                (tableNo) =>
                                    (ordersByTable[tableNo]?.isNotEmpty ??
                                    false),
                              )
                              .toSet();
                          return SingleChildScrollView(
                            padding: const EdgeInsets.only(bottom: 8),
                            child: _buildGarsonGroupedTableGrids(
                              groups: _garsonTableAreaGroupsForNumbers(
                                displayTableNumbers,
                              ),
                              occupiedTableNumbers: occupiedTableNumbers,
                              columnsResolver: _webGarsonGridColumns,
                              aspectRatioResolver: _webGarsonGridAspectRatio,
                              sectionPadding: EdgeInsets.zero,
                              cardBuilder: (tableNumber) {
                                var tableOrders =
                                    ordersByTable[tableNumber] ??
                                    const <Map<String, dynamic>>[];
                                final opAt =
                                    _mobileGarsonOptimisticSentAtByTable[tableNumber];
                                final opItems =
                                    _mobileGarsonOptimisticItemsByTable[tableNumber] ??
                                    const <Map<String, dynamic>>[];
                                if (opAt != null &&
                                    DateTime.now().difference(opAt) <=
                                        const Duration(seconds: 45) &&
                                    tableOrders.isEmpty) {
                                  tableOrders = [
                                    <String, dynamic>{
                                      'status': 'sent',
                                      'table_number': tableNumber,
                                      'created_at': opAt.toIso8601String(),
                                      'items': opItems,
                                    },
                                  ];
                                }
                                final order = tableOrders.firstWhere(
                                  (order) => !_isGarsonCompletedStatus(
                                    order['status']?.toString(),
                                  ),
                                  orElse: () => tableOrders.isNotEmpty
                                      ? tableOrders.first
                                      : <String, dynamic>{},
                                );
                                return _buildWebGarsonTableCard(
                                  tableNumber: tableNumber,
                                  order: order.isEmpty ? null : order,
                                  orderCount: tableOrders.length,
                                  tableOrders: tableOrders,
                                );
                              },
                            ),
                          );
                        },
                      );
                    }
                    final allOrders = _resolveGarsonTableOrdersForUi(
                      snapshot.data,
                    );
                    if (_shouldShowGarsonInitialLoadingUi(allOrders)) {
                      return const Center(child: CircularProgressIndicator());
                    }
                    if (_garsonInitialLoadError != null &&
                        allOrders.isEmpty &&
                        _storeTables.isEmpty &&
                        !_isGarsonInitialLoading) {
                      return _buildGarsonInitialLoadErrorState();
                    }
                    if (allOrders.isEmpty && _storeTables.isEmpty) {
                      return _buildGarsonEmptyState(
                        message:
                            'Henüz masa/sipariş verisi yok. Yenile’ye bas.',
                      );
                    }

                    var orders = allOrders
                        .where(
                          (order) => !_isGarsonClosedStatus(
                            order['status']?.toString(),
                          ),
                        )
                        .toList(growable: false);
                    orders = orders
                        .where((order) {
                          final tableNo = _garsonTableNumberFromOrder(order);
                          final closedAt = _webGarsonClosedTableAt[tableNo];
                          if (closedAt == null) return true;
                          final createdAt = _garsonOrderCreatedAt(
                            order['created_at']?.toString(),
                          );
                          return createdAt.isAfter(closedAt);
                        })
                        .toList(growable: false);

                    final ordersByTable = <int, List<Map<String, dynamic>>>{};
                    for (final order in orders) {
                      final tableNo = _garsonTableNumberFromOrder(order);
                      if (tableNo <= 0) continue;
                      ordersByTable
                          .putIfAbsent(tableNo, () => <Map<String, dynamic>>[])
                          .add(order);
                    }
                    for (final entry in ordersByTable.entries) {
                      entry.value.sort(
                        (a, b) =>
                            _garsonOrderCreatedAt(
                              b['created_at']?.toString(),
                            ).compareTo(
                              _garsonOrderCreatedAt(
                                a['created_at']?.toString(),
                              ),
                            ),
                      );
                    }

                    if (_shouldShowGarsonInitialLoadingUi(allOrders)) {
                      return _buildGarsonTablesLoadingPlaceholder();
                    }

                    final tableNumbers = _garsonTableNumbersForGrid(
                      orderTableNumbers: ordersByTable.keys.toList(
                        growable: false,
                      ),
                    );
                    if (tableNumbers.isEmpty) {
                      return Center(
                        child: Column(
                          mainAxisAlignment: MainAxisAlignment.center,
                          children: [
                            const Icon(
                              Icons.event_busy_outlined,
                              size: 40,
                              color: Color(0xFF9CA3AF),
                            ),
                            const SizedBox(height: 8),
                            Text(
                              'Masa siparişi yok',
                              style: TextStyle(
                                fontSize: 13,
                                color: Colors.grey.shade600,
                              ),
                            ),
                          ],
                        ),
                      );
                    }

                    final filledCount = tableNumbers
                        .where(
                          (tableNo) =>
                              (ordersByTable[tableNo]?.isNotEmpty ?? false),
                        )
                        .length;

                    final preparingCount = tableNumbers.where((tableNo) {
                      final tOrders = ordersByTable[tableNo] ?? [];
                      return tOrders.any(
                        (o) => (o['status']?.toString() ?? '') == 'preparing',
                      );
                    }).length;

                    final paymentPendingCount = tableNumbers.where((tableNo) {
                      final tOrders = ordersByTable[tableNo] ?? [];
                      return tOrders.any((o) {
                        final s = (o['status']?.toString() ?? '');
                        return s == 'ready' || s == 'served';
                      });
                    }).length;

                    // Apply status filter
                    final displayTableNumbers = tableNumbers
                        .where((tableNo) {
                          final tOrders = ordersByTable[tableNo] ?? [];
                          switch (_garsonStatusFilter) {
                            case 'occupied':
                              return tOrders.isNotEmpty;
                            case 'preparing':
                              return tOrders.any(
                                (o) =>
                                    (o['status']?.toString() ?? '') ==
                                    'preparing',
                              );
                            case 'payment_pending':
                              return tOrders.any((o) {
                                final s = (o['status']?.toString() ?? '');
                                return s == 'ready' || s == 'served';
                              });
                            default:
                              return true;
                          }
                        })
                        .where(_matchesGarsonAreaFilter)
                        .toList(growable: false);

                    return Column(
                      crossAxisAlignment: CrossAxisAlignment.stretch,
                      children: [
                        Padding(
                          padding: const EdgeInsets.only(bottom: 8),
                          child: _mobileSurfaceCard(
                            child: Row(
                              children: [
                                const Icon(
                                  Icons.map_outlined,
                                  size: 18,
                                  color: Color(0xFF0F172A),
                                ),
                                const SizedBox(width: 8),
                                const Text(
                                  'Alan Seç',
                                  style: TextStyle(fontWeight: FontWeight.w800),
                                ),
                                const SizedBox(width: 10),
                                Expanded(
                                  child: DropdownButtonHideUnderline(
                                    child: DropdownButton<String>(
                                      isExpanded: true,
                                      value:
                                          _garsonAreaOptions().any(
                                            (o) =>
                                                o.key == _garsonAreaFilterKey,
                                          )
                                          ? _garsonAreaFilterKey
                                          : 'all',
                                      items: _garsonAreaOptions()
                                          .map(
                                            (o) => DropdownMenuItem<String>(
                                              value: o.key,
                                              child: Text(
                                                o.label,
                                                overflow: TextOverflow.ellipsis,
                                              ),
                                            ),
                                          )
                                          .toList(growable: false),
                                      onChanged: (value) {
                                        final next = (value ?? 'all').trim();
                                        if (next.isEmpty) return;
                                        setState(
                                          () => _garsonAreaFilterKey = next,
                                        );
                                        unawaited(
                                          _persistGarsonAreaFilter(next),
                                        );
                                      },
                                    ),
                                  ),
                                ),
                              ],
                            ),
                          ),
                        ),
                        // Status filter badges row
                        SingleChildScrollView(
                          scrollDirection: Axis.horizontal,
                          child: Row(
                            children: [
                              _garsonFilterBadge(
                                label: 'Toplam Masa',
                                value: '${tableNumbers.length}',
                                filterKey: null,
                                activeFilter: _garsonStatusFilter,
                                onTap: () =>
                                    setState(() => _garsonStatusFilter = null),
                              ),
                              const SizedBox(width: 6),
                              _garsonFilterBadge(
                                label: 'Dolu Masa',
                                value: '$filledCount',
                                filterKey: 'occupied',
                                activeFilter: _garsonStatusFilter,
                                activeColor: const Color(0xFF16A34A),
                                onTap: () => setState(
                                  () => _garsonStatusFilter =
                                      _garsonStatusFilter == 'occupied'
                                      ? null
                                      : 'occupied',
                                ),
                              ),
                              const SizedBox(width: 6),
                              _garsonFilterBadge(
                                label: 'Hazırlanıyor',
                                value: '$preparingCount',
                                filterKey: 'preparing',
                                activeFilter: _garsonStatusFilter,
                                activeColor: const Color(0xFF0D9488),
                                onTap: () => setState(
                                  () => _garsonStatusFilter =
                                      _garsonStatusFilter == 'preparing'
                                      ? null
                                      : 'preparing',
                                ),
                              ),
                              const SizedBox(width: 6),
                              _garsonFilterBadge(
                                label: 'Ödeme Bekliyor',
                                value: '$paymentPendingCount',
                                filterKey: 'payment_pending',
                                activeFilter: _garsonStatusFilter,
                                activeColor: const Color(0xFFD97706),
                                onTap: () => setState(
                                  () => _garsonStatusFilter =
                                      _garsonStatusFilter == 'payment_pending'
                                      ? null
                                      : 'payment_pending',
                                ),
                              ),
                            ],
                          ),
                        ),
                        const SizedBox(height: 10),
                        Expanded(
                          child: displayTableNumbers.isEmpty
                              ? Center(
                                  child: Column(
                                    mainAxisAlignment: MainAxisAlignment.center,
                                    children: [
                                      Icon(
                                        Icons.filter_alt_outlined,
                                        size: 36,
                                        color: Colors.grey.shade400,
                                      ),
                                      const SizedBox(height: 8),
                                      Text(
                                        'Bu filtreyle eşleşen masa yok.',
                                        style: TextStyle(
                                          color: Colors.grey.shade500,
                                        ),
                                      ),
                                      const SizedBox(height: 8),
                                      TextButton(
                                        onPressed: () => setState(
                                          () => _garsonStatusFilter = null,
                                        ),
                                        child: const Text('Filtreyi Temizle'),
                                      ),
                                    ],
                                  ),
                                )
                              : Builder(
                                  builder: (context) {
                                    final occupiedTableNumbers =
                                        displayTableNumbers
                                            .where(
                                              (tableNo) =>
                                                  (ordersByTable[tableNo]
                                                      ?.isNotEmpty ??
                                                  false),
                                            )
                                            .toSet();
                                    return SingleChildScrollView(
                                      child: _buildGarsonGroupedTableGrids(
                                        groups:
                                            _garsonTableAreaGroupsForNumbers(
                                              displayTableNumbers,
                                            ),
                                        occupiedTableNumbers:
                                            occupiedTableNumbers,
                                        columnsResolver: _webGarsonGridColumns,
                                        aspectRatioResolver:
                                            _webGarsonGridAspectRatio,
                                        sectionPadding: EdgeInsets.zero,
                                        cardBuilder: (tableNumber) {
                                          var tableOrders =
                                              ordersByTable[tableNumber] ??
                                              const <Map<String, dynamic>>[];
                                          final opAt =
                                              _mobileGarsonOptimisticSentAtByTable[tableNumber];
                                          final opItems =
                                              _mobileGarsonOptimisticItemsByTable[tableNumber] ??
                                              const <Map<String, dynamic>>[];
                                          if (opAt != null &&
                                              DateTime.now().difference(opAt) <=
                                                  const Duration(seconds: 45) &&
                                              tableOrders.isEmpty) {
                                            tableOrders = [
                                              <String, dynamic>{
                                                'status': 'sent',
                                                'table_number': tableNumber,
                                                'created_at': opAt
                                                    .toIso8601String(),
                                                'items': opItems,
                                              },
                                            ];
                                          }
                                          Map<String, dynamic>? selectedOrder;
                                          if (tableOrders.isNotEmpty) {
                                            selectedOrder = tableOrders
                                                .firstWhere(
                                                  (order) =>
                                                      !_isGarsonCompletedStatus(
                                                        order['status']
                                                            ?.toString(),
                                                      ),
                                                  orElse: () =>
                                                      tableOrders.first,
                                                );
                                          }
                                          return _buildWebGarsonTableCard(
                                            tableNumber: tableNumber,
                                            order: selectedOrder,
                                            orderCount: tableOrders.length,
                                            tableOrders: tableOrders,
                                          );
                                        },
                                      ),
                                    );
                                  },
                                ),
                        ),
                      ],
                    );
                  },
                ),
        ),
      ],
    );
  }

  int _webGarsonGridColumns(double maxWidth) {
    const spacing = 10.0;
    const minCardWidth = 200.0;
    final columns = ((maxWidth + spacing) / (minCardWidth + spacing)).floor();
    return columns.clamp(1, 8);
  }

  double _webGarsonGridAspectRatio(double maxWidth, int columns) {
    const spacing = 10.0;
    final safeColumns = columns <= 0 ? 1 : columns;
    final cardWidth = (maxWidth - ((safeColumns - 1) * spacing)) / safeColumns;
    if (cardWidth >= 330) return 1.6;
    if (cardWidth >= 280) return 1.45;
    if (cardWidth >= 230) return 1.28;
    if (cardWidth >= 200) return 1.15;
    return 1.0;
  }

