  /// Clickable status badge for the garson grid filter bar.
  Widget _garsonFilterBadge({
    required String label,
    required String value,
    required String? filterKey,
    required String? activeFilter,
    required VoidCallback onTap,
    Color? activeColor,
  }) {
    final isActive = activeFilter == filterKey;
    final accentColor = activeColor ?? AppColors.primary;
    return GestureDetector(
      onTap: onTap,
      child: AnimatedContainer(
        duration: const Duration(milliseconds: 150),
        padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 5),
        decoration: BoxDecoration(
          color: isActive ? accentColor.withValues(alpha: 0.12) : Colors.white,
          borderRadius: BorderRadius.circular(8),
          border: Border.all(
            color: isActive ? accentColor : Colors.grey.shade300,
            width: isActive ? 1.5 : 1,
          ),
        ),
        child: Row(
          mainAxisSize: MainAxisSize.min,
          children: [
            Text(
              label,
              style: TextStyle(
                fontSize: 12,
                fontWeight: FontWeight.w600,
                color: isActive ? accentColor : const Color(0xFF374151),
              ),
            ),
            const SizedBox(width: 5),
            Container(
              padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 2),
              decoration: BoxDecoration(
                color: isActive ? accentColor : Colors.grey.shade200,
                borderRadius: BorderRadius.circular(999),
              ),
              child: Text(
                value,
                style: TextStyle(
                  fontSize: 11,
                  fontWeight: FontWeight.w700,
                  color: isActive ? Colors.white : const Color(0xFF374151),
                ),
              ),
            ),
          ],
        ),
      ),
    );
  }

  Widget _buildWebGarsonTableCard({
    required int tableNumber,
    required Map<String, dynamic>? order,
    required int orderCount,
    required List<Map<String, dynamic>> tableOrders,
  }) {
    final hasOrder = orderCount > 0;
    final status = order?['status']?.toString();
    final color = _mobileGarsonStatusColor(status, hasOrder: hasOrder);
    final statusLabel = _mobileGarsonStatusLabel(status, hasOrder: hasOrder);
    final cardItems = <Map<String, dynamic>>[];
    for (final tableOrder in tableOrders) {
      cardItems.addAll(_garsonExtractItems(tableOrder));
    }
    final tableTotal = _garsonOrdersTotal(tableOrders);
    final subtitle = hasOrder && order != null
        ? '${_garsonOrderTimeAgoLabel(order)} önce • $orderCount sipariş'
        : 'Sipariş yok';
    final tableRow = _storeTableRowByNumber(tableNumber);
    final tableTitle = tableRow == null
        ? 'Masa $tableNumber'
        : _tableDisplayLabelFromRow(tableRow);
    debugPrint(
      '[GARSON_TABLE_CARD_BIND] '
      'table_id=${tableRow?['id'] ?? order?['table_id'] ?? order?['store_table_id'] ?? '-'} '
      'table_number=$tableNumber '
      'display_label=$tableTitle '
      'active_order_found=${hasOrder} '
      'order_id=${order?['id'] ?? '-'} '
      'items_count=${cardItems.length} '
      'total=$tableTotal',
    );
    return Material(
      color: Colors.transparent,
      child: InkWell(
        borderRadius: BorderRadius.circular(10),
        onTap: () {
          _openGarsonTableFlowPage(
            tableNumber: tableNumber,
            initialOrder: order,
          );
        },
        child: Container(
          padding: const EdgeInsets.all(8),
          decoration: BoxDecoration(
            color: hasOrder ? color.withValues(alpha: 0.12) : Colors.white,
            borderRadius: BorderRadius.circular(10),
            border: Border.all(
              color: hasOrder
                  ? color.withValues(alpha: 0.45)
                  : const Color(0xFFE2E8F0),
            ),
          ),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Row(
                children: [
                  Expanded(
                    child: Text(
                      tableTitle,
                      maxLines: 1,
                      overflow: TextOverflow.ellipsis,
                      style: const TextStyle(
                        fontSize: 12,
                        fontWeight: FontWeight.w800,
                        color: Color(0xFF111827),
                      ),
                    ),
                  ),
                  if (orderCount > 0)
                    Container(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 6,
                        vertical: 1,
                      ),
                      decoration: BoxDecoration(
                        color: color,
                        borderRadius: BorderRadius.circular(999),
                      ),
                      child: Text(
                        '$orderCount',
                        style: const TextStyle(
                          fontSize: 10,
                          fontWeight: FontWeight.w800,
                          color: Colors.white,
                        ),
                      ),
                    ),
                ],
              ),
              const SizedBox(height: 5),
              Row(
                children: [
                  Icon(
                    hasOrder
                        ? Icons.notifications_active_rounded
                        : Icons.table_restaurant_outlined,
                    color: color,
                    size: 15,
                  ),
                  const SizedBox(width: 5),
                  Expanded(
                    child: Text(
                      statusLabel,
                      maxLines: 1,
                      overflow: TextOverflow.ellipsis,
                      style: TextStyle(
                        fontSize: 10,
                        fontWeight: FontWeight.w700,
                        color: color,
                      ),
                    ),
                  ),
                ],
              ),
              const SizedBox(height: 2),
              Text(
                subtitle,
                maxLines: 1,
                overflow: TextOverflow.ellipsis,
                style: TextStyle(fontSize: 9, color: Colors.grey.shade600),
              ),
              const SizedBox(height: 4),
              if (hasOrder)
                Expanded(
                  child: SingleChildScrollView(
                    physics: const BouncingScrollPhysics(),
                    child: Column(
                      children: cardItems
                          .map((item) {
                            final qty =
                                (item['quantity'] as num?)?.toInt() ?? 1;
                            final lineTotal = MixedServiceOrder.itemLineTotal(
                              item,
                            );
                            final detailLines = _garsonItemDetailLines(item);
                            return Padding(
                              padding: const EdgeInsets.only(bottom: 3),
                              child: Column(
                                crossAxisAlignment: CrossAxisAlignment.start,
                                children: [
                                  Row(
                                    children: [
                                      Container(
