                )
              else
                const Spacer(),
              if (hasOrder)
                Padding(
                  padding: const EdgeInsets.only(top: 3),
                  child: Text(
                    'Toplam: ${_garsonFormatMoney(tableTotal)}',
                    style: TextStyle(
                      fontSize: 10,
                      fontWeight: FontWeight.w800,
                      color: Colors.grey.shade800,
