                                    selectedSizeName?.trim() ?? '';
                                final amountLabel =
                                    normalizedSizeName.isNotEmpty
                                    ? normalizedSizeName
                                    : matchedProduct
                                              ?.usesServiceControlStepper ==
                                          true
                                    ? ProductPriceCalculator.formatServiceAmountLabel(
                                        type: matchedProduct!
                                            .resolvedServiceControlType,
                                        amount:
                                            matchedProduct
                                                .usesPortionLikeStepper
                                            ? selectedServiceAmount
                                            : null,
                                        grams:
                                            matchedProduct
                                                    .resolvedServiceControlType ==
                                                ProductServiceControlType
                                                    .weightStepper
                                            ? selectedWeightGrams
                                            : null,
                                      )
                                    : gramajController.text.trim();
                                final updated = Map<String, dynamic>.from(item)
                                  ..['quantity'] = quantity
                                  ..['price'] = unitPrice
                                  ..['gramaj'] = amountLabel
                                  ..['amountLabel'] = amountLabel
                                  ..['selectedSizeName'] =
                                      normalizedSizeName.isEmpty
                                      ? null
                                      : normalizedSizeName
                                  ..['selectedSizePrice'] =
                                      normalizedSizeName.isEmpty
                                      ? null
                                      : unitPrice
                                  ..['serviceControlType'] = matchedProduct
                                      ?.resolvedServiceControlType
                                      .storageValue
                                  ..['selectedServiceAmount'] =
                                      matchedProduct?.usesPortionLikeStepper ==
                                          true
                                      ? selectedServiceAmount
                                      : null
                                  ..['selectedWeightGrams'] =
                                      matchedProduct
                                              ?.resolvedServiceControlType ==
                                          ProductServiceControlType
                                              .weightStepper
                                      ? selectedWeightGrams
                                      : null
                                  ..['line_total'] = unitPrice * quantity
                                  ..['notes'] = notesController.text.trim()
                                  ..['attributes'] = selectedAttrs.toList(
                                    growable: false,
                                  );
                                onSave(updated);
                                Navigator.pop(dialogCtx);
                              },
                              style: ElevatedButton.styleFrom(
                                backgroundColor: AppColors.primary,
                                foregroundColor: Colors.white,
                                padding: const EdgeInsets.symmetric(
                                  vertical: 11,
                                ),
                                shape: RoundedRectangleBorder(
                                  borderRadius: BorderRadius.circular(12),
                                ),
                              ),
                              child: const Text(
                                'Onayla',
                                style: TextStyle(
                                  fontSize: 14,
                                  fontWeight: FontWeight.w700,
                                ),
                              ),
                            ),
                          ),
                        ],
                      ),
                    ),
                  ),
                ),
              );
            },
          );
        },
      );
    } finally {
      gramajController.dispose();
      notesController.dispose();
    }
  }

  Future<List<Map<String, dynamic>>?> _configureGarsonProductItem(
    BuildContext ctx,
    SellerProduct product, [
    Map<String, dynamic>? editingItem,
    int? editIndex,
  ]) async {
    final isEditing = editingItem != null;
    garsonDraftLog(
      'OpenModal',
      extra: <String, Object?>{
        'mode': isEditing ? 'edit' : 'new',
        'productName': product.name,
        'editIndex': editIndex ?? -1,
        'existingQuantity': isEditing
            ? ((editingItem['quantity'] as num?)?.toInt() ?? 1)
            : 0,
      },
    );
    final modalState = isEditing
        ? GarsonProductModalState.fromDraftItem(product, editingItem)
        : GarsonProductModalState.openNew(product);
    final notesCtrl = TextEditingController(text: modalState.activeUnit.note);
    final customGramsCtrl = TextEditingController();
    final attrs = product.attributes;
    final gramajPresets = GarsonProductSelection.weightQuickGramOptions(
      product,
    );

    // showModalBottomSheet correctly propagates MediaQuery.viewInsets so the
    // note field stays visible when the keyboard is shown (keyboard-safe).
    void syncNoteFromField() => modalState.syncActiveUnitNote(notesCtrl.text);

    void switchActiveUnit(
      int index,
      void Function(void Function()) setStateDialog,
    ) {
      syncNoteFromField();
      setStateDialog(() {
        modalState.setActiveUnitIndex(index);
        notesCtrl.text = modalState.activeUnit.note;
      });
    }

    void applyCustomGramInput(void Function(void Function()) setStateDialog) {
      final raw = customGramsCtrl.text;
      final grams = GarsonProductSelection.parseCustomGramInput(
        raw,
        product: product,
      );
      if (grams == null) {
        ScaffoldMessenger.of(ctx).showSnackBar(
          const SnackBar(
            content: Text('Geçerli bir gramaj girin (ör. 575).'),
            duration: Duration(seconds: 2),
          ),
        );
        return;
      }
      setStateDialog(() {
        modalState.setWeightModeForActiveUnit(grams, snapToStep: false);
        customGramsCtrl.text = '$grams';
      });
      if (kDebugMode) {
        final price = GarsonProductSelection.resolveUnitPrice(
          product: product,
          activeMode: GarsonActivePricingMode.weight,
          selectedGramsForWeight: modalState.selectedGrams,
        );
        final probe = GarsonProductSelection.buildOrderItemFromUnit(
          product: product,
          quantity: 1,
          unit: modalState.activeUnit,
          showGramajUi: modalState.showGramajUi,
        );
        debugPrint(
          '[GarsonProductSelect][custom_gram_apply] ${jsonEncode(<String, Object?>{'raw': raw, 'parsedGrams': grams, 'activeUnitIndex': modalState.activeUnitIndex, 'pricingMode': 'weight', 'selectedGrams': modalState.selectedGrams, 'selectedWeightGrams': modalState.selectedWeightGrams, 'displayLabel': probe['display_label'] ?? '', 'amountLabel': probe['amount_label'] ?? probe['gramaj'] ?? '', 'price': price})}',
        );
      }
    }

    return showModalBottomSheet<List<Map<String, dynamic>>>(
      context: ctx,
      isScrollControlled: true,
      useSafeArea: true,
      backgroundColor: Colors.white,
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.vertical(top: Radius.circular(20)),
      ),
      builder: (bCtx) {
        return StatefulBuilder(
          builder: (bCtx, setStateDialog) {
            final kbPad = MediaQuery.viewInsetsOf(bCtx).bottom;
            return SizedBox(
              width: double.infinity,
              child: Padding(
                padding: EdgeInsets.fromLTRB(20, 16, 20, 20 + kbPad),
                child: SingleChildScrollView(
                  child: Column(
                    mainAxisSize: MainAxisSize.min,
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      Row(
                        children: [
                          Expanded(
                            child: Column(
