  Future<void> _pickSellerVideo() async {
    // Limit check (Max 5 videos)
    if (_sellerVideos.length >= 5) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('En fazla 5 adet video ekleyebilirsiniz.'),
        ),
      );
      return;
    }

    try {
      final XFile? video = await _picker.pickVideo(
        source: ImageSource.gallery,
        maxDuration: const Duration(seconds: 60),
      );

      if (video == null) return;

      // Check size
      final size = await video.length();
      if (size > 50 * 1024 * 1024) {
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(
              content: Text('Video boyutu 50MB\'dan büyük olamaz'),
            ),
          );
        }
        return;
      }

      setState(() => _isUploadingVideo = true);

      final url = await _storeService.uploadStoreVideo(video);

      if (mounted) {
        setState(() {
          _sellerVideos.add(url);
          _isUploadingVideo = false;
        });
        // Auto-save
        _saveStoreProfile();
      }
    } catch (e) {
      if (mounted) {
        setState(() => _isUploadingVideo = false);
        ScaffoldMessenger.of(
          context,
        ).showSnackBar(SnackBar(content: Text('Video yüklenirken hata: $e')));
      }
    }
  }

  Future<void> _selectVideoFromProducts() async {
    // Limit check (Max 5 videos)
    if (_sellerVideos.length >= 5) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('En fazla 5 adet video ekleyebilirsiniz.'),
        ),
      );
      return;
    }

    setState(() => _isLoading = true);
    try {
      final productsWithVideos = await _storeService.getProductsWithVideos();

      if (!mounted) return;

      if (productsWithVideos.isEmpty) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(content: Text('Videosu olan ürün bulunamadı')),
        );
        return;
      }

      await showDialog(
        context: context,
        builder: (context) => Dialog(
          child: Container(
            width: 500,
            padding: const EdgeInsets.all(20),
            child: Column(
              mainAxisSize: MainAxisSize.min,
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                const Text(
                  'Ürün Videolarından Seç',
                  style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold),
                ),
                const SizedBox(height: 16),
                SizedBox(
                  height: 400,
                  child: ListView.separated(
                    itemCount: productsWithVideos.length,
                    separatorBuilder: (context, index) => const Divider(),
                    itemBuilder: (context, index) {
                      final product = productsWithVideos[index];
                      final isSelected = _sellerVideos.contains(
                        product.videoUrl,
                      );

                      return ListTile(
                        leading: Container(
                          width: 50,
                          height: 50,
                          decoration: BoxDecoration(
                            borderRadius: BorderRadius.circular(8),
                            image: product.imageUrl != null
                                ? DecorationImage(
                                    image: ResizeImage.resizeIfNeeded(
                                      200,
                                      200,
                                      CachedNetworkImageProvider(
                                        product.imageUrl!,
                                      ),
                                    ),
                                    fit: BoxFit.cover,
                                  )
                                : null,
                            color: Colors.grey.shade200,
                          ),
                          child: product.imageUrl == null
                              ? const Icon(Icons.image)
                              : null,
                        ),
                        title: Text(product.name),
                        subtitle: Text(product.mainCategory),
                        trailing: isSelected
                            ? const Icon(
                                Icons.check_circle,
                                color: Colors.green,
                              )
                            : ElevatedButton(
                                onPressed: () {
                                  if (product.videoUrl != null) {
                                    setState(() {
                                      _sellerVideos.add(product.videoUrl!);
                                    });
                                    Navigator.pop(context);
                                    _saveStoreProfile();
                                  }
                                },
                                child: const Text('Seç'),
                              ),
                      );
                    },
                  ),
                ),
                const SizedBox(height: 16),
                Align(
                  alignment: Alignment.centerRight,
                  child: TextButton(
                    onPressed: () => Navigator.pop(context),
                    child: const Text('Kapat'),
                  ),
                ),
              ],
            ),
          ),
        ),
      );
    } catch (e) {
      if (mounted) {
        ScaffoldMessenger.of(
          context,
        ).showSnackBar(SnackBar(content: Text('Hata: $e')));
      }
    } finally {
      if (mounted) setState(() => _isLoading = false);
    }
  }

