  String _financeFilterLabel(String raw) {
    switch (raw) {
      case 'Tum Islemler':
        return 'Tüm İşlemler';
      case 'Satis':
        return 'Satış';
      case 'Bekleyen':
        return 'Bekleyen';
      case 'Komisyon':
        return 'Komisyon';
      case 'Iade':
        return 'İade';
      default:
        return raw;
    }
  }

