  Widget _buildFeedbackTimelineCard(Map<String, dynamic> item) {
    final kind = item['kind']?.toString() ?? 'review';
    final complaintKind = item['complaintKind']?.toString() ?? '';
    final isCancelAppealComplaint = complaintKind == 'cancel_appeal';
    final color = switch (kind) {
      'question' => const Color(0xFF0EA5E9),
      'complaint' => const Color(0xFFEF4444),
      _ => const Color(0xFF610BEF),
    };
    final icon = switch (kind) {
      'question' => Icons.help_center_rounded,
      'complaint' => Icons.report_problem_rounded,
      _ => Icons.rate_review_rounded,
    };
    final rating = (item['rating'] as num?)?.toDouble();
    final answer = item['answer']?.toString() ?? '';
    final date = item['createdAtDate'] as DateTime?;
    final complaintStatus = item['status']?.toString() ?? 'İnceleniyor';
    final cancelReason = item['cancelReason']?.toString().trim() ?? '';
    final trackingNumber = item['trackingNumber']?.toString().trim() ?? '';
    final orderId = item['orderId']?.toString().trim() ?? '';
    final requestReorder = item['requestReorder'] == true;
    final complaintStatusBg = isCancelAppealComplaint
        ? switch (_normalizeCancelAppealStatus(complaintStatus)) {
            'Yeni' => const Color(0xFFFFF7ED),
            'İnceleniyor' => const Color(0xFFEFF6FF),
            'Çözüldü' => const Color(0xFFECFDF3),
            _ => const Color(0xFFFEF2F2),
          }
        : const Color(0xFFFEF2F2);
    final complaintStatusFg = isCancelAppealComplaint
        ? switch (_normalizeCancelAppealStatus(complaintStatus)) {
            'Yeni' => const Color(0xFF9A3412),
            'İnceleniyor' => const Color(0xFF1D4ED8),
            'Çözüldü' => const Color(0xFF166534),
            _ => const Color(0xFFB91C1C),
          }
        : const Color(0xFFB91C1C);

    return Container(
      margin: const EdgeInsets.only(bottom: 14),
      padding: const EdgeInsets.all(16),
