  void _showFeedbackComplaintDetailDialog(Map<String, dynamic> item) {
    final title = item['title']?.toString().trim().isNotEmpty == true
        ? item['title'].toString().trim()
        : 'Şikayet Detayı';
    final status = item['status']?.toString().trim().isNotEmpty == true
        ? item['status'].toString().trim()
        : 'İnceleniyor';
    final sourceLabel =
        item['sourceLabel']?.toString().trim().isNotEmpty == true
        ? item['sourceLabel'].toString().trim()
        : 'Şikayet';
    final message = item['message']?.toString().trim().isNotEmpty == true
        ? item['message'].toString().trim()
        : '-';
    final userName = item['userName']?.toString().trim().isNotEmpty == true
        ? item['userName'].toString().trim()
        : 'Müşteri';
    final date = item['createdAtDate'] as DateTime?;
    final cancelReason = item['cancelReason']?.toString().trim() ?? '';
    final trackingNumber = item['trackingNumber']?.toString().trim() ?? '';
    final orderId = item['orderId']?.toString().trim() ?? '';
    final orderItemId = item['orderItemId']?.toString().trim() ?? '';
    final requestReorder = item['requestReorder'] == true;
    final complaintKind = item['complaintKind']?.toString() ?? '';
    final isCancelAppeal = complaintKind == 'cancel_appeal';
    final shownStatus = isCancelAppeal
        ? _normalizeCancelAppealStatus(status)
        : status;

    showDialog(
      context: context,
      builder: (dialogContext) => Dialog(
        backgroundColor: Colors.white,
        child: Container(
          width: 560,
          constraints: const BoxConstraints(maxHeight: 640),
          child: Column(
