  Future<void> _answerFeedbackQuestionFromPanel(
    Map<String, dynamic> question,
  ) async {
    final controller = TextEditingController(
      text: question['answer']?.toString() ?? '',
    );
    final result = await showDialog<String>(
      context: context,
      builder: (dialogContext) => AlertDialog(
        title: const Text('Soruyu Yanıtla'),
        content: TextField(
          controller: controller,
          maxLines: 5,
          decoration: const InputDecoration(
            hintText: 'Yanıtınızı yazın',
            border: OutlineInputBorder(),
          ),
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(dialogContext),
            child: const Text('İptal'),
          ),
          ElevatedButton(
            onPressed: () =>
                Navigator.pop(dialogContext, controller.text.trim()),
            child: const Text('Kaydet'),
          ),
        ],
      ),
    );
    if (result == null || result.isEmpty) return;
    try {
      await ProductQuestionService.instance.answerQuestion(
        questionId: question['id']?.toString() ?? '',
        answer: result,
      );
    } catch (_) {
      await AppState().answerProductQuestion(
        questionId: question['id']?.toString() ?? '',
        answer: result,
      );
    }
    await _loadSellerQuestions();
    if (!mounted) return;
    setState(() {});
  }

