  Widget _buildSupportModule() => _buildSupportModuleImpl();

  List<SupportTicket> _filterSupportTickets(List<SupportTicket> tickets) {
    final query = _debouncedSupportQuery;
    return tickets.where((ticket) {
      if (_selectedSupportTab == 'Açık' &&
          ticket.status != TicketStatus.open &&
          ticket.status != TicketStatus.in_progress) {
        return false;
      }
      if (_selectedSupportTab == 'Kapalı' &&
          ticket.status != TicketStatus.closed &&
          ticket.status != TicketStatus.resolved) {
        return false;
      }
      if (query.isEmpty) return true;
      final haystack = [
        ticket.subject,
        ticket.category,
        ticket.description,
        ticket.id,
      ].join(' ').toLowerCase();
      return haystack.contains(query);
    }).toList();
  }

  Widget _buildSupportTrendCard(List<SupportTicket> tickets) {
    final now = DateTime.now();
    final buckets = List.generate(7, (index) {
      final date = DateTime(
        now.year,
        now.month,
        now.day,
      ).subtract(Duration(days: 6 - index));
      final opened = tickets.where((ticket) {
        final created = DateTime(
          ticket.createdAt.year,
          ticket.createdAt.month,
          ticket.createdAt.day,
        );
        return created == date;
      }).length;
      final resolved = tickets.where((ticket) {
        if (ticket.updatedAt == null) return false;
        final updated = DateTime(
          ticket.updatedAt!.year,
          ticket.updatedAt!.month,
          ticket.updatedAt!.day,
        );
        final isResolved =
            ticket.status == TicketStatus.closed ||
            ticket.status == TicketStatus.resolved;
        return isResolved && updated == date;
      }).length;
      return {
        'label': _shortDayLabel(date.weekday),
        'opened': opened,
        'resolved': resolved,
      };
    });
    final maxValue = buckets.fold<int>(
      1,
      (prev, item) => math.max(
        prev,
        math.max(item['opened'] as int, item['resolved'] as int),
      ),
    );

    return Container(
      padding: const EdgeInsets.all(20),
      decoration: BoxDecoration(
        color: Colors.white,
        borderRadius: BorderRadius.circular(18),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          const Text(
            'Destek Trafiği',
            style: TextStyle(fontSize: 18, fontWeight: FontWeight.w800),
          ),
          const SizedBox(height: 6),
          Text(
            'Son 7 günde açılan ve çözülen talepler',
            style: TextStyle(fontSize: 12, color: Colors.grey.shade600),
          ),
          const SizedBox(height: 18),
          Row(
            children: const [
              _SupportLegendDot(color: Color(0xFF6C63FF), label: 'Açılan'),
              SizedBox(width: 12),
              _SupportLegendDot(color: Color(0xFF10B981), label: 'Çözülen'),
            ],
          ),
          const SizedBox(height: 16),
          SizedBox(
            height: 170,
            child: Row(
              crossAxisAlignment: CrossAxisAlignment.end,
              children: buckets.map((bucket) {
                final opened = bucket['opened'] as int;
                final resolved = bucket['resolved'] as int;
                final openedHeight = (opened / maxValue) * 120;
                final resolvedHeight = (resolved / maxValue) * 120;
                return Expanded(
                  child: Column(
                    mainAxisAlignment: MainAxisAlignment.end,
                    children: [
                      Row(
                        mainAxisAlignment: MainAxisAlignment.center,
                        crossAxisAlignment: CrossAxisAlignment.end,
                        children: [
                          Container(
                            width: 14,
                            height: math.max(openedHeight, 6),
                            decoration: BoxDecoration(
                              color: const Color(0xFF6C63FF),
                              borderRadius: BorderRadius.circular(12),
                            ),
                          ),
                          const SizedBox(width: 4),
                          Container(
                            width: 14,
                            height: math.max(resolvedHeight, 6),
                            decoration: BoxDecoration(
                              color: const Color(0xFF10B981),
                              borderRadius: BorderRadius.circular(12),
                            ),
                          ),
                        ],
                      ),
                      const SizedBox(height: 8),
                      Text(
                        bucket['label'] as String,
                        style: TextStyle(
                          fontSize: 11,
                          color: Colors.grey.shade600,
                        ),
                      ),
                    ],
                  ),
                );
              }).toList(),
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildSupportCategoryCard(List<SupportTicket> tickets) {
    final counts = <String, int>{};
    for (final ticket in tickets) {
      counts[ticket.category] = (counts[ticket.category] ?? 0) + 1;
    }
    final entries = counts.entries.toList()
      ..sort((a, b) => b.value.compareTo(a.value));

    return Container(
      padding: const EdgeInsets.all(20),
      decoration: BoxDecoration(
        color: Colors.white,
        borderRadius: BorderRadius.circular(18),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          const Text(
            'Konu Dağılımı',
            style: TextStyle(fontSize: 18, fontWeight: FontWeight.w800),
          ),
          const SizedBox(height: 6),
          Text(
            'Satıcıların en sık açtığı destek başlıkları',
            style: TextStyle(fontSize: 12, color: Colors.grey.shade600),
          ),
          const SizedBox(height: 18),
          if (entries.isEmpty)
            Padding(
              padding: const EdgeInsets.only(top: 24),
              child: Text(
                'Henüz kategori verisi yok',
                style: TextStyle(color: Colors.grey.shade500),
              ),
            )
          else
            ...entries.take(5).map((entry) {
              final ratio = tickets.isEmpty
                  ? 0.0
                  : entry.value / tickets.length;
              return Padding(
                padding: const EdgeInsets.only(bottom: 14),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Row(
                      children: [
                        Expanded(
                          child: Text(
                            entry.key,
                            style: const TextStyle(
                              fontSize: 13,
                              fontWeight: FontWeight.w700,
                            ),
                          ),
                        ),
                        Text(
                          '${entry.value}',
                          style: TextStyle(color: Colors.grey.shade600),
                        ),
                      ],
                    ),
                    const SizedBox(height: 8),
                    ClipRRect(
                      borderRadius: BorderRadius.circular(999),
                      child: LinearProgressIndicator(
                        value: ratio,
                        minHeight: 10,
                        backgroundColor: const Color(0xFFEEF2F7),
                        valueColor: const AlwaysStoppedAnimation<Color>(
                          Color(0xFF6C63FF),
                        ),
                      ),
                    ),
                  ],
                ),
              );
            }),
        ],
      ),
    );
  }

