            child: Icon(icon, color: color, size: 22),
          ),
          const SizedBox(width: 12),
          Expanded(
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Text(
                  title,
                  style: TextStyle(fontSize: 12, color: Colors.grey.shade600),
                ),
                const SizedBox(height: 4),
                Text(
                  value,
                  style: TextStyle(
                    fontSize: 20,
                    fontWeight: FontWeight.bold,
                    color: color,
                  ),
                ),
                if (subtitle != null) ...[
                  const SizedBox(height: 2),
                  Text(
                    subtitle,
                    style: TextStyle(fontSize: 10, color: Colors.grey.shade500),
                  ),
                ],
              ],
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildSupportTabButton(
    String label,
    bool isActive,
    VoidCallback onTap,
  ) {
    return Material(
      color: isActive ? Colors.white : Colors.transparent,
      borderRadius: BorderRadius.circular(6),
      child: InkWell(
        onTap: onTap,
        borderRadius: BorderRadius.circular(6),
        child: Container(
          padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 6),
          decoration: BoxDecoration(
            color: isActive ? Colors.white : Colors.transparent,
            borderRadius: BorderRadius.circular(6),
            boxShadow: isActive
                ? [
                    BoxShadow(
                      color: Colors.black.withValues(alpha: 0.05),
                      blurRadius: 4,
                      offset: const Offset(0, 2),
                    ),
                  ]
                : null,
          ),
          child: Text(
            label,
            style: TextStyle(
              fontSize: 12,
              fontWeight: isActive ? FontWeight.w600 : FontWeight.normal,
              color: isActive ? const Color(0xFF6C63FF) : Colors.grey.shade600,
            ),
          ),
        ),
      ),
    );
  }

  Widget _buildSupportTicketCard(SupportTicket ticket) {
    // Sekme filtresine göre göster/gizle
    if (_selectedSupportTab == 'Açık' &&
        ticket.status != TicketStatus.open &&
        ticket.status != TicketStatus.in_progress) {
      return const SizedBox.shrink();
    }
    if (_selectedSupportTab == 'Kapalı' &&
        ticket.status != TicketStatus.closed &&
        ticket.status != TicketStatus.resolved) {
      return const SizedBox.shrink();
    }

    final priorityColors = {
      TicketPriority.high: Colors.red,
      TicketPriority.medium: Colors.orange,
      TicketPriority.low: Colors.green,
    };

    final statusColors = {
      TicketStatus.open: Colors.orange,
      TicketStatus.in_progress: Colors.blue,
      TicketStatus.closed: Colors.green,
      TicketStatus.resolved: Colors.green,
    };

    final statusText = {
      TicketStatus.open: 'Açık',
      TicketStatus.in_progress: 'İnceleniyor',
      TicketStatus.closed: 'Kapalı',
      TicketStatus.resolved: 'Çözüldü',
    };

    return Container(
      margin: const EdgeInsets.only(bottom: 10),
      padding: const EdgeInsets.all(14),
      decoration: BoxDecoration(
        color: Colors.white,
        borderRadius: BorderRadius.circular(10),
        border: Border.all(
          color: ticket.status == TicketStatus.open
              ? const Color(0xFF6C63FF).withValues(alpha: 0.3)
              : Colors.grey.shade200,
          width: 1.5,
        ),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          // Üst Satır: Konu ve Durum
          Row(
            children: [
              Container(
                width: 36,
                height: 36,
                decoration: BoxDecoration(
                  color: priorityColors[ticket.priority]!.withValues(
                    alpha: 0.1,
                  ),
                  borderRadius: BorderRadius.circular(6),
                ),
                child: Icon(
                  Icons.headset_mic,
                  color: priorityColors[ticket.priority],
                  size: 18,
                ),
              ),
              const SizedBox(width: 10),
              Expanded(
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text(
                      ticket.subject,
                      style: const TextStyle(
                        fontSize: 13,
                        fontWeight: FontWeight.w600,
                      ),
                    ),
                    const SizedBox(height: 2),
                    Row(
                      children: [
                        Text(
                          ticket.category,
                          style: TextStyle(
                            fontSize: 10,
                            color: Colors.grey.shade600,
                          ),
                        ),
                        const SizedBox(width: 8),
                        Container(
                          width: 4,
                          height: 4,
                          decoration: BoxDecoration(
                            color: Colors.grey.shade400,
                            shape: BoxShape.circle,
                          ),
                        ),
                        const SizedBox(width: 8),
                        Text(
                          '#${ticket.id.substring(0, 6)}',
                          style: TextStyle(
                            fontSize: 10,
                            color: Colors.grey.shade500,
                          ),
                        ),
                      ],
                    ),
                  ],
                ),
              ),
              Container(
                padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 3),
                decoration: BoxDecoration(
                  color: statusColors[ticket.status]!.withValues(alpha: 0.1),
                  borderRadius: BorderRadius.circular(6),
                ),
                child: Text(
                  statusText[ticket.status] ?? 'Bilinmiyor',
                  style: TextStyle(
                    fontSize: 10,
                    fontWeight: FontWeight.w600,
                    color: statusColors[ticket.status],
                  ),
                ),
              ),
            ],
          ),
          const Divider(height: 14),

          // Alt Satır: Bilgiler ve Butonlar
          Row(
            children: [
              // Öncelik
              Container(
                padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 2),
                decoration: BoxDecoration(
                  color: priorityColors[ticket.priority]!.withValues(
                    alpha: 0.1,
                  ),
                  borderRadius: BorderRadius.circular(4),
                ),
                child: Row(
                  mainAxisSize: MainAxisSize.min,
                  children: [
                    Icon(
                      Icons.flag,
                      size: 10,
                      color: priorityColors[ticket.priority],
                    ),
                    const SizedBox(width: 3),
                    Text(
                      ticket.priority.name.toUpperCase(),
                      style: TextStyle(
                        fontSize: 9,
                        fontWeight: FontWeight.w600,
                        color: priorityColors[ticket.priority],
                      ),
                    ),
                  ],
                ),
              ),
              const SizedBox(width: 12),

              // Tarih
              Icon(Icons.calendar_today, size: 11, color: Colors.grey.shade500),
              const SizedBox(width: 4),
              Text(
                '${ticket.createdAt.day}.${ticket.createdAt.month}.${ticket.createdAt.year}',
                style: TextStyle(fontSize: 10, color: Colors.grey.shade600),
              ),

              const Spacer(),
            ],
          ),

          const SizedBox(height: 10),

          // İşlem Butonları
          if (ticket.status == TicketStatus.open ||
              ticket.status == TicketStatus.in_progress)
            Row(
              mainAxisAlignment: MainAxisAlignment.end,
              children: [
                TextButton.icon(
                  onPressed: () {
                    // TODO: Implement reply or view detail
                    _showSupportTicketDetailDialog(ticket);
                  },
                  icon: const Icon(Icons.visibility, size: 14),
                  label: const Text('Detay', style: TextStyle(fontSize: 11)),
                  style: TextButton.styleFrom(
                    foregroundColor: Colors.grey.shade600,
                    padding: const EdgeInsets.symmetric(
                      horizontal: 8,
                      vertical: 4,
                    ),
                    minimumSize: Size.zero,
                    tapTargetSize: MaterialTapTargetSize.shrinkWrap,
                  ),
                ),
              ],
            ),
        ],
      ),
    );
  }

  void _showNewSupportTicketDialog() {
    final supportCategories = [
      'Teknik Destek',
      'Odeme ve Finans',
      'Siparis ve Operasyon',
      'Magaza Yonetimi',
      'Kampanya ve Reklam',
      'Hesap ve Onay',
      'Diğer',
    ];
    String category = supportCategories.first;
    String selectedSubjectMode = 'preset';
    String selectedPresetSubject = _supportSubjectOptionsFor(
      supportCategories.first,
    ).first;
    final subjectController = TextEditingController();
    final descriptionController = TextEditingController();

    showDialog(
      context: context,
      builder: (dialogContext) => Dialog(
        backgroundColor: Colors.white,
        child: StatefulBuilder(
          builder: (context, setDialogState) {
            return Container(
              width: 500,
              padding: const EdgeInsets.all(24),
              child: Column(
                mainAxisSize: MainAxisSize.min,
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  const Row(
                    children: [
                      Icon(
                        Icons.support_agent,
                        color: Color(0xFF6C63FF),
                        size: 24,
                      ),
                      SizedBox(width: 12),
                      Text(
                        'Yeni Destek Talebi',
                        style: TextStyle(
                          fontSize: 18,
                          fontWeight: FontWeight.bold,
                        ),
                      ),
                    ],
                  ),
                  const SizedBox(height: 20),
                  DropdownButtonFormField<String>(
                    initialValue: supportCategories.contains(category)
                        ? category
                        : supportCategories.first,
                    decoration: const InputDecoration(
                      labelText: 'Kategori *',
                      border: OutlineInputBorder(),
                    ),
                    items: supportCategories
                        .map(
                          (item) =>
                              DropdownMenuItem(value: item, child: Text(item)),
                        )
                        .toList(),
                    onChanged: (value) {
                      if (value != null) {
                        category = value;
                        selectedPresetSubject = _supportSubjectOptionsFor(
                          category,
                        ).first;
                        setDialogState(() {});
                      }
                    },
                  ),
                  const SizedBox(height: 12),
                  DropdownButtonFormField<String>(
                    initialValue: selectedSubjectMode,
                    decoration: const InputDecoration(
                      labelText: 'Konu tipi *',
                      border: OutlineInputBorder(),
                    ),
                    items: const [
                      DropdownMenuItem(
                        value: 'preset',
                        child: Text('Hazır konu seç'),
                      ),
                      DropdownMenuItem(
                        value: 'custom',
                        child: Text('Konuyu kendim yazacağım'),
                      ),
                    ],
                    onChanged: (value) {
                      if (value == null) return;
                      selectedSubjectMode = value;
                      setDialogState(() {});
                    },
                  ),
                  const SizedBox(height: 12),
                  if (selectedSubjectMode == 'preset') ...[
                    DropdownButtonFormField<String>(
                      initialValue: selectedPresetSubject,
                      decoration: const InputDecoration(
                        labelText: 'Konu *',
                        border: OutlineInputBorder(),
                      ),
                      items: _supportSubjectOptionsFor(category)
                          .map(
                            (item) => DropdownMenuItem(
                              value: item,
                              child: Text(item),
                            ),
                          )
                          .toList(),
                      onChanged: (value) {
                        if (value == null) return;
                        selectedPresetSubject = value;
                        setDialogState(() {});
                      },
                    ),
                  ] else ...[
                    TextField(
                      controller: subjectController,
                      decoration: const InputDecoration(
                        labelText: 'Konu *',
                        hintText: 'Kısa bir konu başlığı yazın',
                        border: OutlineInputBorder(),
                      ),
                    ),
                  ],
                  const SizedBox(height: 12),
                  TextField(
                    controller: descriptionController,
                    maxLines: 4,
                    decoration: const InputDecoration(
                      labelText: 'Açıklama *',
                      hintText: 'Sorununuzu detaylı açıklayın...',
                      border: OutlineInputBorder(),
                    ),
                  ),
                  const SizedBox(height: 8),
                  Text(
                    'Talebiniz en kısa sürede yanıtlanacaktır.',
                    style: TextStyle(fontSize: 11, color: Colors.grey.shade500),
                  ),
                  const SizedBox(height: 20),
                  Row(
                    children: [
                      Expanded(
                        child: OutlinedButton(
                          onPressed: () => Navigator.pop(dialogContext),
                          child: const Text('İptal'),
                        ),
                      ),
                      const SizedBox(width: 12),
                      Expanded(
                        child: ElevatedButton.icon(
                          onPressed: () async {
                            final subject = selectedSubjectMode == 'preset'
                                ? selectedPresetSubject.trim()
                                : subjectController.text.trim();
                            final description = descriptionController.text
                                .trim();
                            if (subject.isEmpty || description.isEmpty) {
                              ScaffoldMessenger.of(dialogContext).showSnackBar(
                                const SnackBar(
                                  content: Text('Lütfen tüm alanları doldurun'),
                                ),
                              );
                              return;
                            }
                            final user = _authService.currentUser;
                            if (user == null) return;
                            try {
                              final isCloseAccountRequest = subject
                                  .toLowerCase()
                                  .contains(
                                    'satıcı hesabımı kalıcı olarak kapat',
                                  );
                              await _supportService.createTicket(
                                userId: user.id,
                                userType: 'seller',
                                category: category,
                                subject: subject,
                                description: description,
                                priority: isCloseAccountRequest
                                    ? TicketPriority.high
                                    : TicketPriority.medium,
                              );
                              if (isCloseAccountRequest) {
                                await _storeService.requestStoreDeletion(
                                  reason: description,
                                );
                              }

                              if (!mounted || !dialogContext.mounted) return;
                              Navigator.pop(dialogContext);
                              ScaffoldMessenger.of(this.context).showSnackBar(
                                SnackBar(
                                  content: Text(
                                    isCloseAccountRequest
                                        ? 'Kapatma talebiniz oluşturuldu. Admin onayı bekleniyor.'
                                        : 'Destek talebiniz oluşturuldu!',
                                  ),
                                  backgroundColor: Colors.green,
                                ),
                              );
                            } catch (e) {
                              if (!mounted) return;
                              ScaffoldMessenger.of(this.context).showSnackBar(
                                SnackBar(content: Text('Hata: $e')),
                              );
                            }
                          },
                          icon: const Icon(Icons.send, size: 18),
                          label: const Text('Gönder'),
                          style: ElevatedButton.styleFrom(
                            backgroundColor: const Color(0xFF6C63FF),
                            foregroundColor: Colors.white,
                          ),
                        ),
                      ),
                    ],
                  ),
                ],
              ),
            );
          },
        ),
      ),
    );
  }

  List<String> _supportSubjectOptionsFor(String category) {
    switch (category) {
      case 'Teknik Destek':
        return const [
          'Sipariş bildirimleri çalışmıyor',
          'Ürün yükleme sırasında hata alıyorum',
          'Satıcı paneli yavaş çalışıyor',
          'Kargo takip bilgisi görünmüyor',
          'Mağaza sayfam eksik görünüyor',
        ];
      case 'Odeme ve Finans':
        return const [
          'Odeme talebim hesaba gecmedi',
          'Komisyon oranını kontrol etmek istiyorum',
          'Iade sonrası finans hareketi hatalı',
          'Fatura / odeme dekontu talebi',
          'Banka hesabı bilgimi güncellemek istiyorum',
        ];
      case 'Siparis ve Operasyon':
        return const [
          'Sipariş durumu güncellenmiyor',
          'Kargo entegrasyonu hatası',
          'Stokta olan ürün siparişe düşmüyor',
          'Teslimat akışında gecikme yaşıyorum',
          'Müşteri sipariş iptal süreci desteği',
        ];
      case 'Magaza Yonetimi':
        return const [
          'Mağaza profil bilgimi güncellemek istiyorum',
          'Mağaza onay sürecimi soruyorum',
          'Alt yönetici yetkisi vermek istiyorum',
          'Mağaza konumu / adres değişikliği talebi',
          'Mağaza görünürlüğüm düşük görünüyor',
        ];
      case 'Kampanya ve Reklam':
        return const [
          'Kampanya alanım görünmüyor',
          'Öne çıkarılan ürün talebi',
          'Banner / reklam görseli desteği',
          'İndirim kampanyası oluşturma yardımı',
          'Pazarlama raporu talebi',
        ];
      case 'Hesap ve Onay':
        return const [
          'Satıcı hesabımı kalıcı olarak kapat',
          'Hesap doğrulama desteği',
          'Giriş / oturum problemi yaşıyorum',
          'Yetki / güvenlik kontrolü talebi',
          'Vergi / şirket evrağı güncellemesi',
        ];
      default:
        return const [
          'Genel destek talebi',
          'Bilgi almak istiyorum',
          'Satıcı hesabımı kalıcı olarak kapat',
        ];
    }
  }

  void _showSupportTicketDetailDialog(SupportTicket ticket) {
    final statusColors = {
      TicketStatus.open: Colors.orange,
      TicketStatus.in_progress: Colors.blue,
      TicketStatus.closed: Colors.green,
      TicketStatus.resolved: Colors.green,
    };
    final statusText = {
      TicketStatus.open: 'Açık',
      TicketStatus.in_progress: 'İnceleniyor',
      TicketStatus.closed: 'Kapalı',
      TicketStatus.resolved: 'Çözüldü',
    };

    showDialog(
      context: context,
      builder: (context) => Dialog(
        backgroundColor: Colors.white,
        child: Container(
          width: 550,
          constraints: const BoxConstraints(maxHeight: 600),
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              // Header
              Container(
                padding: const EdgeInsets.all(20),
                decoration: BoxDecoration(
                  border: Border(
                    bottom: BorderSide(color: Colors.grey.shade200),
                  ),
                ),
                child: Row(
                  children: [
                    const Icon(
                      Icons.support_agent,
                      color: Color(0xFF6C63FF),
                      size: 24,
                    ),
                    const SizedBox(width: 12),
                    const Expanded(
                      child: Text(
                        'Destek Talebi Detayı',
                        style: TextStyle(
                          fontSize: 18,
                          fontWeight: FontWeight.bold,
                        ),
                      ),
                    ),
                    Container(
                      padding: const EdgeInsets.symmetric(
                        horizontal: 10,
                        vertical: 4,
                      ),
                      decoration: BoxDecoration(
                        color: statusColors[ticket.status]!.withValues(
                          alpha: 0.1,
                        ),
                        borderRadius: BorderRadius.circular(6),
                      ),
                      child: Text(
                        statusText[ticket.status] ?? 'Bilinmiyor',
                        style: TextStyle(
                          fontSize: 12,
                          fontWeight: FontWeight.w600,
                          color: statusColors[ticket.status],
                        ),
                      ),
                    ),
                    const SizedBox(width: 12),
                    IconButton(
                      onPressed: () => Navigator.pop(context),
                      icon: const Icon(Icons.close),
                    ),
                  ],
                ),
              ),

              // Content
              Flexible(
                child: SingleChildScrollView(
                  padding: const EdgeInsets.all(24),
                  child: Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      _buildDetailRow(
                        'Talep No',
                        '#${ticket.id.substring(0, 6)}',
