class _StoreLocationChangeDialog extends StatefulWidget {
  final double? initialLat;
  final double? initialLng;

  const _StoreLocationChangeDialog({this.initialLat, this.initialLng});

  @override
  State<_StoreLocationChangeDialog> createState() =>
      _StoreLocationChangeDialogState();
}

class _StoreLocationChangeDialogState
    extends State<_StoreLocationChangeDialog> {
  late final MapController _mapController;
  double? _selectedLat;
  double? _selectedLng;
  bool _locating = false;

  @override
  void initState() {
    super.initState();
    _selectedLat = widget.initialLat ?? 41.0082;
    _selectedLng = widget.initialLng ?? 28.9784;
    _mapController = MapController();
  }

  Future<void> _useCurrentLocation() async {
    setState(() => _locating = true);
    try {
      final enabled = await Geolocator.isLocationServiceEnabled();
      if (!enabled) {
        throw Exception('Konum servisleri kapalı');
      }
      var permission = await Geolocator.checkPermission();
      if (permission == LocationPermission.denied) {
        permission = await Geolocator.requestPermission();
      }
      if (permission == LocationPermission.denied ||
          permission == LocationPermission.deniedForever) {
        throw Exception('Konum izni verilmedi');
      }
      final pos = await Geolocator.getCurrentPosition(
        locationSettings: const LocationSettings(
          accuracy: LocationAccuracy.high,
        ),
      );
      if (!mounted) return;
      setState(() {
        _selectedLat = pos.latitude;
        _selectedLng = pos.longitude;
      });
      _mapController.move(LatLng(pos.latitude, pos.longitude), 15);
    } catch (e) {
      if (!mounted) return;
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text('Konum alınamadı: $e')));
    } finally {
      if (mounted) setState(() => _locating = false);
    }
  }

  @override
  Widget build(BuildContext context) {
    final currentPoint = LatLng(_selectedLat!, _selectedLng!);
    return Dialog(
      insetPadding: const EdgeInsets.symmetric(horizontal: 40, vertical: 32),
      shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(22)),
      child: Container(
        width: 780,
        padding: const EdgeInsets.all(22),
        child: Column(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            const Text(
              'Konum Değiştir',
              style: TextStyle(fontSize: 22, fontWeight: FontWeight.w700),
            ),
            const SizedBox(height: 8),
            Text(
              'Haritadan yeni mağaza konumunu seçin. Talep admin onayına düşecektir.',
              style: TextStyle(fontSize: 13, color: Colors.grey.shade600),
            ),
            const SizedBox(height: 16),
            Row(
              children: [
                FilledButton.icon(
                  onPressed: _locating ? null : _useCurrentLocation,
                  icon: _locating
                      ? const SizedBox(
                          width: 14,
                          height: 14,
                          child: CircularProgressIndicator(
                            strokeWidth: 2,
                            color: Colors.white,
                          ),
                        )
                      : const Icon(Icons.my_location, size: 16),
                  label: Text(_locating ? 'Bulunuyor...' : 'Bulunduğum Konum'),
                  style: FilledButton.styleFrom(
                    backgroundColor: AppColors.primary,
                    foregroundColor: Colors.white,
                  ),
                ),
                const SizedBox(width: 12),
                Text(
                  '${_selectedLat!.toStringAsFixed(5)}, ${_selectedLng!.toStringAsFixed(5)}',
                  style: TextStyle(
                    fontSize: 12,
                    fontWeight: FontWeight.w600,
                    color: Colors.grey.shade700,
                  ),
                ),
              ],
            ),
            const SizedBox(height: 16),
            Container(
              height: 360,
              decoration: BoxDecoration(
                borderRadius: BorderRadius.circular(18),
                border: Border.all(color: Colors.grey.shade300),
              ),
              clipBehavior: Clip.antiAlias,
              child: FlutterMap(
                mapController: _mapController,
                options: MapOptions(
                  initialCenter: currentPoint,
                  initialZoom: 14,
                  onTap: (_, latLng) {
                    setState(() {
                      _selectedLat = latLng.latitude;
                      _selectedLng = latLng.longitude;
                    });
                  },
                ),
                children: [
                  TileLayer(
                    urlTemplate:
                        'https://tile.openstreetmap.org/{z}/{x}/{y}.png',
                    userAgentPackageName: 'com.ibul.app',
                  ),
                  MarkerLayer(
                    markers: [
                      Marker(
                        point: LatLng(_selectedLat!, _selectedLng!),
                        width: 48,
                        height: 48,
                        child: const Icon(
                          Icons.location_on,
                          size: 46,
                          color: AppColors.primary,
                        ),
                      ),
                    ],
                  ),
                ],
              ),
            ),
            const SizedBox(height: 18),
            Row(
              mainAxisAlignment: MainAxisAlignment.end,
              children: [
                OutlinedButton(
                  onPressed: () => Navigator.pop(context),
                  child: const Text('Vazgeç'),
                ),
                const SizedBox(width: 10),
                ElevatedButton.icon(
                  onPressed: () {
                    Navigator.pop(context, {
                      'lat': _selectedLat!,
                      'lng': _selectedLng!,
                    });
                  },
                  icon: const Icon(Icons.check_circle_outline, size: 16),
                  label: const Text('Onayla'),
                  style: ElevatedButton.styleFrom(
                    backgroundColor: AppColors.primary,
                    foregroundColor: Colors.white,
                  ),
                ),
              ],
            ),
          ],
        ),
      ),
    );
  }
}

typedef _GarsonConfigureProductItem =
    Future<List<Map<String, dynamic>>?> Function(
      BuildContext context,
      SellerProduct product, [
      Map<String, dynamic>? editingItem,
      int? editIndex,
    ]);
typedef _GarsonEditItemSettings =
    Future<void> Function(
      BuildContext context,
      Map<String, dynamic> item,
      void Function(Map<String, dynamic>) onSave,
    );

typedef _MobileGarsonDraftChanged =
    void Function(int tableNumber, List<Map<String, dynamic>> draftItems);
typedef _MobileGarsonOrderSubmitted =
    void Function(
      int tableNumber,
      List<Map<String, dynamic>> submittedItems,
      Map<String, dynamic> submittedOrder,
    );
typedef _MobileGarsonPrintAdisyon =
    Future<void> Function(
      int tableNumber,
      List<Map<String, dynamic>> tableOrders,
    );
typedef _MobileGarsonConfirmCustomerKitchenPrint =
    Future<bool> Function({
      required int tableNumber,
      required List<Map<String, dynamic>> tableOrders,
    });

enum _GarsonOrderChangeType { added, removed, updated }

/// Actions available in the draft-item edit bottom sheet.
enum _DraftItemEditChoice { settings, price }

class _GarsonOrderUpdatedEntry {
  const _GarsonOrderUpdatedEntry({required this.before, required this.after});

  final Map<String, dynamic> before;
  final Map<String, dynamic> after;
}

class _GarsonOrderChangeEntry {
  const _GarsonOrderChangeEntry({
    required this.type,
    required this.item,
    this.previousItem,
  });

  final _GarsonOrderChangeType type;
  final Map<String, dynamic> item;
  final Map<String, dynamic>? previousItem;
}

class _GarsonOrderChangeSummary {
  const _GarsonOrderChangeSummary({
    this.kitchenAddedItems = const <Map<String, dynamic>>[],
    this.kitchenRemovedItems = const <Map<String, dynamic>>[],
    this.displayEntries = const <_GarsonOrderChangeEntry>[],
    this.addedQuantity = 0,
    this.removedQuantity = 0,
    this.updatedQuantity = 0,
  });

  final List<Map<String, dynamic>> kitchenAddedItems;
  final List<Map<String, dynamic>> kitchenRemovedItems;
  final List<_GarsonOrderChangeEntry> displayEntries;
  final int addedQuantity;
  final int removedQuantity;
  final int updatedQuantity;

  bool get hasChanges =>
      displayEntries.isNotEmpty ||
      kitchenAddedItems.isNotEmpty ||
      kitchenRemovedItems.isNotEmpty;

  List<_GarsonOrderChangeEntry> previewEntries({int limit = 4}) {
    if (displayEntries.length <= limit) return displayEntries;
    return displayEntries.take(limit).toList(growable: false);
  }
}

