  double _draftTotal() {
    return _draftItems.fold<double>(
      0,
      (sum, item) => sum + _itemLineTotal(item),
    );
  }

  String _formatMoney(double amount) {
    final safe = amount.isFinite ? amount : 0;
    final text = safe.toStringAsFixed(2);
    final parts = text.split('.');
    final whole = parts[0];
    final decimal = parts.length > 1 ? parts[1] : '00';
    final buffer = StringBuffer();
    for (var i = 0; i < whole.length; i++) {
      final idxFromRight = whole.length - i;
      buffer.write(whole[i]);
      if (idxFromRight > 1 && idxFromRight % 3 == 1) {
        buffer.write('.');
      }
    }
    return '₺${buffer.toString()},$decimal';
  }

  Map<String, dynamic> _normalizeItem(Map<String, dynamic> item) {
    return MixedServiceOrder.normalizeOrderItem(item);
  }

  List<Map<String, dynamic>> _extractItems(dynamic raw) {
