  Future<void> _showTemplateProductActions(SellerProduct product) async {
    if (_isMenuTemplateProduct(product)) {
      _addMenuTemplateProductToDraft(product);
      return;
    }
    final resolution = _inspectServiceTemplateResolution(product);
    final selectableProducts = resolution.selectableProducts;
    if (selectableProducts.isEmpty) {
      debugPrint(
        '[SERVICE_EMPTY] '
        'serviceId=${product.id} '
        'serviceName="${product.name}" '
        'templateItems=${resolution.templateItemsCount} '
        'matchedProducts=${resolution.matchedSelectableProductsCount} '
        'activeMatchedProducts=${resolution.activeMatchedProductsCount} '
        'finalSelectableCount=${resolution.selectableProducts.length}',
      );
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('Bu serviste seçilebilir aktif içerik bulunmuyor.'),
        ),
      );
      return;
    }
    await _customizeServiceTemplateProduct(
      product,
      selectableProducts: selectableProducts,
    );
  }

  int _draftQuantityForProduct(SellerProduct product) {
    var total = 0;
    for (final item in _draftItems) {
      final itemProductId = item['product_id']?.toString();
      if (itemProductId != null && itemProductId.isNotEmpty) {
        if (itemProductId != product.id) continue;
      } else if ((item['name']?.toString() ?? '') != product.name) {
        continue;
      }
      total += (item['quantity'] as num?)?.toInt() ?? 1;
    }
    return total;
  }

  int _draftLineCountForProduct(SellerProduct product) {
    var count = 0;
    for (final item in _draftItems) {
      if (_isMixedServiceItem(item)) continue;
      final itemProductId = item['product_id']?.toString();
      if (itemProductId != null && itemProductId.isNotEmpty) {
        if (itemProductId != product.id) continue;
      } else if ((item['name']?.toString() ?? '') != product.name) {
        continue;
      }
      count++;
    }
    return count;
  }

  /// Yalnızca ürün için tek taslak satır varsa o satırın indeksini döner.
  int _singleDraftIndexForProduct(SellerProduct product) {
    if (_draftLineCountForProduct(product) != 1) return -1;
    for (var i = 0; i < _draftItems.length; i++) {
      final item = _draftItems[i];
      if (_isMixedServiceItem(item)) continue;
      final itemProductId = item['product_id']?.toString();
      if (itemProductId != null && itemProductId.isNotEmpty) {
        if (itemProductId != product.id) continue;
      } else if ((item['name']?.toString() ?? '') != product.name) {
        continue;
      }
      return i;
    }
    return -1;
  }

  int _portionQuickAddDraftIndex(SellerProduct product) {
    final probe = GarsonProductSelection.buildOrderItem(
      product: product,
      quantity: 1,
      activeMode: GarsonActivePricingMode.portion,
    );
    final key = GarsonProductSelection.orderLineMergeKey(probe);
    return _draftItems.indexWhere(
      (item) =>
          !_isMixedServiceItem(item) &&
          GarsonProductSelection.orderLineMergeKey(item) == key,
    );
  }

  SellerProduct? _sellerProductById(String productId) {
    for (final product in _allGarsonProducts()) {
      if (product.id == productId) return product;
    }
    return null;
  }

  int _simpleDraftIndexForProduct(
    SellerProduct product, {
    GarsonActivePricingMode? pricingMode,
    String? selectedSizeName,
    double? selectedServiceAmount,
    int? selectedWeightGrams,
    int? selectedGramsForWeight,
  }) {
    final probe = GarsonProductSelection.buildOrderItem(
      product: product,
      quantity: 1,
      activeMode:
          pricingMode ??
          GarsonProductSelection.resolveDefaults(product).pricingMode,
      selectedSizeName: selectedSizeName,
      selectedServiceAmount: selectedServiceAmount,
      selectedWeightGrams: selectedWeightGrams,
      selectedGramsForWeight: selectedGramsForWeight,
    );
    final key = GarsonProductSelection.orderLineMergeKey(probe);
    return _draftItems.indexWhere(
      (item) =>
          !_isMixedServiceItem(item) &&
          GarsonProductSelection.orderLineMergeKey(item) == key,
    );
  }

  Map<String, dynamic>? _simpleDraftItemForProduct(SellerProduct product) {
    final index = _simpleDraftIndexForProduct(product);
    if (index < 0 || index >= _draftItems.length) return null;
    return _draftItems[index];
  }

  double _selectedServiceAmountForProduct(SellerProduct product) {
    final item = _simpleDraftItemForProduct(product);
    if (product.resolvedServiceControlType ==
        ProductServiceControlType.weightStepper) {
      return ((item?['selectedWeightGrams'] as num?)?.toDouble()) ??
          ((item?['selected_weight_grams'] as num?)?.toDouble()) ??
          product.resolvedDefaultWeightGrams.toDouble();
    }
    return ((item?['selectedServiceAmount'] as num?)?.toDouble()) ??
        ((item?['selected_service_amount'] as num?)?.toDouble()) ??
        product.resolvedDefaultServiceAmount;
  }

  String? _serviceStepperLabelForProduct(SellerProduct product) {
    final item = _simpleDraftItemForProduct(product);
    final label = item?['amountLabel']?.toString().trim() ?? '';
    if (label.isNotEmpty) return label;
    final normalizedLabel = item?['amount_label']?.toString().trim() ?? '';
    if (normalizedLabel.isNotEmpty) return normalizedLabel;
    return null;
  }

  Map<String, dynamic> _buildDraftItem(
    SellerProduct product, {
    int quantity = 1,
    String notes = '',
    List<String> attributes = const <String>[],
    double? selectedServiceAmount,
    int? selectedWeightGrams,
    String? selectedSizeName,
    GarsonActivePricingMode? activeMode,
    int? selectedGramsForWeight,
  }) {
    final defaults = GarsonProductSelection.resolveDefaults(product);
    final mode = activeMode ?? GarsonActivePricingMode.portion;
    final effectiveServiceAmount =
        ProductPriceCalculator.usesPortionLikeStepper(
          product.resolvedServiceControlType,
        )
        ? ProductPriceCalculator.clampPortionSelection(
            selectedServiceAmount ?? defaults.serviceAmount,
            type: product.resolvedServiceControlType,
            minPortion: product.minPortion,
            maxPortion: product.maxPortion,
            portionStep: product.portionStep,
          )
        : null;
    final effectiveWeight =
        product.resolvedServiceControlType ==
            ProductServiceControlType.weightStepper
        ? ProductPriceCalculator.clampWeightSelection(
            selectedWeightGrams ?? defaults.weightGrams,
            minWeightGrams: product.minWeightGrams,
            weightStepGrams: product.weightStepGrams,
            maxWeightGrams: product.maxWeightGrams,
          )
        : null;
    return GarsonProductSelection.buildOrderItem(
      product: product,
      quantity: quantity,
      activeMode: mode,
      selectedSizeName: mode == GarsonActivePricingMode.size
          ? (selectedSizeName ?? defaults.sizeName)
          : null,
      selectedServiceAmount: effectiveServiceAmount,
      selectedWeightGrams: effectiveWeight,
      selectedGramsForWeight: mode == GarsonActivePricingMode.weight
          ? (selectedGramsForWeight ?? defaults.gramsForWeightPrice)
          : null,
      notes: notes,
      attributes: attributes,
    );
  }

  void _setServiceControlledProductAmount(
    SellerProduct product,
    double? nextAmount,
  ) {
    final index = _simpleDraftIndexForProduct(product);
    setState(() {
      if (index >= 0 && index < _draftItems.length) {
        _draftItems.removeAt(index);
      }
      if (nextAmount == null || nextAmount <= 0) return;
      _draftItems.add(
        _normalizeItem(
          _buildDraftItem(
            product,
            selectedServiceAmount:
                product.resolvedServiceControlType ==
                    ProductServiceControlType.weightStepper
                ? null
                : nextAmount,
            selectedWeightGrams:
                product.resolvedServiceControlType ==
                    ProductServiceControlType.weightStepper
                ? nextAmount.round()
                : null,
          ),
        ),
      );
    });
    _notifyDraftChanged();
  }

  void _quickAddProduct(SellerProduct product) {
    if (_isTemplateProduct(product)) {
      _showTemplateProductActions(product);
      return;
    }
    if (product.usesServiceControlStepper) {
      _setServiceControlledProductAmount(
        product,
        product.resolvedServiceControlType ==
                ProductServiceControlType.weightStepper
            ? product.resolvedDefaultWeightGrams.toDouble()
            : product.resolvedDefaultServiceAmount,
      );
      return;
    }

    // ── Auto-enter edit mode when this product already lives in a sent ──
    // ── order and the draft is still empty.                            ──
    if (!_isEditingOrder && _draftItems.isEmpty) {
      final currentOrders = _displayTableOrders(_hydratedTableOrders);
      for (final o in currentOrders) {
        final normalized = _normalizeTableOrder(o);
        final statusKey = _normalizedOrderStatusKey(
          normalized['status']?.toString(),
        );
        if (statusKey != 'sent' &&
            statusKey != 'preparing' &&
            statusKey != 'ready' &&
            statusKey != 'served') {
          continue;
        }
        final orderItems = _extractItems(normalized['items']);
        final hasProduct = orderItems.any((item) {
          final pid = item['product_id']?.toString() ?? '';
          final pname = item['name']?.toString() ?? '';
          return (pid.isNotEmpty && pid == product.id) || pname == product.name;
        });
        if (hasProduct) {
          _loadOrderIntoDraft(normalized);
          break;
        }
      }
    }

    final index = _portionQuickAddDraftIndex(product);

    // Duplicate detection: product was already in the draft AND was added
    // within the last 3 seconds — intercept and show a confirmation warning
    // instead of silently incrementing (guards against double-tap accidents).
    final productKey = product.id.isNotEmpty ? product.id : product.name;
    final lastAdded = _recentlyAddedProductIds[productKey];
    final isRecentDuplicate =
        index >= 0 &&
        lastAdded != null &&
        DateTime.now().difference(lastAdded).inSeconds < 3;
    if (isRecentDuplicate && mounted) {
      showDuplicateProductWarning(
        context,
        productName: product.name,
        onIncreaseQty: () {
          if (!mounted) return;
          final i = _portionQuickAddDraftIndex(product);
          if (i < 0) return;
          setState(() {
            final qty = (_draftItems[i]['quantity'] as num?)?.toInt() ?? 1;
            _draftItems[i] = _copyDraftItemWithQuantity(
              _draftItems[i],
              qty + 1,
            );
          });
          _recentlyAddedProductIds[productKey] = DateTime.now();
          _notifyDraftChanged();
        },
        onKeepBoth: () {
          if (!mounted) return;
          _upsertGarsonDraftLine(_buildDraftItem(product, quantity: 1));
          _recentlyAddedProductIds[productKey] = DateTime.now();
        },
      );
      return;
    }

    _recentlyAddedProductIds[productKey] = DateTime.now();
    if (index >= 0) {
      setState(() {
        final qty = (_draftItems[index]['quantity'] as num?)?.toInt() ?? 1;
        _draftItems[index] = _copyDraftItemWithQuantity(
          _draftItems[index],
          qty + 1,
        );
      });
      _notifyDraftChanged();
    } else {
      _upsertGarsonDraftLine(_buildDraftItem(product, quantity: 1));
    }
  }

  /// Removes ALL draft entries for [product] and shows a SnackBar with an undo
  /// action that re-adds the removed items. Called from the right-swipe action
  /// in the product list.
  void _quickRemoveProductFromDraft(SellerProduct product) {
    final removed = <Map<String, dynamic>>[];
    setState(() {
      final toRemove = <int>[];
      for (var i = 0; i < _draftItems.length; i++) {
        final id = _draftItems[i]['product_id']?.toString();
        final nameMatch =
            (_draftItems[i]['name']?.toString() ?? '') == product.name;
        if ((id != null && id.isNotEmpty && id == product.id) || nameMatch) {
          toRemove.add(i);
        }
      }
      for (final idx in toRemove.reversed) {
        removed.insert(0, Map<String, dynamic>.from(_draftItems[idx]));
        _draftItems.removeAt(idx);
      }
    });
    if (removed.isEmpty) return;
    _notifyDraftChanged();
    if (!mounted) return;
    final label = removed.length == 1
        ? '"${product.name}" taslaktan çıkarıldı.'
        : '"${product.name}" — ${removed.length} adet taslaktan çıkarıldı.';
    ScaffoldMessenger.of(context).clearSnackBars();
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text(label),
        duration: const Duration(seconds: 4),
        behavior: SnackBarBehavior.floating,
        margin: const EdgeInsets.fromLTRB(12, 0, 12, 8),
        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(10)),
      ),
    );
  }

  void _upsertGarsonDraftLine(Map<String, dynamic> item, {int? replaceIndex}) {
    final normalized = _normalizeItem(item);
    final mergeKey = GarsonProductSelection.orderLineMergeKey(normalized);
    final addQty = (normalized['quantity'] as num?)?.toInt() ?? 1;
    setState(() {
      if (replaceIndex != null &&
          replaceIndex >= 0 &&
          replaceIndex < _draftItems.length) {
        final old = _draftItems[replaceIndex];
        garsonDraftLog(
          'merge_decision',
          extra: {
            'existingKey': GarsonProductSelection.orderLineMergeKey(old),
            'newKey': mergeKey,
            'merged': false,
            'replaced': true,
            'oldQty': (old['quantity'] as num?)?.toInt() ?? 1,
            'newQty': addQty,
          },
        );
        _draftItems[replaceIndex] = normalized;
        return;
      }

      final existingIndex = _draftItems.indexWhere(
        (draft) =>
            !_isMixedServiceItem(draft) &&
            GarsonProductSelection.orderLineMergeKey(draft) == mergeKey,
      );
      if (existingIndex >= 0) {
        final oldQty =
            (_draftItems[existingIndex]['quantity'] as num?)?.toInt() ?? 1;
        final newQty = oldQty + addQty;
        garsonDraftLog(
          'merge_decision',
          extra: {
            'existingKey': mergeKey,
            'newKey': mergeKey,
            'merged': true,
            'oldQty': oldQty,
            'newQty': newQty,
          },
        );
        _draftItems[existingIndex] = _copyDraftItemWithQuantity(
          _draftItems[existingIndex],
          newQty,
        );
      } else {
        garsonDraftLog(
          'merge_decision',
          extra: {
            'existingKey': '',
            'newKey': mergeKey,
            'merged': false,
            'oldQty': 0,
            'newQty': addQty,
          },
        );
        _draftItems.add(normalized);
      }
    });
    _notifyDraftChanged();
  }

  Future<void> _addConfiguredProduct(
    SellerProduct product, {
    int? editDraftIndex,
    Map<String, dynamic>? editingItem,
  }) async {
    if (_isTemplateProduct(product)) {
      await _showTemplateProductActions(product);
      return;
    }
    final lines = await widget.configureProductItem(
      context,
      product,
      editingItem,
      editDraftIndex,
    );
    if (lines == null || lines.isEmpty || !mounted) return;
    if (editDraftIndex != null &&
        editDraftIndex >= 0 &&
        editDraftIndex < _draftItems.length) {
      _replaceGarsonDraftLinesAt(editDraftIndex, lines);
      return;
    }
    garsonDraftLog(
      'AppendLine',
      extra: const <String, Object?>{'reason': 'new_selection'},
    );
    for (final item in lines) {
      _upsertGarsonDraftLine(item);
    }
  }

  void _replaceGarsonDraftLinesAt(
    int replaceIndex,
    List<Map<String, dynamic>> items,
  ) {
    if (items.isEmpty) return;
    final oldQty = replaceIndex >= 0 && replaceIndex < _draftItems.length
        ? ((_draftItems[replaceIndex]['quantity'] as num?)?.toInt() ?? 1)
        : 0;
    setState(() {
      if (replaceIndex >= 0 && replaceIndex < _draftItems.length) {
        _draftItems.removeAt(replaceIndex);
      }
      var insertAt = replaceIndex.clamp(0, _draftItems.length);
      for (final raw in items) {
        final normalized = _normalizeItem(raw);
        _draftItems.insert(insertAt, normalized);
        insertAt++;
      }
    });
    final newQty = items.fold<int>(
      0,
      (sum, line) => sum + ((line['quantity'] as num?)?.toInt() ?? 1),
    );
    garsonDraftLog(
      'ReplaceLine',
      extra: <String, Object?>{
        'oldIndex': replaceIndex,
        'oldQuantity': oldQty,
        'newQuantity': newQty,
        'addedLines': items.length,
      },
    );
    _notifyDraftChanged();
  }

  Map<String, dynamic> _copyDraftItemWithQuantity(
    Map<String, dynamic> item,
    int quantity,
  ) {
    final safeQuantity = quantity <= 0 ? 1 : quantity;
    if (_isMixedServiceItem(item)) {
      return _normalizeItem(
        Map<String, dynamic>.from(item)..['quantity'] = safeQuantity,
      );
    }

    final updated = Map<String, dynamic>.from(item)
      ..['quantity'] = safeQuantity;
    final unitPrice = MixedServiceOrder.parsePrice(
      updated['unitPriceSnapshot'] ?? updated['price'],
    );
    final lineTotal = unitPrice * safeQuantity;
    updated['line_total'] = lineTotal;
    updated['total_price'] = lineTotal;
    return GarsonProductSelection.enrichOrderItem(updated);
  }

  bool get _isEditingOrder => _editingOrderId?.isNotEmpty == true;

  int _draftTotalQuantity() {
    return _draftItems.fold<int>(
      0,
      (sum, item) => sum + ((item['quantity'] as num?)?.toInt() ?? 1),
    );
  }

  String _normalizedOrderStatusKey(String? status) {
    final normalized = (status ?? '')
        .trim()
        .toLowerCase()
        .replaceAll(' ', '_')
        .replaceAll('-', '_');
    switch (normalized) {
      case 'done':
      case 'kitchen':
        return 'sent';
      default:
        return normalized;
    }
  }

  /// Delegates entirely to [GarsonOperationRules] — single source of truth.
  _GarsonOrderEditPolicy _orderEditPolicy(String? status) {
    final rules = GarsonOperationRules.forStatus(status);
    return _GarsonOrderEditPolicy(
      canEdit: rules.canEdit,
      canResend: rules.canResend,
      message: rules.editNote,
      isWarning: rules.showEditWarning,
      isLocked: !rules.canEdit,
    );
  }

  /// Returns `true` when [item] in the draft is newly added (i.e. not present
  /// in [_editingBaseItems]) while the waiter is editing an existing order.
  bool _isDraftItemNew(Map<String, dynamic> item) {
    if (!_isEditingOrder) return false;
    final id = item['product_id']?.toString() ?? '';
    final name = item['name']?.toString() ?? '';
    return !_editingBaseItems.any((base) {
      final baseId = base['product_id']?.toString() ?? '';
      final baseName = base['name']?.toString() ?? '';
      if (id.isNotEmpty && baseId.isNotEmpty) return id == baseId;
      return name == baseName;
    });
  }

  /// Returns a composite string key that uniquely identifies an order item from
  /// a business perspective. Two items with the same key are merge-compatible.
  ///
  /// Mixed-service items should be handled before calling this; the caller is
  /// responsible for keeping them in separate rows.
  String _draftItemCompositeKey(Map<String, dynamic> item) {
    return GarsonProductSelection.orderLineMergeKey(item);
  }

  /// Builds a merged list of display rows for [_draftItems].
  ///
  /// Items that share the same composite key (product identity, gramaj, note,
  /// unit price, attributes) are collapsed into a single
  /// [_MergedDraftDisplayRow].  Mixed-service items are NEVER merged.
  ///
  /// [newQty] is computed as `max(0, totalDraftQty - totalBaseQty)` using the
  /// same composite key.  This correctly covers both the case where
  /// [_quickAddProduct] *incremented* an existing [_draftItems] entry in-place
  /// and the case where it *appended* a brand-new entry.
  List<_MergedDraftDisplayRow> _computeMergedDraftRows() {
    final editing = _isEditingOrder;
    final merged = <_MergedDraftDisplayRow>[];
    final keyToIdx = <String, int>{}; // composite key → index into [merged]

    // Pre-compute base quantities by composite key so we can compute the
    // per-row new-qty delta in a single final pass.
    final baseQtyByKey = <String, int>{};
    if (editing) {
      for (final base in _editingBaseItems) {
        if (_isMixedServiceItem(base)) continue;
        final k = _draftItemCompositeKey(base);
        baseQtyByKey[k] =
            (baseQtyByKey[k] ?? 0) + ((base['quantity'] as num?)?.toInt() ?? 1);
      }
    }

    for (int i = 0; i < _draftItems.length; i++) {
      final item = _draftItems[i];
      final qty = (item['quantity'] as num?)?.toInt() ?? 1;

      // Mixed-service items are never merged — each has a unique composition.
      if (_isMixedServiceItem(item)) {
        merged.add(
          _MergedDraftDisplayRow(
            displayItem: item,
            totalQty: qty,
            newQty: editing && _isDraftItemNew(item) ? qty : 0,
            allIndices: [i],
          ),
        );
        continue;
      }

      final key = _draftItemCompositeKey(item);

      if (keyToIdx.containsKey(key)) {
        final mIdx = keyToIdx[key]!;
        final ex = merged[mIdx];
        merged[mIdx] = _MergedDraftDisplayRow(
          displayItem: ex.displayItem,
          totalQty: ex.totalQty + qty,
          newQty: 0, // recalculated in the final pass below
          allIndices: [...ex.allIndices, i],
        );
      } else {
        keyToIdx[key] = merged.length;
        merged.add(
          _MergedDraftDisplayRow(
            displayItem: item,
            totalQty: qty,
            newQty: 0, // recalculated in the final pass below
            allIndices: [i],
          ),
        );
      }
    }

    // Final pass: compute newQty as the delta between draft total and base total.
    if (!editing) return merged;
    return merged.map((row) {
      final key = _draftItemCompositeKey(row.displayItem);
      final baseQty = baseQtyByKey[key] ?? 0;
      final newQty = (row.totalQty - baseQty).clamp(0, row.totalQty);
      return _MergedDraftDisplayRow(
        displayItem: row.displayItem,
        totalQty: row.totalQty,
        newQty: newQty,
        allIndices: row.allIndices,
      );
    }).toList();
  }

  /// Shows a modal dialog that lets the waiter change the unit price of a
  /// draft item. The updated price is reflected in `line_total` immediately.
  Future<void> _showPriceChangeDialog(int draftIndex) async {
    if (draftIndex < 0 || draftIndex >= _draftItems.length) return;
    final item = _draftItems[draftIndex];
    final currentPrice = MixedServiceOrder.parsePrice(
      item['unitPriceSnapshot'] ?? item['price'],
    );
    final controller = TextEditingController(
      text: currentPrice.toStringAsFixed(2),
    );
    final result = await showDialog<double>(
      context: context,
      barrierDismissible: true,
      builder: (ctx) => AlertDialog(
        title: Text(
          item['name']?.toString() ?? 'Ürün',
          style: const TextStyle(fontSize: 15, fontWeight: FontWeight.w800),
        ),
        content: Column(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            const Text(
              'Fiyatı Değiştir',
              style: TextStyle(fontSize: 13, fontWeight: FontWeight.w700),
            ),
            const SizedBox(height: 4),
            Text(
              'Mevcut fiyat: ${_formatMoney(currentPrice)}',
              style: TextStyle(fontSize: 11, color: Colors.grey.shade600),
            ),
            const SizedBox(height: 12),
            TextField(
              controller: controller,
              keyboardType: const TextInputType.numberWithOptions(
                decimal: true,
              ),
              autofocus: true,
              decoration: const InputDecoration(
                labelText: 'Yeni Fiyat (₺)',
                border: OutlineInputBorder(),
                contentPadding: EdgeInsets.symmetric(
                  horizontal: 12,
                  vertical: 10,
                ),
              ),
              onSubmitted: (_) {
                final parsed = double.tryParse(
                  controller.text.replaceAll(',', '.'),
                );
                Navigator.of(ctx).pop(parsed);
              },
            ),
            const SizedBox(height: 8),
            Text(
              'Bu değişiklik sipariş özetine ve adisyona yansır.',
              style: TextStyle(fontSize: 10, color: Colors.grey.shade500),
            ),
          ],
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.of(ctx).pop(null),
            child: const Text('İptal'),
          ),
          FilledButton(
            onPressed: () {
              final parsed = double.tryParse(
                controller.text.replaceAll(',', '.'),
              );
              Navigator.of(ctx).pop(parsed);
            },
            child: const Text('Uygula'),
          ),
        ],
      ),
    );
    controller.dispose();
    if (result == null || result < 0 || !mounted) return;
    if (draftIndex >= _draftItems.length) return;
    final updatedItem = Map<String, dynamic>.from(_draftItems[draftIndex]);
    final qty = (updatedItem['quantity'] as num?)?.toInt() ?? 1;
    updatedItem['price'] = result;
    updatedItem['unitPriceSnapshot'] = result;
    updatedItem['line_total'] = result * qty;
    updatedItem['total_price'] = result * qty;
    // Flag as manually overridden so it can be flagged in summaries
    updatedItem['price_override'] = true;
    setState(() {
      if (draftIndex < _draftItems.length) {
        _draftItems[draftIndex] = _normalizeItem(updatedItem);
      }
    });
    _notifyDraftChanged();
  }

  String _draftItemAmountLabel(Map<String, dynamic> item) {
    final amountLabel = item['amountLabel']?.toString().trim() ?? '';
    if (amountLabel.isNotEmpty) return amountLabel;
    final normalizedLabel = item['amount_label']?.toString().trim() ?? '';
    if (normalizedLabel.isNotEmpty) return normalizedLabel;
    return item['gramaj']?.toString().trim() ?? '';
  }

  String _draftItemPreviewLabel(Map<String, dynamic> item) {
    return GarsonProductSelection.orderItemDisplayLabel(item);
  }

  String _updatedEntryReason(_GarsonOrderChangeEntry entry) {
    final before = entry.previousItem ?? const <String, dynamic>{};
    final after = entry.item;
    final beforeNote = before['notes']?.toString().trim() ?? '';
    final afterNote = after['notes']?.toString().trim() ?? '';
    if (beforeNote != afterNote) {
      return 'Not güncellendi';
    }
    final beforeAmount = _draftItemAmountLabel(before);
    final afterAmount = _draftItemAmountLabel(after);
    if (beforeAmount != afterAmount) {
      if (beforeAmount.isNotEmpty && afterAmount.isNotEmpty) {
        return '$beforeAmount -> $afterAmount';
      }
      return 'Porsiyon güncellendi';
    }
    final beforeAttributes = List<String>.from(
      (before['attributes'] as List?)?.map((item) => item.toString()) ??
          const <String>[],
      growable: false,
    )..sort();
    final afterAttributes = List<String>.from(
      (after['attributes'] as List?)?.map((item) => item.toString()) ??
          const <String>[],
      growable: false,
    )..sort();
    if (!listEquals(beforeAttributes, afterAttributes)) {
      return 'Seçim güncellendi';
    }
    if (MixedServiceOrder.childSummary(before) !=
        MixedServiceOrder.childSummary(after)) {
      return 'İçerik güncellendi';
    }
    return 'Revize edildi';
  }

  String _orderChangeEntryLabel(_GarsonOrderChangeEntry entry) {
    final base = _draftItemPreviewLabel(entry.item);
    switch (entry.type) {
      case _GarsonOrderChangeType.added:
        return '$base eklendi';
      case _GarsonOrderChangeType.removed:
        return '$base çıkarıldı';
      case _GarsonOrderChangeType.updated:
        return '$base • ${_updatedEntryReason(entry)}';
    }
  }

  dynamic _canonicalizeJsonValue(dynamic value) {
    if (value is Map) {
      final entries = value.entries.toList(growable: false)
        ..sort((a, b) => a.key.toString().compareTo(b.key.toString()));
      return <String, dynamic>{
        for (final entry in entries)
          entry.key.toString(): _canonicalizeJsonValue(entry.value),
      };
    }
    if (value is List) {
      return value.map(_canonicalizeJsonValue).toList(growable: false);
    }
    if (value is num) return value.toDouble();
    return value;
  }

  String _orderItemProductKey(Map<String, dynamic> item) {
    final normalized = _normalizeItem(item);
    return jsonEncode(<String, dynamic>{
      'item_type': normalized['item_type']?.toString() ?? 'product',
      'product_id': normalized['product_id']?.toString() ?? '',
      'name': normalized['name']?.toString() ?? '-',
    });
  }

  String _orderItemContentSignature(Map<String, dynamic> item) {
    final normalized = _normalizeItem(item);
    final attributes = List<String>.from(
      (normalized['attributes'] as List?)?.map((item) => item.toString()) ??
          const <String>[],
      growable: false,
    )..sort();
    final childItems =
        MixedServiceOrder.normalizeChildItems(normalized['child_items'])
            .map((child) {
              return <String, dynamic>{
                'product_id': child['product_id']?.toString() ?? '',
                'product_name': child['product_name']?.toString() ?? '-',
                'quantity': (child['quantity'] as num?)?.toInt() ?? 1,
                'amount_label': child['amount_label']?.toString() ?? '',
                'note': child['note']?.toString() ?? '',
                'service_round': MixedServiceOrder.normalizeServiceRound(
                  child['service_round'],
                ),
              };
            })
            .toList(growable: false)
          ..sort(
            (left, right) => jsonEncode(
              _canonicalizeJsonValue(left),
            ).compareTo(jsonEncode(_canonicalizeJsonValue(right))),
          );

    final resolvedUnitPrice = _isMixedServiceItem(normalized)
        ? MixedServiceOrder.resolveMainItemTotal(normalized)
        : MixedServiceOrder.parsePrice(
            normalized['unitPriceSnapshot'] ??
                normalized['unit_price_snapshot'] ??
                normalized['price'],
          );

    return jsonEncode(
      _canonicalizeJsonValue(<String, dynamic>{
        'product_id': normalized['product_id']?.toString() ?? '',
        'name': normalized['name']?.toString() ?? '-',
        'item_type': normalized['item_type']?.toString() ?? 'product',
        'source_product_type':
            normalized['source_product_type']?.toString() ?? '',
        'amount_label': _draftItemAmountLabel(normalized),
        'notes': normalized['notes']?.toString().trim() ?? '',
        'service_control_type':
            normalized['service_control_type']?.toString() ?? '',
        'selected_service_amount':
            (normalized['selected_service_amount'] as num?)?.toDouble(),
        'selected_weight_grams': (normalized['selected_weight_grams'] as num?)
            ?.toInt(),
        'pricing_mode': normalized['pricing_mode']?.toString() ?? '',
        'manual_price': MixedServiceOrder.parsePrice(
          normalized['manual_price'],
        ),
        'fixed_price': MixedServiceOrder.parsePrice(normalized['fixed_price']),
        'resolved_unit_price': resolvedUnitPrice,
        'attributes': attributes,
        'child_items': childItems,
      }),
    );
  }

  Map<String, _GarsonAggregatedOrderItem> _aggregateOrderItems(
    Iterable<Map<String, dynamic>> items,
  ) {
    final aggregated = <String, _GarsonAggregatedOrderItem>{};
    for (final rawItem in items) {
      final normalized = _normalizeItem(rawItem);
      final signature = _orderItemContentSignature(normalized);
      final quantity = (normalized['quantity'] as num?)?.toInt() ?? 1;
      final current = aggregated[signature];
      final baseItem = _copyDraftItemWithQuantity(normalized, 1);
      aggregated[signature] = _GarsonAggregatedOrderItem(
        item: current?.item ?? baseItem,
        quantity: (current?.quantity ?? 0) + quantity,
      );
    }
    return aggregated;
  }

  _GarsonOrderChangeSummary _buildOrderChangeSummary({
    required List<Map<String, dynamic>> originalItems,
    required List<Map<String, dynamic>> nextItems,
  }) {
    final originalAgg = _aggregateOrderItems(originalItems);
    final nextAgg = _aggregateOrderItems(nextItems);
    final kitchenAddedItems = <Map<String, dynamic>>[];
    final kitchenRemovedItems = <Map<String, dynamic>>[];
    final allKeys = <String>{...originalAgg.keys, ...nextAgg.keys};

    for (final key in allKeys) {
      final original = originalAgg[key];
      final next = nextAgg[key];
      final originalQty = original?.quantity ?? 0;
      final nextQty = next?.quantity ?? 0;
      if (nextQty > originalQty && next != null) {
        kitchenAddedItems.add(
          _copyDraftItemWithQuantity(next.item, nextQty - originalQty),
        );
      }
      if (originalQty > nextQty && original != null) {
        kitchenRemovedItems.add(
          _copyDraftItemWithQuantity(original.item, originalQty - nextQty),
        );
      }
    }

    final addedDisplayPool = kitchenAddedItems
        .map((item) => Map<String, dynamic>.from(item))
        .toList(growable: false);
    final removedDisplayPool = kitchenRemovedItems
        .map((item) => Map<String, dynamic>.from(item))
        .toList(growable: false);
    final addedByProduct = <String, List<Map<String, dynamic>>>{};
    final removedByProduct = <String, List<Map<String, dynamic>>>{};

    for (final item in addedDisplayPool) {
      addedByProduct
          .putIfAbsent(
            _orderItemProductKey(item),
            () => <Map<String, dynamic>>[],
          )
          .add(item);
    }
    for (final item in removedDisplayPool) {
      removedByProduct
          .putIfAbsent(
            _orderItemProductKey(item),
            () => <Map<String, dynamic>>[],
          )
          .add(item);
    }

    final updatedEntries = <_GarsonOrderUpdatedEntry>[];
    final sharedKeys = <String>{
      ...addedByProduct.keys,
      ...removedByProduct.keys,
    };
    for (final key in sharedKeys) {
      final additions = addedByProduct[key];
      final removals = removedByProduct[key];
      if (additions == null || removals == null) continue;
      while (additions.isNotEmpty && removals.isNotEmpty) {
        final addedItem = additions.first;
        final removedItem = removals.first;

        // IMPORTANT: Only classify a paired add+remove as "updated" when the
        // underlying item content actually changed (note/attrs/amount/price/...).
        // If content is the same, the user most likely just changed quantity
        // and we must keep it as "added" / "removed" so the kitchen sees
        // clear cancellation tickets on decreases (and clear additions on increases).
        final addedSig = _orderItemContentSignature(
          _normalizeItem(Map<String, dynamic>.from(addedItem)),
        );
        final removedSig = _orderItemContentSignature(
          _normalizeItem(Map<String, dynamic>.from(removedItem)),
        );
        if (addedSig == removedSig) {
          break;
        }

        final addedQty = (addedItem['quantity'] as num?)?.toInt() ?? 1;
        final removedQty = (removedItem['quantity'] as num?)?.toInt() ?? 1;
        final matchedQty = math.min(addedQty, removedQty);
        updatedEntries.add(
          _GarsonOrderUpdatedEntry(
            before: _copyDraftItemWithQuantity(removedItem, matchedQty),
            after: _copyDraftItemWithQuantity(addedItem, matchedQty),
          ),
        );
        if (addedQty <= matchedQty) {
          additions.removeAt(0);
        } else {
          additions[0] = _copyDraftItemWithQuantity(
            addedItem,
            addedQty - matchedQty,
          );
        }
        if (removedQty <= matchedQty) {
          removals.removeAt(0);
        } else {
          removals[0] = _copyDraftItemWithQuantity(
            removedItem,
            removedQty - matchedQty,
          );
        }
      }
    }

    final remainingAddedItems = addedByProduct.values
        .expand((items) => items)
        .toList(growable: false);
    final remainingRemovedItems = removedByProduct.values
        .expand((items) => items)
        .toList(growable: false);
    final displayEntries = <_GarsonOrderChangeEntry>[
      ...updatedEntries.map(
        (entry) => _GarsonOrderChangeEntry(
          type: _GarsonOrderChangeType.updated,
          item: entry.after,
          previousItem: entry.before,
        ),
      ),
      ...remainingAddedItems.map(
        (item) => _GarsonOrderChangeEntry(
          type: _GarsonOrderChangeType.added,
          item: item,
        ),
      ),
      ...remainingRemovedItems.map(
        (item) => _GarsonOrderChangeEntry(
          type: _GarsonOrderChangeType.removed,
          item: item,
        ),
      ),
    ];

    final addedQuantity = remainingAddedItems.fold<int>(
      0,
      (sum, item) => sum + ((item['quantity'] as num?)?.toInt() ?? 1),
    );
    final removedQuantity = remainingRemovedItems.fold<int>(
      0,
      (sum, item) => sum + ((item['quantity'] as num?)?.toInt() ?? 1),
    );
    final updatedQuantity = updatedEntries.fold<int>(
      0,
      (sum, entry) => sum + ((entry.after['quantity'] as num?)?.toInt() ?? 1),
    );

    return _GarsonOrderChangeSummary(
      kitchenAddedItems: kitchenAddedItems,
      kitchenRemovedItems: kitchenRemovedItems,
      displayEntries: displayEntries,
      addedQuantity: addedQuantity,
      removedQuantity: removedQuantity,
      updatedQuantity: updatedQuantity,
    );
  }

  _GarsonOrderChangeSummary _currentEditingChangeSummary() {
    if (!_isEditingOrder) return const _GarsonOrderChangeSummary();
    return _buildOrderChangeSummary(
      originalItems: _editingBaseItems,
      nextItems: _draftItems,
    );
  }

  bool _customerKitchenPendingForUi(Map<String, dynamic> order) {
    final id = order['id']?.toString() ?? '';
    if (id.isNotEmpty && _customerKitchenDispatchDoneIds.contains(id)) {
      return false;
    }
    return _garsonTableOrderNeedsCustomerKitchenApproval(order);
  }

  /// Müşteri siparişi `new`/`waiting` ve garson henüz mutfağa iletmediyse; düzenleme
  /// ekranında değişiklik olmasa da [Siparişi Gönder] ile iletilebilir.
  bool _editingOrderAwaitingCustomerKitchenSend() {
    if (!_isEditingOrder) return false;
    final snap = _editingOrderSnapshot;
    if (snap == null || snap.isEmpty) return false;
    return _customerKitchenPendingForUi(snap);
  }

  bool _canSubmitDraft() {
    if (_draftItems.isEmpty || _isSubmitting) return false;
    if (!_isEditingOrder) return true;
    if (_currentEditingChangeSummary().hasChanges) return true;
    if (!_editingOrderAwaitingCustomerKitchenSend()) return false;
    return widget.onConfirmCustomerKitchenPrint != null;
  }

  Map<String, dynamic> _orderChangeSummaryPayload(
    _GarsonOrderChangeSummary summary,
  ) {
    if (!summary.hasChanges) return const <String, dynamic>{};
    final entries = summary.previewEntries(limit: 6);
    return <String, dynamic>{
      'added_quantity': summary.addedQuantity,
      'removed_quantity': summary.removedQuantity,
      'updated_quantity': summary.updatedQuantity,
      'changes': entries
          .map(
            (entry) => <String, dynamic>{
              'type': entry.type.name,
              'label': _orderChangeEntryLabel(entry),
            },
          )
          .toList(growable: false),
    };
  }

  bool _shouldDispatchFullKitchenTicket(String? status) =>
      KitchenPrintPolicy.shouldDispatchFullTicket(status);

  Future<_KitchenDispatchFeedback> _dispatchUpdatedOrderPrintJobs({
    required String? previousStatus,
    required _GarsonOrderChangeSummary changeSummary,
    required List<Map<String, dynamic>> nextItems,
  }) async {
    if (_shouldDispatchFullKitchenTicket(previousStatus)) {
      return _dispatchKitchenPrintJobs(nextItems);
    }

    final feedbacks = <_KitchenDispatchFeedback>[];
    final removalFeedback = await _dispatchKitchenRemovals(
      changeSummary.kitchenRemovedItems,
      note: KitchenPrintPolicy.removeItemsNote,
    );
    feedbacks.add(removalFeedback);

    final additionFeedback = await _dispatchKitchenAdditions(
      changeSummary.kitchenAddedItems,
      note: KitchenPrintPolicy.addItemsNote,
    );
    feedbacks.add(additionFeedback);

    if (changeSummary.kitchenRemovedItems.isEmpty &&
        changeSummary.kitchenAddedItems.isEmpty) {
      final reprintFeedback = await _dispatchKitchenReprintJobs(
        nextItems,
        note: KitchenPrintPolicy.reprintNote,
      );
      feedbacks.add(reprintFeedback);
    }

    return _mergeDispatchFeedbacks(feedbacks);
  }

  void _changeDraftQty(int index, int delta) {
    if (index < 0 || index >= _draftItems.length) return;
    final matchedProduct = _sellerProductById(
      _draftItems[index]['product_id']?.toString() ?? '',
    );
    if (matchedProduct != null && matchedProduct.usesServiceControlStepper) {
      final current = _draftItems[index];
      if (matchedProduct.resolvedServiceControlType ==
          ProductServiceControlType.weightStepper) {
        final currentGrams =
            (current['selectedWeightGrams'] as num?)?.toDouble() ??
            (current['selected_weight_grams'] as num?)?.toDouble() ??
            matchedProduct.resolvedDefaultWeightGrams.toDouble();
        final min = matchedProduct.resolvedMinWeightGrams.toDouble();
        if (delta < 0 && currentGrams <= min) {
          setState(() {
            _draftItems.removeAt(index);
          });
          _notifyDraftChanged();
          return;
        }
        _setServiceControlledProductAmount(
          matchedProduct,
          ProductPriceCalculator.clampWeightSelection(
            currentGrams.round() +
                (delta * matchedProduct.resolvedWeightStepGrams),
            minWeightGrams: matchedProduct.minWeightGrams,
            weightStepGrams: matchedProduct.weightStepGrams,
            maxWeightGrams: matchedProduct.maxWeightGrams,
          ).toDouble(),
        );
        return;
      }

      final currentAmount =
          (current['selectedServiceAmount'] as num?)?.toDouble() ??
          (current['selected_service_amount'] as num?)?.toDouble() ??
          matchedProduct.resolvedDefaultServiceAmount;
      final min = matchedProduct.resolvedMinPortionAmount;
      if (delta < 0 && currentAmount <= min + 0.0001) {
        setState(() {
          _draftItems.removeAt(index);
        });
        _notifyDraftChanged();
        return;
      }
      _setServiceControlledProductAmount(
        matchedProduct,
        ProductPriceCalculator.clampPortionSelection(
          currentAmount + (delta * matchedProduct.resolvedPortionStepAmount),
          type: matchedProduct.resolvedServiceControlType,
          minPortion: matchedProduct.minPortion,
          maxPortion: matchedProduct.maxPortion,
          portionStep: matchedProduct.portionStep,
        ),
      );
      return;
    }
    setState(() {
      final current = (_draftItems[index]['quantity'] as num?)?.toInt() ?? 1;
      final next = current + delta;
      if (next <= 0) {
        _draftItems.removeAt(index);
      } else {
        _draftItems[index] = _copyDraftItemWithQuantity(
          _draftItems[index],
          next,
        );
      }
    });
    _notifyDraftChanged();
  }

  Future<void> _editDraftItem(int index) async {
    if (index < 0 || index >= _draftItems.length) return;
    final original = Map<String, dynamic>.from(_draftItems[index]);

    // For mixed-service items (menus / services), go directly to the
    // specialised editor — "Fiyatı Değiştir" is not applicable there.
    if (_isMixedServiceItem(original)) {
      final updated = await showMixedServiceDialog(
        context: context,
        products: _activeProducts(),
        mode: MixedServiceDialogMode.edit,
        initialItem: original,
      );
      if (updated == null || !mounted) return;
      final preservedQuantity = (original['quantity'] as num?)?.toInt() ?? 1;
      setState(() {
        if (index < _draftItems.length) {
          _draftItems[index] = _normalizeItem(
            Map<String, dynamic>.from(updated)
              ..['quantity'] = preservedQuantity,
          );
        }
      });
      _notifyDraftChanged();
      return;
    }

    // For regular items show an action sheet with edit options.
    final choice = await showModalBottomSheet<_DraftItemEditChoice>(
      context: context,
      backgroundColor: Colors.transparent,
      builder: (_) => SafeArea(
        top: false,
        child: Container(
          padding: const EdgeInsets.fromLTRB(16, 20, 16, 16),
          decoration: const BoxDecoration(
            color: Colors.white,
            borderRadius: BorderRadius.vertical(top: Radius.circular(20)),
          ),
          child: Column(
            mainAxisSize: MainAxisSize.min,
            crossAxisAlignment: CrossAxisAlignment.stretch,
            children: [
              Text(
                original['name']?.toString() ?? 'Ürün',
                style: const TextStyle(
                  fontSize: 15,
                  fontWeight: FontWeight.w800,
                ),
              ),
              const SizedBox(height: 14),
              OutlinedButton.icon(
                onPressed: () =>
                    Navigator.of(context).pop(_DraftItemEditChoice.settings),
                icon: const Icon(Icons.tune_rounded, size: 18),
                label: const Text('Ayarları Düzenle'),
                style: OutlinedButton.styleFrom(
                  minimumSize: const Size(0, 44),
                  alignment: Alignment.centerLeft,
                ),
              ),
              const SizedBox(height: 8),
              OutlinedButton.icon(
                onPressed: () =>
                    Navigator.of(context).pop(_DraftItemEditChoice.price),
                icon: const Icon(Icons.price_change_outlined, size: 18),
                label: const Text('Fiyatı Değiştir'),
                style: OutlinedButton.styleFrom(
                  minimumSize: const Size(0, 44),
                  alignment: Alignment.centerLeft,
                ),
              ),
              const SizedBox(height: 6),
            ],
          ),
        ),
      ),
    );

    if (choice == null || !mounted) return;

    if (choice == _DraftItemEditChoice.price) {
      await _showPriceChangeDialog(index);
      return;
    }

    final productId = original['product_id']?.toString() ?? '';
    SellerProduct? matchedProduct = productId.isNotEmpty
        ? _sellerProductById(productId)
        : null;
    matchedProduct ??= _allGarsonProducts().cast<SellerProduct?>().firstWhere(
      (p) =>
          (p?.name.trim().toLowerCase() ?? '') ==
          (original['name']?.toString().trim().toLowerCase() ?? ''),
      orElse: () => null,
    );

    if (matchedProduct != null) {
      final updatedLines = await widget.configureProductItem(
        context,
        matchedProduct,
        original,
        index,
      );
      if (updatedLines == null || updatedLines.isEmpty || !mounted) return;
      _replaceGarsonDraftLinesAt(index, updatedLines);
      return;
    }

    await widget.editItemSettings(context, original, (updated) {
      if (!mounted) return;
      _upsertGarsonDraftLine(updated, replaceIndex: index);
    });
  }

  String _timeAgo(DateTime createdAt) {
    final diff = DateTime.now().difference(createdAt);
    if (diff.inMinutes < 1) return 'Az önce';
    if (diff.inMinutes < 60) return '${diff.inMinutes} dk önce';
    if (diff.inHours < 24) return '${diff.inHours} sa önce';
    return '${diff.inDays} gün önce';
  }

  bool _isWaitingStatus(String status) {
    final normalized = _normalizedOrderStatusKey(status);
    return normalized == 'draft' ||
        normalized == 'new' ||
        normalized == 'waiting';
  }

  void _clearDraftComposer() {
    setState(() {
      _draftItems.clear();
      _editingOrderId = null;
      _editingOrderSnapshot = null;
      _editingBaseItems = const <Map<String, dynamic>>[];
    });
    _notifyDraftChanged();
  }

  void _loadOrderIntoDraft(Map<String, dynamic> order) {
    final normalizedOrder = _normalizeTableOrder(order);
    final orderId = normalizedOrder['id']?.toString();
    if (orderId == null || orderId.isEmpty) return;
    final originalItems = _extractItems(
      normalizedOrder['items'],
    ).map((item) => Map<String, dynamic>.from(item)).toList(growable: false);
    setState(() {
      _editingOrderId = orderId;
      _editingOrderSnapshot = Map<String, dynamic>.from(normalizedOrder);
      _editingBaseItems = originalItems
          .map((item) => Map<String, dynamic>.from(item))
          .toList(growable: false);
      _draftItems
        ..clear()
        ..addAll(
          originalItems
              .map((item) => Map<String, dynamic>.from(item))
              .toList(growable: false),
        );
      _clearSubmitFeedback();
      _bottomIndex = 2;
    });
    _notifyDraftChanged();
  }

  Future<bool> _confirmReplaceDraftForEditing() async {
    return await showDialog<bool>(
          context: context,
          builder: (dialogContext) {
            return AlertDialog(
              title: const Text('Mevcut taslak değiştirilsin mi?'),
              content: const Text(
                'Şu an açık bir taslak var. Bu siparişi düzenlersen mevcut taslak bununla değişecek.',
              ),
              actions: [
                TextButton(
                  onPressed: () => Navigator.of(dialogContext).pop(false),
                  child: const Text('Vazgeç'),
                ),
                FilledButton(
                  onPressed: () => Navigator.of(dialogContext).pop(true),
                  child: const Text('Taslağı Değiştir'),
                ),
              ],
            );
          },
        ) ??
        false;
  }

  Future<void> _beginOrderEditing(Map<String, dynamic> order) async {
    final normalizedOrder = _normalizeTableOrder(order);
    final orderId = normalizedOrder['id']?.toString().trim() ?? '';
    final status = normalizedOrder['status']?.toString();
    final policy = _orderEditPolicy(status);

    if (!policy.canEdit) {
      if (!mounted) return;
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text(policy.message)));
      return;
    }

    if (_editingOrderId == orderId) {
      setState(() => _bottomIndex = 2);
      return;
    }

    if (_draftItems.isNotEmpty) {
      final confirmed = await _confirmReplaceDraftForEditing();
      if (!confirmed || !mounted) return;
    }

    _loadOrderIntoDraft(normalizedOrder);
  }

  String _nextStatusAfterDraftSubmit(String? previousStatus) {
    switch (_normalizedOrderStatusKey(previousStatus)) {
      case 'draft':
      case 'new':
      case 'waiting':
        return 'sent';
      case 'preparing':
        return 'preparing';
      case 'ready':
        return 'ready';
      case 'served':
        return 'served';
      case 'closed':
        return 'closed';
      case 'sent':
      default:
        return 'sent';
    }
  }

  Future<void> _resendOrderToKitchen(Map<String, dynamic> order) async {
    if (_isSubmitting) return;
    final policy = _orderEditPolicy(order['status']?.toString());
    if (!policy.canResend) {
      if (!mounted) return;
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text(policy.message)));
      return;
    }
    final items = _extractItems(order['items']);
    if (items.isEmpty) {
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('Tekrar iletmek için sipariş kalemi bulunamadı.'),
        ),
      );
      return;
    }

    setState(() => _isSubmitting = true);
    try {
      final dispatchFeedback = await _dispatchKitchenReprintJobs(
        items,
        note: 'Sipariş tekrar iletimi',
      );
      final snackMessage = dispatchFeedback.hasError
          ? dispatchFeedback.error!
          : dispatchFeedback.progressed
          ? 'Mutfak fişi tekrar gönderildi.'
          : dispatchFeedback.queuedOnly
          ? 'Mutfak fişi yazdırma kuyruğuna alındı.'
          : 'Mutfak fişi tekrar iletimi bekleniyor.';
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(snackMessage),
          backgroundColor: dispatchFeedback.hasError
              ? Colors.orange.shade700
              : null,
        ),
      );
    } finally {
      if (mounted) setState(() => _isSubmitting = false);
    }
  }

  /// Enters edit mode for [order] (if not already editing it) then calls
  /// [act] with the [_draftItems] index that corresponds to [sentItemIndex].
  ///
  /// Fast-path (no conflicting draft): [_loadOrderIntoDraft] runs
  /// synchronously and [act] is invoked immediately after.
  /// Slow-path (conflicting draft exists): shows the confirmation dialog
  /// first, then invokes [act] once editing is set up.
  void _enterEditAndAct(
    Map<String, dynamic> order,
    void Function(int draftItemIndex) act,
    int sentItemIndex,
  ) {
    final normalized = _normalizeTableOrder(order);
    final orderId = normalized['id']?.toString() ?? '';
    if (orderId.isEmpty) return;

    if (_editingOrderId == orderId) {
      // Already editing this order — apply directly.
      if (sentItemIndex >= 0 && sentItemIndex < _draftItems.length) {
        act(sentItemIndex);
      }
      return;
    }

    // Fast path: no conflicting draft.
    if (_draftItems.isEmpty) {
      _loadOrderIntoDraft(normalized);
      if (mounted && sentItemIndex >= 0 && sentItemIndex < _draftItems.length) {
        act(sentItemIndex);
      }
      return;
    }

    // Slow path: existing draft — ask for confirmation first.
    _beginOrderEditing(normalized).then((_) {
      if (!mounted) return;
      if (_editingOrderId == orderId &&
          sentItemIndex >= 0 &&
          sentItemIndex < _draftItems.length) {
        act(sentItemIndex);
      }
    });
  }

  /// Canlı listede gecikme olsa bile düzenlenen siparişin `placement_source` vb.
  /// alanlarının mutfak onay RPC'sine girmesi için birleştirir.
  List<Map<String, dynamic>> _tableOrdersForCustomerKitchenConfirm(
    List<Map<String, dynamic>> tableOrders,
  ) {
    final snap = _editingOrderSnapshot;
    if (snap == null || snap.isEmpty) {
      return tableOrders;
    }
    final sid = snap['id']?.toString();
    if (sid == null || sid.isEmpty) {
      return tableOrders;
    }
    final out = tableOrders.map((o) => Map<String, dynamic>.from(o)).toList();
    final ix = out.indexWhere((o) => o['id']?.toString() == sid);
    if (ix >= 0) {
      out[ix] = Map<String, dynamic>.from(snap);
    } else {
      out.add(Map<String, dynamic>.from(snap));
    }
    return out;
  }

  Future<void> _submitDraft(
    List<Map<String, dynamic>> existingTableOrders,
  ) async {
    if (_isSubmitting) return;
    if (!_canSubmitDraft()) return;
    setState(() => _isSubmitting = true);
    final pipelineWatch = Stopwatch()..start();
    final isUpdate =
        _editingOrderId != null && _editingOrderId!.trim().isNotEmpty;
    debugPrint(
      '[GarsonPerf] garson_update_tap_at=${DateTime.now().toIso8601String()} '
      'table=${widget.tableNumber} isUpdate=$isUpdate',
    );
    try {
      _tableOrdersFallbackFuture = null;
      final items = _draftItems
          .map((item) => _normalizeItem(Map<String, dynamic>.from(item)))
          .toList(growable: false);
      final editingId = _editingOrderId;
      final originalOrder = editingId == null || editingId.isEmpty
          ? null
          : (existingTableOrders.cast<Map<String, dynamic>?>().firstWhere(
                  (order) => order?['id']?.toString() == editingId,
                  orElse: () => null,
                ) ??
                _editingOrderSnapshot);
      final changeSummary = editingId == null || editingId.isEmpty
          ? const _GarsonOrderChangeSummary()
          : _buildOrderChangeSummary(
              originalItems: _editingBaseItems,
              nextItems: items,
            );
      final customerKitchenSendOnly =
          editingId != null &&
          editingId.isNotEmpty &&
          !changeSummary.hasChanges &&
          originalOrder != null &&
          _customerKitchenPendingForUi(originalOrder);

      if (customerKitchenSendOnly) {
        final cb = widget.onConfirmCustomerKitchenPrint;
        if (cb == null) return;
        final submittedItems = _draftItems
            .map((item) => Map<String, dynamic>.from(item))
            .toList(growable: false);
        final kitchenOk = await cb(
          tableNumber: widget.tableNumber,
          tableOrders: _tableOrdersForCustomerKitchenConfirm(
            existingTableOrders,
          ),
        );
        if (!mounted) return;
        if (!kitchenOk) return;
        final snap = _editingOrderSnapshot;
        final pseudoSubmitted =
            snap == null
                  ? <String, dynamic>{'id': editingId, 'status': 'sent'}
                  : Map<String, dynamic>.from(snap)
              ..['status'] = 'sent';
        setState(() {
          _customerKitchenDispatchDoneIds.add(editingId);
          _draftItems.clear();
          _editingOrderId = null;
          _editingOrderSnapshot = null;
          _editingBaseItems = const <Map<String, dynamic>>[];
          _bottomIndex = 2;
          _lastSubmitActionLabel = 'Mutfak gönderildi.';
        });
        _clearSubmitFeedback();
        _notifyDraftChanged();
        widget.onOrderSubmitted?.call(
          widget.tableNumber,
          submittedItems,
          pseudoSubmitted,
        );
        if (!widget.debugDisableLiveSync && !widget.debugUseLocalSubmit) {
          unawaited(_refreshTableOrdersAfterSubmit());
        }
        return;
      }

      if (editingId != null &&
          editingId.isNotEmpty &&
          !changeSummary.hasChanges) {
        return;
      }
      final regularCount = items
          .where((item) => !_isMixedServiceItem(item))
          .length;
      final menuCount = items
          .where(
            (item) =>
                _isMixedServiceItem(item) &&
                item['source_product_type']?.toString() ==
                    MixedServiceOrder.menuTemplateProductType,
          )
          .length;
      final serviceCount = items
          .where(
            (item) =>
                _isMixedServiceItem(item) &&
                item['source_product_type']?.toString() ==
                    MixedServiceOrder.serviceTemplateProductType,
          )
          .length;
      // TODO(debug): remove before production
      for (final item in items) {
        final rawPrice = item['price'];
        final rawLineTotal = item['line_total'];
        final rawQty = item['quantity'];
        debugPrint(
          '[ORDER_PAYLOAD_DEBUG] '
          'name=${item['name']} '
          'price=$rawPrice (${rawPrice?.runtimeType}) '
          'line_total=$rawLineTotal (${rawLineTotal?.runtimeType}) '
          'quantity=$rawQty (${rawQty?.runtimeType}) '
          'item_type=${item['item_type']}',
        );
        if (rawPrice is String) {
          debugPrint(
            '[ORDER_PARSE_WARNING] '
            'field=price '
            'raw=$rawPrice '
            'reason=string_price_in_payload',
          );
        }
        final resolvedLineTotal = MixedServiceOrder.parsePrice(
          rawLineTotal ?? rawPrice,
        );
        debugPrint(
          '[ORDER_PAYLOAD_ROW] '
          'item=${item['name']} '
          'resolved_line_total=$resolvedLineTotal',
        );
      }
      final orderTotal = items.fold<double>(
        0,
        (sum, item) =>
            sum +
            MixedServiceOrder.parsePrice(item['line_total'] ?? item['price']),
      );
      // TODO(debug): remove before production
      debugPrint(
        '[ORDER_PAYLOAD] '
        'regular_count=$regularCount '
        'menu_count=$menuCount '
        'service_count=$serviceCount '
        'total=$orderTotal',
      );
      final originalStatus =
          originalOrder?['status']?.toString() ??
          _editingOrderSnapshot?['status']?.toString() ??
          'sent';
      final nextStatus = editingId != null && editingId.isNotEmpty
          ? _nextStatusAfterDraftSubmit(originalStatus)
          : 'sent';
      final nextRevision = editingId != null && editingId.isNotEmpty
          ? _orderRevision(
                  originalOrder ??
                      _editingOrderSnapshot ??
                      const <String, dynamic>{},
                ) +
                1
          : 1;
      final updatedAt = DateTime.now().toIso8601String();
      final editPolicyMessage = editingId != null && editingId.isNotEmpty
          ? _orderEditPolicy(originalStatus).message
          : null;
      final lastEditSummary = editingId != null && editingId.isNotEmpty
          ? _orderChangeSummaryPayload(changeSummary)
          : const <String, dynamic>{};
      late final Map<String, dynamic> submittedOrder;
      _KitchenDispatchFeedback? parallelDispatchFeedback;
      String? kitchenPerfTapAt;
      int? kitchenPerfDbSaveMs;
      if (widget.debugUseLocalSubmit) {
        submittedOrder = <String, dynamic>{
          'id': editingId != null && editingId.isNotEmpty
              ? editingId
              : 'debug-order-${DateTime.now().microsecondsSinceEpoch}',
          'seller_id': widget.sellerId,
          'table_number': widget.tableNumber,
          'items': items,
          'status': nextStatus,
          'created_at':
              originalOrder?['created_at']?.toString() ??
              DateTime.now().toIso8601String(),
          'updated_at': updatedAt,
          'revision': nextRevision,
          'last_edit_summary': lastEditSummary,
          'last_edit_note': editPolicyMessage ?? '',
        };
        if (!_debugPrintSystemEnabled) {
          parallelDispatchFeedback = _KitchenDispatchFeedback(
            notice:
                'Sipariş kaydedildi. Baskı sistemi kapalı olduğu için mutfak fişi yazdırılmadı.',
            orderId: submittedOrder['id']?.toString(),
            printJobIds: const <String>['debug-print-disabled'],
          );
        }
      } else if (editingId != null && editingId.isNotEmpty) {
        Future<Map<String, dynamic>?> updateFuture() async {
          final dbWatch = Stopwatch()..start();
          final updated = await _storeService.updateTableOrder(
            editingId,
            items: items,
            status: nextStatus,
            revision: nextRevision,
            lastEditSummary: lastEditSummary,
            lastEditNote: editPolicyMessage,
          );
          debugPrint(
            '[GarsonPerf] db_update_ms=${dbWatch.elapsedMilliseconds} '
            'table=${widget.tableNumber}',
          );
          return updated;
        }

        Future<_KitchenDispatchFeedback> printFuture() async {
          final printWatch = Stopwatch()..start();
          final feedback = await _dispatchUpdatedOrderPrintJobs(
            previousStatus: originalStatus,
            changeSummary: changeSummary,
            nextItems: items,
          );
          debugPrint(
            '[GarsonPerf] print_dispatch_ms=${printWatch.elapsedMilliseconds} '
            'physicallyDispatched=${feedback.physicallyDispatched} '
            'table=${widget.tableNumber}',
          );
          return feedback;
        }

        final updateAndPrint = await Future.wait<dynamic>([
          updateFuture(),
          printFuture(),
        ]);
        final updatedOrder = updateAndPrint[0] as Map<String, dynamic>?;
        parallelDispatchFeedback =
            updateAndPrint[1] as _KitchenDispatchFeedback;
        final baseSubmitted =
            updatedOrder ??
            <String, dynamic>{
              'id': editingId,
              'seller_id': widget.sellerId,
              'table_number': widget.tableNumber,
              'items': items,
              'status': nextStatus,
              'created_at':
                  originalOrder?['created_at']?.toString() ??
                  DateTime.now().toIso8601String(),
              'updated_at': updatedAt,
              'revision': nextRevision,
              'last_edit_summary': lastEditSummary,
              'last_edit_note': editPolicyMessage ?? '',
            };
        submittedOrder = applyGarsonSubmittedOrderItems(
          submittedOrder: baseSubmitted,
          items: items,
          revision: nextRevision,
          updatedAt: updatedAt,
        );
      } else {
        kitchenPerfTapAt = DateTime.now().toIso8601String();
        final canFastKitchen = await _resolveCanUseGarsonKitchenFastPath();
        debugPrint(
          '[PrintPipeline] table_order_save_started_at=${DateTime.now().toIso8601String()} '
          'table=${widget.tableNumber} seller=${widget.sellerId} '
          'canFastKitchen=$canFastKitchen',
        );

        logKitchenDispatchPath(
          path: canFastKitchen ? 'print_jobs_garson_fast' : 'legacy_rpc',
          physicallyDispatched: false,
          reason: 'new_order_dispatch_started',
          itemCount: items.length,
        );
        final orderDispatchWatch = Stopwatch()..start();
        final dispatchResult = await _orderPrintJobService.dispatchNewOrder(
          restaurantId: widget.sellerId,
          tableNumber: widget.tableNumber,
          items: items,
          waiterId: _currentWaiterId(),
          waiterName: _currentWaiterName(),
          jobType: 'new_order',
          garsonDesktopFastKitchen: canFastKitchen,
        );
        kitchenPerfDbSaveMs = orderDispatchWatch.elapsedMilliseconds;
        _orderPrintJobService.debugLogResult(dispatchResult);
        parallelDispatchFeedback = _feedbackFromDispatchResult(dispatchResult);
        submittedOrder = _tableOrderFromPrintDispatch(
          dispatchResult,
          items: items,
          status: nextStatus,
          revision: nextRevision,
          updatedAt: updatedAt,
        );
        debugPrint(
          '[PrintPipeline] table_order_saved_at=${DateTime.now().toIso8601String()} '
          'table=${widget.tableNumber} db_save_ms=$kitchenPerfDbSaveMs '
          'print_jobs=${dispatchResult.printJobIds.length} '
          'print_failed=${dispatchResult.printFailureMessage ?? '-'}',
        );
      }
      final dispatchFeedback = widget.debugUseLocalSubmit
          ? (parallelDispatchFeedback ?? _KitchenDispatchFeedback.none)
          : parallelDispatchFeedback ?? _KitchenDispatchFeedback.none;
      final uiReconcileWatch = Stopwatch()..start();
      final optimisticOrders = _buildOptimisticTableOrders(
        existingTableOrders: existingTableOrders,
        submittedOrder: submittedOrder,
        editingOrderId: editingId,
      );
      final uiReconcileMs = uiReconcileWatch.elapsedMilliseconds;
      final totalToBridgeMs = dispatchFeedback.totalToBridgeMs > 0
          ? dispatchFeedback.totalToBridgeMs
          : dispatchFeedback.bridgeRequestMs;
      final perfTapAt = kitchenPerfTapAt ?? DateTime.now().toIso8601String();
      _logGarsonKitchenPerf(<String, Object?>{
        'tap_at': perfTapAt,
        'fast_path_decision_ms': dispatchFeedback.fastPathDecisionMs,
        'printer_resolve_ms': dispatchFeedback.printerResolveMs,
        'printer_cache_resolve_ms': dispatchFeedback.printerCacheResolveMs > 0
            ? dispatchFeedback.printerCacheResolveMs
            : dispatchFeedback.printerResolveMs,
        'station_resolve_ms': dispatchFeedback.stationResolveMs,
        'payload_build_ms': dispatchFeedback.payloadBuildMs,
        'bridge_request_ms': dispatchFeedback.bridgeRequestMs,
        'direct_print_started_ms': dispatchFeedback.directPrintStartedMs,
        'direct_print_done_ms': dispatchFeedback.directPrintDoneMs > 0
            ? dispatchFeedback.directPrintDoneMs
            : totalToBridgeMs,
        if (kitchenPerfDbSaveMs != null) 'db_save_ms': kitchenPerfDbSaveMs,
        'ui_reconcile_ms': uiReconcileMs,
        'total_to_bridge_ms': totalToBridgeMs,
        'total_submit_to_print_ms': totalToBridgeMs,
        'total_ui_done_ms': pipelineWatch.elapsedMilliseconds,
        'physicallyDispatched': dispatchFeedback.physicallyDispatched,
        'path': dispatchFeedback.dispatchPath.isEmpty
            ? 'legacy'
            : dispatchFeedback.dispatchPath,
        if (dispatchFeedback.selectedPrinterId.isNotEmpty)
          'printerId': dispatchFeedback.selectedPrinterId,
        if (widget.cachedKitchenPrinterId?.trim().isNotEmpty == true)
          'cachedKitchenPrinterId': widget.cachedKitchenPrinterId,
        if (dispatchFeedback.fallbackReason.isNotEmpty)
          'fallback_reason': dispatchFeedback.fallbackReason,
        'table': widget.tableNumber,
      });
      logPrintPerf('kitchen_order', <String, Object?>{
        'tap_at': perfTapAt,
        'fast_path_decision_ms': dispatchFeedback.fastPathDecisionMs,
        'printer_resolve_ms': dispatchFeedback.printerResolveMs,
        'printer_cache_resolve_ms': dispatchFeedback.printerCacheResolveMs > 0
            ? dispatchFeedback.printerCacheResolveMs
            : dispatchFeedback.printerResolveMs,
        'station_resolve_ms': dispatchFeedback.stationResolveMs,
        'bridge_request_ms': dispatchFeedback.bridgeRequestMs,
        'payload_build_ms': dispatchFeedback.payloadBuildMs,
        'total_submit_to_print_ms': totalToBridgeMs,
        'total_to_bridge_ms': totalToBridgeMs,
        if (kitchenPerfDbSaveMs != null) 'db_save_ms': kitchenPerfDbSaveMs,
        'ui_reconcile_ms': uiReconcileMs,
        'total_ui_done_ms': pipelineWatch.elapsedMilliseconds,
        'physicallyDispatched': dispatchFeedback.physicallyDispatched,
        'path': dispatchFeedback.dispatchPath.isEmpty
            ? 'legacy'
            : dispatchFeedback.dispatchPath,
        if (dispatchFeedback.fallbackReason.isNotEmpty)
          'fallback_reason': dispatchFeedback.fallbackReason,
        if (dispatchFeedback.selectedPrinterId.isNotEmpty)
          'printerId': dispatchFeedback.selectedPrinterId,
        'table': widget.tableNumber,
        'ok': dispatchFeedback.physicallyDispatched,
      });
      if (!mounted) return;
      final actionLabel = (editingId != null && editingId.isNotEmpty)
          ? 'Sipariş güncellendi.'
          : 'Sipariş gönderildi.';
      setState(() {
        _draftItems.clear();
        _editingOrderId = null;
        _editingOrderSnapshot = null;
        _editingBaseItems = const <Map<String, dynamic>>[];
        _bottomIndex = 2;
        _hydratedTableOrders = optimisticOrders;
        _optimisticTableOrders = optimisticOrders;
        _lastSubmitActionLabel = actionLabel;
      });
      // Always show an immediate "sent/saved" message; print tracking may
      // override it with a more specific "queued/printing" status.
      _setSubmitFeedback(
        actionLabel,
        tone: _GarsonSubmitFeedbackTone.success,
        autoHideAfter: const Duration(seconds: 3),
      );
      _applyKitchenDispatchFeedback(dispatchFeedback);
      if (!dispatchFeedback.hasError &&
          dispatchFeedback.shouldTrackPrintCompletion) {
        _startPrintCompletionTracking(dispatchFeedback);
      }
      _notifyDraftChanged();
      widget.onOrderSubmitted?.call(widget.tableNumber, items, submittedOrder);
      if (!widget.debugDisableLiveSync && !widget.debugUseLocalSubmit) {
        unawaited(_refreshTableOrdersAfterSubmit());
      }
    } catch (error) {
      if (!mounted) return;
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(SnackBar(content: Text('Sipariş kaydedilemedi: $error')));
    } finally {
      if (mounted) setState(() => _isSubmitting = false);
    }
  }

  Widget _buildCategoryChips(
    List<String> categories, {
    required String selectedCategory,
  }) {
    final options = <String>['Tümü', ...categories];
    return SizedBox(
      height: 40,
      child: ListView.builder(
        scrollDirection: Axis.horizontal,
        itemCount: options.length,
        itemBuilder: (context, index) {
          final category = options[index];
          final selected = category == selectedCategory;
          return Padding(
            padding: const EdgeInsets.only(right: 8),
            child: ChoiceChip(
              selected: selected,
              label: Text(
                category,
                style: TextStyle(
                  fontSize: 12,
                  fontWeight: FontWeight.w700,
                  color: selected ? Colors.white : const Color(0xFF111827),
                ),
              ),
              selectedColor: AppColors.primary,
              backgroundColor: const Color(0xFFF3F4F6),
              onSelected: (_) {
                setState(() => _selectedCategory = category);
              },
            ),
          );
        },
      ),
    );
  }

  bool _showProductsLiveSummaryBar() {
    return _bottomIndex == 0;
  }

  Widget _buildProductsLiveSummaryBar() {
    final totalQuantity = _draftTotalQuantity();
    // Compact single-row live bar — keeps vertical space for the product list.
    return Container(
      width: double.infinity,
      padding: const EdgeInsets.fromLTRB(12, 8, 8, 10),
      decoration: BoxDecoration(
        color: Colors.white,
        border: const Border(top: BorderSide(color: Color(0xFFE5E7EB))),
        boxShadow: [
          BoxShadow(
            color: Colors.black.withValues(alpha: 0.05),
            blurRadius: 12,
            offset: const Offset(0, -3),
          ),
        ],
      ),
      child: Row(
        children: [
          // Item-count badge: green when items exist, neutral when empty
          AnimatedContainer(
            duration: const Duration(milliseconds: 150),
            padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 6),
            decoration: BoxDecoration(
              color: totalQuantity == 0
                  ? const Color(0xFFF1F5F9)
                  : const Color(0xFFF0FDF4),
              borderRadius: BorderRadius.circular(10),
              border: Border.all(
                color: totalQuantity == 0
                    ? const Color(0xFFE2E8F0)
                    : const Color(0xFFBBF7D0),
              ),
            ),
            child: Row(
              mainAxisSize: MainAxisSize.min,
              children: [
                Icon(
                  Icons.receipt_long_outlined,
                  size: 14,
                  color: totalQuantity == 0
                      ? const Color(0xFF94A3B8)
                      : const Color(0xFF15803D),
                ),
                const SizedBox(width: 5),
                Text(
                  totalQuantity == 0 ? 'Taslak boş' : '$totalQuantity ürün',
                  style: TextStyle(
                    fontSize: 12,
                    fontWeight: FontWeight.w700,
                    color: totalQuantity == 0
                        ? const Color(0xFF64748B)
                        : const Color(0xFF15803D),
                  ),
                ),
              ],
            ),
          ),
          const SizedBox(width: 10),
          // Total price or placeholder hint
          if (totalQuantity > 0)
            Expanded(
              child: Text(
                _formatMoney(_draftTotal()),
                style: const TextStyle(
                  fontSize: 15,
                  fontWeight: FontWeight.w900,
                  color: Color(0xFF111827),
                ),
              ),
            )
          else
            const Expanded(
              child: Text(
                'Ürün seçince burada görünür',
                style: TextStyle(fontSize: 11, color: Color(0xFF94A3B8)),
              ),
            ),
          // Jump CTA — only visible when draft has items
          if (totalQuantity > 0)
            FilledButton.icon(
              onPressed: () => setState(() => _bottomIndex = 2),
              icon: const Icon(Icons.receipt_long_outlined, size: 14),
              label: const Text(
                'Sipariş',
                style: TextStyle(fontSize: 12, fontWeight: FontWeight.w800),
              ),
              style: FilledButton.styleFrom(
                backgroundColor: AppColors.primary,
                foregroundColor: Colors.white,
                minimumSize: const Size(0, 36),
                padding: const EdgeInsets.symmetric(horizontal: 12),
                shape: RoundedRectangleBorder(
                  borderRadius: BorderRadius.circular(10),
                ),
              ),
            ),
        ],
      ),
    );
  }

  Widget _buildProductsTab() {
    final sourceProducts = _allGarsonProducts();
    final allProducts = _activeProducts();
    final extraBottomPadding = _showProductsLiveSummaryBar() ? 88.0 : 16.0;
    final categories = _productCategories(allProducts);
    final effectiveCategory =
        (_selectedCategory == 'Tümü' || categories.contains(_selectedCategory))
        ? _selectedCategory
        : 'Tümü';

    // Category filter
    var products = effectiveCategory == 'Tümü'
        ? allProducts
        : allProducts
              .where((p) => _productCategory(p) == effectiveCategory)
              .toList(growable: false);

    // Search filter (debounced query is stored in _searchQuery)
    final query = _searchQuery.toLowerCase();
    if (query.isNotEmpty) {
      products = products
          .where((p) {
            final name = p.name.toLowerCase();
            final main = p.mainCategory.toLowerCase();
            final sub = p.subCategory.toLowerCase();
            return name.contains(query) ||
                main.contains(query) ||
                sub.contains(query);
          })
          .toList(growable: false);
    }

    _debugLogProductPipeline(
      sourceProducts: sourceProducts,
      allProducts: allProducts,
      visibleProducts: products,
      selectedCategory: effectiveCategory,
    );

    // ── Empty states ──
    final String emptyMessage;
    if (_isLoadingProducts && sourceProducts.isEmpty) {
      emptyMessage = '';
    } else if (query.isNotEmpty && products.isEmpty) {
      emptyMessage = '"$_searchQuery" için sonuç bulunamadı.';
    } else if (products.isEmpty) {
      emptyMessage = 'Bu kategoride ürün yok.';
    } else {
      emptyMessage = '';
    }

    return Column(
      children: [
        // ── Sticky header: category chips + search bar ───────────────────
        Material(
          color: const Color(0xFFF3F4F6),
          child: Padding(
            padding: const EdgeInsets.fromLTRB(12, 10, 12, 8),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                _buildCategoryChips(
                  categories,
                  selectedCategory: effectiveCategory,
                ),
                const SizedBox(height: 8),
                ProductSearchBar(
                  initialQuery: _searchQuery,
                  onChanged: (value) => setState(() => _searchQuery = value),
                ),
              ],
            ),
          ),
        ),
        // ── Product list ─────────────────────────────────────────────────
        Expanded(
          child: _isLoadingProducts && sourceProducts.isEmpty
              ? const Center(child: CircularProgressIndicator())
              : emptyMessage.isNotEmpty
              ? Center(
                  child: Padding(
                    padding: const EdgeInsets.all(24),
                    child: Text(
                      emptyMessage,
                      textAlign: TextAlign.center,
                      style: TextStyle(
                        fontSize: 13,
                        color: Colors.grey.shade600,
                      ),
                    ),
                  ),
                )
              : ListView.builder(
                  padding: EdgeInsets.fromLTRB(12, 2, 12, extraBottomPadding),
                  itemCount: products.length,
                  itemBuilder: (context, index) {
                    final product = products[index];
                    final category = _productCategory(product);
                    final imageUrl = product.imageUrl?.trim() ?? '';
                    final outOfStock = product.stock <= 0;
                    final draftQty = _draftQuantityForProduct(product);
                    final draftLineCount = _draftLineCountForProduct(product);
                    final singleDraftIndex = _singleDraftIndexForProduct(
                      product,
                    );
                    final isAdded = draftQty > 0;
                    final isTemplate = _isTemplateProduct(product);
                    final isServiceConfigured =
                        product.usesServiceControlStepper &&
                        _serviceStepperLabelForProduct(product) != null;
                    final isSelectedCard = isAdded || isServiceConfigured;
                    final resolvedKind =
                        MixedServiceOrder.productTypeFromProduct(product);
                    // TODO(debug): remove before production
                    debugPrint(
                      '[WAITER_SOURCE] '
                      'id=${product.id} name="${product.name}" '
                      'category=${product.mainCategory} '
                      'subCategory=${product.subCategory} '
                      'product_type=$resolvedKind '
                      'spec_len=${product.specifications?.length ?? 0}b '
                      'resolved_kind=$resolvedKind',
                    );
                    final serviceStepperLabel = _serviceStepperLabelForProduct(
                      product,
                    );
                    final usesServiceStepper =
                        product.usesServiceControlStepper;
                    final buttonMode = isTemplate
                        ? _templatePrimaryActionLabel(product)
                        : usesServiceStepper
                        ? 'service_stepper'
                        : (draftQty > 0 ? 'qty_stepper' : 'Ekle');
                    // TODO(debug): remove before production
                    debugPrint(
                      '[WAITER_CARD] '
                      'name="${product.name}" '
                      'resolved_kind=$resolvedKind '
                      'button_mode=$buttonMode '
                      'addLabel=$buttonMode '
                      'hasIncrement=${usesServiceStepper || draftQty > 0} '
                      'hasDecrement=${usesServiceStepper || draftQty > 0} '
                      'hasCustomize=true',
                    );
                    final imageThumb = ClipRRect(
                      borderRadius: BorderRadius.circular(10),
                      child: imageUrl.isEmpty
                          ? Container(
                              width: 56,
                              height: 56,
                              color: const Color(0xFFF3F4F6),
                              alignment: Alignment.center,
                              child: const Icon(
                                Icons.fastfood_rounded,
                                color: Color(0xFF9CA3AF),
                              ),
                            )
                          : OptimizedImage(
                              imageUrlOrPath: imageUrl,
                              width: 56,
                              height: 56,
                              fit: BoxFit.cover,
                              errorBuilder: (_, _, _) => Container(
                                width: 56,
                                height: 56,
                                color: const Color(0xFFF3F4F6),
                                alignment: Alignment.center,
                                child: const Icon(
                                  Icons.broken_image_outlined,
                                  color: Color(0xFF9CA3AF),
                                ),
                              ),
                            ),
                    );
                    final infoSection = Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: [
                        Text(
                          product.name,
                          maxLines: 2,
                          overflow: TextOverflow.ellipsis,
                          style: const TextStyle(
                            fontSize: 13,
                            fontWeight: FontWeight.w700,
                            color: Color(0xFF111827),
                          ),
                        ),
                        if (isTemplate) ...[
                          const SizedBox(height: 4),
                          _templateTypeBadge(
                            product,
                            fontSize: 10,
                            padding: const EdgeInsets.symmetric(
                              horizontal: 8,
                              vertical: 3,
                            ),
                          ),
                        ],
                        const SizedBox(height: 4),
                        Text(
                          isTemplate
                              ? '$category • ${MixedServiceOrder.templatePricingLabel(product)}'
                              : '$category • Stok: ${product.stock}',
                          style: TextStyle(
                            fontSize: 11,
                            color: Colors.grey.shade600,
                          ),
                        ),
                        const SizedBox(height: 2),
                        Text(
                          isTemplate
                              ? _formatMoney(
                                  MixedServiceOrder.templatePreviewPriceFromProduct(
                                    product,
                                    availableProducts: products,
                                  ),
                                )
                              : product.displayPrice,
                          style: const TextStyle(
                            fontSize: 12,
                            fontWeight: FontWeight.w800,
                            color: AppColors.primary,
                          ),
                        ),
                        if (isSelectedCard) ...[
                          const SizedBox(height: 6),
                          Container(
                            padding: const EdgeInsets.symmetric(
                              horizontal: 8,
                              vertical: 4,
                            ),
                            decoration: BoxDecoration(
                              color: const Color(0xFFE8F7EE),
                              borderRadius: BorderRadius.circular(999),
                              border: Border.all(
                                color: const Color(0xFFA7E3BE),
                              ),
                            ),
                            child: Text(
                              isTemplate
                                  ? 'Taslakta hazır'
                                  : isServiceConfigured && !isAdded
                                  ? serviceStepperLabel ?? 'Seçildi'
                                  : draftLineCount > 1
                                  ? '$draftQty adet · $draftLineCount satır'
                                  : '$draftQty adet taslakta',
                              style: const TextStyle(
                                fontSize: 10.5,
                                fontWeight: FontWeight.w800,
                                color: Color(0xFF15803D),
                              ),
                            ),
                          ),
                        ],
                      ],
                    );
                    final actionSection = Column(
                      mainAxisSize: MainAxisSize.min,
                      children: [
                        if (!isTemplate && usesServiceStepper)
                          ProductQuantityStepper(
                            quantity: serviceStepperLabel == null ? 0 : 1,
                            onAdd: () => _quickAddProduct(product),
                            onIncrement: () {
                              if (product.resolvedServiceControlType ==
                                  ProductServiceControlType.weightStepper) {
                                final current =
                                    _selectedServiceAmountForProduct(product);
                                _setServiceControlledProductAmount(
                                  product,
                                  ProductPriceCalculator.clampWeightSelection(
                                    current.round() +
                                        product.resolvedWeightStepGrams,
                                    minWeightGrams: product.minWeightGrams,
                                    weightStepGrams: product.weightStepGrams,
                                    maxWeightGrams: product.maxWeightGrams,
                                  ).toDouble(),
                                );
                              } else {
                                final current =
                                    _selectedServiceAmountForProduct(product);
                                _setServiceControlledProductAmount(
                                  product,
                                  ProductPriceCalculator.clampPortionSelection(
                                    current + product.resolvedPortionStepAmount,
                                    type: product.resolvedServiceControlType,
                                    minPortion: product.minPortion,
                                    maxPortion: product.maxPortion,
                                    portionStep: product.portionStep,
                                  ),
                                );
                              }
                            },
                            onDecrement: () {
                              if (product.resolvedServiceControlType ==
                                  ProductServiceControlType.weightStepper) {
                                final current =
                                    _selectedServiceAmountForProduct(product);
                                final min = product.resolvedMinWeightGrams
                                    .toDouble();
                                if (current <= min) {
                                  _setServiceControlledProductAmount(
                                    product,
                                    null,
                                  );
                                  return;
                                }
                                _setServiceControlledProductAmount(
                                  product,
                                  ProductPriceCalculator.clampWeightSelection(
                                    current.round() -
                                        product.resolvedWeightStepGrams,
                                    minWeightGrams: product.minWeightGrams,
                                    weightStepGrams: product.weightStepGrams,
                                    maxWeightGrams: product.maxWeightGrams,
                                  ).toDouble(),
                                );
                              } else {
                                final current =
                                    _selectedServiceAmountForProduct(product);
                                final min = product.resolvedMinPortionAmount;
                                if (current <= min + 0.0001) {
                                  _setServiceControlledProductAmount(
                                    product,
                                    null,
                                  );
                                  return;
                                }
                                _setServiceControlledProductAmount(
                                  product,
                                  ProductPriceCalculator.clampPortionSelection(
                                    current - product.resolvedPortionStepAmount,
                                    type: product.resolvedServiceControlType,
                                    minPortion: product.minPortion,
                                    maxPortion: product.maxPortion,
                                    portionStep: product.portionStep,
                                  ),
                                );
                              }
                            },
                            compact: true,
                            addLabel:
                                product.resolvedServiceControlType ==
                                    ProductServiceControlType.weightStepper
                                ? ProductPriceCalculator.formatServiceAmountLabel(
                                    type: product.resolvedServiceControlType,
                                    grams: product.resolvedDefaultWeightGrams,
                                  )
                                : ProductPriceCalculator.formatServiceAmountLabel(
                                    type: product.resolvedServiceControlType,
                                    amount:
                                        product.resolvedDefaultServiceAmount,
                                  ),
                            valueLabel: serviceStepperLabel,
                          )
                        else if (!isTemplate && !usesServiceStepper && isAdded)
                          draftLineCount > 1
                              ? SizedBox(
                                  height: 32,
                                  child: OutlinedButton(
                                    onPressed: outOfStock
                                        ? null
                                        : () => _addConfiguredProduct(product),
                                    style: OutlinedButton.styleFrom(
                                      padding: const EdgeInsets.symmetric(
                                        horizontal: 10,
                                      ),
                                    ),
                                    child: const Text(
                                      'Seçim ekle',
                                      style: TextStyle(
                                        fontSize: 12,
                                        fontWeight: FontWeight.w600,
                                      ),
                                    ),
                                  ),
                                )
                              : ProductQuantityStepper(
                                  quantity: draftQty,
                                  onAdd: () => _quickAddProduct(product),
                                  onIncrement: () =>
                                      _changeDraftQty(singleDraftIndex, 1),
                                  onDecrement: () =>
                                      _changeDraftQty(singleDraftIndex, -1),
                                  compact: true,
                                )
                        else
                          SizedBox(
                            height: 32,
                            child: OutlinedButton(
                              onPressed: outOfStock
                                  ? null
                                  : () => isTemplate
                                        ? _showTemplateProductActions(product)
                                        : _quickAddProduct(product),
                              style: OutlinedButton.styleFrom(
                                padding: const EdgeInsets.symmetric(
                                  horizontal: 10,
                                ),
                              ),
                              child: Text(
                                isTemplate
                                    ? _templatePrimaryActionLabel(product)
                                    : 'Ekle',
                                style: const TextStyle(
                                  fontSize: 12,
                                  fontWeight: FontWeight.w600,
                                ),
                              ),
                            ),
                          ),
                        const SizedBox(height: 6),
                        IconButton(
                          onPressed: outOfStock
                              ? null
                              : () {
                                  if (singleDraftIndex >= 0) {
                                    final draftItem = Map<String, dynamic>.from(
                                      _draftItems[singleDraftIndex],
                                    );
                                    _addConfiguredProduct(
                                      product,
                                      editDraftIndex: singleDraftIndex,
                                      editingItem: draftItem,
                                    );
                                  } else {
                                    _addConfiguredProduct(product);
                                  }
                                },
                          icon: const Icon(Icons.tune, size: 18),
                          tooltip: isTemplate
                              ? _isMenuTemplateProduct(product)
                                    ? 'Menüyü Aç'
                                    : _isServiceTemplateProduct(product)
                                    ? 'Servisi Aç'
                                    : 'Şablonu Aç'
                              : 'Özelleştir',
                          splashRadius: 18,
                        ),
                      ],
                    );

                    final card = AnimatedContainer(
                      duration: const Duration(milliseconds: 160),
                      margin: const EdgeInsets.only(bottom: 8),
                      padding: const EdgeInsets.all(10),
                      decoration: BoxDecoration(
                        color: isSelectedCard
                            ? const Color(0xFFF0F9F3)
                            : Colors.white,
                        borderRadius: BorderRadius.circular(14),
                        border: Border.all(
                          color: isSelectedCard
                              ? const Color(0xFFA7E3BE)
                              : const Color(0xFFE5E7EB),
                          width: isSelectedCard ? 1.2 : 1,
                        ),
                        boxShadow: [
                          BoxShadow(
                            color: isSelectedCard
                                ? const Color(
                                    0xFF16A34A,
                                  ).withValues(alpha: 0.10)
                                : Colors.black.withValues(alpha: 0.03),
                            blurRadius: isSelectedCard ? 16 : 10,
                            offset: const Offset(0, 4),
                          ),
                        ],
                      ),
                      child: LayoutBuilder(
                        builder: (context, constraints) {
                          final useStackedLayout = constraints.maxWidth < 360;
                          if (useStackedLayout) {
                            return Column(
                              crossAxisAlignment: CrossAxisAlignment.start,
                              children: [
                                Row(
                                  crossAxisAlignment: CrossAxisAlignment.start,
                                  children: [
                                    imageThumb,
                                    const SizedBox(width: 10),
                                    Expanded(child: infoSection),
                                  ],
                                ),
                                const SizedBox(height: 8),
                                Align(
                                  alignment: Alignment.centerRight,
                                  child: actionSection,
                                ),
                              ],
                            );
                          }
                          return Row(
                            crossAxisAlignment: CrossAxisAlignment.start,
                            children: [
                              imageThumb,
                              const SizedBox(width: 10),
                              Expanded(child: infoSection),
                              const SizedBox(width: 8),
                              actionSection,
                            ],
                          );
                        },
                      ),
                    );

                    // Wrap card with swipe actions:
                    //   ← left  swipe → Edit (configure product)
                    //   → right swipe → Quick remove from draft (with undo)
                    return SwipeableProductCard(
                      productKey: product.id.isNotEmpty
                          ? product.id
                          : '${product.name}_$index',
                      isInDraft: isAdded,
                      enabled: !outOfStock,
                      onEdit: () {
                        if (singleDraftIndex >= 0) {
                          _editDraftItem(singleDraftIndex);
                        } else {
                          _addConfiguredProduct(product);
                        }
                      },
                      onQuickRemove: () =>
                          _quickRemoveProductFromDraft(product),
                      child: card,
                    );
                  },
                ),
        ),
      ],
    );
  }

  // ── Payment & Close Table ─────────────────────────────────────────────────

  double _tableOrdersTotal(List<Map<String, dynamic>> orders) {
    var total = 0.0;
    for (final order in orders) {
      final items = _extractItems(order['items']);
      for (final item in items) {
        total += _itemLineTotal(item);
      }
    }
    return total;
  }

