  }) {
    final btnMin = compact ? 26.0 : 30.0;
    final iconSize = compact ? 14.0 : 15.0;
    final btnPad = compact ? 2.0 : 4.0;
    final labelMinWidth = compact ? 46.0 : 58.0;
    final qtyFontSize = compact ? 9.0 : 10.0;
    final labelFontSize = compact ? 8.5 : 9.5;
    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 2, vertical: 2),
      decoration: BoxDecoration(
        color: const Color(0xFFF8FAFC),
        borderRadius: BorderRadius.circular(compact ? 8 : 10),
        border: Border.all(color: const Color(0xFFE2E8F0)),
      ),
      child: Row(
        mainAxisSize: MainAxisSize.min,
        children: [
          IconButton(
            onPressed: onDecrement,
            icon: Icon(Icons.remove_circle_outline, size: iconSize),
            color: const Color(0xFF475569),
            splashRadius: compact ? 14 : 16,
            visualDensity: VisualDensity.compact,
            padding: EdgeInsets.all(btnPad),
            constraints: BoxConstraints(minWidth: btnMin, minHeight: btnMin),
          ),
          ConstrainedBox(
            constraints: BoxConstraints(minWidth: labelMinWidth),
            child: Column(
              mainAxisSize: MainAxisSize.min,
              children: [
                Text(
                  '$quantity adet',
                  style: TextStyle(
                    fontSize: qtyFontSize,
                    fontWeight: FontWeight.w800,
                    color: const Color(0xFF111827),
                  ),
                ),
                Text(
                  label,
                  maxLines: 1,
                  overflow: TextOverflow.ellipsis,
                  textAlign: TextAlign.center,
                  style: TextStyle(
                    fontSize: labelFontSize,
                    fontWeight: FontWeight.w600,
                    color: const Color(0xFF64748B),
                  ),
                ),
              ],
            ),
          ),
          IconButton(
            onPressed: onIncrement,
            icon: Icon(Icons.add_circle_outline, size: iconSize),
            color: AppColors.primary,
            splashRadius: compact ? 14 : 16,
            visualDensity: VisualDensity.compact,
            padding: EdgeInsets.all(btnPad),
            constraints: BoxConstraints(minWidth: btnMin, minHeight: btnMin),
          ),
        ],
      ),
    );
  }

  Widget _buildDraftEditorCard() {
    final isEditing = _editingOrderId != null && _editingOrderId!.isNotEmpty;
    final editingStatus = _editingOrderSnapshot?['status']?.toString() ?? '';
    final editingRevision = _orderRevision(
      _editingOrderSnapshot ?? const <String, dynamic>{},
    );

    if (_draftItems.isEmpty) {
      return Container(
        width: double.infinity,
        padding: const EdgeInsets.all(14),
        decoration: BoxDecoration(
          color: Colors.white,
          borderRadius: BorderRadius.circular(14),
          border: Border.all(color: const Color(0xFFE2E8F0)),
        ),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Text(
              isEditing ? 'Siparişi Düzenle' : 'Yeni Sipariş Taslağı',
              style: const TextStyle(fontSize: 14, fontWeight: FontWeight.w800),
            ),
            const SizedBox(height: 6),
            Text(
              isEditing
                  ? 'Bu siparişte ürün kalmadı. Ürünler sekmesinden yeni kalem ekleyebilir veya düzenlemeyi iptal edebilirsin.'
                  : 'Henüz ürün seçilmedi. Ürünler sekmesinden ekleyebilirsin.',
              style: TextStyle(fontSize: 12, color: Colors.grey.shade600),
            ),
            const SizedBox(height: 8),
            Row(
              children: [
                TextButton.icon(
                  onPressed: () => setState(() => _bottomIndex = 0),
                  icon: const Icon(Icons.storefront_outlined, size: 16),
                  label: const Text('Ürünlere Git'),
                ),
                if (isEditing) ...[
                  const SizedBox(width: 8),
                  TextButton.icon(
                    onPressed: _isSubmitting ? null : _clearDraftComposer,
                    icon: const Icon(Icons.close_rounded, size: 16),
                    label: const Text('Düzenlemeyi İptal Et'),
                  ),
                ],
              ],
            ),
          ],
        ),
      );
    }

    return Container(
      padding: const EdgeInsets.all(12),
      decoration: BoxDecoration(
        color: Colors.white,
        borderRadius: BorderRadius.circular(14),
        border: Border.all(color: const Color(0xFFE2E8F0)),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            children: [
              Expanded(
                child: Text(
                  isEditing ? 'Siparişi Düzenle' : 'Yeni Sipariş Taslağı',
                  maxLines: 1,
                  overflow: TextOverflow.ellipsis,
                  style: const TextStyle(
                    fontSize: 14,
                    fontWeight: FontWeight.w800,
                  ),
                ),
              ),
              // "Yeni Nx" badge — shown when editing and new items were added
              if (isEditing) ...[
                Builder(
                  builder: (ctx) {
                    final added = _currentEditingChangeSummary().addedQuantity;
                    if (added <= 0) return const SizedBox.shrink();
                    return Container(
                      margin: const EdgeInsets.only(right: 6),
                      padding: const EdgeInsets.symmetric(
                        horizontal: 8,
                        vertical: 4,
                      ),
                      decoration: BoxDecoration(
                        color: const Color(0xFF16A34A).withValues(alpha: 0.12),
                        borderRadius: BorderRadius.circular(999),
                      ),
                      child: Text(
                        'Yeni ${added}x',
                        style: const TextStyle(
                          fontSize: 10,
                          fontWeight: FontWeight.w800,
                          color: Color(0xFF16A34A),
                        ),
                      ),
                    );
                  },
                ),
                Container(
                  padding: const EdgeInsets.symmetric(
                    horizontal: 8,
                    vertical: 4,
                  ),
                  decoration: BoxDecoration(
                    color: AppColors.primary.withValues(alpha: 0.10),
                    borderRadius: BorderRadius.circular(999),
                  ),
                  child: Text(
                    'Rev $editingRevision',
                    style: const TextStyle(
                      fontSize: 10,
                      fontWeight: FontWeight.w800,
                      color: AppColors.primary,
                    ),
                  ),
                ),
              ],
              const SizedBox(width: 6),
              TextButton(
                onPressed: _isSubmitting ? null : _clearDraftComposer,
                child: Text(isEditing ? 'İptal' : 'Temizle'),
              ),
            ],
          ),
          const SizedBox(height: 6),
          if (isEditing) ...[
            _buildOrderPolicyNotice(editingStatus),
            const SizedBox(height: 8),
            _buildCurrentEditChangeSummaryCard(),
            const SizedBox(height: 8),
          ],
          // Build merged display rows: items sharing the same product_id are
          // collapsed into one row showing total qty and a "Nx yeni" badge.
          ..._computeMergedDraftRows().map((row) {
            final item = row.displayItem;
            final qty = row.totalQty;
            final isMixedService = _isMixedServiceItem(item);
            final rawAmountLabel = item['amountLabel']?.toString().trim() ?? '';
            final amountLabel = rawAmountLabel.isNotEmpty
                ? rawAmountLabel
                : item['amount_label']?.toString().trim() ?? '';
            final name =
                item['display_label']?.toString().trim().isNotEmpty == true
                ? item['display_label'].toString().trim()
                : GarsonProductSelection.orderItemTitleLabel(item).isNotEmpty
                ? GarsonProductSelection.orderItemTitleLabel(item)
                : item['name']?.toString() ?? '-';
            final detailLines = _itemDetailLines(item);
            final quantityLabel = amountLabel.isNotEmpty && !isMixedService
                ? amountLabel
                : 'Standart';
            // Total price across all constituent _draftItems entries
            final totalLinePrice = row.allIndices.fold<double>(
              0,
              (sum, idx) => sum + _itemLineTotal(_draftItems[idx]),
            );
            // Colour: green if fully sent (editing + no new qty), white otherwise
            final rowIsSent = isEditing && !row.hasNew;
            return AnimatedContainer(
              width: double.infinity,
              duration: const Duration(milliseconds: 160),
              margin: const EdgeInsets.only(bottom: 6),
              padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 8),
              decoration: BoxDecoration(
                color: rowIsSent ? const Color(0xFFF0FFF4) : Colors.white,
                borderRadius: BorderRadius.circular(12),
                border: Border.all(
                  color: rowIsSent
                      ? const Color(0xFFBBF7D0)
                      : isMixedService
                      ? AppColors.primary.withValues(alpha: 0.18)
                      : const Color(0xFFE5E7EB),
                ),
                boxShadow: [
                  BoxShadow(
                    color: Colors.black.withValues(alpha: 0.025),
                    blurRadius: 10,
                    offset: const Offset(0, 3),
                  ),
                ],
              ),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  // ── ROW 1: qty badge + name + price ──────────────────
                  Row(
                    crossAxisAlignment: CrossAxisAlignment.center,
                    children: [
                      Container(
                        width: 28,
                        height: 28,
                        alignment: Alignment.center,
                        decoration: BoxDecoration(
                          color: isMixedService
                              ? AppColors.primary.withValues(alpha: 0.12)
                              : rowIsSent
                              ? const Color(0xFF16A34A).withValues(alpha: 0.14)
                              : const Color(0xFFF3F4F6),
                          borderRadius: BorderRadius.circular(8),
                        ),
                        child: Text(
                          '$qty',
                          style: TextStyle(
                            fontSize: 11,
                            fontWeight: FontWeight.w900,
                            color: isMixedService
                                ? AppColors.primary
                                : rowIsSent
                                ? const Color(0xFF16A34A)
                                : const Color(0xFF111827),
                          ),
                        ),
                      ),
                      // "Nx yeni" badge shown when this row has new additions
                      if (row.hasNew) ...[
                        const SizedBox(width: 5),
                        Container(
                          padding: const EdgeInsets.symmetric(
                            horizontal: 5,
                            vertical: 2,
                          ),
                          decoration: BoxDecoration(
                            color: const Color(
                              0xFF16A34A,
                            ).withValues(alpha: 0.12),
                            borderRadius: BorderRadius.circular(999),
                          ),
                          child: Text(
                            '${row.newQty}x yeni',
                            style: const TextStyle(
                              fontSize: 9,
                              fontWeight: FontWeight.w800,
                              color: Color(0xFF16A34A),
                            ),
                          ),
                        ),
                      ],
                      const SizedBox(width: 8),
                      Expanded(
                        child: Column(
                          crossAxisAlignment: CrossAxisAlignment.start,
                          children: [
                            Text(
                              name,
                              maxLines: 2,
                              overflow: TextOverflow.ellipsis,
                              style: const TextStyle(
                                fontSize: 13,
                                fontWeight: FontWeight.w700,
                              ),
                            ),
                            if (isMixedService) ...[
                              const SizedBox(height: 3),
                              Container(
                                padding: const EdgeInsets.symmetric(
                                  horizontal: 7,
                                  vertical: 2,
                                ),
                                decoration: BoxDecoration(
                                  color: AppColors.primary.withValues(
                                    alpha: 0.10,
                                  ),
                                  borderRadius: BorderRadius.circular(999),
                                ),
                                child: const Text(
                                  'Karışık Servis',
                                  style: TextStyle(
                                    fontSize: 9,
                                    fontWeight: FontWeight.w800,
                                    color: AppColors.primary,
                                  ),
                                ),
                              ),
                            ],
                          ],
                        ),
                      ),
                      const SizedBox(width: 8),
                      Text(
                        _formatMoney(totalLinePrice),
                        style: TextStyle(
                          fontSize: 13,
                          fontWeight: FontWeight.w900,
                          color: rowIsSent
                              ? const Color(0xFF16A34A)
                              : AppColors.primary,
                        ),
                      ),
                    ],
                  ),
                  if (detailLines.isNotEmpty) ...[
                    const SizedBox(height: 3),
                    ...detailLines.map((e) {
                      final isChildLine = isMixedService && !e.isGroupHeader;
                      return Padding(
                        padding: const EdgeInsets.only(left: 36, bottom: 2),
                        child: Text(
                          isChildLine ? '• ${e.label}' : e.label,
                          style: TextStyle(
                            fontSize: 11,
                            fontWeight: e.isGroupHeader
                                ? FontWeight.w800
                                : FontWeight.w500,
                            color: e.isGroupHeader
                                ? const Color(0xFF334155)
                                : Colors.grey.shade600,
                          ),
                        ),
                      );
                    }),
                  ],
                  // ── ROW 2: action controls ────────────────────────────
                  const SizedBox(height: 6),
                  Row(
                    mainAxisAlignment: MainAxisAlignment.end,
                    children: [
                      _buildDraftQuantityControl(
                        quantity: qty,
                        label: quantityLabel,
                        compact: _isNarrowScreen,
                        // Decrement/increment always targets the last
                        // index in the group (the most recently added).
                        onDecrement: _isSubmitting
                            ? null
                            : () => _changeDraftQty(row.allIndices.last, -1),
                        onIncrement: _isSubmitting
                            ? null
                            : () => _changeDraftQty(row.allIndices.last, 1),
                      ),
                      const SizedBox(width: 4),
                      _buildDraftActionChip(
                        icon: Icons.tune_rounded,
                        label: 'Düzenle',
                        compact: _isNarrowScreen,
                        // Edit always operates on the primary (first) entry
                        onPressed: _isSubmitting
                            ? null
                            : () => _editDraftItem(row.primaryIndex),
                      ),
                      const SizedBox(width: 4),
                      _buildDraftActionChip(
                        icon: Icons.delete_outline_rounded,
                        label: 'Sil',
                        compact: _isNarrowScreen,
                        // Delete removes all entries in this product group
                        onPressed: _isSubmitting
                            ? null
                            : () async {
                                final confirmed = await _confirmDraftItemDelete(
                                  name,
                                );
                                if (!confirmed || !mounted) return;
                                setState(() {
                                  for (final idx in row.allIndices.reversed) {
                                    if (idx < _draftItems.length) {
                                      _draftItems.removeAt(idx);
                                    }
                                  }
                                });
                                _notifyDraftChanged();
                              },
                        foregroundColor: const Color(0xFFDC2626),
                        backgroundColor: const Color(0xFFFEF2F2),
                        borderColor: const Color(0xFFFECACA),
                      ),
                    ],
                  ),
                ],
              ),
            );
          }),
          const SizedBox(height: 2),
        ],
      ),
    );
  }

  Widget _buildIncomingOrderCard(Map<String, dynamic> order) {
    final normalizedOrder = _normalizeTableOrder(order);
    final orderId = normalizedOrder['id']?.toString() ?? '';
    final status = normalizedOrder['status']?.toString() ?? 'new';
    final statusKey = _normalizedOrderStatusKey(status);
    final policy = _orderEditPolicy(status);
    final activityAt =
        garsonOrderActivityAt(normalizedOrder) ?? _createdAt(normalizedOrder);
    final items = _extractItems(normalizedOrder['items']);
    final isEditingThis = _editingOrderId == orderId;
    final revision = _orderRevision(normalizedOrder);
    final orderTotal = items.fold<double>(0, (sum, item) {
      return sum + _itemLineTotal(item);
    });

    final isSentOrLater = switch (statusKey) {
      'sent' || 'preparing' || 'ready' || 'served' => true,
      _ => false,
    };
    final cardBg = isSentOrLater ? const Color(0xFFF0FFF4) : Colors.white;
    final cardBorder = isSentOrLater
        ? const Color(0xFFBBF7D0)
        : const Color(0xFFE2E8F0);
    final priceColor = isSentOrLater
        ? const Color(0xFF16A34A)
        : AppColors.primary;

    // Resolve table number once — shared by preview and inline desktop actions.
    final tableNo = normalizedOrder['table_number'] is int
        ? normalizedOrder['table_number'] as int
        : int.tryParse(normalizedOrder['table_number']?.toString() ?? '') ??
              widget.tableNumber;

    // Helper to open the order preview sheet
    void openPreview() {
      showModalBottomSheet(
        context: context,
        isScrollControlled: true,
        backgroundColor: Colors.transparent,
        builder: (_) => OrderPreviewSheet(
          record: OrderPreviewRecord.fromTableOrder(normalizedOrder),
          onPrintAdisyon: widget.onPrintAdisyon != null
              ? () => widget.onPrintAdisyon!(tableNo, [normalizedOrder])
              : null,
          onResendToKitchen: policy.canResend && orderId.isNotEmpty
              ? () => _resendOrderToKitchen(normalizedOrder)
              : null,
        ),
      );
    }

    final canAct = policy.canEdit || _isWaitingStatus(status);

    return Container(
      margin: const EdgeInsets.only(bottom: 8),
      padding: const EdgeInsets.all(10),
      decoration: BoxDecoration(
        color: cardBg,
        borderRadius: BorderRadius.circular(14),
        border: Border.all(color: cardBorder),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          // ── Minimal header row ─────────────────────────────────────────
          Row(
            children: [
              Text(
                _timeAgo(activityAt),
                style: TextStyle(fontSize: 11, color: Colors.grey.shade500),
              ),
              if (revision > 1) ...[
                const SizedBox(width: 5),
                Container(
                  padding: const EdgeInsets.symmetric(
                    horizontal: 6,
                    vertical: 2,
                  ),
                  decoration: BoxDecoration(
                    color: AppColors.primary.withValues(alpha: 0.10),
                    borderRadius: BorderRadius.circular(999),
                  ),
                  child: Text(
                    'Rev $revision',
                    style: const TextStyle(
                      fontSize: 9,
                      fontWeight: FontWeight.w800,
                      color: AppColors.primary,
                    ),
                  ),
                ),
              ],
              if (isEditingThis) ...[
                const SizedBox(width: 5),
                Container(
                  padding: const EdgeInsets.symmetric(
                    horizontal: 6,
                    vertical: 2,
                  ),
                  decoration: BoxDecoration(
                    color: AppColors.primary,
                    borderRadius: BorderRadius.circular(999),
                  ),
                  child: const Text(
                    'Düzenleniyor',
                    style: TextStyle(
                      fontSize: 9,
                      fontWeight: FontWeight.w700,
                      color: Colors.white,
                    ),
                  ),
                ),
              ],
              const Spacer(),
              // Önizle icon
              GestureDetector(
                onTap: openPreview,
                child: Padding(
                  padding: const EdgeInsets.all(4),
                  child: Icon(
                    Icons.visibility_outlined,
                    size: 18,
                    color: Colors.grey.shade400,
                  ),
                ),
              ),
            ],
          ),
          // Compact revision warning (only for preparing / ready / served)
          if (policy.isWarning) ...[
            const SizedBox(height: 4),
            Text(
              policy.message,
              style: const TextStyle(
                fontSize: 10.5,
                fontWeight: FontWeight.w600,
                color: Color(0xFFD97706),
              ),
            ),
          ],
          const SizedBox(height: 8),
          // ── Flat item rows (always-visible adet/düzenle/sil actions) ──
          ...List.generate(items.length, (i) {
            final item = items[i];
            final qty = (item['quantity'] as num?)?.toInt() ?? 1;
            final isMixedService = _isMixedServiceItem(item);
            final name =
                item['display_label']?.toString().trim().isNotEmpty == true
                ? item['display_label'].toString().trim()
                : GarsonProductSelection.orderItemTitleLabel(item).isNotEmpty
                ? GarsonProductSelection.orderItemTitleLabel(item)
                : item['name']?.toString() ?? '-';
            final detailLines = _itemDetailLines(item);
            final lineTotal = _itemLineTotal(item);
            final rawAmountLabel = item['amountLabel']?.toString().trim() ?? '';
            final amountLabel = rawAmountLabel.isNotEmpty
                ? rawAmountLabel
                : item['amount_label']?.toString().trim() ?? '';
            final quantityLabel = amountLabel.isNotEmpty && !isMixedService
                ? amountLabel
                : 'Standart';
            return Container(
              width: double.infinity,
              margin: const EdgeInsets.only(bottom: 5),
              padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 8),
              decoration: BoxDecoration(
                color: cardBg,
                borderRadius: BorderRadius.circular(10),
                border: Border.all(color: cardBorder),
              ),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  // ── ROW 1: qty badge + name + price ──────────────────
                  Row(
                    crossAxisAlignment: CrossAxisAlignment.center,
                    children: [
                      Container(
                        width: 26,
                        height: 26,
                        alignment: Alignment.center,
                        decoration: BoxDecoration(
                          color: isMixedService
                              ? AppColors.primary.withValues(alpha: 0.12)
                              : isSentOrLater
                              ? const Color(0xFF16A34A).withValues(alpha: 0.14)
                              : const Color(0xFFF3F4F6),
                          borderRadius: BorderRadius.circular(7),
                        ),
                        child: Text(
                          '$qty',
                          style: TextStyle(
                            fontSize: 11,
                            fontWeight: FontWeight.w900,
                            color: isMixedService
                                ? AppColors.primary
                                : isSentOrLater
                                ? const Color(0xFF16A34A)
                                : const Color(0xFF111827),
                          ),
                        ),
                      ),
                      const SizedBox(width: 8),
                      Expanded(
                        child: Column(
                          crossAxisAlignment: CrossAxisAlignment.start,
                          children: [
                            Text(
                              name,
                              maxLines: 2,
                              overflow: TextOverflow.ellipsis,
                              style: const TextStyle(
                                fontSize: 12.5,
                                fontWeight: FontWeight.w700,
                              ),
                            ),
                            if (isMixedService) ...[
                              const SizedBox(height: 2),
                              Container(
                                padding: const EdgeInsets.symmetric(
                                  horizontal: 6,
                                  vertical: 2,
                                ),
                                decoration: BoxDecoration(
                                  color: AppColors.primary.withValues(
                                    alpha: 0.10,
                                  ),
                                  borderRadius: BorderRadius.circular(999),
                                ),
                                child: const Text(
                                  'Karışık Servis',
                                  style: TextStyle(
                                    fontSize: 9,
                                    fontWeight: FontWeight.w800,
                                    color: AppColors.primary,
                                  ),
                                ),
                              ),
                            ],
                            if (detailLines.isNotEmpty) ...[
                              const SizedBox(height: 3),
                              ...detailLines.map((e) {
                                final isChild =
                                    isMixedService && !e.isGroupHeader;
                                return Padding(
                                  padding: const EdgeInsets.only(bottom: 2),
                                  child: Text(
                                    isChild ? '• ${e.label}' : e.label,
                                    style: TextStyle(
                                      fontSize: 10.5,
                                      fontWeight: e.isGroupHeader
                                          ? FontWeight.w800
                                          : FontWeight.w500,
                                      color: e.isGroupHeader
                                          ? const Color(0xFF334155)
                                          : Colors.grey.shade600,
                                    ),
                                  ),
                                );
                              }),
                            ],
                          ],
                        ),
                      ),
                      const SizedBox(width: 8),
                      Text(
                        _formatMoney(lineTotal),
                        style: TextStyle(
                          fontSize: 12.5,
                          fontWeight: FontWeight.w900,
                          color: priceColor,
                        ),
                      ),
                    ],
                  ),
                  // ── ROW 2: action controls (only when editable) ───────
                  if (canAct) ...[
                    const SizedBox(height: 6),
                    Row(
                      mainAxisAlignment: MainAxisAlignment.end,
                      children: [
                        _buildDraftQuantityControl(
                          quantity: qty,
                          label: quantityLabel,
                          compact: _isNarrowScreen,
                          onDecrement: _isSubmitting
                              ? null
                              : () => _enterEditAndAct(
                                  normalizedOrder,
                                  (di) => _changeDraftQty(di, -1),
                                  i,
                                ),
                          onIncrement: _isSubmitting
                              ? null
                              : () => _enterEditAndAct(
                                  normalizedOrder,
                                  (di) => _changeDraftQty(di, 1),
                                  i,
                                ),
                        ),
                        const SizedBox(width: 4),
                        _buildDraftActionChip(
                          icon: Icons.tune_rounded,
                          label: 'Düzenle',
                          compact: _isNarrowScreen,
                          onPressed: _isSubmitting
                              ? null
                              : () async {
                                  await _beginOrderEditing(normalizedOrder);
                                  if (mounted &&
                                      _editingOrderId == orderId &&
                                      i < _draftItems.length) {
                                    await _editDraftItem(i);
                                  }
                                },
                        ),
                        const SizedBox(width: 4),
                        _buildDraftActionChip(
                          icon: Icons.delete_outline_rounded,
                          label: 'Sil',
                          compact: _isNarrowScreen,
                          onPressed: _isSubmitting
                              ? null
                              : () async {
                                  final confirmed =
                                      await _confirmDraftItemDelete(name);
                                  if (!confirmed || !mounted) return;
                                  _enterEditAndAct(normalizedOrder, (di) {
                                    setState(() {
                                      if (di < _draftItems.length) {
                                        _draftItems.removeAt(di);
                                      }
                                    });
                                    _notifyDraftChanged();
                                  }, i);
                                },
                          foregroundColor: const Color(0xFFDC2626),
                          backgroundColor: const Color(0xFFFEF2F2),
                          borderColor: const Color(0xFFFECACA),
                        ),
                      ],
                    ),
                  ],
                ],
              ),
            );
          }),
          // ── Footer: count + total ──────────────────────────────────────
          Padding(
            padding: const EdgeInsets.only(top: 2),
            child: Row(
              children: [
                Text(
                  '${items.length} ürün',
                  style: TextStyle(fontSize: 11, color: Colors.grey.shade500),
                ),
                const Spacer(),
                Text(
                  _formatMoney(orderTotal),
                  style: TextStyle(
                    fontSize: 13,
                    fontWeight: FontWeight.w900,
                    color: priceColor,
                  ),
                ),
              ],
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildOrdersTab(List<Map<String, dynamic>> tableOrders) {
    final extraBottomPadding = _showDraftBottomActionBar() ? 96.0 : 16.0;

    // When editing an existing order the draft card already shows the full
    // merged state for that order, so skip its incoming card to avoid duplication.
    final editingId = _editingOrderId ?? '';
    final visibleOrders = editingId.isEmpty
        ? tableOrders
        : tableOrders
              .where(
                (o) => _normalizeTableOrder(o)['id']?.toString() != editingId,
              )
              .toList(growable: false);

    final draftTotal = _draftItems.fold<double>(
      0,
      (s, item) => s + _itemLineTotal(item),
    );
    final ordersTotal = visibleOrders.fold<double>(0, (s, order) {
      return s +
          _extractItems(
            order['items'],
          ).fold<double>(0, (s2, i) => s2 + _itemLineTotal(i));
    });
    final grandTotal = draftTotal + ordersTotal;
    final hasAnyItems = _draftItems.isNotEmpty || visibleOrders.isNotEmpty;

    return ListView(
      padding: EdgeInsets.fromLTRB(12, 10, 12, extraBottomPadding),
      children: [
        _buildDraftEditorCard(),
        if (_submitFeedbackMessage != null) ...[
          const SizedBox(height: 8),
          _buildSubmitFeedbackCard(),
        ],
        if (visibleOrders.isNotEmpty) ...[
          const SizedBox(height: 10),
          ...visibleOrders.map(_buildIncomingOrderCard),
        ] else if (_draftItems.isEmpty) ...[
          const SizedBox(height: 10),
          Container(
            padding: const EdgeInsets.all(14),
            decoration: BoxDecoration(
              color: Colors.white,
              borderRadius: BorderRadius.circular(14),
              border: Border.all(color: const Color(0xFFE5E7EB)),
            ),
            child: Text(
              'Bu masaya henüz sipariş düşmedi.',
              style: TextStyle(fontSize: 12, color: Colors.grey.shade600),
            ),
          ),
        ],
        if (hasAnyItems) ...[
          const SizedBox(height: 8),
          Container(
            padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 10),
            decoration: BoxDecoration(
              color: Colors.white,
              borderRadius: BorderRadius.circular(12),
              border: Border.all(color: const Color(0xFFE2E8F0)),
            ),
            child: Row(
              children: [
                const Text(
                  'Toplam',
                  style: TextStyle(
                    fontSize: 14,
                    fontWeight: FontWeight.w700,
                    color: Color(0xFF374151),
                  ),
                ),
                const Spacer(),
                Text(
                  _formatMoney(grandTotal),
                  style: const TextStyle(
                    fontSize: 16,
                    fontWeight: FontWeight.w900,
                    color: AppColors.primary,
                  ),
                ),
              ],
            ),
          ),
        ],
      ],
    );
  }

  Widget _buildBody(List<Map<String, dynamic>> tableOrders) {
    switch (_bottomIndex) {
      case 0:
        return _buildProductsTab();
      case 1:
        return _buildReservationTab();
      case 2:
      default:
        return _buildOrdersTab(tableOrders);
    }
  }

  @override
  Widget build(BuildContext context) {
    return StreamBuilder<List<Map<String, dynamic>>>(
      stream: _tableOrdersStream,
      builder: (context, snapshot) {
        var tableOrders = const <Map<String, dynamic>>[];
        Widget body;
        if (snapshot.hasError) {
          final localOrders = _displayTableOrders(
            const <Map<String, dynamic>>[],
          );
          tableOrders = localOrders;
          debugPrint(
            '[GarsonRealtime] mode=flow_stream_error '
            'supabaseUrl=${AppRuntimeConfig.rawSupabaseUrl.trim().isEmpty ? '(missing)' : AppRuntimeConfig.rawSupabaseUrl.trim()} '
            'storeId=${widget.sellerId} '
            'sellerId=${widget.sellerId} '
            'waiterId=${_currentWaiterId() ?? '-'} '
            'schema=public table=table_orders channel=auto:stream(table_orders) '
            'filter=seller_id=eq.${widget.sellerId} '
            'tableNumber=${widget.tableNumber} '
            'error=${snapshot.error}',
          );
          if (_isRealtimeConnectionError(snapshot.error!)) {
            WidgetsBinding.instance.addPostFrameCallback((_) {
              if (!mounted || _hasShownRealtimeFallbackWarning) return;
              _hasShownRealtimeFallbackWarning = true;
              debugPrint(
                '[RealtimeFallback] Canlı sipariş akışı bağlanamadı. '
                'Masa ekranı sorgu verisi ile çalışıyor.',
              );
            });
          }
          body = FutureBuilder<List<Map<String, dynamic>>>(
            future: _getTableOrdersFallbackFuture(),
            builder: (context, fallbackSnapshot) {
              if (fallbackSnapshot.connectionState == ConnectionState.waiting) {
                if (localOrders.isNotEmpty || _draftItems.isNotEmpty) {
                  return _buildBody(localOrders);
                }
                return const Center(child: CircularProgressIndicator());
              }
              if (fallbackSnapshot.hasError) {
                if (localOrders.isNotEmpty || _draftItems.isNotEmpty) {
                  return _buildBody(localOrders);
                }
                return Center(
                  child: Text(
                    'Sipariş akışı alınamadı: ${fallbackSnapshot.error}',
                  ),
                );
              }
              final allOrders =
                  fallbackSnapshot.data ?? const <Map<String, dynamic>>[];
              final rawTableOrders = _extractTableOrders(allOrders);
              final displayTableOrders = _displayTableOrders(rawTableOrders);
              _tryApplyInitialOrder(displayTableOrders);
              return _buildBody(displayTableOrders);
            },
          );
        } else if (snapshot.connectionState == ConnectionState.waiting) {
          final localOrders = _displayTableOrders(
            const <Map<String, dynamic>>[],
          );
          tableOrders = localOrders;
          body = localOrders.isNotEmpty || _draftItems.isNotEmpty
              ? _buildBody(localOrders)
              : const Center(child: CircularProgressIndicator());
        } else {
          final allOrders = snapshot.data ?? const <Map<String, dynamic>>[];
          final rawTableOrders = _extractTableOrders(allOrders);
          tableOrders = _displayTableOrders(rawTableOrders);
          _tryApplyInitialOrder(tableOrders);
          body = _buildBody(tableOrders);
        }

        final isNarrowHeader = MediaQuery.of(context).size.width < 380;
        final headerTableTitle =
            (widget.tableTitleOverride ?? '').trim().isNotEmpty
            ? widget.tableTitleOverride!.trim()
            : 'Masa ${widget.tableNumber}';

        return Scaffold(
          backgroundColor: const Color(0xFFF3F4F6),
          appBar: AppBar(
            elevation: 0,
            backgroundColor: const Color(0xFFF3F4F6),
            foregroundColor: const Color(0xFF111827),
            titleSpacing: isNarrowHeader ? 12 : 16,
            title: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Text(
                  headerTableTitle,
                  style: TextStyle(
                    fontSize: isNarrowHeader ? 15 : 18,
                    fontWeight: FontWeight.w800,
                  ),
                ),
                if (!isNarrowHeader)
                  Text(
                    'Garson İşlem Ekranı',
                    style: TextStyle(fontSize: 11, color: Colors.grey.shade600),
                  ),
              ],
            ),
            actions: [
              if (_draftItems.isNotEmpty &&
                  _bottomIndex != 2 &&
                  !isNarrowHeader)
                TextButton.icon(
                  onPressed: () => setState(() => _bottomIndex = 2),
                  icon: const Icon(Icons.receipt_long_outlined, size: 17),
                  label: const Text('Sipariş'),
                ),
              isNarrowHeader
                  ? IconButton(
                      tooltip: 'İşlemler',
                      onPressed: _isSubmitting
                          ? null
                          : () => _showOperationsSheet(tableOrders),
                      padding: EdgeInsets.zero,
                      constraints: const BoxConstraints.tightFor(
                        width: 40,
                        height: 40,
                      ),
                      visualDensity: VisualDensity.compact,
                      icon: const Icon(Icons.tune_rounded, size: 20),
                    )
                  : TextButton.icon(
                      onPressed: _isSubmitting
                          ? null
                          : () => _showOperationsSheet(tableOrders),
                      icon: const Icon(Icons.tune_rounded, size: 17),
                      label: const Text('İşlemler'),
                    ),
              const SizedBox(width: 4),
            ],
          ),
          body: AnimatedSwitcher(
            duration: AppMotion.normalTransitionDuration,
            reverseDuration: AppMotion.normalTransitionReverseDuration,
            switchInCurve: AppMotion.revealCurve,
            switchOutCurve: AppMotion.revealReverseCurve,
            transitionBuilder: (child, animation) =>
                AppMotion.buildFadeSlideTransition(animation, child),
            child: KeyedSubtree(key: ValueKey<int>(_bottomIndex), child: body),
          ),
          bottomNavigationBar: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              if (_showProductsLiveSummaryBar()) _buildProductsLiveSummaryBar(),
              if (_showDraftBottomActionBar())
                _buildDraftBottomActionBar(tableOrders: tableOrders),
              if (_showCustomerKitchenApproveBar(tableOrders))
                _buildCustomerKitchenApproveBar(tableOrders: tableOrders),
              BottomNavigationBar(
                currentIndex: _bottomIndex,
                onTap: (index) => setState(() => _bottomIndex = index),
                selectedItemColor: AppColors.primary,
                unselectedItemColor: const Color(0xFF6B7280),
                selectedFontSize: 11,
                unselectedFontSize: 11,
                showUnselectedLabels: true,
                type: BottomNavigationBarType.fixed,
                backgroundColor: Colors.white,
                items: const [
                  BottomNavigationBarItem(
                    icon: Icon(Icons.storefront_outlined),
                    label: 'Ürünler',
                  ),
                  BottomNavigationBarItem(
                    icon: Icon(Icons.event_seat_outlined),
                    label: 'Rezervasyon',
                  ),
                  BottomNavigationBarItem(
                    icon: Icon(Icons.receipt_long_outlined),
                    label: 'Sipariş',
                  ),
                ],
              ),
            ],
          ),
        );
      },
    );
  }
}

